INSERT INTO club_authors (id, slug, name, bio) VALUES (1, 'cory-doctorow', 'Cory Doctorow', 'From his website: Cory Doctorow (craphound.com) is a science fiction author, activist, journalist and blogger -- the co-editor of Boing Boing (boingboing.net) and the author of the bestselling Tor Teens/HarperCollins UK novel LITTLE BROTHER. He is the former European director of the Electronic Frontier Foundation and co-founded the UK Open Rights Group. Born in Toronto, Canada, he now lives in London. 2 Creative Commons-licensed photos: cindiann: http://www.flickr.com/photos/trucolorsfly/2625294688/ & Joi Ito, Creative Commons Attribution 3.0.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (2, 'joseph-conrad', 'Joseph Conrad', 'Joseph Conrad was a Polish-born British novelist, who became a British subject in 1886. He is regarded as one of the greatest novelists in English though he did not speak the language fluently until he was in his twenties (and then always with a marked Polish accent). He wrote stories and novels, predominantly with a nautical or seaboard setting, that depict trials of the human spirit by the demands of duty and honor.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (3, 'hannah-arendt', 'Hannah Arendt', 'German-American philosopher and political theorist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (4, 'ethan-mollick', 'Ethan Mollick', 'Ethan Mollick is a Wharton associate professor, artificial intelligence (AI) researcher, and the author of New York Times bestseller Co-Intelligence. His work focuses primarily on the impact of AI on work and education, and he was named one of TIME Magazine''s Most Influential People in Artificial Intelligence of 2024.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (5, 'jenny-odell', 'Jenny Odell', 'American author and multidisciplinary artist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (6, 'guy-deutscher', 'Guy Deutscher', 'Israeli linguist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (7, 'paul-scharre', 'Paul Scharre', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (8, 'sebastian-mallaby', 'Sebastian Mallaby', 'Sebastian Christopher Peter Mallaby is an English journalist and author, Paul A. Volcker senior fellow for international economics at the Council on Foreign Relations (CFR), and contributing columnist at The Washington Post. Formerly, he was a contributing editor for the Financial Times and a columnist and editorial board member at The Washington Post.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (9, 'sarah-ogilvie', 'Sarah Ogilvie', 'Sarah Ogilvie is an Australian linguist, lexicographer, and computer scientist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (10, 'tim-parks', 'Tim Parks', 'Timothy Harold Parks is a British novelist who has lived in Italy since 1981. He is also an author of nonfiction, a translator from Italian to English, and a professor of literature.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (11, 'david-graeber', 'David Graeber', '**David Rolfe Graeber** (/ˈɡreɪbər/; February 12, 1961 – September 2, 2020) was an American anthropologist, anarchist activist and author known for his books *Debt: The First 5000 Years* (2011), *The Utopia of Rules* (2015) and *Bullshit Jobs: A Theory* (2018). He was a professor of anthropology at the London School of Economics. As an assistant professor and associate professor of anthropology at Yale from 1998–2007 he specialised in theories of value and social theory. The university''s decision not to rehire him when he would otherwise have become eligible for tenure sparked an academic controversy, and a petition with more than 4,500 signatures. He went on to become, from 2007–13, Reader in Social Anthropology at Goldsmiths, University of London.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (12, 'david-wengrow', 'David Wengrow', 'British archaeologist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (13, 'thomas-halliday', 'Thomas Halliday', 'Thomas John Dixon Halliday is a British palaeobiologist and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (14, 'nicholas-eberstadt', 'Nicholas Eberstadt', 'Nicholas Nash Eberstadt is an American political economist. He holds the Henry Wendt Chair in Political Economy at the American Enterprise Institute (AEI), a political think tank. He is also a Senior Adviser to the National Bureau of Asian Research (NBR), a member of the visiting committee at the Harvard School of Public Health, and a member of the Global Leadership Council at the World Economic Forum.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (15, 'david-foster-wallace', 'David Foster Wallace', 'American novelist, short-story writer, and essayist whose dense works provide a dark, often satirical analysis of American culture.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (16, 'jedidiah-jenkins', 'Jedidiah Jenkins', 'Jedidiah Jenkins is an American author and travel writer.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (17, 'gwen-westerman', 'Gwen Westerman', 'Gwen Nell Westerman is a Native American educator, writer, and fiber artist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (18, 'bruce-white', 'Bruce White', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (19, 'natasha-dow-schull', 'Natasha Dow Schüll', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (20, 'paul-strathern', 'Paul Strathern', 'Paul Strathern is a Scots-Irish writer and academic.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (21, 'patrick-radden-keefe', 'Patrick Radden Keefe', 'Patrick Radden Keefe is an award-winning staff writer at The New Yorker magazine and the author of the New York Times bestseller Say Nothing: A True Story of Murder and Memory in Northern Ireland, as well as two other books: The Snakehead: An Epic Tale of the Chinatown Underworld and the American Dream, and Chatter: Dispatches from the Secret World of Global Eavesdropping. He started contributing to The New Yorker in 2006 and has written articles about the chef and TV host Anthony Bourdain, the hunt for the drug lord Chapo Guzman, the tragic personal history of the mass shooter Amy Bishop, and the role that the Sackler family and their company Purdue Pharma played in sparking the opioid crisis. He received the National Magazine Award for Feature Writing in 2014, and was a finalist for the National Magazine Award for Reporting in 2015 and 2016. Say Nothing received the Orwell Prize for Political Writing in 2019 and was named one of Literary Hub’s “20 Best Nonfiction Books of the Decade.” Patrick grew up in Dorchester, Massachusetts and went to college at Columbia. He received masters degrees from Cambridge University and the London School of Economics, and a JD from Yale Law School. In addition to The New Yorker, his work has appeared in The New York Review of Books, The New York Times Magazine, Slate, and other publications. He is the recipient of fellowships from the Guggenheim Foundation, the Rockefeller Foundation, the New America Foundation, the Woodrow Wilson International Center for Scholars, and the Cullman Center for Scholars and Writers at the New York Public Library. Photograph by Philip Montgomery.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (22, 'jonathan-bier', 'Jonathan Bier', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (23, 'isabel-wilkerson', 'Isabel Wilkerson', 'Isabel Wilkerson is an American journalist and the author of The Warmth of Other Suns: The Epic Story of America''s Great Migration (2010) and Caste: The Origins of Our Discontents (2020). She is the first woman of African-American heritage to win the Pulitzer Prize in journalism.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (24, 'matthew-desmond', 'Matthew Desmond', 'Matthew Desmond is Maurice P. During Professor of Sociology and Principal Investigator of The Eviction Lab. After receiving his Ph.D. in 2010 from the University of Wisconsin at Madison, he joined the Harvard Society of Fellows as a Junior Fellow. His primary teaching and research interests include urban sociology, poverty, race and ethnicity, organizations and work, social theory, and ethnography. Desmond is the author of four books: On the Fireline: Living and Dying with WIldland Firefighters (2007), Race in America (with Mustafa Emirbayer, 2015), The Racial Order (with Mustafa Emirbayer, 2015), and Evicted: Poverty and Profit in the American City (2016). He also is the editor of the inaugural issue of RSF: The Russell Sage Foundation Journal of the Social Sciences, Volumes 1 & 2: Severe Deprivation in America (2015). Desmond has written essays on educational inequality, dangerous work, political ideology, race and social theory, and the inner-city housing market. Recently, he has published on the prevalence and consequences of eviction and the low-income rental market, network-based survival strategies among the urban poor, and the consequences of new crime control policies on inner-city women in the American Journal of Sociology, American Sociological Review, Social Forces, and Demography. In 2015, Desmond was awarded a MacArthur “Genius” grant.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (25, 'steven-pressfield', 'Steven Pressfield', 'I was born in Port of Spain, Trinidad, in 1943 to a Navy father and mother. I graduated from Duke University in 1965. In January of 1966, when I was on the bus leaving Parris Island as a freshly-minted Marine, I looked back and thought there was at least one good thing about this departure. "No matter what happens to me for the rest of my life, no one can ever send me back to this freakin'' place again." Forty years later, to my surprise and gratification, I am far more closely bound to the young men of the Marine Corps and to all other dirt-eating, ground-pounding outfits than I could ever have imagined. GATES OF FIRE is one reason. Dog-eared paperbacks of this tale of the ancient Spartans have circulated throughout platoons of U.S. troops in Iraq and Afghanistan since the first days of the invasions. E-mails come in by hundreds. GATES OF FIRE is on the Commandant of the Marine Corps'' Reading list. It is taught at West Point and Annapolis and at the Marine Corps Basic School at Quantico. TIDES OF WAR is on the curriculum of the Naval War College. From 2nd Battalion/6th Marines, which calls itself "the Spartans," to ODA 316 of the Special Forces, whose forearms are tattooed with the lambda of Lakedaemon, today''s young warriors find a bond to their ancient precursors in the historical narratives of these novels. My struggles to earn a living as a writer (it took seventeen years to get the first paycheck) are detailed in my 2002 book, THE WAR OF ART. I have worked as an advertising copywriter, schoolteacher, tractor-trailer driver, bartender, oilfield roustabout and attendant in a mental hospital. I have picked fruit in Washington state and written screenplays in Tinseltown. With the publication of THE LEGEND OF BAGGER VANCE in 1995, I became a writer of books once and for all. My writing philosophy is, not surprisingly, a kind of warrior code — internal rather than external — in which the enemy is identified as those forms of self-sabotage that I have labeled "Resistance" with a capital R (in THE WAR OF ART) and the technique for combatting these foes can be described as "turning pro." I believe in previous lives. I believe in the Muse. I believe that books and music exist before they are written and that they are propelled into material being by their own imperative to be born, via the offices of those willing servants of discipline, imagination and inspiration, whom we call artists. My conception of the artist''s role is a combination of reverence for the unknowable nature of "where it all comes from" and a no-nonsense, blue-collar demystification of the process by which this mystery is approached. In other words, a paradox. There''s a recurring character in my books named Telamon, a mercenary of ancient days. Telamon doesn''t say much. He rarely gets hurt or wounded. And he never seems to age. His view of the profession of arms is a lot like my conception of art and the artist: "It is one thing to study war, and another to live the warrior''s life.".');
INSERT INTO club_authors (id, slug, name, bio) VALUES (26, 'kazuo-ishiguro', 'Kazuo Ishiguro', 'Sir Kazuo Ishiguro OBE FRSA FRSL (/kæˈzuːoʊ ˌɪʃɪˈɡʊəroʊ, ˈkæzuoʊ -/ kaz-OO-oh ISH-ig-OOR-oh, KAZ-oo-oh -⁠; born 8 November 1954) is an English novelist, screenwriter, musician, and short-story writer. Ishiguro was born in Nagasaki, Japan, and moved to Britain in 1960 with his parents when he was five. He is one of the most critically-acclaimed and praised contemporary fiction authors writing in English, being awarded the 2017 Nobel Prize in Literature. In its 2017 citation, the Swedish Academy described Ishiguro as a writer "who, in novels of great emotional force, has uncovered the abyss beneath our illusory sense of connection with the world". source.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (27, 'david-anthony', 'David Anthony', 'David W. Anthony is an American anthropologist who is Professor Emeritus of Anthropology at Hartwick College. He specializes in Indo-European migrations, and is a proponent of the Kurgan hypothesis. Anthony is well known for his award-winning book The Horse, the Wheel, and Language (2007). -Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (28, 'christopher-mcdougall', 'Christopher McDougall', 'Trained as a foreign correspondent for the Associated Press, Christopher McDougall covered wars in Rwanda and Angola before writing his international bestseller, Born to Run. His fascination with the limits of human potential led him to create the Outside magazine web series, “Art of the Hero.” --chrismcdougall.com.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (29, 'joseph-henrich', 'Joseph Henrich', 'Joseph Henrich is an American anthropologist and professor of human evolutionary biology at Harvard University. Before arriving at Harvard, Henrich was a professor of psychology and economics at the University of British Columbia. He is interested in the question of how humans evolved from "being a relatively unremarkable primate a few million years ago to the most successful species on the globe", and how culture shaped our species'' genetic evolution.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (30, 'frans-de-waal', 'Frans De Waal', 'Frans de Waal has been named one of Time magazine’s 100 Most Influential People. The author of Are We Smart Enough to Know How Smart Animals Are?, among many other works, he is the C. H. Candler Professor in Emory University’s Psychology Department and director of the Living Links Center at the Yerkes National Primate Research Center. He lives in Atlanta, Georgia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (31, 'nick-sousanis', 'Nick Sousanis', 'Walter Nickell "Nick" Sousanis is an American scholar, art critic, and cartoonist; a co-founder of the TheDetroiter.com, he is also the first person at Columbia University to write a dissertation entirely in a comic book format.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (32, 'david-pilling', 'David Pilling', 'David Pilling is a British journalist and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (33, 'andrew-guthrie-ferguson', 'Andrew Guthrie Ferguson', 'Andrew Guthrie Ferguson is a professor of law at The George Washington University Law School.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (34, 'walter-isaacson', 'Walter Isaacson', 'Walter Isaacson, the CEO of the Aspen Institute, has been chairman of CNN and the managing editor of Time magazine. He is the author of Steve Jobs; Einstein: His Life and Universe; Benjamin Franklin: An American Life; and Kissinger: A Biography, and the coauthor of The Wise Men: Six Friends and the World They Made. He lives in Washington, DC. [].');
INSERT INTO club_authors (id, slug, name, bio) VALUES (35, 'ken-grimwood', 'Ken Grimwood', 'Kenneth Milton Grimwood was an American author, who also published work under the name of Alan Cochran. In his fantasy fiction, Grimwood combined themes of life-affirmation and hope with metaphysical concepts, themes found in his best-known novel, Replay (1986). It won the 1988 World Fantasy Award for Best Novel.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (36, 'michael-pillsbury', 'Michael Pillsbury', 'Born in California in 1945, Pillsbury was educated at Stanford University (B.A. in History with Honors in Social Thought) and Columbia University (M.A., Ph.D.). Major academic advisers to Pillsbury at Columbia were Zbigniew Brzezinski and Michel Oksenberg, who later played key roles in the Jimmy Carter administration on policy toward both China and Afghanistan. Pillsbury studied the art and practice of bureaucratic politics with Roger Hilsman, President John Kennedy''s intelligence director at the State Department and the author of Politics Of Policy Making In Defense and Foreign Affairs. At Stanford, Pillsbury''s academic mentor was Mark Mancall, author of two books on the influence of ancient traditions on Chinese foreign policy. In 1969-1970 Pillsbury was the Assistant Political Affairs Officer at the United Nations. From 1971-72, he was a doctoral dissertation Fellow for the National Science Foundation in Taiwan, and in 1973-1977, Pillsbury was an analyst at the Social Science Department at RAND. In 1978, Pillsbury was a research fellow at the Center for Science and International Affairs at Harvard University. During the Reagan administration, Dr. Pillsbury was the Assistant Under Secretary of Defense for Policy Planning and responsible for implementation of the program of covert aid known as the Reagan Doctrine. In 1975-76, while an analyst at the RAND Corporation, Pillsbury published articles in Foreign Policy and International Security recommending that the United States establish intelligence and military ties with China. The proposal, publicly commended by Ronald Reagan, Henry Kissinger, and James Schlesinger, later became US policy during the Carter and Reagan administrations. Pillsbury served on the staff of four US Senate Committees from 1978-1984 and 1986-1991. As a staff member, Pillsbury drafted the Senate Labor Committee version of the legislation that enacted the US Institute of Peace in 1984. He also assisted in drafting the legislation to create the National Endowment for Democracy and the annual requirement for a DOD report on Chinese military power. In 1992, under President George H. W. Bush, Pillsbury was Special Assistant for Asian Affairs in the Office of the Secretary of Defense, reporting to Andrew W. Marshall, Director of Net Assessment. Michael Pillsbury is a member of the Council on Foreign Relations and the International Institute for Strategic Studies.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (37, 'robert-pirsig', 'Robert Pirsig', 'Robert Maynard Pirsig (Minneapolis, Minesota; September 6, 1928-South Berwick, Maine; April 24, 2017) was an American writer and philosopher, and the author of the philosophical novels *Zen and the Art of Motorcycle Maintenance: An Inquiry into Values* (1974) and *Lila: An Inquiry into Morals (1991)* **Source**: Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (38, 'tara-westover', 'Tara Westover', 'Tara Westover (born September 27, 1986) is an American memoirist, essayist and historian. Her memoir *Educated* (2018) debuted at No. 1 on *The New York Times* bestseller list and was a finalist for a number of national awards, including the LA Times Book Prize, PEN America''s Jean Stein Book Award, and two awards from the National Book Critics Circle Award.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (39, 'yuval-noah-harari', 'Yuval Noah Harari', 'Yuval Noah Harari is an Israeli medievalist, military historian, public intellectual, and popular science writer. He is a professor of history at the Hebrew University of Jerusalem. His first bestselling book, Sapiens: A Brief History of Humankind (2011) is based on his lectures to an undergraduate world history class. His other works include the bestsellers Homo Deus: A Brief History of Tomorrow (2016), 21 Lessons for the 21st Century (2018), and Nexus: A Brief History of Information Networks from the Stone Age to AI (2024). His published work examines themes of free will, consciousness, intelligence, happiness, suffering and the role of storytelling in human evolution.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (40, 'robert-wright', 'Robert Wright', 'Robert Wright is an American author and journalist known for his wide-ranging interests in philosophy, society, science, history, politics, international relations, and religion. He has published five books: Three Scientists and Their Gods: Looking for Meaning in an Age of Information (1988), The Moral Animal (1994), Nonzero: The Logic of Human Destiny (1999), The Evolution of God (2009), and Why Buddhism is True (2017). Wright has taught at Princeton University and the University of Pennsylvania; more recently, in 2019 he was Visiting Professor of Science and Religion at Union Theological Seminary, New York.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (41, 'jennifer-a-doudna', 'Jennifer A. Doudna', 'JENNIFER A. DOUDNA, Ph.D. is a professor in the Chemistry and the Molecular and Cell Biology Departments at the University of California, Berkeley, investigator with the Howard Hughes Medical Institute, and researcher in the Molecular Biophysics and Integrated Bioimaging Division at the Lawrence Berkeley National Laboratory. She is internationally recognized as a leading expert on RNA-protein biochemistry, CRISPR biology, and genome engineering. She lives in the Bay Area.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (42, 'sarah-bakewell', 'Sarah Bakewell', 'Sarah Bakewell is a British author and professor. She lives in London. She received the Windham–Campbell Literature Prize in Non-Fiction.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (43, 'anders-ericsson', 'Anders Ericsson', 'K. Anders Ericsson was a Swedish psychologist and Conradi Eminent Scholar and Professor of Psychology at Florida State University who was internationally recognized as a researcher in the psychological nature of expertise and human performance.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (44, 'nessa-carey', 'Nessa Carey', 'Nessa Carey is a British biologist working in the field of molecular biology and biotechnology. She is International Director of the technology transfer organization PraxisUnico and a visiting professor at Imperial College London.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (45, 'mark-miodownik', 'Mark Miodownik', 'Mark Andrew Miodownik is a British materials scientist, engineer, broadcaster and writer at University College London. Previously, he was the head of the Materials Research Group at King''s College London, and a co-founder of Materials Library.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (46, 'neil-gaiman', 'Neil Gaiman', 'Neil Richard MacKinnon Gaiman born Neil Richard Gaiman, 10 November 1960) is an English author of short fiction, novels, comic books, graphic novels, audio theatre, and films. His notable works include the comic book series The Sandman and novels Stardust, American Gods, Coraline, and The Graveyard Book. He has won numerous awards, including the Hugo, Nebula, and Bram Stoker awards, as well as the Newbery and Carnegie medals. He is the first author to win both the Newbery and the Carnegie medals for the same work, The Graveyard Book (2008). In 2013, The Ocean at the End of the Lane was voted Book of the Year in the British National Book Awards.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (47, 'george-orwell', 'George Orwell', 'George Orwell, originally born as Eric Arthur Blair, was an English novelist and journalist. His work is marked by keen intelligence and wit, a profound awareness of social injustice, an intense, revolutionary opposition to totalitarianism, a passion for clarity in language and a belief in democratic socialism.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (48, 'nick-lane', 'Nick Lane', 'Nick Lane is a British biochemist and writer. He is a professor in evolutionary biochemistry at University College London. His books have won several awards.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (49, 'janine-r-wedel', 'Janine R. Wedel', 'Janine R. Wedel is an American anthropologist and university professor in the Schar School of Policy and Government at George Mason University and a senior research fellow of the New America Foundation. She is the author of several books and many articles on some key systemic processes of the day. She is the first anthropologist to win the Grawemeyer Award for Ideas Improving World Order.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (50, 'j-d-vance', 'J. D. Vance', 'American venture capitalist, author, and the junior United States senator from Ohio since 2023.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (51, 'ann-leckie', 'Ann Leckie', 'Ann Leckie is an American author of science fiction and fantasy. Her 2013 debut novel Ancillary Justice, which features artificial consciousness and gender-blindness, won the 2014 Hugo Award for Best Novel, as well as the Nebula Award, the Arthur C. Clarke Award, and the BSFA Award. The sequels, Ancillary Sword and Ancillary Mercy, each won the Locus Award and were both nominated for the Nebula Award. Provenance, published in 2017, Translation State, published in 2023, and Radiant Star, published in 2026, are also set in the Imperial Radch universe.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (52, 'louis-menand', 'Louis Menand', 'Louis Menand is an American critic, essayist, and professor who wrote the Pulitzer-winning book The Metaphysical Club (2001), an intellectual and cultural history of late 19th- and early 20th-century America.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (53, 'colin-woodard', 'Colin Woodard', 'Colin Strohn Woodard is an American journalist and writer known for his books American Nations: A History of the Eleven Rival Regional Cultures of North America (2011), The Republic of Pirates (2007), and The Lobster Coast (2004), a cultural and environmental history of coastal Maine. He is known for his writing that examines how the historically distinct regional cultures of America shape its current politics, society and health status.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (54, 'robert-j-gordon', 'Robert J. Gordon', 'Robert James Gordon is an American economist. He is the Stanley G. Harris Professor of the Social Sciences at Northwestern University and one of the world''s leading experts on inflation, unemployment, and long-term economic growth.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (55, 'ashlee-vance', 'Ashlee Vance', 'Ashlee Vance is an American reporter, writer, and filmmaker. He is known for his 2015 biography of Elon Musk, titled Elon Musk: Tesla, SpaceX, and the Quest for a Fantastic Future.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (56, 'philip-e-tetlock', 'Philip E. Tetlock', 'Philip E. Tetlock (born 2 March 1954) is a Canadian-American political science writer, and the Annenberg University Professor at the University of Pennsylvania, where he is cross-appointed at the Wharton School and the School of Arts and Sciences. He was elected a Member of the American Philosophical Society in 2019.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (57, 'atul-gawande', 'Atul Gawande', 'Atul Gawande, MD, MPH, is a surgeon, writer, and public health researcher. For more than 20 years, he has practiced general and endocrine surgery at Brigham and Women’s Hospital. He is Professor in the Department of Health Policy and Management at the Harvard T.H. Chan School of Public Health and the Samuel O. Thier Professor of Surgery at Harvard Medical School. He is also Executive Director of Ariadne Labs, a joint center for health systems innovation, and Chairman of Lifebox, a nonprofit organization making surgery safer globally. Photo Credit: By <a href="//commons.wikimedia.org/w/index.php?title=User:Amar_Karodkar&amp;action=edit&amp;redlink=1" class="new" title="User:Amar Karodkar (page does not exist)">Amar Karodkar</a> - <span class="int-own-work" lang="en">Own work</span>, <a href="https://creativecommons.org/licenses/by-sa/4.0" title="Creative Commons Attribution-Share Alike 4.0">.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (58, 'jared-diamond', 'Jared Diamond', 'Jared Mason Diamond is an American scientist and author best known for his popular science books.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (59, 'neil-postman', 'Neil Postman', 'Neil Postman was an American author, educator, media theorist, and cultural critic who eschewed digital technology, including personal computers and mobile devices, and was critical of the use of personal computers in schools. He is best known for 20 books about technology and education, including Teaching as a Subversive Activity (1970), The Disappearance of Childhood (1982), Amusing Ourselves to Death (1985), Conscientious Objections (1988), Technopoly: The Surrender of Culture to Technology (1992) and The End of Education: Redefining the Value of School (1995).');
INSERT INTO club_authors (id, slug, name, bio) VALUES (60, 'arkady-strugatsky', 'Arkady Strugatsky', 'The brothers Arkady Strugatsky and Boris Strugatsky were Soviet and Russian science-fiction authors who collaborated through most of their careers.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (61, 'boris-strugatsky', 'Boris Strugatsky', 'The brothers Arkady Strugatsky and Boris Strugatsky were Soviet and Russian science-fiction authors who collaborated through most of their careers.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (62, 'john-h-holland', 'John H. Holland', 'John Henry Holland was an American scientist and professor of electrical engineering and computer science at the University of Michigan. He was a pioneer in what became known as genetic algorithms.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (63, 'glenn-greenwald', 'Glenn Greenwald', 'Glenn Edward Greenwald is an American journalist, author, and former lawyer.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (64, 'paul-vigna', 'Paul Vigna', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (65, 'michael-j-casey', 'Michael J. Casey', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (66, 'mark-newman', 'Mark Newman', 'Mark Newman is a British physicist and Anatol Rapoport Distinguished University Professor of Physics at the University of Michigan, as well as an external faculty member of the Santa Fe Institute. He is known for his fundamental contributions to the fields of complex systems and complex networks, for which he was awarded the Lagrange Prize in 2014 and the APS Kadanoff Prize in 2024.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (67, 'duncan-j-watts', 'Duncan J. Watts', 'Duncan James Watts is a computational social scientist and a professor at the University of Pennsylvania. He was formerly a principal researcher at Microsoft Research in New York City, and is known for his work on small-world networks.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (68, 'sue-johnson', 'Sue Johnson', 'British clinical psychologist, couples therapist and author living and working in Canada.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (69, 'andrew-solomon', 'Andrew Solomon', 'Andrew Solomon is a writer and lecturer on psychology, politics, and the arts; winner of the National Book Award; and an activist in LGBT rights, mental health, and the arts. --http://andrewsolomon.com/andrew-solomon-biography/.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (70, 'donella-meadows', 'Donella Meadows', 'American environmental scientist, teacher, and writer.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (71, 'brad-stone', 'Brad Stone', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (72, 'nassim-nicholas-taleb', 'Nassim Nicholas Taleb', 'French-Lebanese-American essayist, scholar, statistician, former trader and risk analyst.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (73, 'andy-weir', 'Andy Weir', 'Andy Weir built a career as a software engineer until the success of his first published novel, THE MARTIAN, allowed him to live out his dream of writing fulltime. He is a lifelong space nerd and a devoted hobbyist of subjects such as relativistic physics, orbital mechanics, and the history of manned spaceflight. He also mixes a mean cocktail. He lives in California.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (74, 'karen-armstrong', 'Karen Armstrong', 'Karen Armstrong is a British author and commentator known for her books on comparative religion. A former Roman Catholic religious sister, she went from a conservative to a more liberal and mystical Christian faith. - Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (75, 'susan-cain', 'Susan Cain', 'SUSAN CAIN is the author of the award-winning New York Times bestseller QUIET: The Power of Introverts in A World That Can’t Stop Talking, which has been translated into thirty-six languages, has appeared on many “Best of” lists, and was named the #1 best book of the year by Fast Company magazine. Cain’s book was the subject of a TIME Magazine cover story, and her writing has appeared in the The New York Times, The Atlantic, The Wall Street Journal, and many other publications. Her record-smashing TED talk has been viewed almost 10 million times, and was named by Bill Gates one of his all-time favorite talks. Cain has also spoken at Microsoft, Google, the U.S. Treasury, the S.E.C., Harvard, Yale, West Point and the US Naval Academy. She received quite a few awards and recognitions, including Harvard Law School’s Celebration Award for Thought Leadership.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (76, 'alexis-madrigal', 'Alexis Madrigal', 'Alexis Madrigal is an American journalist. He co-hosts the daily Forum program on California Public Radio for KQED in San Francisco.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (77, 'siddhartha-mukherjee', 'Siddhartha Mukherjee', 'Siddhartha Mukherjee (born 21 July 1970) is an Indian-American physician, biologist, oncologist, and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (78, 'katherine-boo', 'Katherine Boo', 'Katherine J. "Kate" Boo is an American investigative journalist who has documented the lives of people in poverty. She has received the MacArthur Fellowship (2002), the National Book Award for Nonfiction (2012), and her work earned the 2000 Pulitzer Prize for Public Service for The Washington Post. She has been a staff writer for The New Yorker magazine since 2003. Her book Behind the Beautiful Forevers: Life, Death and Hope in a Mumbai Undercity won nonfiction prizes from PEN, the Los Angeles Times Book Awards, the New York Public Library, and the American Academy of Arts and Letters, in addition to the National Book Award for Nonfiction.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (79, 'andy-greenberg', 'Andy Greenberg', 'Andy Greenberg is a technology journalist serving as a senior writer at Wired magazine. He previously worked as a staff writer at Forbes magazine and as a contributor for Forbes.com. He has published the books This Machine Kills Secrets concerning whistleblowing, Sandworm, concerning the eponymous hacking group, and Tracers in the Dark, concerning cryptocurrency tracing as a law enforcement investigative technique.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (80, 'andrei-lankov', 'Andrei Lankov', 'Andrei Nikolaevich Lankov is a Russo-Australian scholar of Asia and specialist in Korean studies and Director of Korea Risk Group, the parent company of NK News and NK Pro. In the 1990s, he worked in South Korea and Australia, and has been teaching in Seoul since 2004.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (81, 'steven-strogatz', 'Steven Strogatz', 'Steven Henry Strogatz is an American mathematician and the Jacob Gould Schurman Professor of Applied Mathematics at Cornell University. He is known for his work on nonlinear systems, including contributions to the study of synchronization in dynamical systems, for his research in a variety of areas of applied mathematics, including mathematical biology and complex network theory, and for his outreach work in the public communication of mathematics.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (82, 'kelly-mcgonigal', 'Kelly McGonigal', 'Kelly McGonigal is a health psychologist and lecturer at Stanford University who is known for her work in the field of "science help" which focuses on translating insights from psychology and neuroscience into practical strategies that support health and well-being. Mainstream media articles about inner-conflict-related aspects of modern lifestyles regularly quote her. A longtime advocate of self-compassion and mindfulness as stress-coping strategies, McGonigal has altered her focus on the problematic aspects of stress; in a talk at the TEDGlobal 2013, she emphasized the importance of an individual''s subjective belief in themselves as someone who is able to cope successfully as being a crucial factor in their actual response to stress.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (83, 'nate-silver', 'Nate Silver', 'Nathaniel Read Silver is an American statistician, writer, and poker player who analyzes baseball, basketball, and elections.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (84, 'connie-willis', 'Connie Willis', 'Constance Elaine Trimmer "Connie" Willis is an American science fiction and fantasy writer. She has won more major genre awards than any other writer, including eleven Hugo Awards and seven Nebula Awards. Most recently, she won the "Best Novel" Hugo and Nebula Awards for Blackout/All Clear (2010). She was inducted by the Science Fiction Hall of Fame in 2009 and the Science Fiction Writers of America named her its 28th SFWA Grand Master in 2011.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (85, 'bruce-schneier', 'Bruce Schneier', 'American cryptographer, and security specialist.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (86, 'tina-rosenberg', 'Tina Rosenberg', 'Tina Rosenberg is an American journalist and the author of three books. For one of them, The Haunted Land: Facing Europe''s Ghosts After Communism (1995), she won the Pulitzer Prize for General Nonfiction and the National Book Award for Nonfiction.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (87, 'dale-carpenter', 'Dale Carpenter', 'Dale Carpenter is an American legal commentator and professor of law at the Southern Methodist University Dedman School of Law. He formerly served as the Earl R. Larson Professor of Civil Rights and Civil Liberties Law at the University of Minnesota Law School for sixteen years. As a professor, Carpenter specializes in constitutional law, the First Amendment, Due Process and Equal Protection clauses, sexual orientation and the law, and commercial law.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (88, 'walter-m-miller-jr', 'Walter M. Miller, Jr.', 'Walter Michael Miller Jr. was an American science fiction writer. He wrote short stories that became a celebrated fix-up novel, A Canticle for Leibowitz (1959). His only novel published in his lifetime, it won the 1961 Hugo Award for Best Novel.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (89, 'erik-larson', 'Erik Larson', 'Erik Larson is the author of the international bestseller Isaac''s Storm won an Edgar Award for fact-crime writing. His latest book, In the Garden of Beasts: Love Terror and an American Family in Hitler''s Berlin, has been acquired for publication in 20 countries and optioned by Tom Hanks for a feature film. Erik is a former features writer for The Wall Street Journal and Time. His magazine stories have appeared in The New Yorker, The Atlantic Monthly, Harper''s and other publications.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (90, 'murray-n-rothbard', 'Murray N. Rothbard', 'Murray Newton Rothbard was an American economist of the Austrian School, economic historian, political theorist, and activist. Rothbard was a central figure in the 20th-century American libertarian movement, particularly its right-wing strands, and was a founder and leading theoretician of anarcho-capitalism. He wrote over twenty books on political theory, history, economics, and other subjects.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (91, 'william-gibson', 'William Gibson', 'William Ford Gibson is an American-Canadian writer who has been called the "noir prophet" of the cyberpunk subgenre of science fiction. Gibson coined the term "cyberspace" in his short story "Burning Chrome" and later popularized the concept in his debut novel, *Neuromancer* (1984). In envisaging cyberspace, Gibson created an iconography for the information age before the ubiquity of the Internet in the 1990s. He is also credited with predicting the rise of reality television and with establishing the conceptual foundations for the rapid growth of virtual environments such as video games and the Web.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (92, 'daniel-kahneman', 'Daniel Kahneman', 'Israeli-American psychologist and economist notable for his work on the psychology of judgment and decision-making, as well as behavioral economics.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (93, 'brian-christian', 'Brian Christian', 'Brian Christian is an American non-fiction author, researcher, poet, and programmer, best known for a bestselling series of books about the human implications of computer science, including The Most Human Human (2011), Algorithms to Live By (2016), and The Alignment Problem (2020).');
INSERT INTO club_authors (id, slug, name, bio) VALUES (94, 'lawrence-lessig', 'Lawrence Lessig', 'Lawrence "Larry" Lessig is an American academic and political activist. He is best known as a proponent of reduced legal restrictions on copyright, trademark, and radio frequency spectrum, particularly in technology applications. He is a director of the Edmond J. Safra Foundation Center for Ethics at Harvard University and a professor of law at Harvard Law School. Prior to rejoining Harvard, he was a professor of law at Stanford Law School and founder of its Center for Internet and Society. Lessig is a founding board member of Creative Commons, a board member of the Software Freedom Law Center and a former board member of the Electronic Frontier Foundation.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (95, 'greg-bear', 'Greg Bear', 'Gregory Dale Bear (born August 20, 1951) is an American writer and illustrator best known for science fiction. His work has covered themes of galactic conflict (Forge of God books), artificial universes (The Way series), consciousness and cultural practices (Queen of Angels), and accelerated evolution (Blood Music, Darwin''s Radio, and Darwin''s Children). His most recent work is the 2021 novel The Unfinished Land. Greg Bear has written over 50 books in total. Greg Bear was also one of the five co-founders of the San Diego Comic-Con. source.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (96, 'richard-dawkins', 'Richard Dawkins', 'Clinton Richard Dawkins, FRS, FRSL is a British ethologist, evolutionary biologist and popular science author. He was formerly Professor for Public Understanding of Science at Oxford and was a fellow of New College, Oxford. Dawkins came to prominence with his 1976 book *The Selfish Gene*, which popularised the gene-centred view of evolution and introduced the term meme. In 1982, he made a widely cited contribution to evolutionary biology with the concept, presented in his book *The Extended Phenotype*, that the phenotypic effects of a gene are not necessarily limited to an organism''s body, but can stretch far into the environment, including the bodies of other organisms. Dawkins is well known for his candid criticism of creationism and intelligent design. In his 1986 book *The Blind Watchmaker*, he argued against the watchmaker analogy, an argument for the existence of a supernatural creator based upon the complexity of living organisms. Instead, he described evolutionary processes as analogous to a blind watchmaker. He has since written several popular science books, and makes regular television and radio appearances, predominantly discussing these topics.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (97, 'deborah-gordon', 'Deborah Gordon', 'Deborah M. Gordon is an American biologist best known for her impactful research in the behavioral ecology of ants and her studies on the operations of ant colonies without a central control. In addition to overseeing The Gordon Lab, she is currently a Professor of Biology at Stanford University.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (98, 'edward-glaeser', 'Edward Glaeser', 'Edward L. Glaeser is the Fred and Eleanor Glimp Professor of Economics at Harvard University. He studies the economics of cities, housing, segregation, obesity, crime, innovation and other subjects, and writes about many of these issues for Economix. He serves as the director of the Taubman Center for State and Local Government and the Rappaport Institute for Greater Boston. He is also a senior fellow at the Manhattan Institute. He received his Ph.D. from the University of Chicago in 1992. (*.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (99, 'tim-wu', 'Tim Wu', 'Timothy Shiou-Ming Wu is a Taiwanese-American legal scholar who served as Special Assistant to the President for Technology and Competition Policy at the United States from 2021 to 2023. He is also a professor of law at Columbia University and a contributing opinion writer for The New York Times. He is known legally and academically for significant contributions to antitrust and communications policy, coining the phrase "network neutrality" in his 2003 law journal article, Network Neutrality, Broadband Discrimination. In the late 2010s, Wu was a leading advocate for an antitrust lawsuit directed at the breakup of Facebook.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (100, 'bill-bryson', 'Bill Bryson', '"William McGuire "Bill" Bryson is a best-selling Anglo-American author of humorous books on travel, as well as books on the English language and science." - Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (101, 'noam-chomsky', 'Noam Chomsky', 'American linguist, philosopher, cognitive scientist, political activist, author, and lecturer.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (102, 'barbara-tuchman', 'Barbara Tuchman', 'American historian and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (103, 'dennis-bray', 'Dennis Bray', 'Dennis Bray is an active emeritus professor at University of Cambridge. His group is also part of the Oxford Centre for Integrative Systems Biology. After a first career in Neurobiology, working on cell growth and movement, Dennis Bray moved in Cambridge to develop computational models of cell signaling, in particular in relation to bacterial chemotaxis.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (104, 'doris-kearns-goodwin', 'Doris Kearns Goodwin', 'Doris Kearns Goodwin is an American biographer, historian, and political commentator. She has authored biographies of several U.S. presidents. - Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (105, 'john-c-wright', 'John C. Wright', 'John C. Wright (John Charles Justin Wright, born 1961) is an American author of science fiction and fantasy novels.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (106, 'steve-krug', 'Steve Krug', 'Steve Krug is a UX professional based in Chestnut Hill, Massachusetts. He is best known for his book Don''t Make Me Think about human-computer interaction and web usability, which is in its third edition with over 700,000 copies sold. He also heads a one-man consulting firm called Advanced Common Sense. Krug offers in-house workshops where he teaches do-it-yourself usability testing and provides targeted advice to clients on web usability strategies. Krug published Rocket Surgery Made Easy: The Do-It-Yourself Guide to Finding and Fixing Usability Problems in 2009.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (107, 'muhammad-yunus', 'Muhammad Yunus', 'Bangladeshi economist, Nobel prize winner, entrepreneur, politician, and civil society leader.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (108, 'robert-b-cialdini', 'Robert B. Cialdini', 'Robert Beno Cialdini born April 27, 1945 is an American psychologist and author. He is the Regents'' Professor Emeritus of Psychology and Marketing at Arizona State University and was a visiting professor of marketing, business and psychology at Stanford University.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (109, 'stuart-brown', 'Stuart Brown', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (110, 'mihaly-csikszentmihalyi', 'Mihaly Csikszentmihalyi', 'Hungarian psychologist Mihaly Csikszentmihalyi was the Distinguished Professor of Psychology and Management at Claremont Graduate University. He is noted for his work in the study of happiness and creativity, but is best known as the architect of the notion of flow, a highly focused mental state. Martin Seligman, former president of the American Psychological Association, described Csikszentmihalyi as the world''s leading researcher on positive psychology. Csikszentmihalyi once said: "Repression is not the way to virtue. When people restrain themselves out of fear, their lives are by necessity diminished. Only through freely chosen discipline can life be enjoyed and still kept within the bounds of reason." (Wikipedia).');
INSERT INTO club_authors (id, slug, name, bio) VALUES (111, 'david-mackay', 'David MacKay', 'Professor of Natural Philosophy, Department of Physics, Cavendish Laboratory, University of Cambridge.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (112, 'thomas-campbell', 'Thomas Campbell', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (113, 't-colin-campbell', 'T. Colin Campbell', 'Thomas Colin Campbell is an American biochemist who specializes in the effect of nutrition on long-term health. He is the Jacob Gould Schurman Professor Emeritus of Nutritional Biochemistry at Cornell University.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (114, 'alexander-sandy-pentland', 'Alexander (Sandy) Pentland', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (115, 'maggie-mahar', 'Maggie Mahar', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (116, 'jeffrey-toobin', 'Jeffrey Toobin', 'American lawyer and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (117, 'lawrence-wright', 'Lawrence Wright', 'Lawrence Wright is an American writer and journalist, a staff writer for The New Yorker magazine, and fellow at the Center for Law and Security at the New York University School of Law.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (118, 'tom-vanderbilt', 'Tom Vanderbilt', 'American journalist, blogger, and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (119, 'richard-h-thaler', 'Richard H. Thaler', 'Richard H. Thaler is an American economist and the Charles R. Walgreen Distinguished Service Professor of Behavioral Science and Economics at the University of Chicago Booth School of Business. In 2015, Thaler was president of the American Economic Association.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (120, 'cass-r-sunstein', 'Cass R. Sunstein', 'American legal scholar known for his work in constitutional law, administrative law, environmental law, and behavioral economics.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (121, 'barbara-kingsolver', 'Barbara Kingsolver', 'Barbara Kingsolver is an American novelist, essayist and poet.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (122, 'bruce-sterling', 'Bruce Sterling', 'Sterling is an American science fiction author, best known for his novels and his work on the Mirrorshades anthology, which helped define the cyberpunk genre.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (123, 'mia-consalvo', 'Mia Consalvo', 'Mia Consalvo is an American professor of Communication Studies presently at Concordia University in Montreal, Canada and holds the post of Canada Research Chair in Game Studies and Design, Communication Studies. Consalvo has authored a number of scholarly books and publications on the topic of video games in contemporary society and the culture of gameplay.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (124, 'jerome-groopman', 'Jerome Groopman', 'Jerome E. Groopman is an American physician and medical writer. He has been a staff writer in medicine and biology for The New Yorker since 1998.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (125, 'alan-weisman', 'Alan Weisman', 'Alan H. Weisman, an American author, professor, and journalist, was born in Minneapolis, Minnesota. He holds a bachelor''s degree in literature and a master''s degree in journalism from Northwestern University. From 2004 to 2013 he was Laureate Professor in Journalism and Latin American Studies at the University of Arizona. He has also taught writing and journalism at Prescott College and Williams College and has been a Fulbright Scholar in Colombia. He has written several books and won numerous international awards for his work in journalism and literature. His reports from around the world have appeared in leading magazines, and in several anthologies. He is also a producer of radio documentaries for Homelands Productions, creating reports for National Public Radio and American Public Media.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (126, 'edward-tufte', 'Edward Tufte', 'An American statistician and professor emeritus of political science, statistics, and computer science.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (127, 'oliver-sacks', 'Oliver Sacks', 'Oliver Sacks, M.D. was a physician, a best-selling author, and a professor of neurology at the NYU School of Medicine. The New York Times has referred to him as “the poet laureate of medicine.” He is best known for his collections of neurological case histories, including The Man who Mistook his Wife for a Hat, Musicophilia: Tales of Music and the Brain and An Anthropologist on Mars. Awakenings, his book about a group of patients who had survived the great encephalitis lethargica epidemic of the early twentieth century, inspired the 1990 Academy Award-nominated feature film starring Robert De Niro and Robin Williams. Dr. Sacks was a frequent contributor to the New Yorker and the New York Review of Books.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (128, 'marc-levinson', 'Marc Levinson', 'American economist, historian, and journalist NOTE: LoC uses two different identities for the same author (saying "Email from Library of Congress (Paul Frank), September 23, 2020(per communication from Marc Levinson, use the access point Levinson, Marc, 1953- for works he wrote in his capacity as CRS [Congressional Research Service] staff member. For his other works, use the access point Levinson, Marc)"), but Wikidata and Open Library treat him as a single author. Levinson, Marc https://id.loc.gov/authorities/no2020111414 Levinson, Marc, 1953- https://id.loc.gov/authorities/n88063626.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (129, 'alan-moore', 'Alan Moore', 'British comic book writer.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (130, 'david-gibbons', 'David Gibbons', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (131, 'frederick-p-brooks-jr', 'Frederick P. Brooks Jr.', 'Frederick Phillips Brooks Jr. was an American computer architect, software engineer, and computer scientist, best known for managing development of IBM''s System/360 family of mainframe computers and the OS/360 software support package, then later writing candidly about those experiences in his seminal book The Mythical Man-Month.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (132, 'matthieu-ricard', 'Matthieu Ricard', 'Matthieu Ricard is a Nepalese French writer, photographer, translator and Buddhist monk who resides at Shechen Tennyi Dargyeling Monastery in Nepal.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (133, 'chris-anderson', 'Chris Anderson', 'Chris Anderson is an English-American author and entrepreneur. He was with The Economist for seven years before joining Wired magazine in 2001, where he was the editor-in-chief until 2012. He is known for his 2004 article entitled "The Long Tail", which he later expanded into the 2006 book, The Long Tail: Why the Future of Business Is Selling Less of More. He is the cofounder and current CEO of 3D Robotics, a drone manufacturing company.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (134, 'cormac-mccarthy', 'Cormac McCarthy', 'Cormac McCarthy (born Charles Joseph McCarthy Jr.) is an American writer who has written twelve novels, two plays, five screenplays, and three short stories, spanning the Western and postapocalyptic genres. He is known for his graphic depictions of violence and his unique writing style, recognizable by a sparse use of punctuation and attribution. McCarthy is widely regarded as one of the greatest contemporary American writers.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (135, 'michael-pollan', 'Michael Pollan', 'Michael Pollan is an American author, journalist, activist, and professor of journalism at the UC Berkeley Graduate School of Journalism. He writes about the places where nature and culture intersect: on our plates, in our farms and gardens, and in the built environment.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (136, 'daniel-gilbert', 'Daniel Gilbert', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (137, 'jack-weatherford', 'Jack Weatherford', 'Jack McIver Weatherford is an American anthropologist and author, best known for his 2004 book, Genghis Khan and the Making of the Modern World.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (138, 'robert-putnam', 'Robert Putnam', 'Robert David Putnam is an American political scientist specializing in comparative politics. He is the Peter and Isabel Malkin Professor of Public Policy at the Harvard University John F. Kennedy School of Government.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (139, 'vernor-vinge', 'Vernor Vinge', 'A retired San Diego State University Professor of Mathematics, computer scientist, and science fiction author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (140, 'steve-weber', 'Steve Weber', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (141, 'eric-von-hippel', 'Eric von Hippel', 'Eric von Hippel is an American economist and a professor at the MIT Sloan School of Management, specializing in the nature and economics of distributed and open innovation. He is best known for his work in developing the concept of user innovation – that end-users, rather than manufacturers, are responsible for a large amount of innovation. In 1986 he coined the term lead user to describe this phenomenon.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (142, 'kenneth-s-deffeyes', 'Kenneth S. Deffeyes', 'Kenneth S. Deffeyes was a geologist who worked with M. King Hubbert, the creator of the Hubbert peak theory, at the Shell Oil Company research laboratory in Houston, Texas. He claimed Chickasaw ancestry.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (143, 'john-battelle', 'John Battelle', 'American writer on technology.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (144, 'robert-axelrod', 'Robert Axelrod', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (145, 'steven-d-levitt', 'Steven D. Levitt', '"Steven David "Steve" Levitt is a prominent American economist best known for his work on crime, in particular on the link between legalized abortion and crime rates. Winner of the 2003 John Bates Clark Medal, he is currently the Alvin H. Baum Professor of Economics at the University of Chicago, director of the Becker Center on Chicago Price Theory at the University of Chicago Graduate School of Business, and co-editor of the Journal of Political Economy published by the University of Chicago Press." - Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (146, 'stephen-j-dubner', 'Stephen J. Dubner', 'Stephen Joseph Dubner is an American author, journalist, and podcast and radio host. He is co-author of the popular Freakonomics book series: Freakonomics, SuperFreakonomics, Think Like a Freak and When to Rob a Bank. He is the host of Freakonomics Radio.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (147, 'philip-roth', 'Philip Roth', 'Philip Milton Roth (March 19, 1933 – May 22, 2018) was an American novelist and short-story writer. Roth''s fiction—often set in his birthplace of Newark, New Jersey—is known for its intensely autobiographical character, for philosophically and formally blurring the distinction between reality and fiction, for its "sensual, ingenious style" and for its provocative explorations of Jewish and American identity. He first gained attention with the 1959 short story collection *Goodbye, Columbus,* which won the U.S. National Book Award for Fiction. Ten years later, he published the bestseller *Portnoy''s Complaint.* Nathan Zuckerman, Roth''s literary alter ego, narrates several of his books. A fictionalized Roth narrates some of his others, such as the alternate history *The Plot Against America.*.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (148, 'paul-graham', 'Paul Graham', 'Paul Graham is an English-American computer scientist, writer, essayist, entrepreneur and investor. His work includes the programming language Arc, the startup Viaweb, co-founding the startup accelerator and seed capital firm Y Combinator, a number of essays and books, and the media webpage Hacker News.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (149, 'william-jordan', 'William Jordan', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (150, 'billy-collins', 'Billy Collins', 'William James Collins is an American poet who served as the Poet Laureate of the United States from 2001 to 2003. He was a Distinguished Professor at Lehman College of the City University of New York, retiring in 2016. Collins was recognized as a Literary Lion of the New York Public Library (1992) and selected as the New York State Poet for 2004 through 2006. In 2016, Collins was inducted into the American Academy of Arts and Letters. As of 2020, he is a teacher in the MFA program at Stony Brook Southampton.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (151, 'barry-schwartz', 'Barry Schwartz', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (152, 'james-surowiecki', 'James Surowiecki', 'James Michael Surowiecki is an American journalist. He was a staff writer at The New Yorker, where he wrote a regular column on business and finance called "The Financial Page".');
INSERT INTO club_authors (id, slug, name, bio) VALUES (153, 'laurence-bergreen', 'Laurence Bergreen', 'Laurence Bergreen is an American historian and biographer. His most recent book is *Columbus: The Four Voyages*, a New York Times Best Seller. - Wikipedia.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (154, 'robert-harris', 'Robert Harris', 'English author known for his novel "Fatherland" as well as a series of novels on ancient Rome and non-fiction books.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (155, 'neal-stephenson', 'Neal Stephenson', 'Neal Town Stephenson (born October 31, 1959) is an American writer and game designer known for his works of speculative fiction. His novels have been categorized as science fiction, historical fiction, cyberpunk, postcyberpunk, and baroque. Stephenson''s work explores subjects such as mathematics, cryptography, linguistics, philosophy, currency, and the history of science. He also writes non-fiction articles about technology in publications such as *Wired*. He has also written novels with his uncle, George Jewsbury ("J. Frederick George"), under the collective pseudonym Stephen Bury. Stephenson has worked part-time as an advisor for Blue Origin, a company (funded by Jeff Bezos) developing a manned sub-orbital launch system, and is also a cofounder of Subutai Corporation, whose first offering is the interactive fiction project *The Mongoliad*. He is currently Magic Leap''s Chief Futurist. **Source**: <a href=.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (156, 'steven-pinker', 'Steven Pinker', 'Steven Arthur "Steve" Pinker is a Canadian-born American cognitive scientist, psychologist, linguist, and popular science author. He is Johnstone Family Professor in the Department of Psychology at Harvard University, and is known for his advocacy of evolutionary psychology and the computational theory of mind.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (157, 'julian-dibbell', 'Julian Dibbell', 'Julian Dibbell is an American author and technology journalist with a focus on social systems within online communities.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (158, 'thomas-l-friedman', 'Thomas L. Friedman', 'Thomas Loren Friedman is an American journalist and author. Friedman has won the Pulitzer Prize three times, and writes a weekly column for *The New York Times.*.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (159, 'samuel-h-sternberg', 'Samuel H. Sternberg', 'Samuel H. Sternberg is an American protein–RNA biochemist and an expert on CRISPR–Cas gene editing technology. He is an associate professor in the Department of Biochemistry and Molecular Biophysics at Columbia University and an Investigator with the Howard Hughes Medical Institute. His research focuses on the molecular mechanisms of CRISPR–Cas systems and the development of genome engineering tools. In addition, Dr. Sternberg is known for his science communication efforts, including public lectures and media appearances discussing the ethical and societal implications of genome editing.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (160, 'christopher-vaughan', 'Christopher Vaughan', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (161, 'henry-david-thoreau', 'Henry David Thoreau', 'Henry David Thoreau (born David Henry Thoreau) was an American author, poet, naturalist, tax resister, development critic, surveyor, historian, philosopher, and leading transcendentalist. He is best known for his book Walden, a reflection upon simple living in natural surroundings, and his essay, Civil Disobedience, an argument for individual resistance to civil government in moral opposition to an unjust state. Thoreau''s books, articles, essays, journals, and poetry total over 20 volumes. Among his lasting contributions were his writings on natural history and philosophy, where he anticipated the methods and findings of ecology and environmental history, two sources of modern day environmentalism. His literary style interweaves close natural observation, personal experience, pointed rhetoric, symbolic meanings, and historical lore; while displaying a poetic sensibility, philosophical austerity, and "Yankee" love of practical detail. He was also deeply interested in the idea of survival in the face of hostile elements, historical change, and natural decay; at the same time imploring one to abandon waste and illusion in order to discover life''s true essential needs.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (162, 'ralph-waldo-emerson', 'Ralph Waldo Emerson', 'Ralph Waldo Emerson was an American philosopher, essayist, and poet, best remembered for leading the Transcendentalist movement of the mid-19th century. His teachings directly influenced the growing New Thought movement of the mid-1800s. He was seen as a champion of individualism and a prescient critic of the countervailing pressures of society. Emerson gradually moved away from the religious and social beliefs of his contemporaries, formulating and expressing the philosophy of Transcendentalism in his 1836 essay, Nature. As a result of this ground-breaking work he gave a speech entitled The American Scholar in 1837, which Oliver Wendell Holmes, Sr. considered to be America''s "Intellectual Declaration of Independence". Considered one of the great orators of the time, Emerson''s enthusiasm and respect for his audience enraptured crowds. His support for abolitionism late in life created controversy, and at times he was subject to abuse from crowds while speaking on the topic. When asked to sum up his work, he said his central doctrine was "the infinitude of the private man.".');
INSERT INTO club_authors (id, slug, name, bio) VALUES (163, 'pedro-domingos', 'Pedro Domingos', 'Pedro Domingos is a Professor Emeritus of computer science and engineering at the University of Washington. He is a researcher in machine learning known for Markov logic network enabling uncertain inference.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (164, 'david-r-montgomery', 'David R. Montgomery', 'David R. Montgomery is a professor of earth and space sciences at the University of Washington in Seattle, where he is a member of the Quaternary Research Center.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (165, 'geoffrey-west', 'Geoffrey West', 'Geoffrey Brian West is a British theoretical physicist and former president and distinguished professor of the Santa Fe Institute. He is one of the leading scientists working on a scientific model of cities. Among other things, his work states that with the doubling of a city''s population, salaries per capita will generally increase by 15%.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (166, 'anu-partanen', 'Anu Partanen', 'Anu Partanen is a Finnish journalist living in the United States. She became a naturalized American citizen in 2013. Her book The Nordic Theory of Everything: In Search of a Better Life was published in June 2016 by HarperCollins.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (167, 'aeschylus', 'Aeschylus', 'Aeschylus was an ancient Greek playwright. He is often recognized as the father of tragedy and is the earliest of the three Greek tragedians whose plays survive, the others being Sophocles and Euripides.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (168, 'george-gilder', 'George Gilder', 'George Franklin Gilder is an American investor, author, economist, and co-founder of the Discovery Institute. His 1981 book, Wealth and Poverty, advanced a case for supply-side economics and capitalism during the early months of the Reagan administration. He is the chairman of George Gilder Fund Management, LLC.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (169, 'mortimer-j-adler', 'Mortimer J. Adler', 'Mortimer Jerome Adler was an American philosopher, educator, and popular author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (170, 'charles-van-doren', 'Charles Van Doren', 'Charles Lincoln Van Doren was an American writer and editor who was involved in a television quiz show scandal in the 1950s. In 1959 he testified before the United States Congress that he had been given the correct answers by the producers of the NBC quiz show Twenty-One. Terminated by NBC, he joined Encyclopædia Britannica, Inc. in 1959, becoming a vice-president and writing and editing many books before retiring in 1982.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (171, 'matthew-walker', 'Matthew Walker', 'Dr. Walker earned his degree in neuroscience from Nottingham University, UK, and his PhD in neurophysiology from the Medical Research Council, London, UK. He subsequently became a Professor of Psychiatry at Harvard Medical School, USA. Currently, he is Professor of Neuroscience and Psychology at the University of California, Berkeley, USA. He is also the founder and director of the Center for Human Sleep Science. Dr. Walker’s research examines the impact of sleep on human health and disease. He has received numerous funding awards from the National Science Foundation and the National Institutes of Health, and is a Kavli Fellow of the National Academy of Sciences. His research examines the impact of sleep on human brain function in healthy and disease populations. To date, he has published over 100 scientific research studies.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (172, 'edward-o-wilson', 'Edward O. Wilson', 'American biologist and author.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (173, 'alexander-langlands', 'Alexander Langlands', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (174, 'daniel-suarez', 'Daniel Suarez', 'Daniel Suarez is an American novelist, writing principally in the science fiction and techno-thriller genres. He initially published under the pseudonym Leinad Zeraus.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (175, 'david-m-gwynn', 'David M. Gwynn', NULL);
INSERT INTO club_authors (id, slug, name, bio) VALUES (176, 'richard-powers', 'Richard Powers', 'Richard Powers is an American novelist whose works explore the effects of modern science and technology. His novel The Echo Maker won the 2006 National Book Award for Fiction. He has also won many other awards over the course of his career, including a MacArthur Fellowship. As of 2024, Powers has published fourteen novels and has taught at the University of Illinois and Stanford University. He won the 2019 Pulitzer Prize for Fiction for The Overstory.');
INSERT INTO club_authors (id, slug, name, bio) VALUES (177, 'philip-ball', 'Philip Ball', 'Philip Ball is a British science writer. For over twenty years he has been an editor of the journal Nature, for which he continues to write regularly.');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (1, 'enshittification', 'Enshittification', NULL, 'Technology', 0, 2025, 352, '9781836742227', '/works/OL42455337W', 'It’s not your imagination. Life online really does get worse by the day, and that is by intent. Misogyny, conspiratorialism, surveillance, manipulation, fraud, and AI slop are drowning the internet. For the monopolists who dominate online – X, TikTok, Amazon, Meta, Apple – this is all part of the playbook. The process is what leading tech critic Cory Doctorow has dubbed ‘enshittification’. First, the platform attracts users with some bait, such as free access; then the activity is monetized, bringing in the business customers and degrading the user experience; then, once everyone is trapped and competitors eradicated, the platform wrings out all the value and transfers it to their executives and shareholders. As a result, online public squares have become places of torment, and online retailers are hellish dumpster fires. The virtual gathering places where we once imagined the world’s problems might be resolved are now a sewer of hatred and abuse – thoroughly enshittified. Doctorow enumerates the symptoms, lays out the diagnosis, and identifies the best responses to these diseased platforms: the monopolies online must be shattered. Companies too big to fail or to jail – and much too big to care – must be cut down to size. Only an attack on corporate power will permit effective regulation and real privacy. Tech unions must protect the workers who should, in turn, defend us against their bosses’ sadism and greed.', '["genre:technological non-fiction literature", "enshittification"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (2, 'heart-of-darkness', 'Heart of Darkness', NULL, 'Science Fiction & Fiction', 1, 1902, 120, '9780613837712', '/works/OL38663W', 'Heart of Darkness (1899) is a novella by Polish-English novelist Joseph Conrad, about a voyage up the Congo River into the Congo Free State, in the heart of Africa, by the story''s narrator Charles Marlow. Marlow tells his story to friends aboard a boat anchored on the River Thames. Joseph Conrad is one of the greatest English writers, and Heart of Darkness is considered his best. His readers are brought to face our psychological selves to answer, ‘Who is the true savage?’. Originally published in 1902, Heart of Darkness remains one of this century’s most enduring works of fiction. Written several years after Joseph Conrad’s grueling sojourn in the Belgian Congo, the novel is a complex meditation on colonialism, evil, and the thin line between civilization and barbarity.', '["Romance", "Degeneration", "Description and travel", "Diaries", "Sailors", "Short stories", "English literature", "Suffering", "Trading posts", "Classic Literature", "Travel", "Discovery and exploration"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (3, 'the-origins-of-totalitarianism', 'The Origins of Totalitarianism', NULL, 'Politics & Social Sciences', 0, 1951, 440, '9780063354487', '/works/OL10460640W', 'The Origins of Totalitarianism begins with the rise of anti-Semitism in central and western Europe in the 1800s and continues with an examination of European colonial imperialism from 1884 to the outbreak of World War I. Arendt explores the institutions and operations of totalitarian movements, focusing on the two genuine forms of totalitarian government in her time—Nazi Germany and Stalinist Russia—which she adroitly recognizes were two sides of the same coin, rather than opposing philosophies of Right and Left. From this vantage point, she discusses the evolution of classes into masses, the role of propaganda in dealing with the nontotalitarian world, the use of terror, and the nature of isolation and loneliness as preconditions for total domination.', '["Antisemitism", "Imperialism", "Totalitarianism", "Philosophy, german", "Antisémitisme", "Impérialisme", "Totalitarisme", "Histoire", "Juifs", "POLITICAL SCIENCE", "Essays", "Government"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (4, 'co-intelligence', 'Co-Intelligence', 'Living and Working with AI', 'Technology', 0, 2024, NULL, '9780593716724', '/works/OL37565105W', 'Something new entered our world in November 2022 — the first general purpose AI that could pass for a human and do the kinds of creative, innovative work that only humans could do previously. After millions of years on our own, humans had developed a kind of co-intelligence that could augment, or even replace, human thinking. Through his writing, speaking, and teaching, Mollick has become one of the most prominent and provocative explainers of AI, focusing on the practical aspects of how these new tools for thought can transform our world.', '["Science", "nyt:combined-print-and-e-book-nonfiction=2024-04-21", "New York Times bestseller"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (5, 'how-to-do-nothing', 'How to Do Nothing', 'Resisting the Attention Economy', 'Politics & Social Sciences', 0, 2019, 256, '9781612197494', '/works/OL20078135W', 'Nothing is harder to do these days than nothing. But in a world where our value is determined by our 24/7 data productivity . . . doing nothing may be our most important form of resistance. So argues artist and critic Jenny Odell in this field guide to doing nothing (at least as capitalism defines it). Odell sees our attention as the most precious—and overdrawn—resource we have. Once we can start paying a new kind of attention, she writes, we can undertake bolder forms of political action, reimagine humankind’s role in the environment, and arrive at more meaningful understandings of happiness and progress. Far from the simple anti-technology screed, or the back-to-nature meditation we read so often, How to do Nothing is an action plan for thinking outside of capitalist narratives of efficiency and techno-determinism. Provocative, timely, and utterly persuasive, this book is a four-course meal in the age of Soylent.', '["Information technology", "Social aspects", "Reflection (Philosophy)", "Attention", "Philosophy", "Work", "Arts", "TECHNOLOGY & ENGINEERING / Social Aspects", "NATURE / Environmental Conservation & Protection", "ART / Digital", "Attention Economy", "Internet Art"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (6, 'through-the-language-glass', 'Through the Language Glass', 'Why the World Looks Different in Other Languages', 'Brain & Psychology', 0, 2010, 296, '978-0805081954', '/works/OL15413083W', 'This book confronts the thorny question of how and whether culture shapes language and language, culture. Linguistics has long shied away from claiming any link between a language and the culture of its speakers: too much simplistic (even bigoted) chatter about the romance of Italian and the goose-stepping orderliness of German has made serious thinkers wary of the entire subject. But now, acclaimed linguist Guy Deutscher has dared to reopen the issue. Can culture influence languageand vice versa? Can different languages lead their speakers to different thoughts? Could our experience of the world depend on whether our language has a word for "blue"? Challenging the consensus that the fundaments of language are hard-wired in our genes and thus universal, Deutscher argues that the answer to all these questions isyes. In thrilling fashion, he takes us from Homer to Darwin, from Yale to the Amazon, from how to name the rainbow to why Russian water -- a "she" -- becomes a "he" once you dip a tea bag into her, demonstrating that language does in fact reflect culture in ways that are anything but trivial. Audacious, delightful, and field-changing, Through the Language Glass is a classic of intellectual discovery. - Publisher.', '["Historical linguistics", "Language and languages in literature", "Comparative linguistics", "Language acquisition -- Social aspects", "Language and culture", "Language and color", "New York Times reviewed", "Sprachliches Weltbild"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (7, 'army-of-none', 'Army of None', 'Autonomous Weapons and the Future of War', 'Technology', 0, 2018, 384, '9780393608991', '/works/OL19746016W', 'What happens when a Predator drone has as much autonomy as a Google car? Although it sounds like science fiction, the technology to create weapons that could hunt and destroy targets on their own already exists. Paul Scharre, a leading expert in emerging weapons technologies, draws on incisive research and firsthand experience to explore how increasingly autonomous weapons are changing warfare. This far-ranging investigation examines the emergence of fully autonomous weapons, the movement to ban them, and the legal and ethical issues surrounding their use. Scharre spotlights the role of artificial intelligence in military technology, spanning decades of innovation from German noise-seeking Wren torpedoes in World War II--antecedents of today''s armed drones--to autonomous cyber weapons. At the forefront of a game-changing debate, Army of None engages military history, global policy, and bleeding-edge science to explore what it would mean to give machines authority over the ultimate decision: life or death.', '["Moral and ethical aspects", "Military weapons", "Robotics", "Forecasting", "Military robots", "Weapons systems", "Military applications", "Technological innovations", "War", "Robots", "Uninhabited combat aerial vehicles", "Drone aircraft"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (8, 'the-power-law', 'The Power Law', 'Venture Capital and the Making of a New Future', 'History & Economics', 0, 2022, 496, '9780141988948', '/works/OL25328015W', NULL, '["Venture capital", "High technology industries", "Finance", "New business enterprises", "Technological innovations", "Economic aspects", "BUSINESS & ECONOMICS / Finance"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (9, 'dictionary-people', 'Dictionary People', NULL, 'Current Events & People', 0, 2023, 384, '9780593469989', '/works/OL34024127W', NULL, '["Setting (Literature)", "Characters and characteristics in literature", "Dictionaries", "American fiction, history and criticism, 19th century", "American fiction, history and criticism, 20th century", "English fiction, history and criticism, 19th century", "English fiction, history and criticism, 20th century", "Fiction, dictionaries", "Science fiction", "Personnages dans la littérature", "Dictionnaires anglais", "Espace et temps (Littérature)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (10, 'medici-money', 'Medici Money', NULL, 'History & Economics', 0, 2006, 288, '9781861977571', '/works/OL25645767W', NULL, '["Fiction, general", "Italy, fiction"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (11, 'dawn-of-everything', 'Dawn of Everything', 'A New History of Humanity', 'History & Economics', 0, 2021, 752, '9780771049828', '/works/OL24663287W', 'The renowned activist and public intellectual David Graeber teams up with the professor of comparative archaeology David Wengrow to deliver a trailblazing account of human history, challenging our most fundamental assumptions about social evolution—from the development of agriculture and cities to the emergence of "the state," political violence, and social inequality—and revealing new possibilities for human emancipation For generations, our remote ancestors have been cast as primitive and childlike—either free and equal innocents, or thuggish and warlike. Civilization, we are told, could be achieved only by sacrificing those original freedoms or, alternatively, by taming our baser instincts. David Graeber and David Wengrow show how such theories first emerged in the eighteenth century as a conservative reaction to powerful critiques of European society posed by Indigenous observers and intellectuals. Revisiting this encounter has startling implications for how we make sense of human history today, including the origins of farming, property, cities, democracy, slavery, and civilization itself. Drawing on pathbreaking research in archaeology and anthropology, the authors show how history becomes a far more interesting place once we learn to throw off our conceptual shackles and perceive what’s really there. If humans did not spend 95 percent of their evolutionary past in tiny bands of hunter-gatherers, what were they doing all that time? If agriculture, and cities, did not mean a plunge into hierarchy and domination, then what kinds of social and economic organization did they lead to? What was really happening during the periods that we usually describe as the emergence of "the state"? The answers are often unexpected, and suggest that the course of human history may be less set in stone, and more full of playful, hopeful possibilities, than we tend to assume. The Dawn of Everything fundamentally transforms our understanding of the human past and offers a path toward imagining new forms of freedom, new ways of organizing society. This is a monumental book of formidable intellectual range, animated by curiosity, moral vision, and a faith in the power of direct action.', '["Civilization, history", "nyt:combined-print-and-e-book-nonfiction=2021-11-28", "New York Times bestseller", "Civilization", "Philosophy", "HISTORY, ANCIENT"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (12, 'otherlands', 'Otherlands', 'A Journey Through Earth''s Extinct Worlds', 'Science and Math', 0, 2022, 112, '9780241611241', '/works/OL24831204W', NULL, '["Paleontology", "Popular works", "Extinction (Biology)", "Biotic communities", "Fossils", "Life (Biology)", "Evolution (Biology)", "Natural history", "Paleobiology", "Biological Extinction", "Paléontologie", "Ouvrages de vulgarisation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (13, 'men-without-work', 'Men Without Work', NULL, 'Politics & Social Sciences', 0, 2016, 206, '9781599475981', '/works/OL17851917W', 'By one reading, things look pretty good for Americans today: the country is richer than ever before and the unemployment rate is down by half since the Great Recession—lower today, in fact, than for most of the postwar era. But a closer look shows that something is going seriously wrong. This is the collapse of work—most especially among America’s men. Nicholas Eberstadt, a political economist who holds the Henry Wendt Chair in Political Economy at the American Enterprise Institute, shows that while “unemployment” has gone down, America’s work rate is also lower today than a generation ago—and that the work rate for US men has been spiraling downward for half a century. Astonishingly, the work rate for American males aged twenty-five to fifty-four—or “men of prime working age”—was actually slightly lower in 2015 than it had been in 1940: before the War, and at the tail end of the Great Depression. Today, nearly one in six prime working age men has no paid work at all—and nearly one in eight is out of the labor force entirely, neither working nor even looking for work. This new normal of “men without work,” argues Eberstadt, is “America’s invisible crisis.” So who are these men? How did they get there? What are they doing with their time? And what are the implications of this exit from work for American society? Nicholas Eberstadt lays out the issue and Jared Bernstein from the left and Henry Olsen from the right offer their responses to this national crisis. For more information, please visit http://menwithoutwork.com.', '["Economic conditions", "Psychology", "Social conditions", "Unemployed", "Men", "Employment", "Labor market", "United states, politics and government", "Kriminalität", "Ausstieg", "Partizipation", "Arbeitslosigkeit"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (14, 'nation-of-takers', 'Nation of Takers', 'America''s Entitlement Epidemic', 'Politics & Social Sciences', 0, 2012, NULL, '9781283692038', '/works/OL17851924W', 'In A Nation of Takers: America’s Entitlement Epidemic, one of our country’s foremost demographers, Nicholas Eberstadt, details the exponential growth in entitlement spending over the past fifty years. As he notes, in 1960, entitlement payments accounted for well under a third of the federal government’s total outlays. Today, entitlement spending accounts for a full two-thirds of the federal budget. Drawing on an impressive array of data and employing a range of easy- to- read, four color charts, Eberstadt shows the unchecked spiral of spending on a range of entitlements, everything from medicare to disability payments. But Eberstadt does not just chart the astonishing growth of entitlement spending, he also details the enormous economic and cultural costs of this epidemic. He powerfully argues that while this spending certainly drains our federal coffers, it also has a very real,long-lasting, negative impact on the character of our citizens. Also included in the book is a response from one of our leading political theorists, William Galston. In his incisive response, he questions Eberstadt’s conclusions about the corrosive effect of entitlements on character and offers his own analysis of the impact of American entitlement growth.', '["Entitlement attitudes", "Entitlement spending", "Budget deficits"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (15, 'a-supposedly-fun-thing-i-ll-never-do-again', 'A Supposedly Fun Thing I''ll Never Do Again', 'Essays and Arguments', 'Essays & Literature', 0, 1997, 353, '978-0316925280', '/works/OL2943597W', 'A collection of stories from David Foster Wallace is occasion to celebrate. These stories -- which have been prominently serialized in Harper''s, Esquire, the Paris Review, and elsewhere -- explore intensely immediate states of mind, with the attention to voice and the extraordinary creative daring that have won Wallace his reputation as one of the most talented fiction writer of his generation.Among the stories are "The Depressed Person", a dazzling portrayal of a woman''s mental state; "Adult World", which reveals a woman''s agonized consideration of her confusing sexual relationship with her husband; and "Brief Interviews with Hideous Men", a dark, hilarious series of portraits of men whose fear of women renders them grotesque.', '["Humor (Nonfiction)", "Wit and humor", "American Wit and humor", "Essays", "American wit and humor, travel", "American essays, 20th century", "American wit and humor, social life and customs", "Essays (single author)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (16, 'to-shake-the-sleeping-self', 'To Shake the Sleeping Self', 'A Journey from Oregon to Patagonia, and a Quest for a Life with No Regret', 'Travel & Memoir', 0, 2018, 352, '978-1524761400', '/works/OL19763522W', 'From travel writer and Instagram phenomenon Jedidiah Jenkins, a long-awaited memoir of adventure, failure, and lessons learned while bicycling the 10,000 miles from Oregon to Patagonia. On the eve of turning thirty, terrified of being sucked into a life he didn''t choose, Jedidiah Jenkins quit his dream job and spent the next sixteen months cycling from Oregon to Patagonia. He chronicled the trip on Instagram, where his photos and profound reflections on life soon attracted hundreds of thousands of followers and got him featured by National Geographic and The Paris Review. In this unflinchingly honest memoir, Jed narrates the adventure that started it all: the people and places he encountered on his way to the bottom of the world, and the internal journey that prompted it--the question of what it means to be an adult; his struggle to reconcile his sexual identity with his conservative Christian upbringing; and his belief in travel as a way to "wake us up" to our lives back home. As he writes in his inspiring search for wonder and a life he could believe in, ''It''s not about the bike. It''s about getting out of your routine--and that could look like anything''', '["Travel", "Cycling", "Description and travel", "America, description and travel", "nyt:combined-print-and-e-book-nonfiction=2018-10-21", "New York Times bestseller", "Bicycle touring", "Self-actualization (psychology)", "BIOGRAPHY & AUTOBIOGRAPHY", "Personal Memoirs", "Special Interest", "Adventure"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (17, 'mni-sota-makoce', 'Mni Sota Makoce', 'The Land of the Dakota', 'History & Economics', 0, 2012, 296, '9780873518697', '/works/OL16681765W', NULL, '["Dakota Indians", "Social life and customs", "Indians of north america, west (u.s.)", "Indians of north america, social life and customs", "Minnesota, history", "Minnesota, social life and customs"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (18, 'addiction-by-design', 'Addiction by Design', 'Machine Gambling in Las Vegas', 'Brain & Psychology', 0, 2012, 472, '9780691160887', '/works/OL20900698W', NULL, '["Gambling", "Compulsive gambling", "Criminals", "Casinos", "Criminals, united states"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (19, 'aeschylus-i', 'Aeschylus I', 'The Persians, The Seven Against Thebes, The Suppliant Maidens, Prometheus Bound', 'History & Economics', 0, 2013, 256, '9780226311449', '/works/OL21049995W', NULL, '["Greek drama, translations into english", "Agamemnon", "Prometheus", "Danaus", "Aeschylus", "Greek drama (tragedy)--translations into english", "Seven against thebes (greek mythology)", "Seven against thebes (greek mythology)--drama", "Erinyes (greek mythology)", "Erinyes (greek mythology)--drama", "Pa3827 .a236 2013"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (20, 'the-florentines', 'The Florentines', 'From Dante to Galileo: The Transformation of Western Civilization', 'History & Economics', 0, 2021, 400, '9781643137322', '/works/OL24778288W', 'Between the birth of Dante in 1265 and the death of Galileo in 1642, something happened that transformed the entire culture of western civilization. Painting, sculpture, and architecture would all visibly change in such a striking fashion that there could be no going back on what had taken place. Likewise, the thought and self-conception of humanity would take on a completely new aspect. Sciences would be born--or emerge in an entirely new guise. The ideas that broke this mold began, and continued to flourish, in the city of Florence in northern central Italy. These ideas, which placed an increasing emphasis on the development of our common humanity--rather than other-worldly spirituality--coalesced in what came to be known as humanism. This philosophy and its new ideas would eventually spread across Italy, yet wherever they took hold they would retain an element essential to their origin. And as they spread further across Europe, this element would remain. Transformations of human culture throughout western history have remained indelibly stamped by their origins. The Reformation would always retain something of central and northern Germany. The Industrial Revolution soon outgrew its British origins, yet also retained something of its original template. Closer to the present, the IT revolution that began in Silicon Valley remains indelibly colored by its Californian origins. Paul Strathern shows how Florence, and the Florentines themselves, played a similarly unique and transformative role in the Renaissance.', '["Italy, history", "Europe, history", "Renaissance", "Art and society", "Renaissance Art", "Humanism"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (21, 'empire-of-pain', 'Empire of Pain', 'The Secret History of the Sackler Dynasty', 'Current Events & People', 0, 2021, 720, '9780385545686', '/works/OL24218388W', NULL, '["Biographies", "Pharmaceutical industry", "Corrupt practices", "drugs", "marketing", "philanthropists", "Oxycodone", "Oxycodone abuse", "Purdue Pharma L.P.", "Biography", "Biography & Memoir", "Business"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (22, 'the-blocksize-war', 'The Blocksize War', 'The battle over who controls Bitcoin’s protocol rules', 'Technology', 0, 2021, 228, '9798721895609', '/works/OL30747417W', NULL, '["genre:non-fiction", "Bitcoin"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (23, 'caste', 'Caste', NULL, 'Politics & Social Sciences', 0, 2020, 496, '9780593230251', '/works/OL20878310W', 'As we go about our daily lives, caste is the wordless usher in a darkened theater, flashlight cast down in the aisles, guiding us to our assigned seats for a performance. The hierarchy of caste is not about feelings or morality. It is about power—which groups have it and which do not.” In this brilliant book, Isabel Wilkerson gives us a masterful portrait of an unseen phenomenon in America as she explores, through an immersive, deeply researched narrative and stories about real people, how America today and throughout its history has been shaped by a hidden caste system, a rigid hierarchy of human rankings. Beyond race, class, or other factors, there is a powerful caste system that influences people’s lives and behavior and the nation’s fate. Linking the caste systems of America, India, and Nazi Germany, Wilkerson explores eight pillars that underlie caste systems across civilizations, including divine will, bloodlines, stigma, and more. Using riveting stories about people—including Martin Luther King, Jr., baseball’s Satchel Paige, a single father and his toddler son, Wilkerson herself, and many others—she shows the ways that the insidious undertow of caste is experienced every day. She documents how the Nazis studied the racial systems in America to plan their out-cast of the Jews; she discusses why the cruel logic of caste requires that there be a bottom rung for those in the middle to measure themselves against; she writes about the surprising health costs of caste, in depression and life expectancy, and the effects of this hierarchy on our culture and politics. Finally, she points forward to ways America can move beyond the artificial and destructive separations of human divisions, toward hope in our common humanity. Beautifully written, original, and revealing, Caste: The Origins of Our Discontents is an eye-opening story of people and history, and a reexamination of what lies under the surface of ordinary lives and of American life today.', '["social sciences", "power", "race relations", "social stratification", "ethnicity", "Caste", "Social classes", "Power (social sciences)", "United states, race relations", "psychology", "nyt:combined-print-and-e-book-nonfiction=2020-08-23", "New York Times bestseller"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (24, 'nature-walking', 'Nature & Walking', NULL, 'Essays & Literature', 0, 2011, 76, '9781463727277', '/works/OL39919089W', NULL, '["Nature study", "Emerson, ralph waldo, 1803-1882", "Thoreau, henry david, 1817-1862"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (25, 'evicted', 'Evicted', NULL, 'Politics & Social Sciences', 0, 2016, 464, '9780553447453', '/works/OL17828326W', 'Evicted: Poverty and Profit in the American City is a 2016 non-fiction book by American author Matthew Desmond. Set in the poorest areas of Milwaukee, Wisconsin, the book follows eight families struggling to pay rent to their landlords during the financial crisis of 2007–2008. Through a year of ethnographic fieldwork, Desmond''s goal in the book is to highlight the issues of extreme poverty, affordable housing, and economic exploitation in the United States. Evicted was well-received and won multiple book awards such as the 2017 Pulitzer Prize for General Nonfiction and the Robert F. Kennedy Book Award. The Pulitzer committee selected the book "for a deeply researched exposé that showed how mass evictions after the 2008 economic crash were less a consequence than a cause of poverty."', '["Domestic Politics", "2008 financial crisis", "low-income housing", "eviction", "poverty", "profit", "cities and towns", "social science", "urban sociology", "poverty and homelessness", "extreme poverty", "affordable housing"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (26, 'a-man-at-arms', 'A Man at Arms', NULL, 'Science Fiction & Fiction', 1, 2021, 336, '9780393540970', '/works/OL21971441W', 'Jerusalem and the Sinai desert, AD 55. In the turbulent aftermath of the crucifixion of Jesus, agents of the Roman Empire receive information about a pilgrim bearing an incendiary letter from a religious fanatic calling himself Paul the Apostle to insurrectionists in Corinth. What''s in the letter could bring down an empire.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (27, 'klara-and-the-sun', 'Klara and the Sun', NULL, 'Science Fiction & Fiction', 1, 2019, 419, '9780593318171', '/works/OL20883297W', 'Klara and the Sun, the first novel by Kazuo Ishiguro since he was awarded the Nobel Prize in Literature, tells the story of Klara, an Artificial Friend with outstanding observational qualities, who, from her place in the store, watches carefully the behavior of those who come in to browse, and of those who pass on the street outside. She remains hopeful that a customer will soon choose her. Klara and the Sun is a thrilling book that offers a look at our changing world through the eyes of an unforgettable narrator, and one that explores the fundamental question: what does it mean to love? In its award citation in 2017, the Nobel committee described Ishiguro''s books as "novels of great emotional force" and said he has "uncovered the abyss beneath our illusory sense of connection with the world."', '["Fiction, science fiction, general", "speculative fiction", "nyt:combined-print-and-e-book-fiction=2021-03-21", "New York Times bestseller", "Fiction, dystopian", "British and irish fiction (fictional works by one author)", "The Future", "Artificial intelligence", "Robots", "Romance fiction", "Friendship", "Love"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (28, 'the-horse-the-wheel-and-language', 'The Horse, the Wheel, and Language', 'How Bronze-Age Riders from the Eurasian Steppes Shaped the Modern World', 'History & Economics', 0, 2010, 568, '9780691148182', '/works/OL19366956W', 'Roughly half the world''s population speaks languages derived from a shared linguistic source known as Proto-Indo-European. But who were the early speakers of this ancient mother tongue, and how did they manage to spread it around the globe?
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (29, 'running-with-sherman', 'Running with Sherman', 'The Donkey with the Heart of a Hero', 'Travel & Memoir', 0, 2019, 496, '9781524732363', '/works/OL20334758W', 'When Chris McDougall agreed to take in a donkey from an animal hoarder, he thought it would be no harder than the rest of the adjustments he and his family had made after moving from Philadelphia to the heart of Pennsylvania Amish country. But when he arrived, Sherman was in such bad shape he could barely move, and his hair was coming out in clumps. Chris decided to undertake a radical rehabilitation program designed not only to heal Sherman''s body but to heal his mind as well. It turns out the best way to soothe a donkey is to give it a job, and so Chris decided to teach Sherman how to run. He''d heard about burro racing--a unique type of race where humans and donkeys run together in a call-back to mining days--and decided he and Sherman would enter the World Championship in Colorado.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (30, 'the-weirdest-people-in-the-world', 'The WEIRDest People in the World', 'How the West Became Psychologically Peculiar and Particularly Prosperous', 'Politics & Social Sciences', 0, 2020, 704, '9780374173227', '/works/OL20844844W', 'Perhaps you are WEIRD: raised in a society that is Western, Educated, Industrialized, Rich, and Democratic. If so, you’re rather psychologically peculiar.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (31, 'mama-s-last-hug', 'Mama''s Last Hug', 'Animal Emotions and What They Tell Us about Ourselves', 'Science and Math', 0, 2019, 396, '9780393635065', '/works/OL20162907W', 'Mama''s Last Hug opens with the dramatic farewell between Mama, a dying 59-year-old chimpanzee matriarch, and biologist Jan Van Hooff. This heartfelt final meeting of two longtime friends, widely shared as a video, offers a window into how deep and instantly recognizable these bonds can be.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (32, 'unflattening', 'Unflattening', NULL, 'Essays & Literature', 0, 2015, 208, '9780674744431', '/works/OL17924067W', 'The primacy of words over images has deep roots in Western culture. But what if the two are inextricably linked, equal partners in meaning-making? Written and drawn entirely as comics, Unflattening is an experiment in visual thinking. Nick Sousanis defies conventional forms of scholarly discourse to offer readers both a stunning work of graphic art and a serious inquiry into the ways humans construct knowledge.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (33, 'bending-adversity', 'Bending Adversity', 'Japan and the Art of Survival', 'Politics & Social Sciences', 0, 2014, 382, '9781594205842', '/works/OL17582325W', 'Financial Times Asia editor David Pilling presents a fresh vision of Japan, drawing on his own deep experience, as well as observations from a cross section of Japanese citizenry, including novelist Haruki Murakami, former prime minister Junichiro Koizumi, industrialists and bankers, activists and artists, teenagers and octogenarians. Through their voices, Pilling captures the dynamism and diversity of contemporary Japan.', '["Politics and government", "Tsunamis", "Economic forecasting", "Social conditions", "Economic conditions", "Japan, history", "Japan, social conditions"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (34, 'the-rise-of-big-data-policing', 'The Rise of Big Data Policing', 'Surveillance, Race, and the Future of Law Enforcement', 'Politics & Social Sciences', 0, 2017, 259, '9781479892822', '/works/OL19764034W', 'In a high-tech command center in downtown Los Angeles, a digital map lights up with 911 calls, television monitors track breaking news stories, surveillance cameras sweep the streets, and rows of networked computers link analysts and police officers to a wealth of law enforcement intelligence. This is just a glimpse into a future where software predicts future crimes, algorithms generate virtual "most-wanted" lists, and databanks collect personal and biometric information. The Rise of Big Data Policing introduces the cutting-edge technology that is changing how the police do their jobs and shows why it is more important than ever that citizens understand the far-reaching consequences of big data surveillance as a law enforcement tool. Andrew Guthrie Ferguson reveals how these new technologies - viewed as race-neutral and objective - have been eagerly adopted by police departments hoping to distance themselves from claims of racial bias and unconstitutional practices. After a series of high-profile police shootings and federal investigations into systemic police misconduct, and in an era of law enforcement budget cutbacks, data-driven policing has been billed as a way to "turn the page" on racial bias. But behind the data are real people, and difficult questions remain about racial discrimination and the potential to distort constitutional protections. In this first book on big data policing, Ferguson offers an examination of how new technologies will alter the who, where, when and how we police. These new technologies also offer data-driven methods to improve police accountability and to remedy the underlying socio-economic risk factors that encourage crime. The Rise of Big Data Policing is a must read for anyone concerned with how technology will revolutionize law enforcement and its potential threat to the security, privacy, and constitutional rights of citizens. --', '["Criminal statistics", "Police", "Electronic surveillance", "Big data", "Law enforcement", "Racial profiling in law enforcement", "Data processing", "Discrimination in law enforcement", "Data mining in law enforcement", "Police, united states"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (35, 'benjamin-franklin', 'Benjamin Franklin', 'An American Life', 'History & Economics', 0, 2003, 626, '9780743258074', '/works/OL4288868W', 'Chronicles the founding father''s life and his multiple careers as a shopkeeper, writer, inventor, media baron, scientist, diplomat, business strategist, and political leader, while showing how his faith in the wisdom of the common citizen helped forge an American national identity based on the virtues of its middle class.', '["Politics and government", "Scientists", "Printers", "Inventors", "Biography", "Statesmen", "Politici", "Politiker", "Umschulungswerkstätten für Siedler und Auswanderer", "History, 18th Century", "Geleerden", "Famous Persons"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (36, 'replay', 'Replay', NULL, 'Science Fiction & Fiction', 0, 1986, 519, '9780688161125', '/works/OL2252098W', 'Jeff Winston, forty-three, didn''t know he was a replayer until he died and woke up twenty-five years younger in his college dorm room; he lived another life. And died again. And lived again and died again—in a continuous twenty-five-year cycle—each time starting from scratch at the age of eighteen to reclaim lost loves, remedy past mistakes, or make a fortune in the stock market. A novel of gripping adventure, romance, and fascinating speculation on the nature of time, Replay asks the question: "What if you could live your life over again?"', '["Conduct of life", "Reincarnation", "Time travel", "Large type books", "Fiction, science fiction, action & adventure", "Fiction, action & adventure", "Fiction, romance, fantasy"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (37, 'the-hundred-year-marathon', 'The Hundred-Year Marathon', 'China''s Secret Strategy to Replace America as the Global Superpower', 'History & Economics', 0, 2015, 352, '9781627790109', '/works/OL19994559W', 'One of the US government''s leading China experts reveals the hidden strategy fueling that country''s rise - and how Americans have been seduced into helping China overtake us as the world''s leading superpower.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (38, 'the-roman-republic', 'The Roman Republic', 'A Very Short Introduction', 'History & Economics', 0, 2012, 144, '9780199595112', '/works/OL21041666W', NULL, '["Rome, history, republic, 510-30 b.c."]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (39, 'the-nordic-theory-of-everything', 'The Nordic Theory of Everything', 'In Search of a Better Life', 'Current Events & People', 0, 2016, 448, '9780062316554', '/works/OL20028831W', 'A Finnish journalist and naturalized American citizen compares and contrasts life in the U.S. with life in the Nordic region to encourage Americans to draw on practices from the Nordic way of life to create a fairer, happier, more secure, and less stressful society. At a 2012 conference on social mobility, where experts discussed whether people worldwide were attaining a better life than their parents'', Ed Miliband, the leader of the British Labour Party, made a surprising quip: "If you want the American dream, go to Finland." For decades, the country best known for opportunity had been the United States. No longer, said Miliband. Anu Partanen, however, had recently left Finland and moved to America for the love of her life, a man who would ultimately become her husband. Their relationship flourished, but she found that navigating the basics of everyday life--from health insurance and taxes to education and child care--was much more complicated and stressful than in her homeland. At first she attributed her crippling anxiety to the difficulty of adapting to a freewheeling new culture. But as she got to know Americans better, she discovered that they shared her deep apprehensions. To understand why life in Finland is so drastically different from the way things are in the United States, Partanen began to look closely at both countries. In The Nordic Theory of Everything, Partanen compares living in the United States with life in the Nordic region, focusing on four key relationships--parents and children, men and women, employees and employers, and government and citizens. She debunks criticism that Nordic countries are socialist "nanny states," revealing instead that it is we Americans who are far more enmeshed in unhealthy dependencies than we realize. Step by step, Partanen explains how the Nordic approach allows citizens to enjoy more individual freedom and equality than we do. She wants to open Americans'' eyes to how much better things can be--to show her beloved new country what it can learn from her homeland to reinvigorate and fulfill the promise of the American dream. Offering insights, advice, and solutions, The Nordic Theory of Everything makes a convincing argument that we can rebuild our society, rekindle our optimism, and restore independence to our relationships and lives. --Adapted from dust jacket.', '["Social conditions", "Civilization", "Social policy", "New York Times reviewed", "Scandinavia, social conditions", "United states, social conditions, 21st century", "United states, social policy"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (40, 'the-master-algorithm', 'The Master Algorithm', 'How the Quest for the Ultimate Learning Machine Will Remake Our World', 'Technology', 0, 2015, 333, '9780465065707', '/works/OL19663805W', 'In the world''s top research labs and universities, the race is on to invent the ultimate learning algorithm: one capable of discovering any knowledge from data, and doing anything we want, before we even ask. In The Master Algorithm, Pedro Domingos lifts the veil to give us a peek inside the learning machines that power Google, Amazon, and your smartphone. He assembles a blueprint for the future universal learner--the Master Algorithm--and discusses what it will mean for business, science, and society. If data-ism is today''s philosophy, this book is its bible.', '["Information Theory", "Cognitive Science", "Algorithms", "Mathematics", "Philosophy", "Artificial intelligence", "Machine Learning", "Knowledge representation (information theory)", "Social aspects", "Information society", "SCIENCE", "System Theory"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (41, 'genesis', 'Genesis', 'The Deep Origin of Societies', 'Science and Math', 0, 2019, 160, '9781631495540', '/works/OL20148876W', 'Asserting that religious creeds and philosophical questions can be reduced to purely genetic and evolutionary components, and that the human body and mind have a physical base obedient to the laws of physics and chemistry, Genesis demonstrates that the only way for us to fully understand human behavior is to study the evolutionary histories of nonhuman species. Of these, Wilson demonstrates that at least 17 - among them the African naked mole rat and the sponge-dwelling shrimp - have been found to have advanced societies based on altruism and cooperation.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (42, 'how-to-read-a-book', 'How to Read a Book', 'The Classic Guide to Intelligent Reading', 'Brain & Psychology', 0, 1940, 385, '9780671212094', '/works/OL487444W', 'Originally published in 1940, this book is a rare phenomenon, a living classic that introduces and elucidates the various levels of reading and how to achieve them—from elementary reading, through systematic skimming and inspectional reading, to speed reading. Readers will learn when and how to “judge a book by its cover,” and also how to X-ray it, read critically, and extract the author’s message from the text.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (43, 'zen-and-the-art-of-motorcycle-maintenance', 'Zen and the Art of Motorcycle Maintenance', NULL, 'Science Fiction & Fiction', 1, 1974, 373, '9780688171667', '/works/OL827357W', 'One of the most important and influential books of the past half-century, Robert M. Pirsig''s Zen and the Art of Motorcycle Maintenance is a powerful, moving, and penetrating examination of how we live and a meditation on how to live better. The narrative of a father on a summer motorcycle trip across America''s Northwest with his young son, it becomes a profound personal and philosophical odyssey into life''s fundamental questions. A true modern classic, it remains at once touching and transcendent, resonant with the myriad confusions of existence and the small, essential triumphs that propel us forward.', '["Pirsig, Robert M.", "Biography", "Description and travel", "Fathers and sons", "Journeys", "Maintenance and repair", "Motorcycles", "Philosophy", "Philosophy and civilization", "Popular culture", "Psychology", "Self"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (44, 'educated', 'Educated', 'A Memoir', 'Current Events & People', 0, 2018, 464, '9781984854858', '/works/OL18139176W', 'Westover recounts overcoming her survivalist Mormon family in order to go to college, and emphasizes the importance of education in enlarging her world. She details her journey from her isolated life in the mountains of Idaho to completing a PhD program in history at Cambridge University. She started college at the age of 17 having had no formal education. She explores her struggle to reconcile her desire to learn with the world she inhabited with her father.', '["Subculture", "Home schooling", "Family", "Anecdotes", "Victims of family violence", "Women college students", "Christian biography", "Rural conditions", "Survivalism", "Biography", "Women", "Ancedotes"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (45, 'craeft', 'Cræft', 'An Inquiry Into the Origins and True Meaning of Traditional Crafts', 'Politics & Social Sciences', 0, 2017, 352, '9780393356571', '/works/OL20162539W', NULL, '["Handicraft", "Artisans, great britain", "Economic anthropology", "Material culture", "Antiquities, prehistoric"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (46, 'growing-a-revolution', 'Growing a Revolution', 'Bringing Our Soil Back to Life', 'Science and Math', 0, 2017, 320, '9780393356090', '/works/OL20179092W', NULL, '["Soil ecology", "Soil biology"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (47, 'scale', 'Scale', 'The Universal Laws of Growth, Innovation, Sustainability, and the Pace of Life in Organisms, Cities, Economies, and Companies', 'Science and Math', 0, 2015, 479, '9781594205583', '/works/OL17826327W', 'From one of the most influential scientists of our time, a dazzling exploration of the hidden laws that govern the life cycle of everything from plants and animals to the cities we live in. The former head of the Sante Fe Institute, visionary physicist Geoffrey West is a pioneer in the field of complexity science, the science of emergent systems and networks. The term "complexity" can be misleading, however, because what makes West''s discoveries so beautiful is that he has found an underlying simplicity that unites the seemingly complex and diverse phenomena of living systems, including our bodies, our cities and our businesses. Fascinated by issues of aging and mortality, West applied the rigor of a physicist to the biological question of why we live as long as we do and no longer. The result was astonishing, and changed science, creating a new understanding of energy use and metabolism: West found that despite the riotous diversity in the sizes of mammals, they are all, to a large degree, scaled versions of each other. If you know the size of a mammal, you can use scaling laws to learn everything from how much food it eats per day, what its heart-rate is, how long it will take to mature, its lifespan, and so on. Furthermore, the efficiency of the mammal''s circulatory systems scales up precisely based on weight: if you compare a mouse, a human and an elephant on a logarithmic graph, you find with every doubling of average weight, a species gets 25% more efficient--and lives 25% longer. This speaks to everything from how long we can expect to live to how many hours of sleep we need. Fundamentally, he has proven, the issue has to do with the fractal geometry of the networks that supply energy and remove waste from the organism''s body', '["Evolution", "Urban ecology (Sociology)", "Sustainable development", "Molecular aspects", "Science", "Evolution (Biology)", "Philosophy", "Scaling (Social sciences)", "Methodology", "Social sciences", "BUSINESS & ECONOMICS", "Strategic Planning"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (48, 'life-after-google', 'Life After Google', 'The Fall of Big Data and the Rise of the Blockchain Economy', 'Technology', 0, 2018, 320, '9781621575764', '/works/OL19764274W', 'The Age of Google, built on big data and machine intelligence, has been an awesome era. But it''s coming to an end. In Life after Google, George Gilder--the peerless visionary of technology and culture--explains why Silicon Valley is suffering a nervous breakdown and what to expect as the post-Google age dawns. Google''s astonishing ability to ''search and sort'' attracts the entire world to its search engine and countless other goodies--videos, maps, email, calendars.... And everything it offers is free, or so it seems. Instead of paying directly, users submit to advertising. The system of ''aggregate and advertise'' works--for a while--if you control an empire of data centers, but a market without prices strangles entrepreneurship and turns the Internet into a wasteland of ads. The crisis is not just economic. Even as advances in artificial intelligence induce delusions of omnipotence and transcendence, Silicon Valley has pretty much given up on security. The Internet firewalls supposedly protecting all those passwords and personal information have proved hopelessly permeable. The crisis cannot be solved within the current computer and network architecture. The future lies with the ''cryptocosm''--The new architecture of the blockchain and its derivatives. Enabling cryptocurrencies such as bitcoin and ether, NEO and Hashgraph, it will provide the Internet a secure global payments system, ending the aggregate-and-advertise Age of Google. Silicon Valley, long dominated by a few giants, faces a ''great unbundling,'' which will disperse computer power and commerce and transform the economy and the Internet', '["Blockchains (Databases)", "Forecasting", "Internet", "Electronic commerce", "High technology industries", "Security measures", "Internet, economic aspects", "Business, data processing", "Internet advertising"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (49, 'how-to-change-your-mind', 'How to Change Your Mind', 'What the New Science of Psychedelics Teaches Us about Consciousness, Dying, Addiction, Depression, and Transcendence', 'Health & Medicine', 0, 2018, 528, '9781594204227', '/works/OL20159801W', 'When Michael Pollan set out to research how LSD and psilocybin (the active ingredient in magic mushrooms) are being used to provide relief to people suffering from difficult-to-treat conditions such as depression, addiction and anxiety, he did not intend to write what is undoubtedly his most personal book. But upon discovering how these remarkable substances are improving the lives not only of the mentally ill but also of healthy people coming to grips with the challenges of everyday life, he decided to explore the landscape of the mind in the first person as well as the third. Thus began a singular adventure into various altered states of consciousness, along with a dive deep into both the latest brain science and the thriving underground community of psychedelic therapists. Pollan sifts the historical record to separate the truth about these mysterious drugs from the myths that have surrounded them since the 1960s, when a handful of psychedelic evangelists inadvertently catalyzed a powerful backlash against what was then a promising field of research.', '["Hallucinogenic drugs", "Mental health", "Therapeutic use", "Biography", "Psychotherapy patients", "Psychological aspects", "Psychotherapy", "Hallucinations and illusions", "nyt:combined-print-and-e-book-nonfiction=2018-06-03", "New York Times bestseller", "New York Times reviewed", "Mental illness"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (50, 'freedom-tm', 'Freedom™', NULL, 'Science Fiction & Fiction', 0, 2010, 499, '9780451231895', '/works/OL14996932W', 'The propulsive, shockingly plausible sequel to New York Times bestseller DaemonIn one of the most buzzed-about debuts of 2009, Daniel Suarez introduced a terrifying vision of a new world order, controlled by the Daemon, an insidious computer program unleashed by a hi-tech wunderkind, Daemon captured the attention of the tech community, became a New York Times and Indie bestseller, and left readers hungry for more.Well, more is here, and it''s even more gripping than its predecessor.In the opening chapters of Freedom(tm), the Daemon is firmly in control, using an expanded network of real-world, dispossessed darknet operatives to tear apart civilization and rebuild it anew. Soon civil war breaks out in the American Midwest, in a brutal wave of violence that becomes known as the Corn Rebellion. Former detective Pete Sebeck, now the Daemon''s most powerful-though reluctant-operative, must lead a small band of enlightened humans toward a populist movement designed to protect the new world order. But the private armies of global business are preparing to crush the Daemon once and for all.In a world of conflicted loyalties, rapidly diminishing human power, and the possibility that anyone can be a spy, what''s at stake is nothing less than human freedom''s last hope to survive the technology revolution.', '["Human-computer interaction", "Stockbrokers", "International economic integration", "Science fiction", "Thriller", "Fiction, suspense", "Fiction, science fiction, general", "Fiction, thrillers, suspense"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (51, 'collapse', 'Collapse', 'How Societies Choose to Fail or Succeed', 'History & Economics', 0, 2004, 515, '9780143036555', '/works/OL276557W', 'In his Pulitzer Prize-winning bestseller Guns, Germs, and Steel, Jared Diamond examined how and why Western civilizations developed the technologies and immunities that allowed them to dominate much of the world. Now, Diamond probes the other side of the equation: What caused some of the great civilizations of the past to collapse into ruin, and what can we learn from their fates?" "As in Guns, Germs, and Steel, Diamond weaves an all-encompassing global thesis through a series of historical-cultural narratives. Moving from the prehistoric Polynesian culture on Easter Island to the formerly flourishing Native American civilizations of the Anasazi and the Maya, the doomed medieval Viking colony on Greenland, and finally to the modern world, Diamond traces a fundamental pattern of catastrophe, spelling out what happens when we squander our resources, when we ignore the signals our environment gives us, and when we reproduce too fast or cut down too many trees. Environmental damage, climate change, rapid population growth, unstable trade partners, and pressure from enemies were all factors in the demise of the doomed societies, but other societies found solutions to those same problems and persisted.', '["Sociology", "Culturen", "Environnement", "Changement social", "Verval (geschiedenis)", "Environment", "Historia social", "Social Conditions", "Nature", "Effect of human beings on", "Case studies", "Hombre"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (52, 'sapiens', 'Sapiens', 'A Brief History of Humankind', 'History & Economics', 0, 2011, 456, '9780062316110', '/works/OL17075811W', 'From a renowned historian comes a groundbreaking narrative of humanity’s creation and evolution—a #1 international bestseller—that explores the ways in which biology and history have defined us and enhanced our understanding of what it means to be “human.” One hundred thousand years ago, at least six different species of humans inhabited Earth. Yet today there is only one—homo sapiens. What happened to the others? And what may happen to us? Most books about the history of humanity pursue either a historical or a biological approach, but Dr. Yuval Noah Harari breaks the mold with this highly original book that begins about 70,000 years ago with the appearance of modern cognition. From examining the role evolving humans have played in the global ecosystem to charting the rise of empires, Sapiens integrates history and science to reconsider accepted narratives, connect past developments with contemporary concerns, and examine specific events within the context of larger ideas. Dr. Harari also compels us to look ahead, because over the last few decades humans have begun to bend laws of natural selection that have governed life for the past four billion years. We are acquiring the ability to design not only the world around us, but also ourselves. Where is this leading us, and what do we want to become? Featuring 27 photographs, 6 maps, and 25 illustrations/diagrams, this provocative and insightful work is sure to spark debate and is essential reading for aficionados of Jared Diamond, James Gleick, Matt Ridley, Robert Wright, and Sharon Moalem.', '["Technology and civilization", "Human beings", "Historical Chronology", "Historia universal", "Historia", "Civilization", "Hombre", "World history", "Science", "SCIENCE / Life Sciences / General", "SCIENCE / General", "SCIENCE / Life Sciences / Evolution"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (53, 'why-we-sleep', 'Why We Sleep', 'Unlocking the Power of Sleep and Dreams', 'Health & Medicine', 0, 2017, 485, '9781501144318', '/works/OL20168133W', 'With two appearances on CBS This Morning and Fresh Air''s most popular interview of 2017, Matthew Walker has made abundantly clear that sleep is one of the most important but least understood aspects of our life. Until very recently, science had no answer to the question of why we sleep, or what good it served, or why we suffer such devastating health consequences when it is absent. Compared to the other basic drives in life—eating, drinking, and reproducing—the purpose of sleep remains more elusive. Within the brain, sleep enriches a diversity of functions, including our ability to learn, memorize, and make logical decisions. It recalibrates our emotions, restocks our immune system, fine-tunes our metabolism, and regulates our appetite. Dreaming creates a virtual reality space in which the brain melds past and present knowledge, inspiring creativity. In this “compelling and utterly convincing” (The Sunday Times) book, preeminent neuroscientist and sleep expert Matthew Walker provides a revolutionary exploration of sleep, examining how it affects every aspect of our physical and mental well-being. Charting the most cutting-edge scientific breakthroughs, and marshalling his decades of research and clinical practice, Walker explains how we can harness sleep to improve learning, mood and energy levels, regulate hormones, prevent cancer, Alzheimer’s and diabetes, slow the effects of aging, and increase longevity. He also provides actionable steps towards getting a better night’s sleep every night.', '["sleep", "health & fitness", "sleep & sleep disorders", "science", "life sciences", "Human Anatomy & Physiology", "psychology", "mental health", "Sleep, psychological aspects", "Dreams", "nyt:science=2017-11-12", "New York Times bestseller"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (54, 'why-buddhism-is-true', 'Why Buddhism is True', 'The Science and Philosophy of Meditation and Enlightenment', 'Philosophy & Religion', 0, 2017, 336, '9781508235408', '/works/OL20917487W', NULL, '["nyt:paperback-nonfiction=2018-05-27", "New York Times bestseller", "Buddhism"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (55, 'walkaway', 'Walkaway', NULL, 'Science Fiction & Fiction', 1, 2017, 560, '9780765392763', '/works/OL17801248W', 'Hubert Vernon Rudolph Clayton Irving Wilson Alva Anton Jeff Harley Timothy Curtis Cleveland Cecil Ollie Edmund Eli Wiley Marvin Ellis Espinoza―known to his friends as Hubert, Etc―was too old to be at that Communist party. But after watching the breakdown of modern society, he really has no where left to be―except amongst the dregs of disaffected youth who party all night and heap scorn on the sheep they see on the morning commute. After falling in with Natalie, an ultra-rich heiress trying to escape the clutches of her repressive father, the two decide to give up fully on formal society―and walk away. After all, now that anyone can design and print the basic necessities of life―food, clothing, shelter―from a computer, there seems to be little reason to toil within the system. It’s still a dangerous world out there, the empty lands wrecked by climate change, dead cities hollowed out by industrial flight, shadows hiding predators animal and human alike. Still, when the initial pioneer walkaways flourish, more people join them. Then the walkaways discover the one thing the ultra-rich have never been able to buy: how to beat death. Now it’s war – a war that will turn the world upside down. Fascinating, moving, and darkly humorous, Walkaway is a multi-generation SF thriller about the wrenching changes of the next hundred years…and the very human people who will live their consequences.', '["Fiction, science fiction, general", "Rich people", "Fathers and daughters", "Social change", "Future life", "Rich people -- Fiction", "Fathers and daughters -- Fiction", "Social change -- Fiction", "Future life -- Fiction"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (56, 'daemon', 'Daemon', NULL, 'Technology', 1, 2009, 640, '9780451228734', '/works/OL13646905W', 'Already an underground sensation, a high-tech thriller for the wireless age that explores the unthinkable consequences of a computer program running without human control—a daemon—designed to dismantle society and bring about a new world order. Technology controls almost everything in our modern-day world, from remote entry on our cars to access to our homes, from the flight controls of our airplanes to the movements of the entire world economy. Thousands of autonomous computer programs, or daemons, make our networked world possible, running constantly in the background of our lives, trafficking e-mail, transferring money, and monitoring power grids. For the most part, daemons are benign, but the same can''t always be said for the people who design them. Matthew Sobol was a legendary computer game designer—the architect behind half-a-dozen popular online games. His premature death depressed both gamers and his company''s stock price. But Sobol''s fans aren''t the only ones to note his passing. When his obituary is posted online, a previously dormant daemon activates, initiating a chain of events intended to unravel the fabric of our hyper-efficient, interconnected world. With Sobol''s secrets buried along with him, and as new layers of his daemon are unleashed at every turn, it''s up to an unlikely alliance to decipher his intricate plans and wrest the world from the grasp of a nameless, faceless enemy—or learn to live in a society in which we are no longer in control... Computer technology expert Daniel Suarez blends haunting high-tech realism with gripping suspense in an authentic, complex thriller in the tradition of Michael Crichton, Neal Stephenson, and William Gibson.', '["Human-computer interaction", "International economic integration", "Computer programmers", "Thriller", "Fiction, suspense", "Programmeurs", "Romans, nouvelles", "Intégration économique internationale", "Fiction, science fiction, action & adventure", "Scientists, fiction", "Long now manual for civilization"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (57, 'a-crack-in-creation', 'A Crack in Creation', 'Gene Editing and the Unthinkable Power to Control Evolution', 'Science and Math', 0, 2017, 248, '9780544716940', '/works/OL17765779W', 'Not since the atomic bomb has a technology so alarmed its inventors that they warned the world about its use. Not, that is, until the spring of 2015, when biologist Jennifer Doudna called for a worldwide moratorium on the use of the new gene-editing tool CRISPR—a revolutionary new technology that she helped create—to make heritable changes in human embryos. The cheapest, simplest, most effective way of manipulating DNA ever known, CRISPR may well give us the cure to HIV, genetic diseases, and some cancers, and will help address the world’s hunger crisis. Yet even the tiniest changes to DNA could have myriad, unforeseeable consequences—to say nothing of the ethical and societal repercussions of intentionally mutating embryos to create “better” humans. Writing with fellow researcher Samuel Sternberg, Doudna shares the thrilling story of her discovery, and passionately argues that enormous responsibility comes with the ability to rewrite the code of life. With CRISPR, she shows, we have effectively taken control of evolution. What will we do with this unfathomable power?', '["Gene Editing", "CRISPR", "Genetic code", "Genetic engineering", "Genetics", "Research", "Rna", "CRISPR-Cas Systems", "Genetic Research", "MEDICAL", "SCIENCE", "Life Sciences"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (58, 'how-to-live', 'How to Live', 'Or A Life of Montaigne in One Question and Twenty Attempts at an Answer', 'Philosophy & Religion', 0, 2011, 416, '9781590514832', '/works/OL25463670W', NULL, '["Montaigne, michel de, 1533-1592", "Conduct of life", "Authors, biography"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (59, 'peak', 'Peak', 'Secrets from the New Science of Expertise', 'Brain & Psychology', 0, 2016, 307, '9780544456235', '/works/OL19664939W', 'Draws on the examples of chess champions, violin virtuosos, star athletes, and memory mavens to outline a powerful approach to learning that enables proficiency through strategic goal setting, self-motivation, and feedback exercises.', '["Performance", "Expertise", "Ability", "Psychological aspects", "Excellence", "Gifted persons"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (60, 'the-epigenetics-revolution', 'The Epigenetics Revolution', 'How Modern Biology Is Rewriting Our Understanding of Genetics, Disease, and Inheritance', 'Science and Math', 0, 2011, 352, '9781848313477', '/works/OL16184574W', 'Epigenetics can potentially revolutionize our understanding of the structure and behavior of biological life on Earth. It explains why mapping an organism''s genetic code is not enough to determine how it develops or acts and shows how nurture combines with nature to engineer biological diversity. Surveying the twenty-year history of the field while also highlighting its latest findings and innovations, this volume provides a readily understandable introduction to the foundations of epigenetics. Nessa Carey, a leading epigenetics researcher, connects the field''s arguments to such diverse phenomena as how ants and queen bees control their colonies; why tortoiseshell cats are always female; why some plants need cold weather before they can flower; and how our bodies age and develop disease. Reaching beyond biology, epigenetics now informs work on drug addiction, the long-term effects of famine, and the physical and psychological consequences of childhood trauma. Carey concludes with a discussion of the future directions for this research and its ability to improve human health and well-being.', '["Genetic Epigenesis", "Molecular Evolution", "Epigenomics", "Epigenesis", "Gene expression", "Genetik", "Genetics", "Evolution (Biology)", "Evolution (biologi)", "Science", "Evolution", "Genetic regulation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (61, 'stuff-matters', 'Stuff Matters', 'Exploring the Marvelous Materials That Shape Our Man-Made World', 'Science and Math', 0, 2013, 272, '9780544236042', '/works/OL17778974W', 'Why is glass see-through? What makes elastic stretchy? Why does a paperclip bend? Why does any material look and behave the way it does?With clarity and humor, world-leading materials scientist Mark Miodownik answers all the questions you''ve ever had about your pens, spoons, and razor blades, while also introducing a whole world full of materials you''ve never even heard of: the diamond five times the size of Earth; concrete cloth that can be molded into any shape; and graphene, the thinnest, strongest, stiffest material in existence--only a single atom thick.Stuff Matters tells enthralling stories that explain the science and history of materials. From the teacup to the jet engine, the silicon chip to the paper clip, the plastic in our appliances to the elastic in our underpants, Miodownik reveals the miracles of engineering that permeate our lives. As engaging as it is incisive, Stuff Matters will make you see the materials that surround you with new eyes', '["Materials", "Material culture", "Materials science", "Popular works", "SCIENCE / Applied Sciences", "SCIENCE / Chemistry / Inorganic", "HISTORY / Modern / General", "nyt:science=2014-07-13", "New York Times bestseller", "New York Times reviewed", "Science des matériaux", "Ouvrages de vulgarisation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (62, 'norse-mythology', 'Norse Mythology', NULL, 'History & Economics', 0, 2016, 272, '9780393609097', '/works/OL17619634W', 'Neil Gaiman has long been inspired by ancient mythology in creating the fantastical realms of his fiction. Now he turns his attention back to the source, presenting a bravura rendition of the great northern tales. In Norse Mythology, Gaiman stays true to the myths in envisioning the major Norse pantheon: Odin, the highest of the high, wise, daring, and cunning; Thor, Odin’s son, incredibly strong yet not the wisest of gods; and Loki―son of a giant―blood brother to Odin and a trickster and unsurpassable manipulator. Gaiman fashions these primeval stories into a novelistic arc that begins with the genesis of the legendary nine worlds and delves into the exploits of deities, dwarfs, and giants. Once, when Thor’s hammer is stolen, Thor must disguise himself as a woman―difficult with his beard and huge appetite―to steal it back. More poignant is the tale in which the blood of Kvasir―the most sagacious of gods―is turned into a mead that infuses drinkers with poetry. The work culminates in Ragnarok, the twilight of the gods and rebirth of a new time and people. Through Gaiman’s deft and witty prose emerge these gods with their fiercely competitive natures, their susceptibility to being duped and to duping others, and their tendency to let passion ignite their actions, making these long-ago myths breathe pungent life again.', '["Norse Mythology", "FICTION / Literary", "FICTION / Fairy Tales, Folk Tales, Legends & Mythology", "Mythology, norse", "Fantasy", "nyt:combined-print-and-e-book-fiction=2017-02-26", "New York Times bestseller", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (63, 'all-art-is-propaganda', 'All Art Is Propaganda', NULL, 'Essays & Literature', 0, 2008, 374, '9780151013555', '/works/OL1167992W', 'Collects critical essays written by George Orwell in the 1940s, in which he discusses the work of Charles Dickens, Rudyard Kipling, T. S. Eliot, Salvador Dali, and others; and also covers propaganda, politics, and more.', '["English essays", "Essays (single author)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (64, 'the-vital-question', 'The Vital Question', 'Energy, Evolution, and the Origins of Complex Life', 'Science and Math', 0, 2001, 352, '9780393352979', '/works/OL19663289W', 'A biochemist, building on the pillars of evolutionary theory and drawing on cutting-edge research into the link between energy and genes, argues that the evolution of multicellular life was the result of a single event.', '["Origin", "Life", "Cells", "Evolution", "Energy metabolism", "Life, origin", "Biogenese", "Chemische Evolution", "Leben"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (65, 'shadow-elite', 'Shadow Elite', 'How the World''s New Power Brokers Undermine Democracy, Government, and the Free Market', 'Politics & Social Sciences', 0, 2010, 283, '9780465022014', '/works/OL27083522W', NULL, '["Corruption", "Political corruption", "Abuse of administrative power", "Elite (Social sciences)", "Privatization", "Government accountability"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (66, 'hillbilly-eligy', 'Hillbilly Eligy', 'A Memoir of a Family and Culture in Crisis', 'Politics & Social Sciences', 0, 2016, 256, '9780062300546', '/works/OL17357665W', 'From a former marine and Yale Law School graduate, this book is a probing look at the struggles of America''s white working class through the author''s own story of growing up in a poor Rust Belt town. Hillbilly Elegy is a passionate and personal analysis of a culture in crisis - that of poor, white Americans. The disintegration of this group, a process that has been slowly occurring now for over forty years, has been reported with growing frequency and alarm, but has never before been written about as searingly from the inside.', '["Mountain people", "Family", "Social mobility", "Working class whites", "Case studies", "Economic conditions", "Social conditions", "Biography", "Arbeitssoziologie", "Sociology", "Umschulungswerkstätten für Siedler und Auswanderer", "Ausgrenzung"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (67, 'ancillary-justice', 'Ancillary Justice', NULL, 'Science Fiction & Fiction', 1, 2013, 444, '9780316246620', '/works/OL17062644W', 'On a remote, icy planet, the soldier known as Breq is drawing closer to completing her quest. Once, she was the *Justice of Toren*--a colossal starship with an artificial intelligence linking thousands of soldiers in the service of the Radch, the empire that conquered the galaxy. Now, an act of treachery has ripped it all away, leaving her with one fragile human body, unanswered questions, and a burning desire for vengeance. Sequels: Ancillary Sword; Ancillary Mercy.', '["Science Fiction", "Quests (Expeditions)", "Ebook", "Space Opera", "Revenge", "Adult", "Adventure", "Fiction, science fiction, general", "award:nebula_award=novel", "Artificial intelligence", "Large type books", "Hugo Award Winner"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (68, 'the-metaphysical-club', 'The Metaphysical Club', 'A Story of Ideas in America', 'History & Economics', 0, 2001, 384, '9780007126903', '/works/OL20452875W', NULL, '["Holmes, oliver wendell, 1841-1935", "James, william, 1842-1910", "Dewey, john, 1859-1952", "Peirce, charles s. (charles sanders), 1839-1914", "United states, intellectual life", "New england, intellectual life", "United states, social conditions, 1865-1945", "Metaphysics", "National characteristics, american"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (69, 'american-nations', 'American Nations', 'A History of the Eleven Rival Regional Cultures of North America', 'Politics & Social Sciences', 0, 2011, 384, '9780143122029', '/works/OL20272183W', NULL, '["Regionalism", "North america, race relations", "Cultural pluralism", "Indians of north america, first contact with europeans", "Whites", "Blacks", "America, discovery and exploration"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (70, 'the-rise-and-fall-of-american-growth', 'The Rise and Fall of American Growth', 'The U.S. Standard of Living since the Civil War', 'History & Economics', 0, 2016, 762, NULL, '/works/OL17343962W', 'The trajectory and impetus of American growth from the end of the Civil War until now.', '["Economic conditions", "Cost and standard of living", "Economic history", "United states, economic conditions, 1865-1918", "United states, economic conditions, 1918-1945", "United states, economic conditions, 1945-", "Lebensstandard", "Wohlstand", "Wohlfahrtsmessung"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (71, 'elon-musk', 'Elon Musk', 'Tesla, SpaceX, and the Quest for a Fantastic Future', 'Current Events & People', 0, 2013, 402, '9780753555620', '/works/OL17184556W', 'In the spirit of Steve Jobs and Moneyball, Elon Musk is both an illuminating and authorized look at the extraordinary life of one of Silicon Valley''s most exciting, unpredictable, and ambitious entrepreneurs -- a real-life Tony Stark -- and a fascinating exploration of the renewal of American invention and its new "makers." Elon Musk spotlights the technology and vision of Elon Musk, the renowned entrepreneur and innovator behind SpaceX, Tesla, and SolarCity, who sold one of his Internet companies, PayPal, for $1.5 billion. Ashlee Vance captures the full spectacle and arc of the genius''s life and work, from his tumultuous upbringing in South Africa and flight to the United States to his dramatic technical innovations and entrepreneurial pursuits. Vance uses Musk''s story to explore one of the pressing questions of our age: can the nation of inventors and creators who led the modern world for a century still compete in an age of fierce global competition? He argues that Musk -- one of the most unusual and striking figures in American business history -- is a contemporary, visionary amalgam of legendary inventors and industrialists including Thomas Edison, Henry Ford, Howard Hughes, and Steve Jobs. More than any other entrepreneur today, Musk has dedicated his energies and his own vast fortune to inventing a future that is as rich and far-reaching as the visionaries of the golden age of science-fiction fantasy. Thorough and insightful, Elon Musk brings to life a technology industry that is rapidly and dramatically changing by examining the life of one of its most powerful and influential titans. - Publisher.', '["SpaceX (Firm)", "PayPal (Firm)", "Businesspeople", "Biography", "Tesla Motors", "Businesspeople, biography", "Technological innovations, economic aspects", "Aerospace industries", "Automobiles, electric", "Inventors", "nyt:combined-print-and-e-book-nonfiction=2015-06-07", "New York Times bestseller"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (72, 'superforecasting', 'Superforecasting', 'The Art and Science of Prediction', 'Science and Math', 0, 2015, 326, '9780771070525', '/works/OL18233878W', 'Everyone would benefit from seeing further into the future, whether buying stocks, crafting policy, launching a new product, or simply planning the week’s meals. Unfortunately, people tend to be terrible forecasters. As Wharton professor Philip Tetlock showed in a landmark 2005 study, even experts’ predictions are only slightly better than chance. However, an important and underreported conclusion of that study was that some experts do have real foresight, and Tetlock has spent the past decade trying to figure out why. What makes some people so good? And can this talent be taught? In Superforecasting, Tetlock and coauthor Dan Gardner offer a masterwork on prediction, drawing on decades of research and the results of a massive, government-funded forecasting tournament. The Good Judgment Project involves tens of thousands of ordinary people—including a Brooklyn filmmaker, a retired pipe installer, and a former ballroom dancer—who set out to forecast global events. Some of the volunteers have turned out to be astonishingly good. They’ve beaten other benchmarks, competitors, and prediction markets. They’ve even beaten the collective judgment of intelligence analysts with access to classified information. They are "superforecasters." In this groundbreaking and accessible book, Tetlock and Gardner show us how we can learn from this elite group. Weaving together stories of forecasting successes (the raid on Osama bin Laden’s compound) and failures (the Bay of Pigs) and interviews with a range of high-level decision makers, from David Petraeus to Robert Rubin, they show that good forecasting doesn’t require powerful computers or arcane methods. It involves gathering evidence from a variety of sources, thinking probabilistically, working in teams, keeping score, and being willing to admit error and change course. Superforecasting offers the first demonstrably effective way to improve our ability to predict the future—whether in business, finance, politics, international affairs, or daily life—and is destined to become a modern classic.', '["Economic forecasting", "Forecasting", "decision making", "predictions", "reasoning", "analysis", "psychology", "SOCIAL SCIENCE / Future Studies", "BUSINESS & ECONOMICS / Forecasting", "PSYCHOLOGY / Cognitive Psychology", "BUSINESS & ECONOMICS", "SOCIAL SCIENCE"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (73, 'being-mortal', 'Being Mortal', 'Medicine and What Matters in the End', 'Health & Medicine', 0, 2014, 287, '9781510015036', '/works/OL17079567W', 'Being Mortal: Medicine and What Matters in the End is a 2014 non-fiction book by American surgeon Atul Gawande. The book addresses end-of-life care, hospice care, and also contains Gawande''s reflections and personal stories. He suggests that medical care should focus on well-being rather than survival. Being Mortal has won awards, appeared on lists of best books, and been featured in a documentary.', '["dying", "geriatrics", "medicine", "Activities of Daily Living", "Conduct of life", "Attitude to Death", "Critical care medicine", "Terminal care", "Diagnosis", "Attitude (Psychology)", "SOCIAL SCIENCE", "Elderly"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (74, 'the-world-until-yesterday', 'The World Until Yesterday', 'What Can We Learn from Traditional Societies?', 'History & Economics', 0, 2012, 592, '9781101606001', '/works/OL16637581W', 'Overview: Most of us take for granted the features of our modern society, from air travel and telecommunications to literacy and obesity. Yet for nearly all of its six million years of existence, human society had none of these things. While the gulf that divides us from our primitive ancestors may seem unbridgeably wide, we can glimpse much of our former lifestyle in those largely traditional societies still or recently in existence. Societies like those of the New Guinea Highlanders remind us that it was only yesterday-in evolutionary time-when everything changed and that we moderns still possess bodies and social practices often better adapted to traditional than to modern conditions. The World Until Yesterday provides a mesmerizing firsthand picture of the human past as it had been for millions of years-a past that has mostly vanished-and considers what the differences between that past and our present mean for our lives today. This is Jared Diamond''s most personal book to date, as he draws extensively from his decades of field work in the Pacific islands, as well as evidence from Inuit, Amazonian Indians, Kalahari San people, and others. Diamond doesn''t romanticize traditional societies-after all, we are shocked by some of their practices-but he finds that their solutions to universal human problems such as child rearing, elder care, dispute resolution, risk, and physical fitness have much to teach us. A characteristically provocative, enlightening, and entertaining book, The World Until Yesterday will be essential and delightful reading.', '["Social life and customs", "Social evolution", "Dani (New Guinean people)", "Cultural assimilation", "Social change", "Anthropology", "Social History", "Manners and customs", "nyt:combined-print-and-e-book-nonfiction=2013-01-20", "New York Times bestseller", "Papua new guinea, social life and customs", "nyt:paperback-nonfiction=2013-11-17"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (75, 'amusing-ourselves-to-death', 'Amusing Ourselves to Death', 'Public Discourse in the Age of Show Business', 'Politics & Social Sciences', 0, 1985, 214, '9780136006466', '/works/OL137916W', 'Amusing Ourselves to Death is a prophetic look at what happens when politics, journalism, education, and even religion become subject to the demands of entertainment. It is also a blueprint for regaining control of our media, so that they can serve our highest goals.', '["Mass media", "Influence", "Television broadcasting", "Social aspects", "Social aspects of Television broadcasting", "Performing Arts", "Sociology", "Culturele invloeden", "Televisie", "open_syllabus_project", "Médias", "Television"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (76, 'roadside-picnic', 'Roadside Picnic', NULL, 'Science Fiction & Fiction', 1, 1978, 256, '9781473208735', '/works/OL7967812W', 'Soviet-era Russian science fiction deserves a wider audience in English. The Strugatsky brothers collaborated on numerous novels and stories, the best known of which is this, partly because it was filmed by Andrei Tarkovsky as Stalker, in 1977. The novel takes place 10 years after a mysterious alien visitation, which seems to have no rational explanation. No one saw the visitors. Their presence caused disease and blindness in the areas where they landed. Now, in the six "Zones", the laws of physics (and, seemingly, of reality) are disturbed by anomalies, and littered with inexplicable, deadly wreckage. Only a few brave "stalkers" risk their lives to enter the zones to gather alien artefacts for sale. Some of these artefacts offer the promise of extraordinary powers. Unlike Tarkovsky''s film, which concentrates on the hallucinatory, vacated landscape of the zones, the novels portray a society adapting to an inexplicable, terrifying event, an eruption of the unknown. Though written in 1971 and published in English in 1977, the novel was heavily bowdlerised by Soviet censors, and an authoritative text wasn''t available in Russian until 2000. It''s a book with an extraordinary atmosphere – and a demonstration of how science fiction, by using a single bold central metaphor, can open up the possibilities of the novel.', '["science fiction", "Russian science fiction", "alien visitation", "anomalies", "Russian fiction", "Fiction, science fiction, general"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (77, 'the-innovators', 'The Innovators', 'How a Group of Hackers, Geniuses, and Geeks Created the Digital Revolution', 'History & Economics', 0, 2014, 608, '9781471138799', '/works/OL17074268W', 'Following his blockbuster biography of Steve Jobs, The Innovators is Walter Isaacson’s revealing story of the people who created the computer and the Internet. It is destined to be the standard history of the digital revolution and an indispensable guide to how innovation really happens. What were the talents that allowed certain inventors and entrepreneurs to turn their visionary ideas into disruptive realities? What led to their creative leaps? Why did some succeed and others fail? In his masterly saga, Isaacson begins with Ada Lovelace, Lord Byron’s daughter, who pioneered computer programming in the 1840s. He explores the fascinating personalities that created our current digital revolution, such as Vannevar Bush, Alan Turing, John von Neumann, J.C.R. Licklider, Doug Engelbart, Robert Noyce, Bill Gates, Steve Wozniak, Steve Jobs, Tim Berners-Lee, and Larry Page. This is the story of how their minds worked and what made them so inventive. It’s also a narrative of how their ability to collaborate and master the art of teamwork made them even more creative. For an era that seeks to foster innovation, creativity, and teamwork, The Innovators shows how they happen.', '["Biography", "Computer scientists", "Internet", "Computer science", "Bell Telephone Laboratories", "BIOGRAPHY & AUTOBIOGRAPHY", "Science & Technology", "BUSINESS & ECONOMICS", "Industries", "Computer Industry", "TECHNOLOGY & ENGINEERING", "TECHNOLOGY & ENGINEERING / History"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (78, 'complexity', 'Complexity', 'A Very Short Introduction', 'Science and Math', 0, 2014, 112, '9780199662548', '/works/OL17785073W', NULL, '["Complexity (philosophy)", "Komplexität", "Komplexes System"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (79, 'no-place-to-hide', 'No Place to Hide', 'Edward Snowden, the NSA, and the U.S. Surveillance State', 'Current Events & People', 0, 2013, 333, '9780241146705', '/works/OL16819228W', 'The story of one of the greatest national security leaks in US history. In June 2013, reporter and political commentator Glenn Greenwald published a series of reports in the Guardian which rocked the world. The reports revealed shocking truths about the extent to which the National Security Agency had been gathering information about US citizens and intercepting communication worldwide, and were based on documents leaked by former National Security Agency employee Edward Snowden to Greenwald. Including new revelations from documents entrusted to Greenwald by Snowden.', '["Überwachung", "USA", "Politischer Skandal", "Datenerfassung", "Electronic surveillance", "Leaks (Disclosure of information)", "United States", "World Wide Web 2.0", "Privatsphäre", "USA National Security Agency", "United States. National Security Agency/Central Security Service", "Enttarnung"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (80, 'the-age-of-cryptocurrency', 'The Age of Cryptocurrency', 'How Bitcoin and Digital Money Are Challenging the Global Economic Order', 'Current Events & People', 0, 2015, 368, '9781250073082', '/works/OL20001821W', 'Bitcoin became a buzzword overnight. A cyber-enigma with an enthusiastic following, it pops up in headlines and fuels endless media debate. You can apparently use it to buy anything from coffee to cars, yet few people seem to truly understand what it is. This raises the question: Why should anyone care about bitcoin? In The Age of Cryptocurrency, Wall Street journalists Paul Vigna and Michael J. Casey deliver the definitive answer to this question. Cybermoney is poised to launch a revolution, one that could reinvent traditional financial and social structures while bringing the world''s billions of "unbanked" individuals into a new global economy. Cryptocurrency holds the promise of a financial system without a middleman, one owned by the people who use it and one safeguarded from the devastation of a 2008-type crash. But bitcoin, the most famous of the cybermonies, carries a reputation for instability, wild fluctuation, and illicit business; some fear it has the power to eliminate jobs and to upend the concept of a nation-state. It implies, above all, monumental and wide-reaching change--for better and for worse. But it is here to stay, and you ignore it at your peril.Vigna and Casey demystify cryptocurrency--its origins, its function, and what you need to know to navigate a cyber-economy. The digital currency world will look very different from the paper currency world; The Age of Cryptocurrency will teach you how to be ready.', '["Electronic commerce", "Currency question", "Electronic funds transfers", "Bitcoin", "BUSINESS & ECONOMICS / E-Commerce / Internet Marketing"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (81, 'the-structure-and-dynamics-of-networks', 'The Structure and Dynamics of Networks', NULL, 'Science and Math', 0, 2006, 592, '9781400841356', '/works/OL19002758W', NULL, '["Réseaux sociaux", "Dynamique", "Computer networks", "Complexity (Philosophy)", "Complexité (Philosophie)", "Social networks", "Réseaux d''ordinateurs", "Dynamics", "Social, group or collective psychology", "Mathematics", "Science/Mathematics", "Applied"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (82, 'love-sense', 'Love Sense', 'The Revolutionary New Science of Romantic Relationships', 'Brain & Psychology', 0, 2013, 352, '9781306759069', '/works/OL24574308W', NULL, NULL);
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (83, 'far-from-the-tree', 'Far from the Tree', NULL, 'Brain & Psychology', 0, 2012, 464, '9781481440905', '/works/OL16654793W', 'Solomon’s startling proposition in *Far from the Tree* is that being exceptional is at the core of the human condition—that difference is what unites us. He writes about families coping with deafness, dwarfism, Down''s syndrome, autism, schizophrenia, or multiple severe disabilities; with children who are prodigies, who are conceived in rape, who become criminals, and who are transgender. While each of these characteristics is potentially isolating, the experience of difference within families is universal, and Solomon documents triumphs of love over prejudice in every chapter. All parenting turns on a crucial question: to what extent should parents accept their children for who they are, and to what extent they should help them become their best selves. Drawing on ten years of research and interviews with more than three-hundred families, Solomon mines the eloquence of ordinary people facing extreme challenges. Elegantly reported by a spectacularly original and compassionate thinker, *Far from the Tree* explores how people who love each other must struggle to accept each other, a theme in every family’s life.', '["homosexuality", "deafness", "dwarfism", "Down Syndrome", "autism", "scizophrenia", "disability", "prodigies", "rape", "crime", "transgender", "Identity (Psychology)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (84, 'thinking-in-systems', 'Thinking in Systems', NULL, 'Science and Math', 0, 2008, 256, '9781136551406', '/works/OL3737036W', 'A clear, thoughtful, and wide-reaching exploration of complex systems, in theory and in practice. Meadows was a masterful and elegant writer and researcher, and an early voice in systems analysis at MIT and elsewhere. This book, completed from draft manuscript after Meadows'' death, is both accessible and deeply thought-provoking. She connects the dots between careful descriptions of systems analysis and systems insights, and the personal, social, societal, and political implications of systems thinking.', '["critical thinking", "systems thinking", "systems dynamics", "complex systems", "policy", "Sustainable development", "Environmental education", "Economic development", "System analysis", "Simulation methods", "Population", "Social sciences"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (85, 'the-everything-store', 'The Everything Store', 'Jeff Bezos and the Age of Amazon', 'Current Events & People', 0, 2013, 416, '9780552167833', '/works/OL16808249W', 'This book is the definitive story of Amazon.com, one of the most successful companies in the world, and of its driven, brilliant founder, Jeff Bezos. Amazon.com started off delivering books through the mail. But its visionary founder, Jeff Bezos, wasn''t content with being a bookseller. He wanted Amazon to become the everything store, offering limitless selection and seductive convenience at disruptively low prices. To do so, he developed a corporate culture of relentless ambition and secrecy that''s never been cracked. Until now. Brad Stone enjoyed unprecedented access to current and former Amazon employees and Bezos family members, giving readers the first in-depth, fly-on-the-wall account of life at Amazon. Compared to tech''s other elite innovators -- Jobs, Gates, Zuckerberg -- Bezos is a private man. But he stands out for his restless pursuit of new markets, leading Amazon into risky new ventures like the Kindle and cloud computing, and transforming retail in the same way Henry Ford revolutionized manufacturing. The Everything Store will be the revealing, definitive biography of the company that placed one of the first and largest bets on the Internet and forever changed the way we shop and read. - Publisher.', '["Amazon.com (Firm)", "Electronic commerce", "Internet bookstores", "Businessmen", "Booksellers and bookselling", "Biography", "Success in business", "Entrepreneurship", "Businesspeople, biography", "nyt:business-books=2013-11-10", "New York Times bestseller", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (86, 'antifragile', 'Antifragile', NULL, 'Science and Math', 0, 2012, 656, '9781846141577', '/works/OL16726829W', 'The acclaimed author of the influential bestseller The Black Swan, Nicholas Nassim Taleb takes a next big step with a deceptively simple concept: the "antifragile." Like the Greek hydra that grows two heads for each one it loses, people, systems, and institutions that are antifragile not only withstand shocks, they benefit from them. In a modern world dominated by chaos and uncertainty, Antifragile is a revolutionary vision from one of the most subversive and important thinkers of our time. Praise for Nicholas Nassim Taleb "[This] is the lesson of Taleb. and also the lesson of our volatile times. There is more courage and heroism in defying the human impulse, in taking the purposeful and painful steps to prepare for the unimaginable."--Malcolm Gladwell, author of The Tipping Point "[Taleb writes] in a style that owes as much to Stephen Colbert as it does to Michel de Montaigne."--The Wall Street Journal "The most prophetic voice of all. [Taleb is] a genuinely significant philosopher. someone who is able to change the way we view the structure of the world through the strength, originality and veracity of his ideas alone."--GQ "Changed my view of how the world works."--Daniel Kahneman, Nobel laureate"-- "Examples of Antifragility: When you stress your body by lifting a big weight, your body gets stronger. New York has the best restaurants in the world because particular restaurants are always going bust, making the aggregate stronger and stronger, or antifragile. Evolution is antifragile. Certain business and investment strategies are antifragile. Older things tend to be more antifragile than newer ones - because they''ve been exposed to more Black Swans', '["Resilience (Personality trait)", "PSYCHOLOGY / General", "BUSINESS & ECONOMICS / General", "Long Now Manual for Civilization", "Social aspects", "Uncertainty (Information theory)", "Forecasting", "Complexity (Philosophy)", "Psychological Resilience", "Psychological Adaptation", "Uncertainty", "Adjustment (psychology)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (87, 'the-martian', 'The Martian', 'A Novel', 'Science Fiction & Fiction', 1, 2011, 384, '9780804139021', '/works/OL17091839W', 'The Martian is a 2011 science fiction novel written by Andy Weir. It was his debut novel under his own name. It was originally self-published in 2011; Crown Publishing purchased the rights and re-released it in 2014. The story follows an American astronaut, Mark Watney, as he becomes stranded alone on Mars in 2035 and must improvise in order to survive.', '["Science-Fiction", "Science Fiction & Fantasy", "Suspense & Thriller", "Science fiction", "Amerikanisches Englisch", "Astronauts", "Survival", "Survival skills", "Supervivencia", "Novela", "Astronautas", "Reading Level-Grade 7"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (88, 'a-history-of-god', 'A History of God', 'The 4,000-Year Quest of Judaism, Christianity and Islam', 'History & Economics', 0, 1993, 528, '9780099273677', '/works/OL3280815W', 'As soon as they became recognizably human, men and women - in their hunger to understand their own presence on earth and the mysteries within and around them - began to worship gods. Karen Armstrong''s masterly and illuminating book explores the ways in which the idea and experience of God evolved among the monotheists - Jews, Christians and Muslims. Weaving a multicolored fabric of historical, philosophical, intellectual and social developments and insights, Armstrong shows how, at various times through the centuries, each of the monotheistic religions has held a subtly different concept of God. At the same time she draws our attention to the basic and profound similarities among them, making it clear that in all of them God has been and is experienced intensely, passionately and often - especially in the West - traumatically. Some monotheists have seen darkness, desolation and terror, where others have seen light and transfiguration; the reasons for these inherent differences are examined, and the people behind them are brought to life. We look first at the gradual move away from the pagan gods to the full-fledged monotheism of the Jews during the exile in Babylon. Next considered is the development of parallel, yet different, perceptions and beliefs among Christians and Muslims. The book then moves "generationally" through time to examine the God of the philosophers and mystics in all three traditions, the God of the Reformation, the God of the Enlightenment and finally the nineteenth- and twentieth-century challenges of skeptics and atheists, as well as the fiercely reductive faith of the fundamentalists of our own day. Armstrong suggests that any particular idea of God must - if it is to survive - work for the people who develop it, and that ideas of God change when they cease to be effective. She argues that the concept of a personal God who behaves like a larger version of ourselves was suited to mankind at a certain stage but no longer works for an increasing number of people. Understanding the ever-changing ideas of God in the past and their relevance and usefulness in their time, she says, is a way to begin the search for a new concept for the twenty-first century. Her book shows that such a development is virtually inevitable, in spite of the despair of our increasingly "Godless" world, because it is a natural aspect of our humanity to seek a symbol for the ineffable reality that is universally perceived.', '["Biblical teaching", "Comparative studies", "Dios", "Dios (Islamismo)", "Dios (Judaísmo)", "Doctrinas", "Doctrines", "Enseñanza bíblica", "Estudios comparados", "God", "God (Islam)", "God (Judaism)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (89, 'quiet', 'Quiet', 'The Power of Introverts in a World That Can''t Stop Talking', 'Brain & Psychology', 0, 2012, 368, '9780606320825', '/works/OL16484595W', 'Passionately argued, impressively researched, and filled with indelible stories of real people, Quiet shows how dramatically we undervalue introverts, and how much we lose in doing so. Taking the reader on a journey from Dale Carnegie''s birthplace to Harvard Business School, from a Tony Robbins seminar to an evangelical megachurch, Susan Cain charts the rise of the Extrovert Ideal in the twentieth century and explores its far-reaching effects. She talks to Asian-American students who feel alienated from the brash, backslapping atmosphere of American schools. She questions the dominant values of American business culture, where forced collaboration can stand in the way of innovation, and where the leadership potential of introverts is often overlooked. And she draws on cutting-edge research in psychology and neuroscience to reveal the surprising differences between extroverts and introverts. Perhaps most inspiring, she introduces us to successful introverts–from a witty, high-octane public speaker who recharges in solitude after his talks, to a record-breaking salesman who quietly taps into the power of questions. Finally, she offers invaluable advice on everything from how to better negotiate differences in introvert-extrovert relationships to how to empower an introverted child to when it makes sense to be a "pretend extrovert." This extraordinary book has the power to permanently change how we see introverts and, equally important, how introverts see themselves. - Publisher.', '["Extraversion", "Introverts", "Interpersonal relations", "Introversion", "New York Times bestseller", "nyt:combined_print_nonfiction=2012-03-03", "Reading Level-Grade 11", "Reading Level-Grade 12", "Self-actualization (psychology)", "Temperament", "Popular Works", "Psychological Introversion"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (90, 'powering-the-dream', 'Powering the Dream', 'The History and Promise of Green Technology', 'Technology', 0, 2011, NULL, '9780306819773', '/works/OL17803533W', NULL, '["Renewable energy sources", "Environmental engineering", "Research", "Popular works", "Forecasting", "Sustainable engineering"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (91, 'the-emperor-of-all-maladies', 'The Emperor of All Maladies', NULL, 'Health & Medicine', 0, 2010, 712, '9780007367481', '/works/OL15540668W', 'The Emperor of All Maladies: A Biography of Cancer is a book written by Siddhartha Mukherjee, an Indian-born American physician and oncologist. Published on 16 November 2010 by Scribner, it won the 2011 Pulitzer Prize for General Non-Fiction.', '["medical history", "social sciences", "civilization", "oncology", "Cancer", "nyt:paperback_nonfiction=2011-08-27", "research", "New York Times bestseller", "medicine", "Leukemia", "Antineoplastic Agents", "drug therapy"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (92, 'behind-the-beautiful-forevers', 'Behind the Beautiful Forevers', NULL, 'Current Events & People', 0, 2011, 290, '9780679643951', '/works/OL16262891W', 'The dramatic and sometimes heartbreaking story of families striving toward a better life in one of the twenty-first century''s great, unequal cities. In this fast-paced book, based on three years of uncompromising reporting, a bewildering age of global change and inequality is made human. Annawadi is a makeshift settlement in the shadow of luxury hotels near the Mumbai airport, and as India starts to prosper, Annawadians are electric with hope. Abdul, a reflective and enterprising Muslim teenager, sees fortune in the recyclable garbage of richer people. Asha, a woman of formidable wit and deep scars from a rural childhood, has identified an alternate route to the middle class: political corruption. And even the poorest Annawadians, like Kalu, a fifteen-year-old scrap-metal thief, believe themselves inching closer to good times. But then, as the tenderest individual hopes intersect with the greatest global truths, the true contours of a competitive age are revealed.', '["Urban poor", "New York Times bestseller", "Creative nonfiction", "nyt:hardcover_political_books=2012-02-25", "Poor", "Slums", "Economic conditions", "Social conditions", "Poverty", "Social classes", "Fattiga", "Armut"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (93, 'this-machine-kills-secrets', 'This Machine Kills Secrets', 'How WikiLeakers, Cypherpunks, and Hacktivists Aim to Free the World''s Information', 'Current Events & People', 0, 2012, 384, '9780142180495', '/works/OL16499532W', 'Who Are The Cypherpunks? This is the unauthorized telling of the revolutionary cryptography story behind the motion picture The Fifth Estate in theatres this October, and We Steal Secrets: The Story of Wikileaks, a documentary out now. WikiLeaks brought to light a new form of whistleblowing, using powerful cryptographic code to hide leakers’ identities while they spill the private data of government agencies and corporations. But that technology has been evolving for decades in the hands of hackers and radical activists, from the libertarian enclaves of Northern California to Berlin to the Balkans. And the secret-killing machine continues to evolve beyond WikiLeaks, as a movement of hacktivists aims to obliterate the world’s institutional secrecy. Forbes journalist Andy Greenberg has traced its shadowy history from the cryptography revolution of the 1970s to Wikileaks founding hacker Julian Assange, Anonymous, and beyond. This is the story of the code and the characters—idealists, anarchists, extremists—who are transforming the next generation’s notion of what activism can be. With unrivaled access to such major players as Julian Assange, Daniel Domscheit-Berg, and WikiLeaks’ shadowy engineer known as the Architect, never before interviewed, Greenberg unveils the world of politically-motivated hackers—who they are and how they operate.', '["Computer hackers", "Whistleblowing", "Official secrets", "Computer crimes", "Secrecy", "Political activity", "World Wide Web", "Hackers", "Whistle blowing", "Informationsfreiheit", "Assange, julian, 1971-", "Wikileaks (organization)"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (94, 'the-real-north-korea', 'The Real North Korea', 'Life and Politics in the Failed Stalinist Utopia', 'Current Events & People', 0, 2013, 283, '9780199964291', '/works/OL17643839W', 'In The Real North Korea, Lankov substitutes cold, clear analysis for the overheated rhetoric surrounding this opaque state. After providing an accessible history of the nation, he turns his focus to what North Korea is, what its leadership thinks, and how its people cope with living in such an oppressive and impoverished place. He argues that North Korea is not irrational, and nothing shows this better than its continuing survival against all odds. A living political fossil, it clings to existence in the face of limited resources and a zombie economy, manipulating great powers despite its weakness. Its leaders are not ideological zealots or madmen, but perhaps the best practitioners of Machiavellian politics that can be found in the modern world. Even though they preside over a failed state, they have successfully used diplomacy - including nuclear threats - to extract support from other nations. But while the people in charge have been ruthless and successful in holding on to power, Lankov contends that this cannot continue forever. The old system is slowly falling apart, and in the long run the regime is unsustainable - with or without reform. Indeed, reforms, if attempted, will most likely trigger a dramatic implosion of the regime. They will not prolong its existence.', '["Politics and government", "Foreign relations", "Political culture", "Communism", "Korea (north), politics and government", "Korea, foreign relations"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (95, 'the-joy-of-x', 'The Joy of x', 'A Guided Tour of Math, from One to Infinity', 'Science and Math', 0, 2012, 336, '9781848878433', '/works/OL16681334W', 'Many people take math in high school and promptly forget much of it. But math plays a part in all of our lives all of the time, whether we know it or not. In The Joy of x, Steven Strogatz expands on his hit New York Times series to explain the big ideas of math gently and clearly, with wit, insight, and brilliant illustrations. Whether he is illuminating how often you should flip your mattress to get the maximum lifespan from it, explaining just how Google searches the internet, or determining how many people you should date before settling down, Strogatz shows how math connects to every aspect of life. Discussing pop culture, medicine, law, philosophy, art, and business, Strogatz is the math teacher you wish you’d had. Whether you aced integral calculus or aren’t sure what an integer is, you’ll find profound wisdom and persistent delight in The Joy of x.', '["Mathematics", "Mathematics, popular works", "Popular works", "MATHEMATICS / General", "award:euler_book_prize"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (96, 'the-willpower-instinct', 'The Willpower Instinct', 'How Self-Control Works, Why It Matters, and What You Can Do To Get More of It', 'Brain & Psychology', 0, 2011, 288, '9781583335086', '/works/OL16184230W', 'The first book to explain the new science of self-control and how it can be harnessed to improve our health, happiness, and productivity. After years of watching her students struggling with their choices, health psychologist Kelly McGonigal, Ph.D., realized that much of what people believe about willpower is actually sabotaging their success. Committed to sharing what the scientific community already knew about self-control, McGonigal created a course called "The Science of Willpower" for Stanford University''s Continuing Studies Program. The course was an instant hit and spawned the hugely successful Psychology Today blog with the same name. Informed by the latest research and combining cutting-edge insights from psychology, economics, neuroscience, and medicine, McGonigal''s book explains exactly what willpower is, how it works, and why it matters. Readers will learn: Willpower is a mind-body response, not a virtue. It is a biological function that can be improved through mindfulness, exercise, nutrition, and sleep. People who have better control of their attention, emotions, and actions are healthier, happier, have more satisfying relationships, and make more money. Willpower is not an unlimited resource. Too much self-control can actually be bad for your health. Temptation and stress hijack the brain''s systems of self-control, and that the brain can be trained for greater willpower. In the groundbreaking tradition of Getting Things Done, The Willpower Instinct combines life-changing prescriptive advice and complementary exercises to help readers with goals ranging from a healthier life to more patient parenting, from greater productivity at work to finally finishing the basement.', '["Will", "Self-control", "SELF-HELP", "Self-Management", "Time Management", "PSYCHOLOGY", "Applied Psychology", "Motivation", "Volition", "Erfolg", "Selbstkontrolle", "Volonté"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (97, 'the-signal-and-the-noise', 'The Signal and the Noise', 'Why So Many Predictions Fail-but Some Don''t', 'Brain & Psychology', 0, 2012, 656, '9780606368056', '/works/OL16700318W', 'Nate Silver built an innovative system for predicting baseball performance, predicted the 2008 election within a hair’s breadth, and became a national sensation as a blogger—all by the time he was thirty. The New York Times now publishes FiveThirtyEight.com, where Silver is one of the nation’s most influential political forecasters. Drawing on his own groundbreaking work, Silver examines the world of prediction, investigating how we can distinguish a true signal from a universe of noisy data. Most predictions fail, often at great cost to society, because most of us have a poor understanding of probability and uncertainty. Both experts and laypeople mistake more confident predictions for more accurate ones. But overconfidence is often the reason for failure. If our appreciation of uncertainty improves, our predictions can get better too. This is the “prediction paradox”: The more humility we have about our ability to make predictions, the more successful we can be in planning for the future. In keeping with his own aim to seek truth from data, Silver visits the most successful forecasters in a range of areas, from hurricanes to baseball, from the poker table to the stock market, from Capitol Hill to the NBA. He explains and evaluates how these forecasters think and what bonds they share. What lies behind their success? Are they good—or just lucky? What patterns have they unraveled? And are their forecasts really right? He explores unanticipated commonalities and exposes unexpected juxtapositions. And sometimes, it is not so much how good a prediction is in an absolute sense that matters but how good it is relative to the competition. In other cases, prediction is still a very rudimentary—and dangerous—science. Silver observes that the most accurate forecasters tend to have a superior command of probability, and they tend to be both humble and hardworking. They distinguish the predictable from the unpredictable, and they notice a thousand little details that lead them closer to the truth. Because of their appreciation of probability, they can distinguish the signal from the noise. With everything from the health of the global economy to our ability to fight terrorism dependent on the quality of our predictions, Nate Silver’s insights are an essential read.', '["Bayesian statistical decision theory", "Theory of Knowledge", "Forecasting", "Methodology", "Knowledge, theory of", "nyt:combined-print-and-e-book-nonfiction=2012-10-14", "New York Times bestseller", "Economics", "POLITICAL SCIENCE", "Bayes-Entscheidungstheorie", "Prognose", "Prévision"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (98, 'to-say-nothing-of-the-dog', 'To Say Nothing of the Dog', NULL, 'Science Fiction & Fiction', 1, 1997, 512, '9781399617192', '/works/OL14858392W', 'Connie Willis'' entertaining comedy inspired by Jerome K. Jerome''s [Three Men in a Boat (to say nothing of the dog)][1]. [Robert A. Heinlein][2] mentioned the earlier work in [Have Spacesuit will Travel][3] as Kip''s father''s favorite.', '["Hugo Award Winner", "award:hugo_award=1999", "award:hugo_award=novel", "Time travel", "Fiction, science fiction, general", "Fiction, historical, general", "England, fiction", "Fantasy", "Science Fiction", "Fiction, historical", "Large type books", "American Fantasy fiction"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (99, 'liars-and-outliers', 'Liars and Outliers', 'Enabling the Trust that Society Needs to Thrive', 'Brain & Psychology', 0, 2012, 366, '9781118143308', '/works/OL16626501W', 'In today''s hyper-connected society, understanding the mechanisms of trust is crucial. Issues of trust are critical to solving problems as diverse as corporate responsibility, global warming, and the political system. In this insightful and entertaining book, Schneier weaves together ideas from across the social and biological sciences to explain how society induces trust. He shows the unique role of trust in facilitating and stabilizing human society. He discusses why and how trust has evolved, why it works the way it does, and the ways the information society is changing everything. - Publisher.', '["Interpersonal relations", "Sociology", "Social stability", "Social aspects", "Trust", "Social interaction", "Truthfulness and falsehood", "Gesellschaft", "Vertrauen", "Wirtschaft"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (100, 'join-the-club', 'Join the Club', 'How Peer Pressure Can Transform the World', 'Brain & Psychology', 0, 2011, 402, '9781848313002', '/works/OL15686817W', 'This book identifies a brewing social revolution that is changing the way people live, based on harnessing the positive force of peer pressure, and shows how peer pressure has reduced teen smoking in the United States, made villages in India healthier and more prosperous, helped minority students get top grades in college calculus, and even led to the fall of Slobodan Milosevic.', '["Peer pressure", "Social groups", "Social change", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (101, 'flagrant-conduct', 'Flagrant Conduct', 'The Story of Lawrence v. Texas', 'Politics & Social Sciences', 0, 2012, 384, '9780393081961', '/works/OL16299424W', 'No one could have predicted that the night of September 17, 1998, would be anything but routine in Houston, Texas. Even the call to police that a black man was "going crazy with a gun" was hardly unusual in this urban setting. Nobody could have imagined that the arrest of two men for a minor criminal offense would reverberate in American constitutional law, exposing a deep malignity in our judicial system and challenging the traditional conception of what makes a family. Indeed, when Harris County sheriff’s deputies entered the second-floor apartment, there was no gun. Instead, they reported that they had walked in on John Lawrence and Tyron Garner having sex in Lawrence’s bedroom. So begins Dale Carpenter’s "gripping and brilliantly researched" Flagrant Conduct, a work nine years in the making that transforms our understanding of what we thought we knew about Lawrence v. Texas, the landmark Supreme Court decision of 2003 that invalidated America’s sodomy laws. Drawing on dozens of interviews, Carpenter has taken on the "gargantuan" task of extracting the truth about the case, analyzing the claims of virtually every person involved. Carpenter first introduces us to the interracial defendants themselves, who were hardly prepared "for the strike of lightning" that would upend their lives, and then to the Harris County arresting officers, including a sheriff’s deputy who claimed he had "looked eye to eye" in the faces of the men as they allegedly fornicated. Carpenter skillfully navigates Houston’s complex gay world of the late 1990s, where a group of activists and court officers, some of them closeted themselves, refused to bury what initially seemed to be a minor arrest. The author charts not only the careful legal strategy that Lambda Legal attorneys adopted to make the case compatible to a conservative Supreme Court but also the miscalculations of the Houston prosecutors who assumed that the nation’s extant sodomy laws would be upheld. Masterfully reenacting the arguments that riveted spectators and Justices alike in 2003, Flagrant Conduct then reaches a point where legal history becomes literature, animating a Supreme Court decision as few writers have done. In situating Lawrence v. Texas within the larger framework of America’s four-century persecution of gay men and lesbians, Flagrant Conduct compellingly demonstrates that gay history is an integral part of our national civil rights story.', '["Gays", "Homosexuality", "Trials, litigation", "Texas", "Criminal provisions", "Law and legislation", "Trials (Sodomy)", "Legal status, laws", "NEW LIST 20120331", "Trials", "Trials, united states", "Homosexuality, law and legislation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (102, 'a-canticle-for-leibowitz', 'A Canticle for Leibowitz', NULL, 'Science Fiction & Fiction', 1, 1959, 294, '9780553121803', '/works/OL2626638W', 'Highly unusual After the Holocaust novel. In the far future, 20th century texts are preserved in a monastery, as "sacred books". The monks preserve for centuries what little science there is, and have saved the science texts and blueprints from destruction many times, also making beautifully illuminated copies. As the story opens to a world run on a basically fuedal lines, science is again becoming fashionable, as a hobby of rich men, at perhaps 18th or early 19th century level of comprehesion. A local lord, interested in science, comes to the monastery. What happens after that is an exquisitely told tale, stunning and extremely moving, totally different from any other After the Holocaust story', '["Hugo Award Winner", "award:hugo_award=1961", "award:hugo_award=novel", "American Science fiction", "apocalypse", "nuclear war", "civilization", "science fiction", "church versus state", "Long Now Manual for Civilization", "Monks", "Monasticism and religious orders"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (103, 'the-mystery-of-banking', 'The Mystery of Banking', NULL, 'History & Economics', 0, 2012, 168, '9781388173838', '/works/OL34894655W', NULL, '["Money", "Banks and banking"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (104, 'count-zero', 'Count Zero', NULL, 'Science Fiction & Fiction', 1, 1986, 320, '9781473217409', '/works/OL27256W', 'Turner, corporate mercenary, wakes in a reconstructed body, a beautiful woman by his side. Then Hosaka Corporation reactivates him for a mission more dangerous than the one he''s recovering from: Maas-Neotek''s chief of R&D is defecting. Turner is the one assigned to get him out intact, along with the biochip he''s perfected. But this proves to be of supreme interest to certain other parties--some of whom aren''t remotely human. Bobby Newmark is entirely human: a rustbelt data-hustler totally unprepared for what comes his way when the defection triggers war in cyberspace. With voodoo on the Net and a price on his head, Newmark thinks he''s only trying to get out alive. The second novel of William Gibson''s Sprawl trilogy, *Count Zero* is a stylish, streetsmart, frighteningly probable parable of the future and sequel to Neuromancer.', '["Long Now Manual for Civilization", "Fiction, mystery & detective, general", "American literature", "Fiction, science fiction, general", "Sprawl Trilogy", "Virtual reality", "Cyberspace", "Matrix (Imaginary place)", "genre:cyberpunk"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (105, 'thinking-fast-and-slow', 'Thinking Fast and Slow', NULL, 'Brain & Psychology', 0, 2011, 400, '9781535535830', '/works/OL15992072W', 'In his mega bestseller, Thinking, Fast and Slow, Daniel Kahneman, world-famous psychologist and winner of the Nobel Prize in Economics, takes us on a groundbreaking tour of the mind and explains the two systems that drive the way we think. System 1 is fast, intuitive, and emotional; System 2 is slower, more deliberative, and more logical. The impact of overconfidence on corporate strategies, the difficulties of predicting what will make us happy in the future, the profound effect of cognitive biases on everything from playing the stock market to planning our next vacation―each of these can be understood only by knowing how the two systems shape our judgments and decisions. Engaging the reader in a lively conversation about how we think, Kahneman reveals where we can and cannot trust our intuitions and how we can tap into the benefits of slow thinking. He offers practical and enlightening insights into how choices are made in both our business and our personal lives―and how we can use different techniques to guard against the mental glitches that often get us into trouble. Topping bestseller lists for almost ten years, Thinking, Fast and Slow is a contemporary classic, an essential book that has changed the lives of millions of readers.', '["Intuition", "Thought and thinking", "Reasoning", "Decision making", "New York Times bestseller", "Long Now Manual for Civilization", "Thinking", "Kognition", "77.32 intelligence, creativity", "New York Times reviewed", "Reason", "Cognition"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (106, 'the-most-human-human', 'The Most Human Human', 'What Talking with Computers Teaches Us About What It Means to Be Alive', 'Brain & Psychology', 0, 2011, 320, '9780385533065', '/works/OL16163232W', '"The Most Human Human" is a provocative exploration of the ways in which computers are reshaping our ideas of what it means to be human. Its starting point is the annual Turing Test, which pits artificial intelligence programs against people to determine if computers can "think."', '["Human beings", "Turing test", "Philosophical anthropology", "PHILOSOPHY", "Humanism", "Movements"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (107, 'republic-lost', 'Republic, Lost', 'How Money Corrupts Congress and a Plan to Stop It', 'Politics & Social Sciences', 0, 2011, 370, '9781306756686', '/works/OL16202595W', 'In an era when special interests funnel huge amounts of money into our government—driven by shifts in campaign-finance rules and brought to new levels by the Supreme Court in Citizens United v. Federal Election Commission—trust in our government has reached an all-time low. More than ever before, Americans believe that money buys results in Congress, and that business interests wield control over our legislature. With heartfelt urgency and a keen desire for righting wrongs, Harvard law professor Lawrence Lessig takes a clear-eyed look at how we arrived at this crisis: how fundamentally good people, with good intentions, have allowed our democracy to be co-opted by outside interests, and how this exploitation has become entrenched in the system. Rejecting simple labels and reductive logic—and instead using examples that resonate as powerfully on the Right as on the Left—Lessig seeks out the root causes of our situation. He plumbs the issues of campaign financing and corporate lobbying, revealing the human faces and follies that have allowed corruption to take such a foothold in our system. He puts the issues in terms that nonwonks can understand, using real-world analogies and real human stories. And ultimately he calls for widespread mobilization and a new Constitutional Convention, presenting achievable solutions for regaining control of our corrupted—but redeemable—representational system. In this way, Lessig plots a roadmap for returning our republic to its intended greatness. While America may be divided, Lessig vividly champions the idea that we can succeed if we accept that corruption is our common enemy and that we must find a way to fight against it. In REPUBLIC, LOST, he not only makes this need palpable and clear—he gives us the practical and intellectual tools to do something about it. *Source:* [Twelve Books][1]', '["Politics and government", "Lobbying", "Corrupt practices", "United States", "Political corruption", "United States. Congress", "Ethics", "Campaign funds", "Korruption", "USA", "Kongress", "USA Congress"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (108, 'darwin-s-radio', 'Darwin''s Radio', NULL, 'Science Fiction & Fiction', 1, 1999, 488, '9780345464927', '/works/OL16508W', '"Virus hunter" Christopher Dicken is a man on a mission, following a trail of rumors, government cover-ups, and dead bodies around the globe in search of a mysterious disease that strikes only pregnant women and invariably results in miscarriage. But when Dicken finds what he''s looking for, the answer proves to be stranger--and far deadlier--than he ever could have imagined. Something that has slept in human DNA for millions of years is waking up.Molecular biologist Kaye Lang has spent her career tracing ancient retroviruses in the human genome. She believes these microscopic fossils can come to life again. But when Dicken''s discovery becomes public, Lang''s theory suddenly turns to chilling fact. As the outbreak of this terrifying disease threatens to become a deadly epidemic, Dicken and Lang must race against time to assemble the pieces of a puzzle only they are equipped to solve--an evolutionary puzzle that will determine the future of the human race . . . if a future exists at all.', '["Women molecular biologists", "DNA viruses", "Science Fiction", "Human evolution", "Evolution", "Viruses", "Evolution (Biology)", "Fiction, thrillers, general", "Fiction, medical", "award:nebula_award=novel", "Fiction, general", "Fiction, science fiction, general"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (109, 'the-selfish-gene', 'The Selfish Gene', NULL, 'Science and Math', 0, 1976, 352, '9780195690668', '/works/OL1966488W', 'As influential today as when it was first published, The Selfish Gene has become a classic exposition of evolutionary thought. Professor Dawkins articulates a gene''s eye view of evolution - a view giving centre stage to these persistent units of information, and in which organisms can be seen as vehicles for their replication. This imaginative, powerful, and stylistically brilliant work not only brought the insights of Neo-Darwinism to a wide audience, but galvanized the biology community, generating much debate and stimulating whole new areas of research. Forty years later, its insights remain as relevant today as on the day it was published. This 40th anniversary edition includes a new epilogue from the author discussing the continuing relevance of these ideas in evolutionary biology today, as well as the original prefaces and foreword, and extracts from early reviews. Oxford Landmark Science books are ''must-read'' classics of modern science writing which have crystallized big ideas, and shaped the way we think.', '["Evolution (Biology)", "Genetics", "Sociobiology", "Behavior genetics", "Genetica", "Etologia Animal", "Genetics.\u001e 0", "Long Now Manual for Civilization", "Natural selection", "Sociobiologie", "Évolution (biologie)", "Memen"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (110, 'the-checklist-manifesto', 'The Checklist Manifesto', 'How to Get Things Right', 'Brain & Psychology', 0, 2010, 209, '9780143423225', '/works/OL15436462W', 'Reveals the surprising power of the ordinary checklist now being used in medicine, aviation, the armed services, homeland security, investment banking, skyscraper construction, and businesses of all kinds.', '["Listes", "Emergency Medicine", "Clinical Competence", "Qualité", "Lists", "Quality control", "Soins médicaux", "Contrôle", "nyt:paperback_business_books=2012-02-25", "New York Times bestseller", "Medical care", "Intensive Care Units"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (111, 'ant-encounters', 'Ant Encounters', 'Interaction Networks and Colony Behavior', 'Science and Math', 0, 2010, 167, '9780691138794', '/works/OL12762964W', NULL, '["Insect societies", "Ants", "Behavior", "Insects, behavior", "Animal Behavior"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (112, 'never-let-me-go', 'Never Let Me Go', NULL, 'Science Fiction & Fiction', 1, 2005, 296, '9780571328475', '/works/OL59038W', 'Ishiguro explores what it means to have a soul and how art distinguishes man from other life forms. But above all, *Never Let Me Go* is a study of friendship and the bonds we form which make or break while we come of age.', '["Organ donors", "Cloning", "Donation of organs, tissues", "Women", "New York Times bestseller", "nyt:trade_fiction_paperback=2010-09-05", "Human cloning", "Science fiction", "Fiction, psychological", "Fiction, science fiction, general", "England, fiction", "Large type books"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (113, 'triumph-of-the-city', 'Triumph of the City', 'How Our Greatest Invention Makes Us Richer, Smarter, Greener, Healthier, and Happier', 'Politics & Social Sciences', 0, 2011, 456, '9780330458078', '/works/OL19873317W', '**A pioneering urban economist offers fascinating, even inspiring proof that the city is humanity''s greatest invention and our best hope for the future.** America is an urban nation. More than two thirds of us live on the 3 percent of land that contains our cities. Yet cities get a bad rap: they''re dirty, poor, unhealthy, crime ridden, expensive, environmentally unfriendly... Or are they? As Edward Glaeser proves in this myth-shattering book, cities are actually the healthiest, greenest, and richest (in cultural and economic terms) places to live. New Yorkers, for instance, live longer than other Americans; heart disease and cancer rates are lower in Gotham than in the nation as a whole. More than half of America''s income is earned in twenty-two metropolitan areas. And city dwellers use, on average, 40 percent less energy than suburbanites. Glaeser travels through history and around the globe to reveal the hidden workings of cities and how they bring out the best in humankind. Even the worst cities-Kinshasa, Kolkata, Lagos- confer surprising benefits on the people who flock to them, including better health and more jobs than the rural areas that surround them. Glaeser visits Bangalore and Silicon Valley, whose strangely similar histories prove how essential education is to urban success and how new technology actually encourages people to gather together physically. He discovers why Detroit is dying while other old industrial cities-Chicago, Boston, New York-thrive. He investigates why a new house costs 350 percent more in Los Angeles than in Houston, even though building costs are only 25 percent higher in L.A. He pinpoints the single factor that most influences urban growth-January temperatures-and explains how certain chilly cities manage to defy that link. He explains how West Coast environmentalists have harmed the environment, and how struggling cities from Youngstown to New Orleans can "shrink to greatness." And he exposes the dangerous anti-urban political bias that is harming both cities and the entire country. Using intrepid reportage, keen analysis, and eloquent argument, Glaeser makes an impassioned case for the city''s import and splendor. He reminds us forcefully why we should nurture our cities or suffer consequences that will hurt us all, no matter where we live. (*Source: Penguin Press blurb*)', '["Long Now Manual for Civilization", "Urban economics", "Urbanisation", "Cities and towns", "Urbanization", "Stedelijke economie", "Forensisme", "Villes", "Urban sociology", "Stadtentwicklung", "Stadtökonomie", "Stadtsoziologie"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (114, 'the-master-switch', 'The Master Switch', 'The Rise and Fall of Information Empires', 'Technology', 0, 2010, 388, '9780307269935', '/works/OL15118227W', 'In this age of an open internet, it is easy to forget that every American information industry, beginning with the telephone, has eventually been taken captive by some ruthless monopoly or cartel. With all our media now traveling a single network, an unprecedented potential is building for centralized control over what Americans see and hear. Could history repeat itself with the next industrial consolidation? Could the internet- the entire flow of American information- come to be ruled by one corporate leviathan in possession of "the master switch"? That is the big question that the author presents in this pathbreaking book. As Wu''s sweeping history shows, each of the new media of the twentieth century- radio, telephone, television, and film- was born free and open. Each invited unrestricted use and enterprising experiment until some would-be mogul battled his way to total domination. Explaining how invention begets industry and industry begets empire- a progress often blessed by government, typically with stifling consequences for free expression and technical innovation alike- Wu identifies a time-honored pattern in the maneuvers of today''s great information powers: Apple, Goggle, and an eerily resurgent AT & T.A battle royal looms for the internet''s future, and with almost every aspect of our lives now dependent on that network, this is one war we dare not tune out. Part industrial expose, part meditation of what freedom requires in the information age, this book is a stirring illumination of a drama that has played out over decades in the shadows of our national life and now culminates with terrifying implications for our future. -- from Book Jacket.', '["Telecommunication", "Information technology", "Long Now Manual for Civilization", "Telecommunication -- History", "Histoire", "Telecommunicatie", "Informationswirtschaft", "Informatiemaatschappij", "Massmedia", "Mass media", "Internet", "Monopol"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (115, 'in-a-sunburned-country', 'In a Sunburned Country', NULL, 'Travel & Memoir', 0, 2000, 411, '9781409095644', '/works/OL74115W', '*In a Sunburned Country* is the 2000 travelogue book about Australia written by best-selling travel writer Bill Bryson. The title is taken from the famous Australian poem, "My Country". In other countries, including Britain, the book was titled *Down Under*. In this book, Bill Bryson describes his travels by railway and car throughout Australia, his conversations with people in all walks of life about the history, geography, unusual plants and animals of the country, and his wry impressions of the life, culture and amenities (or lack thereof) in each locality. In a style similar to his book *A Walk in the Woods*, Bryson''s research enabled him to include many stories about Australia''s 19th-century explorers and settlers who suffered extreme deprivations, as well as details about its natural resources, culture, and economy. His writings are intertwined with recurring humorous themes, notably, in the chapter Crossing Australia he makes constant reference to drinking of urine to survive, as was done by many 19th century explorers.', '["Social life and customs", "Description and travel", "Humour", "Journeys", "Travel", "Civilization", "Australia", "Bill Bryson", "Description", "Large type books", "Australia, social life and customs", "Australia, description and travel"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (116, 'hegemony-or-survival', 'Hegemony or Survival', 'America''s Quest for Global Dominance', 'Politics & Social Sciences', 0, 2003, 319, '9780241142509', '/works/OL71680W', 'From the world''s foremost intellectual activist, here is an irrefutable analysis of America''s pursuit of total domination and the catastrophic consequences that are sure to follow. The United States is in the process of staking out not just the globe, but the last unarmed spot in our neighbourhood - the skies - as a militarized sphere of influence. Our earth and its skies are, for the Bush administration, the final frontiers of imperial control. In Hegemony or Survival, Noam Chomsky explains how we came to this moment, what kind of peril we find ourselves in, and why our rulers are willing to jeopardize the future of our species. In our era, Chomsky argues, empire is a recipe for an earthly wasteland.', '["Imperialism", "War on Terrorism, 2001-2009", "State-sponsored terrorism", "Unilateral acts (International law)", "Ballistic missile defense system", "Military policy", "War on Terrorism, 2001-", "Intervention (International law)", "Foreign relations", "UNILATERAL ACTS OF STATES", "UNITED STATES", "Diplomatic relations"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (117, 'a-distant-mirror', 'A Distant Mirror', 'The Calamitous 14th Century', 'History & Economics', 0, 1979, 726, '9781439558577', '/works/OL3378547W', 'Amazon.com Review In this sweeping historical narrative, Barbara Tuchman writes of the cataclysmic 14th century, when the energies of medieval Europe were devoted to fighting internecine wars and warding off the plague. Some medieval thinkers viewed these disasters as divine punishment for mortal wrongs; others, more practically, viewed them as opportunities to accumulate wealth and power. One of the latter, whose life informs much of Tuchman''s book, was the French nobleman Enguerrand de Coucy, who enjoyed the opulence and elegance of the courtly tradition while ruthlessly exploiting the peasants under his thrall. Tuchman looks into such events as the Hundred Years War, the collapse of the medieval church, and the rise of various heresies, pogroms, and other events that caused medieval Europeans to wonder what they had done to deserve such horrors.', '["Nobleza", "Noblesse", "Biographies", "Histoire", "France", "Middle Ages", "Biography", "Ambassadors", "Soldiers", "Manners and customs", "Biografía", "Nobility"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (118, 'wetware', 'Wetware', 'A Computer in Every Living Cell', 'Science and Math', 0, 2009, 267, '9780300141733', '/works/OL16018523W', '"How does a single-cell creature, such as an amoeba, lead such a sophisticated life? How does it hunt living prey, respond to lights, sounds, and smells, and display complex sequences of movements without the benefit of a nervous system? This book offers a startling and original answer. The author taps the findings of the new discipline of systems biology to show that the internal chemistry of living cells is a form of computation. Cells are built out of molecular circuits that perform logical operations, as electronic devices do, but with unique properties. Bray argues that the computational juice of cells provides the basis of all the distinctive properties of living systems: it allows organisms to embody in their internal structure an image of the world, and this accounts for their adaptability, responsiveness, and intelligence."--Book jacket.', '["Cytology", "Cell interaction", "Molecular biology", "Computational biology", "Cell Biology", "Cell Physiological Phenomena"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (119, 'team-of-rivals', 'Team of Rivals', 'The Political Genius of Abraham Lincoln', 'History & Economics', 0, 2003, 1308, '9780141043722', '/works/OL1856010W', 'Team of Rivals: The Political Genius of Abraham Lincoln is a 2005 book by Pulitzer Prize-winning American historian Doris Kearns Goodwin, published by Simon & Schuster. The book is a biographical portrait of U.S. President Abraham Lincoln and some of the men who served with him in his cabinet from 1861 to 1865. Three of his Cabinet members had previously run against Lincoln in the 1860 election: Attorney General Edward Bates, Secretary of the Treasury Salmon P. Chase and Secretary of State William H. Seward. The book focuses on Lincoln''s mostly successful attempts to reconcile conflicting personalities and political factions on the path to abolition and victory in the American Civil War. Goodwin''s sixth book, Team of Rivals was well received by critics and won the 2006 Lincoln Prize and the inaugural Book Prize for American History of the New-York Historical Society. US President Barack Obama cited it as one of his favorite books and was said to have used it as a model for constructing his own cabinet, although he later wrote this was not the reason he chose Hillary Clinton as his Secretary of State. In 2012, a Steven Spielberg film based on the book was released to critical acclaim.', '["Union Army", "Thirteenth Amendment", "assassination of Abraham Lincoln", "secretary of war", "1864 presidential election", "Emancipation Proclamation", "secretary of state", "secretary of treasury", "United States Attorney General", "American Civil War", "Lincoln-Douglas debates", "Democratic Party"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (120, 'the-golden-age', 'The Golden Age', NULL, 'Science Fiction & Fiction', 1, 2002, 320, '9780812579840', '/works/OL5725219W', '"The Golden Age takes place 10,000 years in the future in our solar system, an interplanetary utopian society filled with immortal humans. Within the frame of a traditional tale - the one rebel who is unhappy in utopia - Wright spins an elaborate plot web filled with suspense and passion." "Phaethon, of Radamanthus House, is attending a glorious party at his family mansion to celebrate the thousand-year anniversary of the High Transcendence. There he meets first an old man who accuses him of being an impostor and then a being from Neptune who claims to be an old friend. The Neptunian tells him that essential parts of his memory were removed and stored by the very government that Phaethon believes to be wholly honorable. It shakes his faith. He is an exile from himself." And so Phaethon embarks upon a quest across the transformed solar system - Jupiter is now a second sun, Mars and Venus terraformed, humanity immortal - among humans, intelligent machines, and bizarre lifeforms that are partly both, to recover his memory, and to learn what crime he planned that warranted such preemptive punishment. His quest is to regain his true identity.', '["Science Fiction", "Space Travel in Fiction", "Fiction, romance, fantasy", "Fiction, science fiction, general", "Amnesia", "Extraterrestrial beings"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (121, 'don-t-make-me-think', 'Don''t Make Me Think', 'A Common Sense Approach to Web Usability', 'Technology', 0, 2000, 200, '9780321965516', '/works/OL8578577W', 'Yesterday''s Web looked far different from today''s Web, and tomorrow''s Web will look more different still. Amidst all of this change, however, one aspect of Web use remains the same: The sites that offer the best, easiest, most intuitive experience are the ones people visit again and again. To ensure that your sites provide that experience, this guide from usability guru Krug distills his years of on-the-job experience into a practical primer on the do''s and don''ts of good Web design. The second edition of this classic adds three new chapters that explain why people really leave Web sites, how to make sites usable and accessible, and the art of surviving executive design whims, plus a new preface and updated recommended reading.--From publisher description', '["Web sites", "Web site development", "Design", "Evaluation", "Publishing", "Internet", "Data Display", "Writing", "User-Computer Interface", "WORLD WIDE WEB", "Sites Web", "INTERNETS"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (122, 'creating-a-world-without-poverty', 'Creating a World without Poverty', 'How Social Business Can Transform Our Lives', 'Politics & Social Sciences', 0, 1999, 320, '9781586484934', '/works/OL1079340W', 'The winner of the Nobel Peace Prize outlines his vision for a new business model that combines the power of free markets with the quest for a more humane world--and he tells the inspiring stories of companies that are doing this work today. In the last two decades, free markets have swept the globe, bringing with them enormous potential for positive change. But traditional capitalism cannot solve problems like inequality and poverty, because it is hampered by a narrow view of human nature in which people are one-dimensional beings concerned only with profit. In fact, human beings have many other drives and passions, including the spiritual, the social, and the altruistic. Welcome to the world of social business, where the creative vision of the entrepreneur is applied to today''s most serious problems: feeding the poor, housing the homeless, healing the sick, and protecting the planet.--From publisher description.', '["Condiciones económicas", "Microcrédit", "Banques", "Histoire", "Conditions sociales", "Conditions économiques", "Pauvreté", "Développement économique et social", "Crédit bancaire", "Microfinance", "Banques populaires", "Débiteur et créancier"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (123, 'influence', 'Influence', 'The Psychology of Persuasion', 'Brain & Psychology', 0, 1983, 272, '9780320087318', '/works/OL3902892W', 'Influence, the classic book on persuasion, explains the psychology of why people say "yes"—and how to apply these understandings. Dr. Robert Cialdini is the seminal expert in the rapidly expanding field of influence and persuasion. His thirty-five years of rigorous, evidence-based research along with a three-year program of study on what moves people to change behavior has resulted in this highly acclaimed book. You''ll learn the six universal principles, how to use them to become a skilled persuader—and how to defend yourself against them. Perfect for people in all walks of life, the principles of Influence will move you toward profound personal change and act as a driving force for your success. Some images that appeared in the print edition of this book are unavailable in the electronic edition due to rights reasons.', '["Compliance", "Influence (Psychology)", "Persuasion (Psychology)", "Self-Improvement", "Persuasion (Psychologie)", "Influence (Psychologie)", "Sociale beïnvloeding", "Overreding", "Complaisance", "Communication", "Psychological aspects", "Beeinflussung"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (124, 'play', 'Play', 'How It Shapes the Brain, Opens the Imagination, and Invigorates the Soul', 'Brain & Psychology', 0, 2009, 229, '9781583333334', '/works/OL6431320W', 'From a leading expert, a groundbreaking book on the science of play, and its essential role in fueling our intelligence and happiness throughout our lives.We’ve all seen the happiness in the face of a child while playing in the school yard. Or the blissful abandon of a golden retriever racing with glee across a lawn. This is the joy of play. By definition, play is purposeless and all-consuming. And, most important, it’s fun.As we become adults, taking time to play feels like a guilty pleasure—a distraction from “real” work and life. But as Dr. Stuart Brown illustrates, play is anything but trivial. It is a biological drive as integral to our health as sleep or nutrition. In fact, our ability to play throughout life is the single most important factor in determining our success and happiness.Dr. Brown has spent his career studying animal behavior and conducting more than six thousand “play histories” of humans from all walks of life—from serial murderers to Nobel Prize winners. Backed by the latest research, Play explains why play is essential to our social skills, adaptability, intelligence, creativity, ability to problem solve, and more. Play is hardwired into our brains—it is the mechanism by which we become resilient, smart, and adaptable people.Beyond play’s role in our personal fulfillment, its benefits have profound implications for child development and the way we parent, education and social policy, business innovation, productivity, and even the future of our society. From new research suggesting the direct role of three-dimensional-object play in shaping our brains to animal studies showing the startling effects of the lack of play, Brown provides a sweeping look at the latest breakthroughs in our understanding of the importance of this behavior. A fascinating blend of cutting-edge neuroscience, biology, psychology, social science, and inspiring human stories of the transformative power of play, this book proves why play just might be the most important work we can ever do.', '["Mind and body", "Play", "Psychological aspects", "Psychological aspects of Play", "Psychology", "Self-Improvement", "Social aspects", "Social aspects of Play", "Spiel", "Psychologie", "Play and Playthings", "Play, psychological aspects"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (125, 'creativity', 'Creativity', 'Flow and the Psychology of Discovery and Invention', 'Brain & Psychology', 0, 1996, 464, '9780060928209', '/works/OL506563W', 'Creativity is about capturing those moments that make life worth living. The author''s objective is to offer an understanding of what leads to these moments, be it the excitement of the artist at the easel or the scientist in the lab, so that knowledge can be used to enrich people''s lives. Drawing on 100 interviews with exceptional people, from biologists and physicists to politicians and business leaders, poets and artists, as well as his 30 years of research on the subject, Csikszentmihalyi uses his famous theory to explore the creative process. He discusses such ideas as why creative individuals are often seen as selfish and arrogant, and why the tortured genius is largely a myth. Most important, he clearly explains why creativity needs to be cultivated and is necessary for the future of our country, if not the world.', '["Creative ability", "Creative thinking", "Psychology", "Creativity", "Bf408 .c77 1996", "Bf 408 c958 1997", "153.3/5"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (126, 'sustainable-energy-without-the-hot-air', 'Sustainable Energy Without the Hot Air', NULL, 'Technology', 0, 2009, 384, '9781906860011', '/works/OL16797804W', 'Provides an overview of the sustainable energy crisis that is threatening the world''s natural resources, explaining how energy consumption is estimated and how those numbers have been skewed by various factors and discussing alternate forms of energy that can and should be used.', '["Energy Policy", "Environment", "Energy consumption", "Sustainable development", "Energy conservation", "Environmental aspects", "Energy industries", "Environmental policy", "Renewable energy sources", "Nachhaltigkeit", "Energies renouvelables", "Développement durable"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (127, 'the-china-study', 'The China Study', 'Startling Implications for Diet, Weight Loss and Long-Term Health', 'Health & Medicine', 0, 2004, 417, '9781932100389', '/works/OL15176142W', 'Referred to as the "Grand Prix of epidemiology" by The New York Times, this study examines more than 350 variables of health and nutrition with surveys from 6,500 adults in more than 2,500 counties across China and Taiwan, and conclusively demonstrates the link between nutrition and heart disease, diabetes, and cancer. While revealing that proper nutrition can have a dramatic effect on reducing and reversing these ailments as well as curbing obesity, this text calls into question the practices of many of the current dietary programs, such as the Atkins diet, that are widely popular in the West. The politics of nutrition and the impact of special interest groups in the creation and dissemination of public information are also discussed.', '["Health & Fitness", "Nutrition", "Nutritionally induced diseases", "diet in disease", "Methods", "Maladies d''origine nutritionnelle", "Food Habits", "Disease", "Diet", "Etiology", "Preventive Medicine", "Adverse effects"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (128, 'honest-signals', 'Honest Signals', 'How They Shape Our World', 'Science and Math', 0, 2008, 184, '9780262162562', '/works/OL11903988W', '"How can you know when someone is bluffing? Paying attention? Genuinely interested? The answer, writes Sandy Pentland in Honest Signals, is that subtle patterns in how we interact with other people reveal our attitudes toward them. These unconscious social signals are not just a back channel or a complement to our conscious language; they form a separate communication network. Biologically based "honest signaling," evolved from ancient primate signaling mechanisms, offers an unmatched window into our intentions, goals, and values. If we understand this ancient channel of communication, Pentland claims, we can accurately predict the outcomes of situations ranging from job interviews to first dates." "Pentland, an MIT professor, has used a specially designed digital sensor worn like an ID badge - a "sociometer"--To monitor and analyze the back-and-forth patterns of signaling among groups of people. He and his researchers found that this second channel of communication, revolving not around words but around social relations, profoundly Influences major decisions in our lives - even though we are largely unaware of it. Pentland presents the scientific background necessary for understanding this form of communication, applies it to examples of group behavior in real organizations, and shows how by "reading" our social networks we can become more successful at pitching an idea, getting a job, or closing a deal. Using this "network intelligence" theory of social signaling, Pentland describes how we can harness the intelligence of our social network to become better managers, workers, and communicators."--', '["Social psychology", "Social perception", "Social interaction", "Organizational behavior", "Business networks", "Communication", "Interpersonal Relations", "Réseau informatique", "Société (milieu humain)", "Comportement organisationnel", "Entreprise", "Internet"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (129, 'doomsday-book', 'Doomsday Book', NULL, 'Science Fiction & Fiction', 1, 1992, 559, '9780739487136', '/works/OL14858406W', 'Somewhere in the future, ordinary history students must travel back in time as part of their university degree. An award-winning best-seller in the United States, this is the first of Connie Willis'' brilliant Oxford trilogy.Kivrin knows everything about the Middle Ages - she''s read all the books. She knows it''s dangerous: cutthroats in the woods, witch hunts, cholera, and millions dying in the plague. For a young historian, it''s fascinating.When Kivrin''s tutors in Oxford''s history lab finally agree to send her on an on-site study trip, she jumps at the chance to observe medieval life first-hand. But a crisis that strangely links the past and future leaves her stranded in the most deadly and terrifying era in human history, face to face with the heart-rending reality behind the statistics. And while she fights for her own life, Kivrin finds she has become an unlikely angel of hope in this dark time.Five years in the writing, Doomsday Book is a storytelling triumph. Connie Willis draws upon her understanding of the universalities of human nature to explore the timeless issues of evil, suffering and the indomitable will of the human spirit.', '["Black Death", "Fantasy", "Hugo Award Winner", "Middle Ages", "Time travel", "award:hugo_award=1993", "award:hugo_award=novel", "Science fiction", "award:nebula_award=novel", "Fiction, science fiction, general", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (130, 'money-driven-medicine', 'Money-Driven Medicine', 'The Real Reason Health Care Costs So Much', 'Politics & Social Sciences', 0, 2006, 480, '9780061873829', '/works/OL274903W', 'Why is medical care in the United States so expensive? For decades, Americans have taken it as a matter of faith that we spend more because we have the best health care system in the world. But as costs levitate, that argument becomes more difficult to make. Today, we spend twice as much as Japan on health care — yet few would argue that our health care system is twice as good.Instead, startling new evidence suggests that one out of every three of our health care dollars is squandered on unnecessary or redundant tests; unproven, sometimes unwanted procedures; and overpriced drugs and devices that, too often, are no better than the less expensive products they have replaced.How did this happen? In Money-Driven Medicine, Maggie Mahar takes the reader behind the scenes of a $2 trillion industry to witness how billions of dollars are wasted in a Hobbesian marketplace that pits the industry''s players against each other. In remarkably candid interviews, doctors, hospital administrators, patients, health care economists, corporate executives, and Wall Street analysts describe a war of "all against all" that can turn physicians, hospitals, insurers, drugmakers, and device makers into blood rivals. Rather than collaborating, doctors and hospitals compete. Rather than sharing knowledge, drugmakers and device makers divide value. Rather than thinking about long-term collective goals, the imperatives of an impatient marketplace force health care providers to focus on short-term fiscal imperatives. And so investments in untested bleeding-edge medical technologies crowd out investments in information technology that might, in the long run, not only reduce errors but contain costs.In theory, free market competition should tame health care inflation. In fact, Mahar demonstrates, when it comes to medicine, the traditional laws of supply and demand do not apply. Normally, when supply expands, prices fall. But in the health care industry, as the number and variety of drugs, devices, and treatments multiplies, demand rises to absorb the excess, and prices climb. Meanwhile, the perverse incentives of a fee-for-service system reward health care providers for doing more, not less.In this superbly written book, Mahar shows why doctors must take responsibility for the future of our health care industry. Today, she observes, "physicians have been stripped of their standing as professionals: Insurers address them as vendors (Dear Health Care Provider''), drugmakers and device makers see them as customers (someone you might take to lunch or a strip club), while . . . consumers (aka patients) are encouraged to see their doctors as overpaid retailers. . . . Before patients can reclaim their rightful place as the center—and indeed as the raison d''etre—of our health care system," Mahar suggests, "we must once again empower doctors . . . to practice patient-centered medicine—based not on corporate imperatives, doctors'' druthers, or even patients'' demands," but on the best scientific research available.', '["Medical", "Business", "Medical care", "Cost effectiveness", "Medical economics", "Fees and Charges", "Cost-Benefit Analysis", "Health Care Costs", "Coût-efficacité", "Soins médicaux", "Économie de la santé", "Popular Works"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (131, 'the-nine', 'The Nine', 'Inside the Secret World of the Supreme Court', 'Politics & Social Sciences', 0, 2007, 369, '9780385516402', '/works/OL119176W', 'Bestselling author Jeffrey Toobin takes you into the chambers of the most important--and secret--legal body in our country, the Supreme Court, and reveals the complex dynamic among the nine people who decide the law of the land.Just in time for the 2008 presidential election--where the future of the Court will be at stake--Toobin reveals an institution at a moment of transition, when decades of conservative disgust with the Court have finally produced a conservative majority, with major changes in store on such issues as abortion, civil rights, presidential power, and church-state relations.Based on exclusive interviews with justices themselves, The Nine tells the story of the Court through personalities--from Anthony Kennedy''s overwhelming sense of self-importance to Clarence Thomas''s well-tended grievances against his critics to David Souter''s odd nineteenth-century lifestyle. There is also, for the first time, the full behind-the-scenes story of Bush v. Gore--and Sandra Day O''Connor''s fateful breach with George W. Bush, the president she helped place in office. The Nine is the book bestselling author Jeffrey Toobin was born to write. A CNN senior legal analyst and New Yorker staff writer, no one is more superbly qualified to profile the nine justices.', '["Current Events", "Political aspects", "Political questions and judicial power", "United States. Supreme Court", "United States", "Conservatism", "Judicial review", "Politics", "Law", "Political aspects of Law", "Politique et pouvoir judiciaire", "Contrôle juridictionnel des lois"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (132, 'the-looming-tower', 'The Looming Tower', 'Al-Qaeda and the Road to 9-11', 'Politics & Social Sciences', 0, 2006, 502, '9780141029351', '/works/OL193645W', 'National Book Award FinalistA Time, Newsweek, Washington Post, Chicago Tribune, and New York Times Book Review Best Book of the YearA gripping narrative that spans five decades, The Looming Tower explains in unprecedented detail the growth of Islamic fundamentalism, the rise of al-Qaeda, and the intelligence failures that culminated in the attacks on the World Trade Center. Lawrence Wright re-creates firsthand the transformation of Osama bin Laden and Ayman al-Zawahiri from incompetent and idealistic soldiers in Afghanistan to leaders of the most successful terrorist group in history. He follows FBI counterterrorism chief John O''Neill as he uncovers the emerging danger from al-Qaeda in the 1990s and struggles to track this new threat. Packed with new information and a deep historical perspective, The Looming Tower is the definitive history of the long road to September 11.From the Trade Paperback edition.', '["Current Events", "September 11 Terrorist Attacks, 2001", "Qaida (Organization)", "Intelligence service", "Government policy", "Terrorism", "Large type books", "HISTORY / Modern / 20th Century", "POLITICAL SCIENCE / Intelligence & Espionage", "POLITICAL SCIENCE / Terrorism", "New York Times reviewed", "Intelligence service, united states"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (133, 'traffic', 'Traffic', 'Why We Drive the Way We Do (and What It Says About Us)', 'Brain & Psychology', 0, 2008, 402, '9780307264787', '/works/OL6209302W', 'A New York Times Notable BookOne of the Best Books of the YearThe Washington Post - The Cleveland Plain-Dealer - Rocky Mountain NewsIn this brilliant, lively, and eye-opening investigation, Tom Vanderbilt examines the perceptual limits and cognitive underpinnings that make us worse drivers than we think we are. He demonstrates why plans to protect pedestrians from cars often lead to more accidents. He uncovers who is more likely to honk at whom, and why. He explains why traffic jams form, outlines the unintended consequences of our quest for safety, and even identifies the most common mistake drivers make in parking lots. Traffic is about more than driving: it''s about human nature. It will change the way we see ourselves and the world around us, and it may even make us better drivers.From the Trade Paperback edition.', '["Automobile driving", "Psychological aspects of Automobile driving", "Traffic congestion", "Psychological aspects", "Sociology", "Transportation", "Conduite automobile", "Migrations alternantes", "Technique de la Circulation", "Verkehrspsychologie", "Circulation routière", "Traffic safety"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (134, 'nudge', 'Nudge', 'Improving Decisions About Health, Wealth, and Happiness', 'Brain & Psychology', 0, 2008, 324, '9780141040011', '/works/OL3936258W', 'Thaler and Sunstein develop libertarian paternalism as a middle path between command-and-control and strict-neutrality choice architectures. Libertarian paternalism protects humans against their damaging psychological traits (inertia, bounded rationality, undue influence) by exploiting those habits to nudge people into making better choices.', '["Business", "Choice (Psychology)", "Consumer behavior", "Decision making", "Economic aspects", "Economic aspects of Choice (Psychology)", "Economics", "Psychological aspects", "Psychological aspects of Decision making", "Psychological aspects of Economics", "autonomy", "decisions"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (135, 'animal-vegetable-miracle', 'Animal, Vegetable, Miracle', 'A Year of Food Life', 'Travel & Memoir', 0, 2007, 370, '9780062020062', '/works/OL1846871W', 'Bestselling author Barbara Kingsolver returns with her first nonfiction narrative that will open your eyes in a hundred new ways to an old truth: You are what you eat."As the U.S. population made an unprecedented mad dash for the Sun Belt, one carload of us paddled against the tide, heading for the Promised Land where water falls from the sky and green stuff grows all around. We were about to begin the adventure of realigning our lives with our food chain."Naturally, our first stop was to buy junk food and fossil fuel. . . ."Hang on for the ride: With characteristic poetry and pluck, Barbara Kingsolver and her family sweep readers along on their journey away from the industrial-food pipeline to a rural life in which they vow to buy only food raised in their own neighborhood, grow it themselves, or learn to live without it. Their good-humored search yields surprising discoveries about turkey sex life and overly zealous zucchini plants, en route to a food culture that''s better for the neighborhood and also better on the table. Part memoir, part journalistic investigation, Animal, Vegetable, Miracle makes a passionate case for putting the kitchen back at the center of family life and diversified farms at the center of the American diet."This is the story of a year in which we made every attempt to feed ourselves animals and vegetables whose provenance we really knew . . . and of how our family was changed by our first year of deliberately eating food produced from the same place where we worked, went to school, loved our neighbors, drank the water, and breathed the air."', '["Gardening", "Anecdotes", "Food habits", "Biography & Autobiography", "Country life", "Farm life", "Agriculture", "Alimentation", "Vie quotidienne", "Sud", "Document", "Farm life, united states"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (136, 'shaping-things', 'Shaping Things', NULL, 'Technology', 0, 2005, 149, NULL, '/works/OL1888034W', NULL, '["Technology assessment", "Technological forecasting", "Technology, social aspects"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (137, 'the-black-swan', 'The Black Swan', 'The Impact of the Highly Improbable', 'Science and Math', 0, 2005, 475, '9780593243657', '/works/OL3295030W', 'From the critically acclaimed author of Fooled by Randomness, a book about the impact of improbable events on every aspect of life.', '["Ereignis", "nyt:paperback_nonfiction=2010-05-09", "Prévision", "New York Times bestseller", "Business", "Social aspects", "Philosophy", "Informationstheorie", "Teoria da informação (aspectos sociais)", "Prognose", "Incertitude (Théorie de l''information)", "Aspect social"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (138, 'cheating', 'Cheating', 'Gaining Advantage in Videogames', 'Technology', 0, 2007, 240, '9780262251211', '/works/OL9281256W', '"In Cheating, Mia Consalvo investigates how players choose to play games and what happens when they can''t always play the way they''d like. She explores a broad range of player behavior, including cheating (alone and in groups); examines the varying ways that players and industry define cheating; describes how the game industry itself has helped systematize cheating; and studies online cheating in context in an online ethnography of Final Fantasy XI."--Jacket.', '["Video games", "Cheating at video games", "Video games industry", "Corrupt practices", "Moral and ethical aspects"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (139, 'how-doctors-think', 'How Doctors Think', NULL, 'Health & Medicine', 0, 2007, 320, '9780739491676', '/works/OL7976337W', 'A physician discusses the thought patterns and actions that lead to misdiagnosis on the part of healthcare providers and suggests methods that patients can use to help doctors assess conditions more accurately.', '["Logique médicale", "Clinical Medicine", "Prise de décision", "Psychology", "Physicians", "Logic", "Médecins", "Médecine", "Psychologie", "Decision making", "Medical logic", "Jugement"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (140, 'the-world-without-us', 'The World Without Us', NULL, 'Politics & Social Sciences', 0, 2007, 428, '9781429917216', '/works/OL2746364W', 'The World Without Us, an intriguing peek inside the impact homo sapiens have on the world around us and what will be left when we cease to exist. Alan Weisman intelligently intertwines the affect we have on the Earth and its ecosystems and the way we have damaged it, the things nature can''t undo. A tremendous report on the ways we have killed the flora and fauna and how we will ultimately exterminate ourselves, bringing all that is left of human civilization with us. ~ Written by an 11 year old', '["Human-plant relationships", "Efecto del ser humano sobre", "Nature", "Effect of human beings on", "Ecología", "Environmental degradation", "Aarde (planeet)", "Relaciones entre seres humanos y animales", "Naturaleza", "Mensheid", "Cultura material", "Het fictieve"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (141, 'beautiful-evidence', 'Beautiful Evidence', NULL, 'Technology', 0, 2006, 213, '9781930824164', '/works/OL2824008W', 'Science and art have in common intense seeing, the wide-eyed observing that generates visual information. Beautiful Evidence is about how seeing turns into showing, how data and evidence turn into explanation. The book identifies excellent and effective methods for showing nearly every kind of information, suggests many new designs (including sparklines), and provides analytical tools for assessing the credibility of evidence presentations (which are seen from both sides: how to produce and how to consume presentations). For alert consumers of presentations, there are chapters on diagnosing evidence corruption and PowerPoint pitches. Beautiful Evidence concludes with two chapters that leave the world of pixel and paper flatland representations - and move onto seeing and thinking in space land, the real-land of three-space and time. Edward Rolf Tufte (born 1942 in Kansas City, Missouri to Virginia and Edward E. Tufte), a professor emeritus of statistics, graphic design, and political economy at Yale University has been described by The New York Times as "the Leonardo da Vinci of Data". He is an expert in the presentation of informational graphics such as charts and diagrams, and is a fellow of the American Statistical Association. Tufte has held fellowships from the Guggenheim Foundation and the Center for Advanced Studies in Behavioral Sciences. Tufte currently resides in Cheshire, Connecticut. He periodically travels around the United States to offer one-day workshops on data presentation and information graphics. http://www.edwardtufte.com', '["Visual communication", "Statistics", "Nonverbal Communication", "Visual Perception", "Communication (human)", "Communication visuelle", "Information", "Gebrauchsgrafik", "Illustration", "Semiotik", "Visualisierung", "Visuelle Kommunikation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (142, 'musicophilia', 'Musicophilia', 'Tales of Music and the Brain', 'Brain & Psychology', 0, 2007, 382, '9781035068371', '/works/OL277255W', 'Music can move us to the heights or depths of emotion. It can persuade us to buy something, or remind us of our first date. It can lift us out of depression when nothing else can. It can get us dancing to its beat. But the power of music goes much, much further. Indeed, music occupies more areas of our brain than language does–humans are a musical species. Oliver Sacks’s compassionate, compelling tales of people struggling to adapt to different neurological conditions have fundamentally changed the way we think of our own brains, and of the human experience. In Musicophilia, he examines the powers of music through the individual experiences of patients, musicians, and everyday people–from a man who is struck by lightning and suddenly inspired to become a pianist at the age of forty-two, to an entire group of children with Williams syndrome who are hypermusical from birth; from people with “amusia,” to whom a symphony sounds like the clattering of pots and pans, to a man whose memory spans only seven seconds–for everything but music. Our exquisite sensitivity to music can sometimes go wrong: Sacks explores how catchy tunes can subject us to hours of mental replay, and how a surprising number of people acquire nonstop musical hallucinations that assault them night and day. Yet far more frequently, music goes right: Sacks describes how music can animate people with Parkinson’s disease who cannot otherwise move, give words to stroke patients who cannot otherwise speak, and calm and organize people whose memories are ravaged by Alzheimer’s or amnesia. Music is irresistible, haunting, and unforgettable, and in Musicophilia, Oliver Sacks tells us why.', '["psychology", "Alzheimer’s disese", "amnesia", "Parkinson’s disease", "amusia", "Williams syndrome", "Musicophilia", "the brain", "the human experience", "medical", "neurology", "psychiatry"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (143, 'the-box', 'The Box', 'How the Shipping Container Made the World Smaller and the World Economy Bigger', 'Technology', 0, 2006, 400, '9780691170817', '/works/OL4988033W', 'In April 1956, a refitted oil tanker carried fifty-eight shipping containers from Newark to Houston. From that modest beginning, container shipping developed into a huge industry that made the boom in global trade possible. The Box tells the dramatic story of the container''s creation, the decade of struggle before it was widely adopted, and the sweeping economic consequences of the sharp fall in transportation costs that containerization brought about. Drawing on previously neglected sources, economist Marc Levinson shows how the container transformed economic geography, devastating traditional ports such as New York and London and fueling the growth of previously obscure ones, such as Oakland. By making shipping so cheap that industry could locate factories far from its customers, the container paved the way for Asia to become the world''s workshop and brought consumers a previously unimaginable variety of low-cost products from around the globe.--From publisher description.', '["Containerization", "International economic integration", "International economic relations", "McLean, Malcolm Purcell,", "Containervervoer", "Businesspeople, biography", "North carolina, biography"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (144, 'beautiful-code', 'Beautiful Code', 'Leading Programmers Explain How They Think', 'Technology', 0, 2007, 824, '9780596515980', '/works/OL19396663W', 'How do the experts solve difficult problems in software development? In this unique and insightful book, leading computer scientists offer case studies that reveal how they found unusual, carefully designed solutions to high-profile projects. You will be able to look over the shoulder of major coding and design experts to see problems through their eyes. This is not simply another design patterns book, or another software engineering treatise on the right and wrong way to do things. The authors think aloud as they work through their project''s architecture, the tradeoffs made in its construction, and when it was important to break rules. Beautiful Code is an opportunity for master coders to tell their story. All author royalties will be donated to Amnesty International.', '["Software engineering", "Computer programming"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (145, 'watchmen', 'Watchmen', NULL, 'Science Fiction & Fiction', 1, 1987, 416, '9780606357425', '/works/OL2897798W', '"This book examines each of the series'' twelve issues in unprecedented detail, moving page by page and panel by panel to reveal the hidden foundations of this milestone in modern storytelling. Edited with notes by Leslie S. Klinger, this new edition draws upon critical and scholastic commentary, in-depth interviews with Dave Gibbons, and previously unseen original source material. Klinger provides the reader with a unique and comprehensive view of Watchmen as both a singular artistic achievement and a transformative event in the history of comics as a medium. Set in a world in which history has been forever altered by the existence of superheroes, Alan Moore and Dave Gibbons'' monumental graphic novel Watchmen is one of the most influential comic book series of all time. Following two generations of masked crime-fighters from the end of World War II to the height of the Cold War, this compelling tale unfolds from a simple murder mystery into an epic saga of power, corruption and the ultimate meaning of humanity. More than 30 years after it was first published, Moore and Gibbons'' masterpiece continues to inspire and entertain readers around the world. Named one of Time magazine''s 100 best English-language novels of the 20th century, Watchmen has won countless critical accolades and honors, including the Eisner Award and the Hugo Award"--', '["Watchmen (Comic strip)", "Graphic novels", "Comic books, strips", "New York Times bestseller", "nyt:paperback_graphic_books=2009-03-15", "Comics & graphic novels, science fiction", "Superheroes", "Crimes against", "Comics & graphic novels, superheroes", "Good and evil", "Bandes dessinées", "Comicroman"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (146, 'understanding-comics', 'Understanding Comics', 'The Invisible Art', 'Essays & Literature', 0, 1993, 215, '9781563897597', '/works/OL276032W', 'Praised throughout the cartoon industry by such luminaries as Art Spiegelman, Matt Groening, and Will Eisner, Scott McCloud''s Understanding Comics is a seminal examination of comics art: its rich history, surprising technical components, and major cultural significance. Explore the secret world between the panels, through the lines, and within the hidden symbols of a powerful but misunderstood art form.', '["Illustrations", "Technique", "Cartooning", "Comics", "Comic Books", "Art", "Historietas", "Cartoon", "Manga", "Story", "Sequential", "Sequential art"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (147, 'the-mythical-man-month', 'The Mythical Man-Month', NULL, 'Technology', 0, 1975, 195, '9780201835953', '/works/OL3510570W', 'Classic text on the human side of software engineering, containing essays on the management of software teams, projections about how computer languages and tools will evolve, and philosophical speculation. Unlike most other books about computing, Brooks'' work has been remarkably enduring, remaining in print for at least four decades. The book is most famous for its statement of Brooks'' Law: "adding manpower to a late software project makes it later".', '["Computer programming management", "Addresses, essays, lectures", "Software engineering", "Electronic digital computers", "Programming", "Computer programming", "MULTICS", "Technologie logiciel", "Gestion projet", "Programmation (Informatique)", "Gestion", "Système exploitation 360"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (148, 'happiness', 'Happiness', 'A Guide to Developing Life''s Most Important Skill', 'Philosophy & Religion', 0, 2007, 304, '9780316376532', '/works/OL21562807W', '"In his ... book, Buddhist monk Matthieu Ricard shows that happiness is not just an emotion, but a skill that can be developed. Free of jargon, Happiness contains simple exercises that will train the mind to recognize and pursue happiness by concentrating on the fundamental things in life, and in doing so change the way we view the world"-- Back cover.', '["Religious life, buddhism", "Happiness", "Buddhism"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (149, 'the-long-tail', 'The Long Tail', 'Why the Future of Business Is Selling Less of More', 'History & Economics', 0, 2006, 224, '9781401302375', '/works/OL4091759W', 'The New York Times bestseller that introduced the business world to a future that’s already here—now in a new edition with a new chapter about Long Tail Marketing and a new epilogue.Winner of the Gerald Loeb Award for Best Business Book of the YearIn the most important business book since The Tipping Point, Chris Anderson shows how the future of commerce and culture isn’t in hits, the high-volume head of a traditional demand curve, but in what used to be regarded as misses—the endlessly long tail of that same curve.', '["Commerce électronique", "Nachfrage", "Electronic commerce", "Marketing", "Angebot", "Innovations technologiques", "Wirtschaftstheorie", "Demande de consommation", "Internet", "Marktforschung", "Telemarketing", "Market segmentation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (150, 'the-road', 'The Road', NULL, 'Science Fiction & Fiction', 1, 2006, 200, '9780330447539', '/works/OL40873W', 'Cormac McCarthy''s tenth novel, The Road, is his most harrowing yet deeply personal work. Some unnamed catastrophe has scourged the world to a burnt-out cinder, inhabited by the last remnants of mankind and a very few surviving dogs and fungi. The sky is perpetually shrouded by dust and toxic particulates; the seasons are merely varied intensities of cold and dampness. Bands of cannibals roam the roads and inhabit what few dwellings remain intact in the woods. Through this nightmarish residue of America a haggard father and his young son attempt to flee the oncoming Appalachian winter and head towards the southern coast along carefully chosen back roads. Mummified corpses are their only benign companions, sitting in doorways and automobiles, variously impaled or displayed on pikes and tables and in cake bells, or they rise in frozen poses of horror and agony out of congealed asphalt. The boy and his father hope to avoid the marauders, reach a milder climate, and perhaps locate some remnants of civilization still worthy of that name. They possess only what they can scavenge to eat, and the rags they wear and the heat of their own bodies are all the shelter they have. A pistol with only a few bullets is their only defense besides flight. Before them the father pushes a shopping cart filled with blankets, cans of food and a few other assets, like jars of lamp oil or gasoline siphoned from the tanks of abandoned vehicles—the cart is equipped with a bicycle mirror so that they will not be surprised from behind. Through encounters with other survivors brutal, desperate or pathetic, the father and son are both hardened and sustained by their will, their hard-won survivalist savvy, and most of all by their love for each other. They struggle over mountains, navigate perilous roads and forests reduced to ash and cinders, endure killing cold and freezing rainfall. Passing through charred ghost towns and ransacking abandoned markets for meager provisions, the pair battle to remain hopeful. They seek the most rudimentary sort of salvation. However, in The Road, such redemption as might be permitted by their circumstances depends on the boy’s ability to sustain his own instincts for compassion and empathy in opposition to his father’s insistence upon their mutual self-interest and survival at all physical and moral costs. The Road was the winner of the 2006 Pulitzer Prize for Literature.', '["Dystopia", "Adventure", "post-apocalyptic fiction", "extinction event", "Fathers and sons", "Survival skills", "Regression (Civilization)", "Voyages and travels", "literary fiction", "Robinsonades", "Apocalyptic fiction", "Novels"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (151, 'the-omnivore-s-dilemma', 'The Omnivore''s Dilemma', 'A Natural History of Four Meals', 'Travel & Memoir', 0, 2006, NULL, '9781504044844', '/works/OL28339036W', NULL, '["hunting", "foodies", "feral pigs", "wild mushrooms", "abalone", "salads", "leaf vegetables", "sourdough", "wild yeast", "cherries", "Whole Foods Market", "omnivores"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (152, 'stumbling-on-happiness', 'Stumbling on Happiness', NULL, 'Brain & Psychology', 0, 2006, 336, '9780676978582', '/works/OL15840192W', 'A smart and funny book by a prominent Harvard psychologist, which uses groundbreaking research and (often hilarious) anecdotes to show us why we''re so lousy at predicting what will make us happy -- and what we can do about it.Most of us spend our lives steering ourselves toward the best of all possible futures, only to find that tomorrow rarely turns out as we had expected. Why? As Harvard psychologist Daniel Gilbert explains, when people try to imagine what the future will hold, they make some basic and consistent mistakes. Just as memory plays tricks on us when we try to look backward in time, so does imagination play tricks when we try to look forward. Using cutting-edge research, much of it original, Gilbert shakes, cajoles, persuades, tricks and jokes us into accepting the fact that happiness is not really what or where we thought it was. Among the unexpected questions he poses: Why are conjoined twins no less happy than the general population? When you go out to eat, is it better to order your favourite dish every time, or to try something new? If Ingrid Bergman hadn''t gotten on the plane at the end of Casablanca, would she and Bogey have been better off?Smart, witty, accessible and laugh-out-loud funny, Stumbling on Happiness brilliantly describes all that science has to tell us about the uniquely human ability to envision the future, and how likely we are to enjoy it when we get there.From the Hardcover edition.', '["Happiness", "Psychology", "Self realization", "Self-Improvement", "New York Times reviewed", "Imagination", "Interpersonal relations", "Bonheur", "Geluk", "Contentment", "Forecasting", "Psychological aspects"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (153, 'genghis-khan-and-the-making-of-the-modern-world', 'Genghis Khan and the Making of the Modern World', NULL, 'History & Economics', 0, 2004, 352, '9781491513705', '/works/OL8162628W', 'The name Genghis Khan often conjures the image of a relentless, bloodthirsty barbarian on horseback leading a ruthless band of nomadic warriors in the looting of the civilized world. But the surprising truth is that Genghis Khan was a visionary leader whose conquests joined backward Europe with the flourishing cultures of Asia to trigger a global awakening, an unprecedented explosion of technologies, trade, and ideas. In Genghis Khan and the Making of the Modern World, Jack Weatherford, the only Western scholar ever to be allowed into the Mongols'' "Great Taboo"--Genghis Khan''s homeland and forbidden burial site--tracks the astonishing story of Genghis Khan and his descendants, and their conquest and transformation of the world. Fighting his way to power on the remote steppes of Mongolia, Genghis Khan developed revolutionary military strategies and weaponry that emphasized rapid attack and siege warfare, which he then brilliantly used to overwhelm opposing armies in Asia, break the back of the Islamic world, and render the armored knights of Europe obsolete. Under Genghis Khan, the Mongol army never numbered more than 100,000 warriors, yet it subjugated more lands and people in twenty-five years than the Romans conquered in four hundred. With an empire that stretched from Siberia to India, from Vietnam to Hungary, and from Korea to the Balkans, the Mongols dramatically redrew the map of the globe, connecting disparate kingdoms into a new world order. But contrary to popular wisdom, Weatherford reveals that the Mongols were not just masters of conquest, but possessed a genius for progressive and benevolent rule. On every level and from any perspective, the scale and scope of Genghis Khan''s accomplishments challenge the limits of imagination. Genghis Khan was an innovative leader, the first ruler in many conquered countries to put the power of law above his own power, encourage religious freedom, create public schools, grant diplomatic immunity, abolish torture, and institute free trade. The trade routes he created became lucrative pathways for commerce, but also for ideas, technologies, and expertise that transformed the way people lived. The Mongols introduced the first international paper currency and postal system and developed and spread revolutionary technologies like printing, the cannon, compass, and abacus. They took local foods and products like lemons, carrots, noodles, tea, rugs, playing cards, and pants and turned them into staples of life around the world. The Mongols were the architects of a new way of life at a pivotal time in history. In Genghis Khan and the Making of the Modern World, Jack Weatherford resurrects the true history of Genghis Khan, from the story of his relentless rise through Mongol tribal culture to the waging of his devastatingly successful wars and the explosion of civilization that the Mongol Empire unleashed. This dazzling work of revisionist history doesn''t just paint an unprecedented portrait of a great leader and his legacy, but challenges us to reconsider how the modern world was made.From the Hardcover edition.', '["Biography & Autobiography", "Mongols", "Kings and rulers", "Biography", "nyt:combined-print-and-e-book-nonfiction=2014-10-12", "New York Times bestseller", "Long Now Manual for Civilization"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (154, 'bowling-alone', 'Bowling Alone', 'The Collapse and Revival of American Community', 'Politics & Social Sciences', 0, 2000, 544, '9781982130848', '/works/OL4291077W', '"Updated to include a new chapter about the influence of social media and the Internet—the 20th anniversary edition of Bowling Alone remains a seminal work of social analysis, and its examination of what happened to our sense of community remains more relevant than ever in today’s fractured America. Twenty years, ago, Robert Putnam made a seemingly simple observation: once we bowled in leagues, usually after work; but no longer. This seemingly small phenomenon symbolized a significant social change that became the basis of the acclaimed bestseller, Bowling Alone, which The Washington Post called “a very important book” and Putnam, “the de Tocqueville of our generation.” Bowling Alone surveyed in detail Americans’ changing behavior over the decades, showing how we had become increasingly disconnected from family, friends, neighbors, and social structures, whether it’s with the PTA, church, clubs, political parties, or bowling leagues. In the revised edition of his classic work, Putnam shows how our shrinking access to the “social capital” that is the reward of communal activity and community sharing still poses a serious threat to our civic and personal health, and how these consequences have a new resonance for our divided country today. He includes critical new material on the pervasive influence of social media and the internet, which has introduced previously unthinkable opportunities for social connection—as well as unprecedented levels of alienation and isolation. At the time of its publication, Putnam’s then-groundbreaking work showed how social bonds are the most powerful predictor of life satisfaction, and how the loss of social capital is felt in critical ways, acting as a strong predictor of crime rates and other measures of neighborhood quality of life, and affecting our health in other ways. While the ways in which we connect, or become disconnected, have changed over the decades, his central argument remains as powerful and urgent as ever: mending our frayed social capital is key to preserving the very fabric of our society"--Simon & Schuster.', '["Social conditions", "Social change", "Isolation <Soziologie>", "Conditions sociales", "Histoire", "Changement social", "Mudança social (história;século 20)", "Sozialer Wandel", "Participation sociale", "Estrutura social (século 20)", "Community life", "Social isolation"]');
