INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (156, 'democratizing-innovation', 'Democratizing Innovation', NULL, 'Technology', 0, 2005, 216, '9780262285636', '/works/OL5275396W', 'Innovation is rapidly becoming democratized. Users, aided by improvements in computer and communications technology, increasingly can develop their own new products and services. Eric von Hippel looks closely at this emerging system of user-centred innovation.', '["Diffusion of innovations", "Democracy", "Economic aspects of Technological innovations", "Technological innovations", "Economic aspects", "Authors Alliance", "authors_alliance", "Entrepreneurship", "Technological innovations, economic aspects"]');
