INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (158, 'beyond-oil', 'Beyond Oil', 'The View from Hubbert''s Peak', 'Current Events & People', 0, 2005, 224, '9780374707026', '/works/OL5744857W', NULL, '["Forecasting", "Petroleum industry and trade", "Petroleum reserves", "Power resources", "Petroleum technology - general & miscellaneous", "Economic forecasting", "Energy industries - crude oil & petroleum", "Energy technology", "Renewable power resources", "Electricity & technology", "Science & technology - forecasting", "Energy conservation"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (159, 'the-search', 'The Search', 'How Google and Its Rivals Rewrote the Rules of Business and Transformed Our Culture', 'Technology', 0, 2005, 311, '9781429514811', '/works/OL8982019W', 'How Google and Its Rivals Rewrote the Rules of Business and Transformed Our Culture• The Wall Street Journal and BusinessWeek Bestseller• Finalist for the Goldman Sachs/FT Business Book of the Year AwardWhat does the world want? According to John Battelle, a company that answers that question—in all its shades of meaning—can unlock the most intractable riddles of business and arguably of human culture itself. And for the past few years, that''s exactly what Google has been doing.But The Search offers much more than the inside story of Google''s triumph. It''s a big- picture book about the past, present, and future of search technology and the enormous impact it''s starting to have on marketing, media, pop culture, dating, job hunting, international law, civil liberties, and just about every other sphere of human interest.', '["Internet industry", "Internet", "Entwicklung", "Recherche sur Internet", "Google (Firme)", "Information society", "Industrie", "Business", "Google (Firm)", "Computer Technology", "World Wide Web", "Biographies"]');
