INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (164, 'free-culture', 'Free Culture', 'The Nature and Future of Creativity', 'Politics & Social Sciences', 0, 2004, 304, '9781549608186', '/works/OL6037024W', 'Lessig details the history of copyright law as it pertains to digital media, how it has affected creativity and expression online. Title for the hardcover and PDF versions: Free Culture: How Big Media Uses Technology and the Law to Lock Down Culture and Control Creativity', '["Intellectual property", "Technological innovations", "Art", "Mass media", "Propriedade intelectual", "Recht", "Médias", "Geistiges Eigentum", "Cultuur", "Technische vernieuwing", "Auteursrecht", "Kultur"]');
