INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (166, 'sailing-alone-around-the-room', 'Sailing Alone Around the Room', 'New and Selected Poems', 'Essays & Literature', 0, 2001, 171, '9781588360953', '/works/OL108869W', 'Offers a collection of witty, emotional, and direct poems by the popular and critically acclaimed poet, including selections from his four previous collections and new works such as "Man Listening to a Disc," about headphones.', '["Poetry (poetic works by one author)", "New York Times reviewed", "Poetry"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (167, 'the-paradox-of-choice', 'The Paradox of Choice', 'Why More Is Less', 'Brain & Psychology', 0, 2004, 273, '9780061461545', '/works/OL272375W', 'In the spirit of [Alvin Toffler](/authors/OL433058A)’s [*Future Shock*](/works/OL2869043W), a social critique of our obsession with choice, and how it contributes to anxiety, dissatisfaction and regret. This paperback includes a new P.S. section with author interviews, insights, features, suggested readings, and more.Whether we’re buying a pair of jeans, ordering a cup of coffee, selecting a long-distance carrier, applying to college, choosing a doctor, or setting up a 401(k), everyday decisions--both big and small--have become increasingly complex due to the overwhelming abundance of choice with which we are presented.We assume that more choice means better options and greater satisfaction. But beware of excessive choice: choice overload can make you question the decisions you make before you even make them, it can set you up for unrealistically high expectations, and it can make you blame yourself for any and all failures. In the long run, this can lead to decision-making paralysis, anxiety, and perpetual stress. And, in a culture that tells us that there is no excuse for falling short of perfection when your options are limitless, too much choice can lead to clinical depression.In The Paradox of Choice, Barry Schwartz explains at what point choice--the hallmark of individual freedom and self-determination that we so cherish--becomes detrimental to our psychological and emotional well-being. In accessible, engaging, and anecdotal prose, Schwartz shows how the dramatic explosion in choice--from the mundane to the profound challenges of balancing career, family, and individual needs--has paradoxically become a problem instead of a solution. Schwartz also shows how our obsession with choice encourages us to seek that which makes us feel worse.By synthesizing current research in the social sciences, Schwartz makes the counterintuitive case that eliminating choices can greatly reduce the stress, anxiety, and busyness of our lives. He offers eleven practical steps on how to limit choices to a manageable number, have the discipline to focus on the important ones and ignore the rest, and ultimately derive greater satisfaction from the choices you have to make.', '["Psychology", "Sociology", "Choice (psychology)", "Decision making", "Choice Behavior", "Wahlmöglichkeit", "Overvloed", "Entscheidungsfindung", "Keuzegedrag", "Entscheidung"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (168, 'when-we-were-orphans', 'When We Were Orphans', NULL, 'Science Fiction & Fiction', 1, 2000, 401, '9780571225408', '/works/OL59042W', '''You seldom read a novel that so convinces you it is extending the possibilities of fiction.'' Sunday TimesEngland, 1930s. Christopher Banks has become the country''s most celebrated detective, his cases the talk of London society. Yet one unsolved crime has always haunted him: the mysterious disappearance of his parents, in old Shanghai, when he was a small boy. Moving between London and Shanghai of the inter-war years, When We Were Orphans is a remarkable story of memory, intrigue and the need to return.', '["Private investigators", "Missing persons", "Death", "British", "Parents", "Psychological fiction", "Psychology", "Orphans", "Detective and mystery stories", "Detectives", "Psychological aspects", "Social life and customs"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (169, 'wisdom-of-crowds', 'Wisdom of Crowds', NULL, 'Brain & Psychology', 0, 2004, 336, '9780385721707', '/works/OL8036447W', 'In this fascinating book, New Yorker business columnist James Surowiecki explores a deceptively simple idea: Large groups of people are smarter than an elite few, no matter how brilliant — better at solving problems, fostering innovation, coming to wise decisions, even predicting the future. Surowiecki ranges across fields as diverse as popular culture, psychology, ant biology, behavioral economics, artificial intelligence, military history, and politics to show how this simple idea offers important lessons for how we live our lives, select our leaders, run our companies, and think about our world. The story is told of the first observations of this effect, through to anecdotes of the effect in modern economics and psychology. The book not heavy on statistics, and has prompted much research since its publication. The title is an allusion to the famous phrase, the "madness of crowds".', '["Sociology", "Common good", "Business", "Group decision making", "Consensus (Social sciences)", "Large type books", "New York Times reviewed", "Group Processes", "Consensus", "Decision Making", "Problem Solving", "Gemeinwohl"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (170, 'over-the-edge-of-the-world', 'Over the Edge of the World', 'Magellan''s Terrifying Circumnavigation of the Globe', 'History & Economics', 0, 2003, 512, '9780062890481', '/works/OL2655768W', NULL, '["Primera circunnavegación", "Expedición Magallanes-Elcano", "Biografías", "1520-1529", "Travel", "Jordomsejlinger", "Voyages around the world", "Opdagelsesrejser", "Explorers", "Biography", "1510-1519", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (171, 'pompeii', 'Pompeii', NULL, 'Science Fiction & Fiction', 0, 2003, 368, '9780345475671', '/works/OL4297223W', 'Historical fiction about the eruption of Mount Vesuvius in 79 AD from the perspective of Marcus Attilius, an *aquarius* (hydraulic engineer) responsible for Aqua Augusta, the regional aqueduct.', '["Pompeji", "Italien", "Vulkaner", "1-99", "Naturkatastrofer"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (172, 'quicksilver', 'Quicksilver', NULL, 'Science Fiction & Fiction', 1, 2003, 927, '9780099410683', '/works/OL38495W', 'Volume One of The Baroque Cycle (Not to be confused with [Quicksilver: The Baroque Cycle #1](https://openlibrary.org/works/OL18199543W/Quicksilver)) Quicksilver is a massive, exuberant and wildly ambitious historical novel that''s also Neal Stephenson''s eagerly awaited prequel to Cryptonomicon--his pyrotechnic reworking of the 20th century, from World War II codebreaking and disinformation to the latest issues of Internet data privacy. Quicksilver, "Volume One of the Baroque Cycle", backtracks to another time of high intellectual ferment: the late 17th century, with the natural philosophers of England''s newly formed Royal Society questioning the universe and dissecting everything that moves. One founding member, the Rev John Wilkins, really did write science fiction and a book on cryptography--but this isn''t history as we know it, for here his code book is called not Mercury but Cryptonomicon. And although the key political schemers of Charles II''s government still have initials spelling the word CABAL, their names are all different... While towering geniuses like Newton and Leibniz decode nature itself, bizarre adventures (merely beginning with the Great Plague and Great Fire) happen to the fictional Royal Society member Daniel Waterhouse, who knows everyone but isn''t quite bright enough for cutting-edge science. Two generations of Daniel''s family appear in Cryptonomicon, as does a descendant of the Shaftoes who here are soldiers and vagabonds. Other links include the island realm of Qwghlm with its impossible language and the mysterious, seemingly ageless alchemist Enoch Root. As the reign of Charles II gives way to that of James II and then William of Orange, Stephenson traces the complex lines of finance and power that form the 17th-century Internet. Gold and silver, lead and (repeatedly) mercury or quicksilver flow in glittering patterns between centres of marketing and intrigue in England, Germany, France and Holland. Paper flows as well: stocks, shares, scams and letters holding layers of concealed code messages. Binary code? Yes, even that had already been invented and described by Francis Bacon. Quicksilver is crammed with unexpected incidents, fascinating digressions and deep-laid plots. Who''d believe that Eliza, a Qwghlmian slave girl liberated from a Turkish harem by mad Jack Shaftoe (King of the Vagabonds) could become a major player in European finance and politics? Still less believable, but all too historically authentic, are the appalling medical procedures of the time--about which we learn a lot. There are frequent passages of high comedy, like the lengthy description of a foppish earl''s costume which memorably explains that someone seemed to have been painted in glue before "shaking and rolling him in a bin containing thousands of black silk doilies". This is a huge, exhausting read, full of rewards and quirky insights that no other author could have created. Fantastic or farcical episodes sometimes clash strangely with the deep cruelty and suffering of 17th-century realism. Recommended, though not to the faint-hearted. ---------- Book One: [Quicksilver](https://openlibrary.org/works/OL18199543W/Quicksilver) Book Two: [King of the Vagabonds](https://openlibrary.org/works/OL38479W/King_of_the_Vagabonds) Book Three: [Odalisque](https://openlibrary.org/works/OL38481W/Odalisque)', '["Scientists", "Adventure stories", "Alchemists", "Puritans", "Adventure and adventurers", "Historical Fiction", "Rogues and vagabonds", "adventure fiction", "Fiction, historical", "Scientists, fiction", "Fiction, historical, general", "Fiction, technological"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (173, 'the-blank-slate', 'The Blank Slate', 'The Modern Denial of Human Nature', 'Brain & Psychology', 0, 2002, 550, '9780713992564', '/works/OL477826W', 'In The Blank Slate, Steven Pinker, one of the world''s leading experts on language and the mind, explores the idea of human nature and its moral, emotional, and political colorings. With characteristic wit, lucidity, and insight, Pinker argues that the dogma that the mind has no innate traits-a doctrine held by many intellectuals during the past century-denies our common humanity and our individual preferences, replaces objective analyses of social problems with feel-good slogans, and distorts our understanding of politics, violence, parenting, and the arts. Injecting calm and rationality into debates that are notorious for ax-grinding and mud-slinging, Pinker shows the importance of an honest acknowledgment of human nature based on science and common sense.', '["Developmental psychology", "Nature and nurture", "Sociology", "Long Now Manual for Civilization", "Hérédité et milieu", "Psychobiologie", "Être humain", "Inné et acquis", "Erfelijkheid en omgeving", "Sociale evolutie", "Anthropologie philosophique", "Menselijke natuur"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (174, 'my-tiny-life', 'My Tiny Life', 'Crime and Passion in a Virtual World', 'Technology', 0, 1998, 352, '9781841150574', '/works/OL1856237W', NULL, '["Computer crimes", "LambdaMOO", "Virtual reality", "World Wide Web", "Criminaliteit", "Internet", "New York Times reviewed", "Fiction, thrillers, technological"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (175, 'the-lexus-and-the-olive-tree', 'The Lexus and the Olive Tree', 'Understanding Globalization', 'History & Economics', 0, 1999, 496, '9780965885942', '/works/OL3740414W', 'As the Foreign Affairs columnist for The New York Times, Thomas L. Friedman has traveled to the four corners of the globe, interviewing people from all walks of contemporary life - Brazilian peasants in the Amazon rain forest, new entrepreneurs in Indonesia, Islamic students in Teheran, and the financial wizards on Wall Street and in Silicon Valley. Now Friedman has drawn on his years on the road to produce an engrossing and original look at the new international system that, more than anything else, is shaping world affairs today: globalization. His argument can be summarized quite simply. Globalization is not just a phenomenon and not just a passing trend. It is the international system that replaced the Cold War system. Globalization is the integration of capital, technology, and information across national borders, in a way that is creating a single global market and, to some degree, a global village. With vivid stories and a set of original terms and concepts, Friedman shows us how to see this new system. He dramatizes the conflict of "the Lexus and the olive tree" - the tension between the globalization system and ancient forces of culture, geography, tradition, and community. He also details the powerful backlash that globalization produces among those who feel brutalized by it, and he spells out what we all need to do to keep this system in balance.', '["ASPECTOS ECONOMICOS", "Aspectos sociales", "Capitalism", "Capitalismo", "Comunicación intercultural", "Economic aspects", "Economic aspects of Technological innovations", "Economía internacional", "Foreign economic relations", "Free trade", "Globalización", "Globalization"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (176, 'the-devil-in-the-white-city', 'The Devil in the White City', NULL, 'History & Economics', 0, 2003, 362, '9780553813531', '/works/OL20262W', 'From back cover: Bringing Chicago circa 1893 to vivid life, Erik Larson''s spell-binding bestseller intertwines the true tale of two men - the brilliant architect behind the legendary 1893 World''s Fair, striving to secure America''s place in the world; and the cunning serial killer who used the fair to lure his victims to their death. Combining meticulous research with nail-biting storytelling, Erik Larson has crafted a narrative with all the wonder of newly discovered history and the thrills of the best fiction.', '["Social life and customs", "Murder", "Serial murders", "Architects", "New York Times bestseller", "Case studies", "Serial murderers", "World''s Columbian Exposition (1893 : Chicago, Ill.)", "Biography", "World''s Columbian Exposition (1893 : Chicago, Ill.) (NOBLE)39295", "World''s Columbian Exposition (1893 : Chicago, Ill)", "Murder, illinois"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (177, 'the-overstory', 'The Overstory', NULL, 'Science Fiction & Fiction', 1, 2019, 512, '978-0393356687', '/works/OL19074847W', 'The Overstory, winner of the 2019 Pulitzer Prize in Fiction, is a sweeping, impassioned work of activism and resistance that is also a stunning evocation of―and paean to―the natural world. From the roots to the crown and back to the seeds, Richard Powers’s twelfth novel unfolds in concentric rings of interlocking fables that range from antebellum New York to the late twentieth-century Timber Wars of the Pacific Northwest and beyond. There is a world alongside ours―vast, slow, interconnected, resourceful, magnificently inventive, and almost invisible to us. This is the story of a handful of people who learn how to see that world and who are drawn up into its unfolding catastrophe.', '["trees", "forest", "conservation", "environment", "activism", "Forest conservation", "Forests and forestry", "American fiction (fictional works by one author)", "Fiction, political", "nyt:hardcover-fiction=2018-05-06", "New York Times bestseller", "New York Times reviewed"]');
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (178, 'patterns-in-nature', 'Patterns in Nature', 'Why the Natural World Looks the Way it Does', 'Science and Math', 0, 2016, 288, '978-0226332420', '/works/OL6334653W', 'Though at first glance the natural world may appear overwhelming in its diversity and complexity, there are regularities running through it, from the hexagons of a honeycomb to the spirals of a seashell and the branching veins of a leaf. Revealing the order at the foundation of the seemingly chaotic natural world, Patterns in Nature explores not only the math and science but also the beauty and artistry behind nature’s awe-inspiring designs.
INSERT INTO club_books (id, slug, title, subtitle, topic, fiction, publication_year, page_count, isbn13, ol_key, synopsis, subjects_json) VALUES (179, 'a-world-appears', 'A World Appears', 'A Journey into Consciousness', 'Essays & Literature', 0, 2026, 320, '978-1984881991', '/works/OL45011996W', 'When it comes to the phenomenon that is consciousness, there is one point on which scientists, philosophers, and artists all agree: it feels like something to be us. Yet the fact that we have subjective experience of the world remains one of nature’s greatest mysteries. How is it that our mental operations are accompanied by feelings, thoughts, and a sense of self? What would a scientific investigation of our inner life look like, when we have as little distance and perspective on it as fish do of the sea? In A World Appears, Michael Pollan traces the unmapped continent that is consciousness, bringing radically different perspectives—scientific, philosophical, literary, spiritual and psychedelic—to see what each can teach us about this central fact of life.
