INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (1, 15216130, 6, '["eng"]', 5.0, 2, 'Q138795546', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:48:59+00:00', '{"openlibrary": {"ol_key": "/works/OL42455337W", "ol_cover_id": 15216130, "edition_count": 6, "languages": ["eng"], "subjects": ["genre:technological non-fiction literature", "enshittification"], "synopsis": "**It’s not your imagination. Life online really does get worse by the day, and that is by intent.**\r\n\r\nMisogyny, conspiratorialism, surveillance, manipulation, fraud, and AI slop are drowning the internet. For the monopolists who dominate online – X, TikTok, Amazon, Meta, Apple – this is all part of the playbook. The process is what leading tech critic Cory Doctorow has dubbed ‘enshittification’. First, the platform attracts users with some bait, such as free access; then the activity is monetized, bringing in the business customers and degrading the user experience; then, once everyone is trapped and competitors eradicated, the platform wrings out all the value and transfers it to their executives and shareholders.\r\n\r\nAs a result, online public squares have become places of torment, and online retailers are hellish dumpster fires. The virtual gathering places where we once imagined the world’s problems might be resolved are now a sewer of hatred and abuse – thoroughly enshittified.\r\n\r\nDoctorow enumerates the symptoms, lays out the diagnosis, and identifies the best responses to these diseased platforms: the monopolies online must be shattered. Companies too big to fail or to jail – and much too big to care – must be cut down to size. Only an attack on corporate power will permit effective regulation and real privacy. Tech unions must protect the workers who should, in turn, defend us against their bosses’ sadism and greed.", "publication_year": 2025, "page_count": 352, "isbn13": "9781836742227", "ratings_average": 5.0, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q138795546", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (2, 12307847, 553, '["eng", "spa"]', 3.58, 134, 'Q129778', 'https://en.wikipedia.org/wiki/Heart_of_Darkness', NULL, NULL, '["20th Century''s Greatest Hits: 100 English-Language Books of Fiction"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:03+00:00', '{"openlibrary": {"ol_key": "/works/OL38663W", "ol_cover_id": 12307847, "edition_count": 553, "languages": ["eng", "spa"], "subjects": ["form:novella", "genre:historical fiction", "Romance", "Degeneration", "Description and travel", "Diaries", "Sailors", "Short stories", "English literature", "Suffering", "Trading posts", "Classic Literature"], "synopsis": "Heart of Darkness (1899) is a novella by Polish-English novelist Joseph Conrad, about a voyage up the Congo River into the Congo Free State, in the heart of Africa, by the story''s narrator Charles Marlow. Marlow tells his story to friends aboard a boat anchored on the River Thames. Joseph Conrad is one of the greatest English writers, and Heart of Darkness is considered his best.  His readers are brought to face our psychological selves to answer, ‘Who is the true savage?’. Originally published in 1902, Heart of Darkness remains one of this century’s most enduring works of fiction. Written several years after Joseph Conrad’s grueling sojourn in the Belgian Congo, the novel is a complex meditation on colonialism, evil, and the thin line between civilization and barbarity.", "publication_year": 1899, "page_count": 136, "isbn13": "9780613837712", "ratings_average": 3.58, "ratings_count": 134}, "wikidata": {"wikidata_id": "Q129778", "awards": ["20th Century''s Greatest Hits: 100 English-Language Books of Fiction"], "series": null, "goodreads_id": null, "wikipedia_title": "Heart of Darkness", "wikipedia_url": "https://en.wikipedia.org/wiki/Heart_of_Darkness"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (3, 10793645, 64, '["dut", "eng", "srp", "fre", "ger", "spa", "ara"]', 4.57, 7, 'Q1327843', 'https://en.wikipedia.org/wiki/The_Origins_of_Totalitarianism', NULL, NULL, '["Le Monde''s 100 Books of the Century"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:06+00:00', '{"openlibrary": {"ol_key": "/works/OL10460640W", "ol_cover_id": 10793645, "edition_count": 64, "languages": ["dut", "eng", "srp", "fre", "ger", "spa", "ara"], "subjects": ["Antisemitism", "Imperialism", "Totalitarianism", "Philosophy, german", "Antisémitisme", "Impérialisme", "Totalitarisme", "Histoire", "Juifs", "POLITICAL SCIENCE", "Essays", "Government"], "synopsis": "**Hannah Arendt''s definitive work on totalitarianism and an essential component of any study of twentieth-century political history**\r\n\r\nThe Origins of Totalitarianism begins with the rise of anti-Semitism in central and western Europe in the 1800s and continues with an examination of European colonial imperialism from 1884 to the outbreak of World War I. Arendt explores the institutions and operations of totalitarian movements, focusing on the two genuine forms of totalitarian government in her time—Nazi Germany and Stalinist Russia—which she adroitly recognizes were two sides of the same coin, rather than opposing philosophies of Right and Left. From this vantage point, she discusses the evolution of classes into masses, the role of propaganda in dealing with the nontotalitarian world, the use of terror, and the nature of isolation and loneliness as preconditions for total domination.", "publication_year": 1951, "page_count": 527, "isbn13": "9780063354487", "ratings_average": 4.57, "ratings_count": 7}, "wikidata": {"wikidata_id": "Q1327843", "awards": ["Le Monde''s 100 Books of the Century"], "series": null, "goodreads_id": null, "wikipedia_title": "The Origins of Totalitarianism", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Origins_of_Totalitarianism"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (4, 15226155, 4, '["eng"]', 4.0, 4, 'Q126021752', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:08+00:00', '{"openlibrary": {"ol_key": "/works/OL37565105W", "ol_cover_id": 15226155, "edition_count": 4, "languages": ["eng"], "subjects": ["Science", "nyt:combined-print-and-e-book-nonfiction=2024-04-21", "New York Times bestseller"], "synopsis": "Something new entered our world in November 2022 — the first general purpose AI that could pass for a human and do the kinds of creative, innovative work that only humans could do previously. After millions of years on our own, humans had developed a kind of co-intelligence that could augment, or even replace, human thinking. \r\nThrough his writing, speaking, and teaching, Mollick has become one of the most prominent and provocative explainers of AI, focusing on the practical aspects of how these new tools for thought can transform our world.", "publication_year": 2024, "page_count": null, "isbn13": "9780593716724", "ratings_average": 4.0, "ratings_count": 4}, "wikidata": {"wikidata_id": "Q126021752", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (5, 8750439, 13, '["eng"]', 4.08, 24, 'Q69603223', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:20+00:00', '{"openlibrary": {"ol_key": "/works/OL20078135W", "ol_cover_id": 8750439, "edition_count": 13, "languages": ["eng"], "subjects": ["Information technology", "Social aspects", "Reflection (Philosophy)", "Attention", "Philosophy", "Work", "Arts", "TECHNOLOGY & ENGINEERING / Social Aspects", "NATURE / Environmental Conservation & Protection", "ART / Digital", "Attention Economy", "Internet Art"], "synopsis": "Nothing is harder to do these days than nothing. But in a world where our value is determined by our 24/7 data productivity . . . doing nothing may be our most important form of resistance.\r\n\r\nSo argues artist and critic Jenny Odell in this field guide to doing nothing (at least as capitalism defines it). Odell sees our attention as the most precious—and overdrawn—resource we have. Once we can start paying a new kind of attention, she writes, we can undertake bolder forms of political action, reimagine humankind’s role in the environment, and arrive at more meaningful understandings of happiness and progress.\r\n\r\nFar from the simple anti-technology screed, or the back-to-nature meditation we read so often, How to do Nothing is an action plan for thinking outside of capitalist narratives of efficiency and techno-determinism. Provocative, timely, and utterly persuasive, this book is a four-course meal in the age of Soylent.", "publication_year": 2019, "page_count": 256, "isbn13": "9781612197494", "ratings_average": 4.08, "ratings_count": 24}, "wikidata": {"wikidata_id": "Q69603223", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (6, 6671356, 9, '["tur", "eng"]', 3.88, 8, 'Q109704889', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:23+00:00', '{"openlibrary": {"ol_key": "/works/OL15413083W", "ol_cover_id": 6671356, "edition_count": 9, "languages": ["tur", "eng"], "subjects": ["Historical linguistics", "Language and languages in literature", "Comparative linguistics", "Language acquisition -- Social aspects", "Language and culture", "Language and color", "New York Times reviewed", "Sprachliches Weltbild"], "synopsis": "This book confronts the thorny question of how and whether culture shapes language and language, culture. Linguistics has long shied away from claiming any link between a language and the culture of its speakers: too much simplistic (even bigoted) chatter about the romance of Italian and the goose-stepping orderliness of German has made serious thinkers wary of the entire subject. But now, acclaimed linguist Guy Deutscher has dared to reopen the issue. Can culture influence languageand vice versa? Can different languages lead their speakers to different thoughts? Could our experience of the world depend on whether our language has a word for \"blue\"? Challenging the consensus that the fundaments of language are hard-wired in our genes and thus universal, Deutscher argues that the answer to all these questions isyes. In thrilling fashion, he takes us from Homer to Darwin, from Yale to the Amazon, from how to name the rainbow to why Russian water -- a \"she\" -- becomes a \"he\" once you dip a tea bag into her, demonstrating that language does in fact reflect culture in ways that are anything but trivial. Audacious, delightful, and field-changing, Through the Language Glass is a classic of intellectual discovery. - Publisher.", "publication_year": 2010, "page_count": 304, "isbn13": "978-0805081954", "ratings_average": 3.88, "ratings_count": 8}, "wikidata": {"wikidata_id": "Q109704889", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (7, 8808893, 5, '["eng"]', 4.0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:25+00:00', '{"openlibrary": {"ol_key": "/works/OL19746016W", "ol_cover_id": 8808893, "edition_count": 5, "languages": ["eng"], "subjects": ["Moral and ethical aspects", "Military weapons", "Robotics", "Forecasting", "Military robots", "Weapons systems", "Military applications", "Technological innovations", "War", "Robots", "Uninhabited combat aerial vehicles", "Drone aircraft"], "synopsis": "\"What happens when a Predator drone has as much autonomy as a Google car? Although it sounds like science fiction, the technology to create weapons that could hunt and destroy targets on their own already exists. Paul Scharre, a leading expert in emerging weapons technologies, draws on incisive research and firsthand experience to explore how increasingly autonomous weapons are changing warfare. This far-ranging investigation examines the emergence of fully autonomous weapons, the movement to ban them, and the legal and ethical issues surrounding their use. Scharre spotlights the role of artificial intelligence in military technology, spanning decades of innovation from German noise-seeking Wren torpedoes in World War II--antecedents of today''s armed drones--to autonomous cyber weapons. At the forefront of a game-changing debate, Army of None engages military history, global policy, and bleeding-edge science to explore what it would mean to give machines authority over the ultimate decision: life or death.\"--Provided by publisher.", "publication_year": 2018, "page_count": 436, "isbn13": "9780393608991", "ratings_average": 4.0, "ratings_count": 4}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (8, 12855991, 5, '["eng"]', 4.0, 1, 'Q137824905', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:28+00:00', '{"openlibrary": {"ol_key": "/works/OL25328015W", "ol_cover_id": 12855991, "edition_count": 5, "languages": ["eng"], "subjects": ["Venture capital", "High technology industries", "Finance", "New business enterprises", "Technological innovations", "Economic aspects", "BUSINESS & ECONOMICS / Finance"], "synopsis": null, "publication_year": 2022, "page_count": 376, "isbn13": "9780141988948", "ratings_average": 4.0, "ratings_count": 1}, "wikidata": {"wikidata_id": "Q137824905", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
