INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (11, 11359192, 18, '["eng", "ita", "por", "tur", "ger", "fre", "spa", "rum"]', 4.05, 19, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:34+00:00', '{"openlibrary": {"ol_key": "/works/OL24663287W", "ol_cover_id": 11359192, "edition_count": 18, "languages": ["eng", "ita", "por", "tur", "ger", "fre", "spa", "rum"], "subjects": ["Civilization, history", "nyt:combined-print-and-e-book-nonfiction=2021-11-28", "New York Times bestseller", "Civilization", "Philosophy", "HISTORY, ANCIENT", "Anthropology", "Archaeology", "Archaeology / Anthropology", "schismogenisis"], "synopsis": "The renowned activist and public intellectual David Graeber teams up with the professor of comparative archaeology David Wengrow to deliver a trailblazing account of human history, challenging our most fundamental assumptions about social evolution—from the development of agriculture and cities to the emergence of \"the state,\" political violence, and social inequality—and revealing new possibilities for human emancipation\r\n\r\nFor generations, our remote ancestors have been cast as primitive and childlike—either free and equal innocents, or thuggish and warlike. Civilization, we are told, could be achieved only by sacrificing those original freedoms or, alternatively, by taming our baser instincts. David Graeber and David Wengrow show how such theories first emerged in the eighteenth century as a conservative reaction to powerful critiques of European society posed by Indigenous observers and intellectuals. Revisiting this encounter has startling implications for how we make sense of human history today, including the origins of farming, property, cities, democracy, slavery, and civilization itself.\r\n\r\nDrawing on pathbreaking research in archaeology and anthropology, the authors show how history becomes a far more interesting place once we learn to throw off our conceptual shackles and perceive what’s really there. If humans did not spend 95 percent of their evolutionary past in tiny bands of hunter-gatherers, what were they doing all that time? If agriculture, and cities, did not mean a plunge into hierarchy and domination, then what kinds of social and economic organization did they lead to? What was really happening during the periods that we usually describe as the emergence of \"the state\"? The answers are often unexpected, and suggest that the course of human history may be less set in stone, and more full of playful, hopeful possibilities, than we tend to assume.\r\n\r\nThe Dawn of Everything fundamentally transforms our understanding of the human past and offers a path toward imagining new forms of freedom, new ways of organizing society. This is a monumental book of formidable intellectual range, animated by curiosity, moral vision, and a faith in the power of direct action.", "publication_year": 2021, "page_count": 704, "isbn13": "9780771049828", "ratings_average": 4.05, "ratings_count": 19}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (12, 11646867, 8, '["eng"]', 4.0, 1, 'Q113903828', 'https://en.wikipedia.org/wiki/Otherlands_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:37+00:00', '{"openlibrary": {"ol_key": "/works/OL24831204W", "ol_cover_id": 11646867, "edition_count": 8, "languages": ["eng"], "subjects": ["Paleontology", "Popular works", "Extinction (Biology)", "Biotic communities", "Fossils", "Life (Biology)", "Evolution (Biology)", "Natural history", "Paleobiology", "Biological Extinction", "Paléontologie", "Ouvrages de vulgarisation"], "synopsis": null, "publication_year": 2022, "page_count": 272, "isbn13": "9780241611241", "ratings_average": 4.0, "ratings_count": 1}, "wikidata": {"wikidata_id": "Q113903828", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Otherlands (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Otherlands_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (13, 8151932, 4, '["eng"]', NULL, NULL, 'Q30602810', 'https://en.wikipedia.org/wiki/Men_Without_Work_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:39+00:00', '{"openlibrary": {"ol_key": "/works/OL17851917W", "ol_cover_id": 8151932, "edition_count": 4, "languages": ["eng"], "subjects": ["Economic conditions", "Psychology", "Social conditions", "Unemployed", "Men", "Employment", "Labor market", "United states, politics and government", "Kriminalität", "Ausstieg", "Partizipation", "Arbeitslosigkeit"], "synopsis": "By one reading, things look pretty good for Americans today: the country is richer than ever before and the unemployment rate is down by half since the Great Recession—lower today, in fact, than for most of the postwar era. \r\n\r\nBut a closer look shows that something is going seriously wrong. This is the collapse of work—most especially among America’s men. Nicholas Eberstadt, a political economist who holds the Henry Wendt Chair in Political Economy at the American Enterprise Institute, shows that while “unemployment” has gone down, America’s work rate is also lower today than a generation ago—and that the work rate for US men has been spiraling downward for half a century. Astonishingly, the work rate for American males aged twenty-five to fifty-four—or “men of prime working age”—was actually slightly lower in 2015 than it had been in 1940: before the War, and at the tail end of the Great Depression.\r\n\r\nToday, nearly one in six prime working age men has no paid work at all—and nearly one in eight is out of the labor force entirely, neither working nor even looking for work. This new normal of “men without work,” argues Eberstadt, is “America’s invisible crisis.”\r\n\r\nSo who are these men? How did they get there? What are they doing with their time? And what are the implications of this exit from work for American society?\r\n\r\nNicholas Eberstadt lays out the issue and Jared Bernstein from the left and Henry Olsen from the right offer their responses to this national crisis.\r\n\r\nFor more information, please visit http://menwithoutwork.com.", "publication_year": 2016, "page_count": 206, "isbn13": "9781599475981", "ratings_average": null, "ratings_count": null}, "wikidata": {"wikidata_id": "Q30602810", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Men Without Work (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Men_Without_Work_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (14, 8151939, 3, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:41+00:00', '{"openlibrary": {"ol_key": "/works/OL17851924W", "ol_cover_id": 8151939, "edition_count": 3, "languages": ["eng"], "subjects": ["Entitlement attitudes", "Entitlement spending", "Budget deficits"], "synopsis": "In A Nation of Takers: America’s Entitlement Epidemic, one of our country’s foremost demographers, Nicholas Eberstadt, details the exponential growth in entitlement spending over the past fifty years. As he notes, in 1960, entitlement payments accounted for well under a third of the federal government’s total outlays. Today, entitlement spending accounts for a full two-thirds of the federal budget. Drawing on an impressive array of data and employing a range of easy- to- read, four color charts, Eberstadt shows the unchecked spiral of spending on a range of entitlements, everything from medicare to disability payments.  But Eberstadt does not just chart the astonishing growth of entitlement spending, he also details the enormous economic and cultural costs of this epidemic.   He powerfully argues that while this spending certainly drains our federal coffers, it also has a very real,long-lasting, negative impact on the character of our citizens. \r\nAlso included in the book is a response from one of our leading political theorists, William Galston. In his incisive response, he questions Eberstadt’s conclusions about the corrosive effect of entitlements on character and offers his own analysis of the impact of American entitlement growth.", "publication_year": 2012, "page_count": null, "isbn13": "9781283692038", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (15, 191074, 4, '["eng"]', 3.73, 15, 'Q4004190', 'https://en.wikipedia.org/wiki/A_Supposedly_Fun_Thing_I%27ll_Never_Do_Again', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:45+00:00', '{"openlibrary": {"ol_key": "/works/OL2943597W", "ol_cover_id": 191074, "edition_count": 4, "languages": ["eng"], "subjects": ["Humor (Nonfiction)", "Wit and humor", "American Wit and humor", "Essays", "American wit and humor, travel", "American essays, 20th century", "American wit and humor, social life and customs", "Essays (single author)"], "synopsis": "A collection of stories from David Foster Wallace is occasion to celebrate. These stories -- which have been prominently serialized in Harper''s, Esquire, the Paris Review, and elsewhere -- explore intensely immediate states of mind, with the attention to voice and the extraordinary creative daring that have won Wallace his reputation as one of the most talented fiction writer of his generation.Among the stories are \"The Depressed Person\", a dazzling portrayal of a woman''s mental state; \"Adult World\", which reveals a woman''s agonized consideration of her confusing sexual relationship with her husband; and \"Brief Interviews with Hideous Men\", a dark, hilarious series of portraits of men whose fear of women renders them grotesque.", "publication_year": 1997, "page_count": 353, "isbn13": "978-0316925280", "ratings_average": 3.73, "ratings_count": 15}, "wikidata": {"wikidata_id": "Q4004190", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "A Supposedly Fun Thing I''ll Never Do Again", "wikipedia_url": "https://en.wikipedia.org/wiki/A_Supposedly_Fun_Thing_I%27ll_Never_Do_Again"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (16, 11556927, 4, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:47+00:00', '{"openlibrary": {"ol_key": "/works/OL19763522W", "ol_cover_id": 11556927, "edition_count": 4, "languages": ["eng"], "subjects": ["Travel", "Cycling", "Description and travel", "America, description and travel", "nyt:combined-print-and-e-book-nonfiction=2018-10-21", "New York Times bestseller", "Bicycle touring", "Self-actualization (psychology)", "BIOGRAPHY & AUTOBIOGRAPHY", "Personal Memoirs", "Special Interest", "Adventure"], "synopsis": "\"From travel writer and Instagram phenomenon Jedidiah Jenkins, a long-awaited memoir of adventure, failure, and lessons learned while bicycling the 10,000 miles from Oregon to Patagonia. On the eve of turning thirty, terrified of being sucked into a life he didn''t choose, Jedidiah Jenkins quit his dream job and spent the next sixteen months cycling from Oregon to Patagonia. He chronicled the trip on Instagram, where his photos and profound reflections on life soon attracted hundreds of thousands of followers and got him featured by National Geographic and The Paris Review. In this unflinchingly honest memoir, Jed narrates the adventure that started it all: the people and places he encountered on his way to the bottom of the world, and the internal journey that prompted it--the question of what it means to be an adult; his struggle to reconcile his sexual identity with his conservative Christian upbringing; and his belief in travel as a way to \"wake us up\" to our lives back home. As he writes in his inspiring search for wonder and a life he could believe in, ''It''s not about the bike. It''s about getting out of your routine--and that could look like anything''\"--", "publication_year": 2018, "page_count": 338, "isbn13": "978-1524761400", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
