INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (20, 11534140, 2, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:49:58+00:00', '{"openlibrary": {"ol_key": "/works/OL24778288W", "ol_cover_id": 11534140, "edition_count": 2, "languages": ["eng"], "subjects": ["Italy, history", "Europe, history", "Renaissance", "Art and society", "Renaissance Art", "Humanism"], "synopsis": "\"Between the birth of Dante in 1265 and the death of Galileo in 1642, something happened that transformed the entire culture of western civilization. Painting, sculpture, and architecture would all visibly change in such a striking fashion that there could be no going back on what had taken place. Likewise, the thought and self-conception of humanity would take on a completely new aspect. Sciences would be born--or emerge in an entirely new guise.  The ideas that broke this mold began, and continued to flourish, in the city of Florence in northern central Italy. These ideas, which placed an increasing emphasis on the development of our common humanity--rather than other-worldly spirituality--coalesced in what came to be known as humanism. This philosophy and its new ideas would eventually spread across Italy, yet wherever they took hold they would retain an element essential to their origin. And as they spread further across Europe, this element would remain.  Transformations of human culture throughout western history have remained indelibly stamped by their origins. The Reformation would always retain something of central and northern Germany. The Industrial Revolution soon outgrew its British origins, yet also retained something of its original template. Closer to the present, the IT revolution that began in Silicon Valley remains indelibly colored by its Californian origins. Paul Strathern shows how Florence, and the Florentines themselves, played a similarly unique and transformative role in the Renaissance.\"--Amazon.", "publication_year": 2021, "page_count": 400, "isbn13": "9781643137322", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (21, 10678221, 12, '["spa", "eng"]', 4.4, 10, 'Q106808347', 'https://en.wikipedia.org/wiki/Empire_of_Pain', NULL, NULL, '["Baillie Gifford Prize", "Goodreads Choice Award for Best History & Biography"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:01+00:00', '{"openlibrary": {"ol_key": "/works/OL24218388W", "ol_cover_id": 10678221, "edition_count": 12, "languages": ["spa", "eng"], "subjects": ["Biographies", "Pharmaceutical industry", "Corrupt practices", "drugs", "marketing", "philanthropists", "Oxycodone", "Oxycodone abuse", "Purdue Pharma L.P.", "Biography", "Biography & Memoir", "Business"], "synopsis": null, "publication_year": 2021, "page_count": 720, "isbn13": "9780385545686", "ratings_average": 4.4, "ratings_count": 10}, "wikidata": {"wikidata_id": "Q106808347", "awards": ["Baillie Gifford Prize", "Goodreads Choice Award for Best History & Biography"], "series": null, "goodreads_id": null, "wikipedia_title": "Empire of Pain", "wikipedia_url": "https://en.wikipedia.org/wiki/Empire_of_Pain"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (22, 14837269, 3, '["eng"]', NULL, NULL, 'Q137442018', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:04+00:00', '{"openlibrary": {"ol_key": "/works/OL30747417W", "ol_cover_id": 14837269, "edition_count": 3, "languages": ["eng"], "subjects": ["genre:non-fiction", "Bitcoin"], "synopsis": null, "publication_year": 2021, "page_count": 228, "isbn13": "9798721895609", "ratings_average": null, "ratings_count": null}, "wikidata": {"wikidata_id": "Q137442018", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (23, 10201429, 17, '["eng", "tur", "spa"]', 4.56, 16, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:08+00:00', '{"openlibrary": {"ol_key": "/works/OL20878310W", "ol_cover_id": 10201429, "edition_count": 17, "languages": ["eng", "tur", "spa"], "subjects": ["social sciences", "power", "race relations", "social stratification", "ethnicity", "Caste", "Social classes", "Power (social sciences)", "United states, race relations", "psychology", "nyt:combined-print-and-e-book-nonfiction=2020-08-23", "New York Times bestseller"], "synopsis": "“As we go about our daily lives, caste is the wordless usher in a darkened theater, flashlight cast down in the aisles, guiding us to our assigned seats for a performance. The hierarchy of caste is not about feelings or morality. It is about power—which groups have it and which do not.”\r\n \r\nIn this brilliant book, Isabel Wilkerson gives us a masterful portrait of an unseen phenomenon in America as she explores, through an immersive, deeply researched narrative and stories about real people, how America today and throughout its history has been shaped by a hidden caste system, a rigid hierarchy of human rankings.\r\n \r\nBeyond race, class, or other factors, there is a powerful caste system that influences people’s lives and behavior and the nation’s fate. Linking the caste systems of America, India, and Nazi Germany, Wilkerson explores eight pillars that underlie caste systems across civilizations, including divine will, bloodlines, stigma, and more. Using riveting stories about people—including Martin Luther King, Jr., baseball’s Satchel Paige, a single father and his toddler son, Wilkerson herself, and many others—she shows the ways that the insidious undertow of caste is experienced every day. She documents how the Nazis studied the racial systems in America to plan their out-cast of the Jews; she discusses why the cruel logic of caste requires that there be a bottom rung for those in the middle to measure themselves against; she writes about the surprising health costs of caste, in depression and life expectancy, and the effects of this hierarchy on our culture and politics. Finally, she points forward to ways America can move beyond the artificial and destructive separations of human divisions, toward hope in our common humanity.\r\n\r\nBeautifully written, original, and revealing, Caste: The Origins of Our Discontents is an eye-opening story of people and history, and a reexamination of what lies under the surface of ordinary lives and of American life today.\r\n--https://www.penguinrandomhouse.ca/books/653196/caste-oprahs-book-club-by-isabel-wilkerson/9780593230268", "publication_year": 2020, "page_count": 496, "isbn13": "9780593230251", "ratings_average": 4.56, "ratings_count": 16}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (24, NULL, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:10+00:00', '{"openlibrary": {"ol_key": "/works/OL39919089W", "ol_cover_id": null, "edition_count": 1, "languages": ["eng"], "subjects": ["Nature study", "Emerson, ralph waldo, 1803-1882", "Thoreau, henry david, 1817-1862"], "synopsis": null, "publication_year": 2011, "page_count": 76, "isbn13": "9781463727277", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (25, 12915110, 19, '["eng", "chi", "ger"]', 4.32, 19, 'Q30078322', 'https://en.wikipedia.org/wiki/Evicted%3A_Poverty_and_Profit_in_the_American_City', NULL, NULL, '["The Stowe Prize for Writing to Advance Social Justice", "Pulitzer Prize for General Nonfiction", "PEN/John Kenneth Galbraith Award", "National Book Critics Circle Award in Nonfiction", "Andrew Carnegie Medal for Excellence in Nonfiction"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:13+00:00', '{"openlibrary": {"ol_key": "/works/OL17828326W", "ol_cover_id": 12915110, "edition_count": 19, "languages": ["eng", "chi", "ger"], "subjects": ["Domestic Politics", "2008 financial crisis", "low-income housing", "eviction", "poverty", "profit", "cities and towns", "social science", "urban sociology", "poverty and homelessness", "extreme poverty", "affordable housing"], "synopsis": "Evicted: Poverty and Profit in the American City is a 2016 non-fiction book by American author Matthew Desmond. Set in the poorest areas of Milwaukee, Wisconsin, the book follows eight families struggling to pay rent to their landlords during the financial crisis of 2007–2008. Through a year of ethnographic fieldwork, Desmond''s goal in the book is to highlight the issues of extreme poverty, affordable housing, and economic exploitation in the United States.\r\n\r\nEvicted was well-received and won multiple book awards such as the 2017 Pulitzer Prize for General Nonfiction and the Robert F. Kennedy Book Award. The Pulitzer committee selected the book \"for a deeply researched exposé that showed how mass evictions after the 2008 economic crash were less a consequence than a cause of poverty.\"", "publication_year": 2016, "page_count": 448, "isbn13": "9780553447453", "ratings_average": 4.32, "ratings_count": 19}, "wikidata": {"wikidata_id": "Q30078322", "awards": ["The Stowe Prize for Writing to Advance Social Justice", "Pulitzer Prize for General Nonfiction", "PEN/John Kenneth Galbraith Award", "National Book Critics Circle Award in Nonfiction", "Andrew Carnegie Medal for Excellence in Nonfiction"], "series": null, "goodreads_id": null, "wikipedia_title": "Evicted: Poverty and Profit in the American City", "wikipedia_url": "https://en.wikipedia.org/wiki/Evicted%3A_Poverty_and_Profit_in_the_American_City"}}');
