INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (31, 8808908, 11, '["eng"]', 5.0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:31+00:00', '{"openlibrary": {"ol_key": "/works/OL20162907W", "ol_cover_id": 8808908, "edition_count": 11, "languages": ["eng"], "subjects": ["Animal psychology", "Chimpanzees", "Primates, behavior", "Human-animal relationships", "nyt:combined-print-and-e-book-nonfiction=2019-03-31", "New York Times bestseller", "Emotions in animals", "Primates", "Behavior", "NATURE / Animals / Primates", "PSYCHOLOGY / Emotions"], "synopsis": "A whirlwind tour of new ideas and findings about animal emotions, based on De Waal''s renowned studies of the social and emotional lives of chimpanzees, bonobos, and other primates. De Waal discusses facial expressions, animal sentience and consciousness, Mama''s life and death, the emotional side of human politics, and the illusion of free will. He distinguishes between emotions and feelings, all the while emphasizing the continuity between our species and other species. And he makes the radical proposal that emotions are like organs: we don''t have a single organ that other animals don''t have, and the same is true for our emotions -- Adapted from publisher''s description.", "publication_year": 2019, "page_count": 368, "isbn13": "9780393635065", "ratings_average": 5.0, "ratings_count": 1}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (32, 8250689, 3, '["eng"]', 5.0, 1, 'Q60715087', 'https://en.wikipedia.org/wiki/Unflattening', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:33+00:00', '{"openlibrary": {"ol_key": "/works/OL17924067W", "ol_cover_id": 8250689, "edition_count": 3, "languages": ["eng"], "subjects": ["Methodology", "Theory of Knowledge", "Communication", "Visual perception", "Imagery (Psychology)", "Comic books, strips", "Comics & graphic novels, general", "Graphic novels", "Comic", "Kognition", "Philosophie", "Visuelle Wahrnehmung"], "synopsis": "The primacy of words over images has deep roots in Western culture. But what if the two are inextricably linked, equal partners in meaning-making? Written and drawn entirely as comics, <i style=\"mso-bidi-font-style:normal\">Unflattening is an experiment in visual thinking. Nick Sousanis defies conventional forms of scholarly discourse to offer readers both a stunning work of graphic art and a serious inquiry into the ways humans construct knowledge. <i style=\"mso-bidi-font-style:normal\">Unflattening is an insurrection against the fixed viewpoint. Weaving together diverse ways of seeing drawn from science, philosophy, art, literature, and mythology, it<i style=\"mso-bidi-font-style: normal\"> uses the collage-like capacity of comics to show that perception is always an active process of incorporating and reevaluating different vantage points. While its vibrant, constantly morphing images occasionally serve as illustrations of text, they more often connect in nonlinear fashion to other visual references throughout the book. They become allusions, allegories, and motifs, pitting realism against abstraction and making us aware that more meets the eye than is presented on the page. In its graphic innovations and restless shape-shifting, <i style=\"mso-bidi-font-style:normal\">Unflattening is meant to counteract the type of narrow, rigid thinking that Sousanis calls “flatness.” Just as the two-dimensional inhabitants of Edwin A. Abbott’s novella <i style=\"mso-bidi-font-style:normal\">Flatland could not fathom the concept of “upwards,” Sousanis says, we are often unable to see past the boundaries of our current frame of mind. Fusing words and images to produce new forms of knowledge, <i style=\"mso-bidi-font-style:normal\">Unflattening teaches us how to access modes of understanding beyond what we normally apprehend.", "publication_year": 2015, "page_count": 201, "isbn13": "9780674744431", "ratings_average": 5.0, "ratings_count": 1}, "wikidata": {"wikidata_id": "Q60715087", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Unflattening", "wikipedia_url": "https://en.wikipedia.org/wiki/Unflattening"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (33, 7865361, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:35+00:00', '{"openlibrary": {"ol_key": "/works/OL17582325W", "ol_cover_id": 7865361, "edition_count": 1, "languages": ["eng"], "subjects": ["Politics and government", "Tsunamis", "Economic forecasting", "Social conditions", "Economic conditions", "Japan, history", "Japan, social conditions"], "synopsis": "Financial Times Asia editor David Pilling presents a fresh vision of Japan, drawing on his own deep experience, as well as observations from a cross section of Japanese citizenry, including novelist Haruki Murakami, former prime minister Junichiro Koizumi, industrialists and bankers, activists and artists, teenagers and octogenarians. Through their voices, Pilling captures the dynamism and diversity of contemporary Japan.", "publication_year": 2014, "page_count": 408, "isbn13": "9781594205842", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (34, NULL, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:38+00:00', '{"openlibrary": {"ol_key": "/works/OL19764034W", "ol_cover_id": null, "edition_count": 1, "languages": ["eng"], "subjects": ["Criminal statistics", "Police", "Electronic surveillance", "Big data", "Law enforcement", "Racial profiling in law enforcement", "Data processing", "Discrimination in law enforcement", "Data mining in law enforcement", "Police, united states"], "synopsis": "In a high-tech command center in downtown Los Angeles, a digital map lights up with 911 calls, television monitors track breaking news stories, surveillance cameras sweep the streets, and rows of networked computers link analysts and police officers to a wealth of law enforcement intelligence. This is just a glimpse into a future where software predicts future crimes, algorithms generate virtual \"most-wanted\" lists, and databanks collect personal and biometric information. The Rise of Big Data Policing introduces the cutting-edge technology that is changing how the police do their jobs and shows why it is more important than ever that citizens understand the far-reaching consequences of big data surveillance as a law enforcement tool. Andrew Guthrie Ferguson reveals how these new technologies - viewed as race-neutral and objective - have been eagerly adopted by police departments hoping to distance themselves from claims of racial bias and unconstitutional practices. After a series of high-profile police shootings and federal investigations into systemic police misconduct, and in an era of law enforcement budget cutbacks, data-driven policing has been billed as a way to \"turn the page\" on racial bias. But behind the data are real people, and difficult questions remain about racial discrimination and the potential to distort constitutional protections. In this first book on big data policing, Ferguson offers an examination of how new technologies will alter the who, where, when and how we police. These new technologies also offer data-driven methods to improve police accountability and to remedy the underlying socio-economic risk factors that encourage crime. The Rise of Big Data Policing is a must read for anyone concerned with how technology will revolutionize law enforcement and its potential threat to the security, privacy, and constitutional rights of citizens. --", "publication_year": 2017, "page_count": 259, "isbn13": "9781479892822", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (35, 541092, 17, '["eng", "rus"]', 4.0, 9, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:43+00:00', '{"openlibrary": {"ol_key": "/works/OL4288868W", "ol_cover_id": 541092, "edition_count": 17, "languages": ["eng", "rus"], "subjects": ["Politics and government", "Scientists", "Printers", "Inventors", "Biography", "Statesmen", "Politici", "Politiker", "Umschulungswerkstätten für Siedler und Auswanderer", "History, 18th Century", "Geleerden", "Famous Persons"], "synopsis": "Chronicles the founding father''s life and his multiple careers as a shopkeeper, writer, inventor, media baron, scientist, diplomat, business strategist, and political leader, while showing how his faith in the wisdom of the common citizen helped forge an American national identity based on the virtues of its middle class.", "publication_year": 2003, "page_count": 590, "isbn13": "9780743258074", "ratings_average": 4.0, "ratings_count": 9}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (36, 432217, 16, '["eng", "ger", "fre"]', 4.35, 26, 'Q1590481', 'https://en.wikipedia.org/wiki/Replay_%28Grimwood_novel%29', NULL, NULL, '["World Fantasy Award for Best Novel"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:48+00:00', '{"openlibrary": {"ol_key": "/works/OL2252098W", "ol_cover_id": 432217, "edition_count": 16, "languages": ["eng", "ger", "fre"], "subjects": ["Conduct of life", "Reincarnation", "Time travel", "Large type books", "Fiction, science fiction, action & adventure", "Fiction, action & adventure", "Fiction, romance, fantasy"], "synopsis": "Jeff Winston, forty-three, didn''t know he was a replayer until he died and woke up twenty-five years younger in his college dorm room; he lived another life. And died again. And lived again and died again—in a continuous twenty-five-year cycle—each time starting from scratch at the age of eighteen to reclaim lost loves, remedy past mistakes, or make a fortune in the stock market. A novel of gripping adventure, romance, and fascinating speculation on the nature of time, Replay asks the question: \"What if you could live your life over again?\"", "publication_year": 1986, "page_count": 335, "isbn13": "9780688161125", "ratings_average": 4.35, "ratings_count": 26}, "wikidata": {"wikidata_id": "Q1590481", "awards": ["World Fantasy Award for Best Novel"], "series": null, "goodreads_id": null, "wikipedia_title": "Replay (Grimwood novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Replay_%28Grimwood_novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (37, 10234261, 4, '["eng"]', 3.67, 3, 'Q124749499', 'https://en.wikipedia.org/wiki/The_Hundred-Year_Marathon', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:51+00:00', '{"openlibrary": {"ol_key": "/works/OL19994559W", "ol_cover_id": 10234261, "edition_count": 4, "languages": ["eng"], "subjects": ["Politics and government", "Strategic planning", "National security", "Foreign relations", "National security, asia", "China, politics and government", "China, foreign relations, united states", "United states, foreign relations, china", "China, history", "POLITICAL SCIENCE / International Relations / Diplomacy", "HISTORY / Asia / China", "HISTORY / United States / 21st Century"], "synopsis": "\"For more than forty years, the United States has reached out to China, helping it develop a booming economy and take its place on the world stage, in the belief that there is little to fear--and everything to gain--from China''s rise. But what if the Chinese have had a different plan all along? The Hundred-Year Marathon reveals China''s secret strategy to supplant the United States as the world''s dominant power, and to do so by 2049, the one hundredth anniversary of the founding of the People''s Republic. Michael Pillsbury, who has served in senior national security positions in the U.S. government since the days of Richard Nixon and Henry Kissinger, draws on Chinese documents, speeches, and books (many of them never translated into English) to reveal the roots of this strategy in traditional Chinese statecraft and track how the Chinese are putting it into practice today. Pillsbury shows how American policymakers have been willfully blind to these developments for decades--and he includes himself in that critique, as he was once a leading voice in favor of aiding China. He also calls for the United States to design a new, more competitive strategy toward China as it really is, and not as we might wish it to be. The Hundred-Year Marathon is a wakeup call for all Americans concerned about how we have misread the greatest national security challenge of the twenty-first century\"--", "publication_year": 2015, "page_count": 319, "isbn13": "9781627790109", "ratings_average": 3.67, "ratings_count": 3}, "wikidata": {"wikidata_id": "Q124749499", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Hundred-Year Marathon", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Hundred-Year_Marathon"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (38, 14319246, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:50:58+00:00', '{"openlibrary": {"ol_key": "/works/OL21041666W", "ol_cover_id": 14319246, "edition_count": 1, "languages": ["eng"], "subjects": ["Rome, history, republic, 510-30 b.c."], "synopsis": null, "publication_year": null, "page_count": null, "isbn13": "9780199595112", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (39, 10709039, 5, '["eng"]', 4.0, 5, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:00+00:00', '{"openlibrary": {"ol_key": "/works/OL20028831W", "ol_cover_id": 10709039, "edition_count": 5, "languages": ["eng"], "subjects": ["Social conditions", "Civilization", "Social policy", "New York Times reviewed", "Scandinavia, social conditions", "United states, social conditions, 21st century", "United states, social policy"], "synopsis": "A Finnish journalist and naturalized American citizen compares and contrasts life in the U.S. with life in the Nordic region to encourage Americans to draw on practices from the Nordic way of life to create a fairer, happier, more secure, and less stressful society.\n\nAt a 2012 conference on social mobility, where experts discussed whether people worldwide were attaining a better life than their parents'', Ed Miliband, the leader of the British Labour Party, made a surprising quip: \"If you want the American dream, go to Finland.\" For decades, the country best known for opportunity had been the United States. No longer, said Miliband. Anu Partanen, however, had recently left Finland and moved to America for the love of her life, a man who would ultimately become her husband. Their relationship flourished, but she found that navigating the basics of everyday life--from health insurance and taxes to education and child care--was much more complicated and stressful than in her homeland. At first she attributed her crippling anxiety to the difficulty of adapting to a freewheeling new culture. But as she got to know Americans better, she discovered that they shared her deep apprehensions. To understand why life in Finland is so drastically different from the way things are in the United States, Partanen began to look closely at both countries. In The Nordic Theory of Everything, Partanen compares living in the United States with life in the Nordic region, focusing on four key relationships--parents and children, men and women, employees and employers, and government and citizens. She debunks criticism that Nordic countries are socialist \"nanny states,\" revealing instead that it is we Americans who are far more enmeshed in unhealthy dependencies than we realize. Step by step, Partanen explains how the Nordic approach allows citizens to enjoy more individual freedom and equality than we do. She wants to open Americans'' eyes to how much better things can be--to show her beloved new country what it can learn from her homeland to reinvigorate and fulfill the promise of the American dream. Offering insights, advice, and solutions, The Nordic Theory of Everything makes a convincing argument that we can rebuild our society, rekindle our optimism, and restore independence to our relationships and lives. --Adapted from dust jacket.", "publication_year": 2016, "page_count": 448, "isbn13": "9780062316554", "ratings_average": 4.0, "ratings_count": 5}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (40, 9321915, 9, '["rus", "eng", "ita"]', 3.25, 8, 'Q21428158', 'https://en.wikipedia.org/wiki/The_Master_Algorithm', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:03+00:00', '{"openlibrary": {"ol_key": "/works/OL19663805W", "ol_cover_id": 9321915, "edition_count": 9, "languages": ["rus", "eng", "ita"], "subjects": ["Information Theory", "Cognitive Science", "Algorithms", "Mathematics", "Philosophy", "Artificial intelligence", "Machine Learning", "Knowledge representation (information theory)", "Social aspects", "Information society", "SCIENCE", "System Theory"], "synopsis": "In the world''s top research labs and universities, the race is on to invent the ultimate learning algorithm: one capable of discovering any knowledge from data, and doing anything we want, before we even ask. In The Master Algorithm, Pedro Domingos lifts the veil to give us a peek inside the learning machines that power Google, Amazon, and your smartphone. He assembles a blueprint for the future universal learner--the Master Algorithm--and discusses what it will mean for business, science, and society. If data-ism is today''s philosophy, this book is its bible.", "publication_year": 2015, "page_count": 352, "isbn13": "9780465065707", "ratings_average": 3.25, "ratings_count": 8}, "wikidata": {"wikidata_id": "Q21428158", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Master Algorithm", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Master_Algorithm"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (41, 8793088, 2, '["eng"]', 3.0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:08+00:00', '{"openlibrary": {"ol_key": "/works/OL20148876W", "ol_cover_id": 8793088, "edition_count": 2, "languages": ["eng"], "subjects": ["Zoology", "Animal behavior", "Behavior evolution", "Behavior genetics", "Social behavior in animals", "Animal societies", "SCIENCE / Life Sciences / Zoology / General"], "synopsis": "Studying animal behavior to understand human behavior.\n\n\"For eons, humanity''s greatest minds--philosophers, theologians, and scientists--have lacked confirmable answers to the questions that define and explain the meaning of human existence: what we are and what created us. In [this book], Edward O. Wilson, examining evolutionary history further back than he has ever done before, delivers a revelatory account of the deep origins of society. Asserting that religious creeds and philosophical questions can be reduced to purely genetic and evolutionary components, and that the human body and mind have a physical base obedient to the laws of physics and chemistry, Wilson argues that the only way for us to fully understand human behavior is to appreciate the long, complicated evolutionary histories of nonhuman species. Of these, Wilson demonstrates that at least seventeen--among them the naked African mole rat and sponge-dwelling shrimp--have developed advanced societies based on similar levels of altruism and cooperation found among humans. Just as Darwin, in his 1871 Descent of Man, proposed humanity''s origins through the study of apes and human behavior, Wilson here synthesizes the most updated research in evolutionary science to offer a pithy yet path-breaking work of evolutionary theory. In Genesis, Wilson eloquently braids twenty-first-century scientific research with the lyrical biological and humanistic observations for which he is known and admired.\"--Dust jacket.", "publication_year": 2019, "page_count": 160, "isbn13": "9781631495540", "ratings_average": 3.0, "ratings_count": 1}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (42, 405381, 23, '["por", "eng", "spa", "chi"]', 4.39, 18, 'Q1091079', 'https://en.wikipedia.org/wiki/How_to_Read_a_Book', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:10+00:00', '{"openlibrary": {"ol_key": "/works/OL487444W", "ol_cover_id": 405381, "edition_count": 23, "languages": ["por", "eng", "spa", "chi"], "subjects": ["Reading, Psychology of", "Psychology of Reading", "Books and reading", "Lecture", "Reading", "Long Now Manual for Civilization", "Reading (Adult education)"], "synopsis": null, "publication_year": 1940, "page_count": 398, "isbn13": "9780671212094", "ratings_average": 4.39, "ratings_count": 18}, "wikidata": {"wikidata_id": "Q1091079", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "How to Read a Book", "wikipedia_url": "https://en.wikipedia.org/wiki/How_to_Read_a_Book"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (43, 10673266, 78, '["eng", "spa", "ger", "fre", "dan"]', 3.83, 126, 'Q189446', 'https://en.wikipedia.org/wiki/Zen_and_the_Art_of_Motorcycle_Maintenance', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:13+00:00', '{"openlibrary": {"ol_key": "/works/OL827357W", "ol_cover_id": 10673266, "edition_count": 78, "languages": ["eng", "spa", "ger", "fre", "dan"], "subjects": ["Pirsig, Robert M.", "Biography", "Description and travel", "Fathers and sons", "Journeys", "Maintenance and repair", "Motorcycles", "Philosophy", "Philosophy and civilization", "Popular culture", "Psychology", "Self"], "synopsis": "\"The real cycle you''re working on is a cycle called ''yourself.''\"One of the most important and influential books of the past half-century, Robert M. Pirsig''s Zen and the Art of Motorcycle Maintenance is a powerful, moving, and penetrating examination of how we live and a meditation on how to live better. The narrative of a father on a summer motorcycle trip across America''s Northwest with his young son, it becomes a profound personal and philosophical odyssey into life''s fundamental questions. A true modern classic, it remains at once touching and transcendent, resonant with the myriad confusions of existence and the small, essential triumphs that propel us forward.", "publication_year": 1974, "page_count": 421, "isbn13": "9780688171667", "ratings_average": 3.83, "ratings_count": 126}, "wikidata": {"wikidata_id": "Q189446", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Zen and the Art of Motorcycle Maintenance", "wikipedia_url": "https://en.wikipedia.org/wiki/Zen_and_the_Art_of_Motorcycle_Maintenance"}}');
