INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (47, 8118023, 5, '["eng"]', 4.33, 6, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:25+00:00', '{"openlibrary": {"ol_key": "/works/OL17826327W", "ol_cover_id": 8118023, "edition_count": 5, "languages": ["eng"], "subjects": ["Evolution", "Urban ecology (Sociology)", "Sustainable development", "Molecular aspects", "Science", "Evolution (Biology)", "Philosophy", "Scaling (Social sciences)", "Methodology", "Social sciences", "BUSINESS & ECONOMICS", "Strategic Planning"], "synopsis": "\"From one of the most influential scientists of our time, a dazzling exploration of the hidden laws that govern the life cycle of everything from plants and animals to the cities we live in. The former head of the Sante Fe Institute, visionary physicist Geoffrey West is a pioneer in the field of complexity science, the science of emergent systems and networks. The term \"complexity\" can be misleading, however, because what makes West''s discoveries so beautiful is that he has found an underlying simplicity that unites the seemingly complex and diverse phenomena of living systems, including our bodies, our cities and our businesses. Fascinated by issues of aging and mortality, West applied the rigor of a physicist to the biological question of why we live as long as we do and no longer. The result was astonishing, and changed science, creating a new understanding of energy use and metabolism: West found that despite the riotous diversity in the sizes of mammals, they are all, to a large degree, scaled versions of each other. If you know the size of a mammal, you can use scaling laws to learn everything from how much food it eats per day, what its heart-rate is, how long it will take to mature, its lifespan, and so on. Furthermore, the efficiency of the mammal''s circulatory systems scales up precisely based on weight: if you compare a mouse, a human and an elephant on a logarithmic graph, you find with every doubling of average weight, a species gets 25% more efficient--and lives 25% longer. This speaks to everything from how long we can expect to live to how many hours of sleep we need. Fundamentally, he has proven, the issue has to do with the fractal geometry of the networks that supply energy and remove waste from the organism''s body\"--", "publication_year": 2015, "page_count": 479, "isbn13": "9781594205583", "ratings_average": 4.33, "ratings_count": 6}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (48, 8828177, 1, '["eng"]', 1.0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:27+00:00', '{"openlibrary": {"ol_key": "/works/OL19764274W", "ol_cover_id": 8828177, "edition_count": 1, "languages": ["eng"], "subjects": ["Blockchains (Databases)", "Forecasting", "Internet", "Electronic commerce", "High technology industries", "Security measures", "Internet, economic aspects", "Business, data processing", "Internet advertising"], "synopsis": "\"The Age of Google, built on big data and machine intelligence, has been an awesome era. But it''s coming to an end. In Life after Google, George Gilder--the peerless visionary of technology and culture--explains why Silicon Valley is suffering a nervous breakdown and what to expect as the post-Google age dawns. Google''s astonishing ability to ''search and sort'' attracts the entire world to its search engine and countless other goodies--videos, maps, email, calendars.... And everything it offers is free, or so it seems. Instead of paying directly, users submit to advertising. The system of ''aggregate and advertise'' works--for a while--if you control an empire of data centers, but a market without prices strangles entrepreneurship and turns the Internet into a wasteland of ads. The crisis is not just economic. Even as advances in artificial intelligence induce delusions of omnipotence and transcendence, Silicon Valley has pretty much given up on security. The Internet firewalls supposedly protecting all those passwords and personal information have proved hopelessly permeable. The crisis cannot be solved within the current computer and network architecture. The future lies with the ''cryptocosm''--The new architecture of the blockchain and its derivatives. Enabling cryptocurrencies such as bitcoin and ether, NEO and Hashgraph, it will provide the Internet a secure global payments system, ending the aggregate-and-advertise Age of Google. Silicon Valley, long dominated by a few giants, faces a ''great unbundling,'' which will disperse computer power and commerce and transform the economy and the Internet\"--Dust jacket.", "publication_year": 2018, "page_count": 320, "isbn13": "9781621575764", "ratings_average": 1.0, "ratings_count": 1}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (49, 8805168, 12, '["spa", "eng"]', 3.0, 7, 'Q86663208', 'https://en.wikipedia.org/wiki/How_to_Change_Your_Mind', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:30+00:00', '{"openlibrary": {"ol_key": "/works/OL20159801W", "ol_cover_id": 8805168, "edition_count": 12, "languages": ["spa", "eng"], "subjects": ["Hallucinogenic drugs", "Mental health", "Therapeutic use", "Biography", "Psychotherapy patients", "Psychological aspects", "Psychotherapy", "Hallucinations and illusions", "nyt:combined-print-and-e-book-nonfiction=2018-06-03", "New York Times bestseller", "New York Times reviewed", "Mental illness"], "synopsis": "When Michael Pollan set out to research how LSD and psilocybin (the active ingredient in magic mushrooms) are being used to provide relief to people suffering from difficult-to-treat conditions such as depression, addiction and anxiety, he did not intend to write what is undoubtedly his most personal book. But upon discovering how these remarkable substances are improving the lives not only of the mentally ill but also of healthy people coming to grips with the challenges of everyday life, he decided to explore the landscape of the mind in the first person as well as the third. Thus began a singular adventure into various altered states of consciousness, along with a dive deep into both the latest brain science and the thriving underground community of psychedelic therapists. Pollan sifts the historical record to separate the truth about these mysterious drugs from the myths that have surrounded them since the 1960s, when a handful of psychedelic evangelists inadvertently catalyzed a powerful backlash against what was then a promising field of research.", "publication_year": 2018, "page_count": 480, "isbn13": "9781594204227", "ratings_average": 3.0, "ratings_count": 7}, "wikidata": {"wikidata_id": "Q86663208", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "How to Change Your Mind", "wikipedia_url": "https://en.wikipedia.org/wiki/How_to_Change_Your_Mind"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (50, 8231871, 5, '["fre", "eng"]', 4.16, 31, 'Q16834408', 'https://en.wikipedia.org/wiki/Freedom%E2%84%A2', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:32+00:00', '{"openlibrary": {"ol_key": "/works/OL14996932W", "ol_cover_id": 8231871, "edition_count": 5, "languages": ["fre", "eng"], "subjects": ["Human-computer interaction", "Stockbrokers", "International economic integration", "Science fiction", "Thriller", "Fiction, suspense", "Fiction, science fiction, general", "Fiction, thrillers, suspense"], "synopsis": "The propulsive, shockingly plausible sequel to New York Times bestseller DaemonIn one of the most buzzed-about debuts of 2009, Daniel Suarez introduced a terrifying vision of a new world order, controlled by the Daemon, an insidious computer program unleashed by a hi-tech wunderkind, Daemon captured the attention of the tech community, became a New York Times and Indie bestseller, and left readers hungry for more.Well, more is here, and it''s even more gripping than its predecessor.In the opening chapters of Freedom(tm), the Daemon is firmly in control, using an expanded network of real-world, dispossessed darknet operatives to tear apart civilization and rebuild it anew. Soon civil war breaks out in the American Midwest, in a brutal wave of violence that becomes known as the Corn Rebellion. Former detective Pete Sebeck, now the Daemon''s most powerful-though reluctant-operative, must lead a small band of enlightened humans toward a populist movement designed to protect the new world order. But the private armies of global business are preparing to crush the Daemon once and for all.In a world of conflicted loyalties, rapidly diminishing human power, and the possibility that anyone can be a spy, what''s at stake is nothing less than human freedom''s last hope to survive the technology revolution.", "publication_year": 2010, "page_count": 416, "isbn13": "9780451231895", "ratings_average": 4.16, "ratings_count": 31}, "wikidata": {"wikidata_id": "Q16834408", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Freedom™", "wikipedia_url": "https://en.wikipedia.org/wiki/Freedom%E2%84%A2"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (51, 12915198, 37, '["heb", "eng", "spa", "ger", "rus", "fre"]', 3.69, 36, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:37+00:00', '{"openlibrary": {"ol_key": "/works/OL276557W", "ol_cover_id": 12915198, "edition_count": 37, "languages": ["heb", "eng", "spa", "ger", "rus", "fre"], "subjects": ["Sociology", "Culturen", "Environnement", "Changement social", "Verval (geschiedenis)", "Environment", "Historia social", "Social Conditions", "Nature", "Effect of human beings on", "Case studies", "Hombre"], "synopsis": "\"In his Pulitzer Prize-winning bestseller Guns, Germs, and Steel, Jared Diamond examined how and why Western civilizations developed the technologies and immunities that allowed them to dominate much of the world. Now, Diamond probes the other side of the equation: What caused some of the great civilizations of the past to collapse into ruin, and what can we learn from their fates?\" \"As in Guns, Germs, and Steel, Diamond weaves an all-encompassing global thesis through a series of historical-cultural narratives. Moving from the prehistoric Polynesian culture on Easter Island to the formerly flourishing Native American civilizations of the Anasazi and the Maya, the doomed medieval Viking colony on Greenland, and finally to the modern world, Diamond traces a fundamental pattern of catastrophe, spelling out what happens when we squander our resources, when we ignore the signals our environment gives us, and when we reproduce too fast or cut down too many trees. Environmental damage, climate change, rapid population growth, unstable trade partners, and pressure from enemies were all factors in the demise of the doomed societies, but other societies found solutions to those same problems and persisted.\"--BOOK JACKET", "publication_year": 2004, "page_count": 628, "isbn13": "9780143036555", "ratings_average": 3.69, "ratings_count": 36}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (52, 8634250, 86, '["spa", "eng", "por", "fre"]', 4.23, 203, 'Q12411055', 'https://en.wikipedia.org/wiki/Sapiens%3A_A_Brief_History_of_Humankind', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:40+00:00', '{"openlibrary": {"ol_key": "/works/OL17075811W", "ol_cover_id": 8634250, "edition_count": 86, "languages": ["spa", "eng", "por", "fre"], "subjects": ["Technology and civilization", "Human beings", "Historical Chronology", "Historia universal", "Historia", "Civilization", "Hombre", "World history", "Science", "SCIENCE / Life Sciences / General", "SCIENCE / General", "SCIENCE / Life Sciences / Evolution"], "synopsis": "From a renowned historian comes a groundbreaking narrative of humanity’s creation and evolution—a #1 international bestseller—that explores the ways in which biology and history have defined us and enhanced our understanding of what it means to be “human.”\r\n\r\nOne hundred thousand years ago, at least six different species of humans inhabited Earth. Yet today there is only one—homo sapiens. What happened to the others? And what may happen to us?\r\n\r\nMost books about the history of humanity pursue either a historical or a biological approach, but Dr. Yuval Noah Harari breaks the mold with this highly original book that begins about 70,000 years ago with the appearance of modern cognition. From examining the role evolving humans have played in the global ecosystem to charting the rise of empires, Sapiens integrates history and science to reconsider accepted narratives, connect past developments with contemporary concerns, and examine specific events within the context of larger ideas.\r\n\r\nDr. Harari also compels us to look ahead, because over the last few decades humans have begun to bend laws of natural selection that have governed life for the past four billion years. We are acquiring the ability to design not only the world around us, but also ourselves. Where is this leading us, and what do we want to become?\r\n\r\nFeaturing 27 photographs, 6 maps, and 25 illustrations/diagrams, this provocative and insightful work is sure to spark debate and is essential reading for aficionados of Jared Diamond, James Gleick, Matt Ridley, Robert Wright, and Sharon Moalem.", "publication_year": 2011, "page_count": 456, "isbn13": "9780062316110", "ratings_average": 4.23, "ratings_count": 203}, "wikidata": {"wikidata_id": "Q12411055", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Sapiens: A Brief History of Humankind", "wikipedia_url": "https://en.wikipedia.org/wiki/Sapiens%3A_A_Brief_History_of_Humankind"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (53, 8814155, 11, '["tur", "spa", "eng", "por"]', 4.52, 31, 'Q42530022', 'https://en.wikipedia.org/wiki/Why_We_Sleep', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:44+00:00', '{"openlibrary": {"ol_key": "/works/OL20168133W", "ol_cover_id": 8814155, "edition_count": 11, "languages": ["tur", "spa", "eng", "por"], "subjects": ["sleep", "health & fitness", "sleep & sleep disorders", "science", "life sciences", "Human Anatomy & Physiology", "psychology", "mental health", "Sleep, psychological aspects", "Dreams", "nyt:science=2017-11-12", "New York Times bestseller"], "synopsis": "With two appearances on CBS This Morning and Fresh Air''s most popular interview of 2017, Matthew Walker has made abundantly clear that sleep is one of the most important but least understood aspects of our life. Until very recently, science had no answer to the question of why we sleep, or what good it served, or why we suffer such devastating health consequences when it is absent. Compared to the other basic drives in life—eating, drinking, and reproducing—the purpose of sleep remains more elusive.\r\n\r\nWithin the brain, sleep enriches a diversity of functions, including our ability to learn, memorize, and make logical decisions. It recalibrates our emotions, restocks our immune system, fine-tunes our metabolism, and regulates our appetite. Dreaming creates a virtual reality space in which the brain melds past and present knowledge, inspiring creativity.\r\n\r\nIn this “compelling and utterly convincing” (The Sunday Times) book, preeminent neuroscientist and sleep expert Matthew Walker provides a revolutionary exploration of sleep, examining how it affects every aspect of our physical and mental well-being. Charting the most cutting-edge scientific breakthroughs, and marshalling his decades of research and clinical practice, Walker explains how we can harness sleep to improve learning, mood and energy levels, regulate hormones, prevent cancer, Alzheimer’s and diabetes, slow the effects of aging, and increase longevity. He also provides actionable steps towards getting a better night’s sleep every night.", "publication_year": 2017, "page_count": 360, "isbn13": "9781501144318", "ratings_average": 4.52, "ratings_count": 31}, "wikidata": {"wikidata_id": "Q42530022", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Why We Sleep", "wikipedia_url": "https://en.wikipedia.org/wiki/Why_We_Sleep"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (54, 10286374, 2, '["eng"]', 5.0, 2, 'Q48726642', 'https://en.wikipedia.org/wiki/Why_Buddhism_Is_True', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:47+00:00', '{"openlibrary": {"ol_key": "/works/OL20917487W", "ol_cover_id": 10286374, "edition_count": 2, "languages": ["eng"], "subjects": ["nyt:paperback-nonfiction=2018-05-27", "New York Times bestseller", "Buddhism"], "synopsis": null, "publication_year": 2017, "page_count": 336, "isbn13": "9781508235408", "ratings_average": 5.0, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q48726642", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Why Buddhism Is True", "wikipedia_url": "https://en.wikipedia.org/wiki/Why_Buddhism_Is_True"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (55, 8458597, 13, '["eng"]', 4.31, 13, 'Q30068660', 'https://en.wikipedia.org/wiki/Walkaway_%28Doctorow_novel%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:49+00:00', '{"openlibrary": {"ol_key": "/works/OL17801248W", "ol_cover_id": 8458597, "edition_count": 13, "languages": ["eng"], "subjects": ["Fiction, science fiction, general", "Rich people", "Fathers and daughters", "Social change", "Future life", "Rich people -- Fiction", "Fathers and daughters -- Fiction", "Social change -- Fiction", "Future life -- Fiction"], "synopsis": "Hubert Vernon Rudolph Clayton Irving Wilson Alva Anton Jeff Harley Timothy Curtis Cleveland Cecil Ollie Edmund Eli Wiley Marvin Ellis Espinoza―known to his friends as Hubert, Etc―was too old to be at that Communist party.\r\n\r\nBut after watching the breakdown of modern society, he really has no where left to be―except amongst the dregs of disaffected youth who party all night and heap scorn on the sheep they see on the morning commute. After falling in with Natalie, an ultra-rich heiress trying to escape the clutches of her repressive father, the two decide to give up fully on formal society―and walk away.\r\n\r\nAfter all, now that anyone can design and print the basic necessities of life―food, clothing, shelter―from a computer, there seems to be little reason to toil within the system.\r\n\r\nIt’s still a dangerous world out there, the empty lands wrecked by climate change, dead cities hollowed out by industrial flight, shadows hiding predators animal and human alike. Still, when the initial pioneer walkaways flourish, more people join them. Then the walkaways discover the one thing the ultra-rich have never been able to buy: how to beat death. Now it’s war – a war that will turn the world upside down.\r\n\r\nFascinating, moving, and darkly humorous, Walkaway is a multi-generation SF thriller about the wrenching changes of the next hundred years…and the very human people who will live their consequences.", "publication_year": 2017, "page_count": 496, "isbn13": "9780765392763", "ratings_average": 4.31, "ratings_count": 13}, "wikidata": {"wikidata_id": "Q30068660", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Walkaway (Doctorow novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Walkaway_%28Doctorow_novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (56, 6404884, 6, '["eng"]', 4.15, 48, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:53+00:00', '{"openlibrary": {"ol_key": "/works/OL13646905W", "ol_cover_id": 6404884, "edition_count": 6, "languages": ["eng"], "subjects": ["Human-computer interaction", "International economic integration", "Computer programmers", "Thriller", "Fiction, suspense", "Programmeurs", "Romans, nouvelles", "Intégration économique internationale", "Fiction, science fiction, action & adventure", "Scientists, fiction", "Long now manual for civilization"], "synopsis": "Already an underground sensation, a high-tech thriller for the wireless age that explores the unthinkable consequences of a computer program running without human control—a daemon—designed to dismantle society and bring about a new world order.\r\n\r\nTechnology controls almost everything in our modern-day world, from remote entry on our cars to access to our homes, from the flight controls of our airplanes to the movements of the entire world economy. Thousands of autonomous computer programs, or daemons, make our networked world possible, running constantly in the background of our lives, trafficking e-mail, transferring money, and monitoring power grids. For the most part, daemons are benign, but the same can''t always be said for the people who design them.\r\n\r\nMatthew Sobol was a legendary computer game designer—the architect behind half-a-dozen popular online games. His premature death depressed both gamers and his company''s stock price. But Sobol''s fans aren''t the only ones to note his passing. When his obituary is posted online, a previously dormant daemon activates, initiating a chain of events intended to unravel the fabric of our hyper-efficient, interconnected world. With Sobol''s secrets buried along with him, and as new layers of his daemon are unleashed at every turn, it''s up to an unlikely alliance to decipher his intricate plans and wrest the world from the grasp of a nameless, faceless enemy—or learn to live in a society in which we are no longer in control...\r\n\r\nComputer technology expert Daniel Suarez blends haunting high-tech realism with gripping suspense in an authentic, complex thriller in the tradition of Michael Crichton, Neal Stephenson, and William Gibson.", "publication_year": 2009, "page_count": 540, "isbn13": "9780451228734", "ratings_average": 4.15, "ratings_count": 48}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (57, 8048632, 11, '["eng", "ger"]', 5.0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:55+00:00', '{"openlibrary": {"ol_key": "/works/OL17765779W", "ol_cover_id": 8048632, "edition_count": 11, "languages": ["eng", "ger"], "subjects": ["Gene Editing", "CRISPR", "Genetic code", "Genetic engineering", "Genetics", "Research", "Rna", "CRISPR-Cas Systems", "Genetic Research", "MEDICAL", "SCIENCE", "Life Sciences"], "synopsis": "**A trailblazing biologist grapples with her role in the biggest scientific discovery of our era: a cheap, easy way of rewriting genetic code, with nearly limitless promise and peril.**\r\n\r\nNot since the atomic bomb has a technology so alarmed its inventors that they warned the world about its use. Not, that is, until the spring of 2015, when biologist Jennifer Doudna called for a worldwide moratorium on the use of the new gene-editing tool CRISPR—a revolutionary new technology that she helped create—to make heritable changes in human embryos. The cheapest, simplest, most effective way of manipulating DNA ever known, CRISPR may well give us the cure to HIV, genetic diseases, and some cancers, and will help address the world’s hunger crisis. Yet even the tiniest changes to DNA could have myriad, unforeseeable consequences—to say nothing of the ethical and societal repercussions of intentionally mutating embryos to create “better” humans.\r\n \r\nWriting with fellow researcher Samuel Sternberg, Doudna shares the thrilling story of her discovery, and passionately argues that enormous responsibility comes with the ability to rewrite the code of life. With CRISPR, she shows, we have effectively taken control of evolution. What will we do with this unfathomable power?\r\n\r\n[(Source)][1]\r\n\r\n\r\n  [1]: https://www.amazon.com/Crack-Creation-Editing-Unthinkable-Evolution/dp/0544716949/", "publication_year": 2017, "page_count": 304, "isbn13": "9780544716940", "ratings_average": 5.0, "ratings_count": 1}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (58, 12025301, 4, '["eng"]', 4.0, 5, 'Q5918648', 'https://en.wikipedia.org/wiki/How_to_Live_%28biography%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:51:58+00:00', '{"openlibrary": {"ol_key": "/works/OL25463670W", "ol_cover_id": 12025301, "edition_count": 4, "languages": ["eng"], "subjects": ["Montaigne, michel de, 1533-1592", "Conduct of life", "Authors, biography"], "synopsis": null, "publication_year": 2010, "page_count": 387, "isbn13": "9781590514832", "ratings_average": 4.0, "ratings_count": 5}, "wikidata": {"wikidata_id": "Q5918648", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "How to Live (biography)", "wikipedia_url": "https://en.wikipedia.org/wiki/How_to_Live_%28biography%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (59, 9577895, 1, '["eng"]', 4.0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:03+00:00', '{"openlibrary": {"ol_key": "/works/OL19664939W", "ol_cover_id": 9577895, "edition_count": 1, "languages": ["eng"], "subjects": ["Performance", "Expertise", "Ability", "Psychological aspects", "Excellence", "Gifted persons"], "synopsis": "Draws on the examples of chess champions, violin virtuosos, star athletes, and memory mavens to outline a powerful approach to learning that enables proficiency through strategic goal setting, self-motivation, and feedback exercises.", "publication_year": 2016, "page_count": 336, "isbn13": "9780544456235", "ratings_average": 4.0, "ratings_count": 4}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (60, 9265707, 10, '["eng"]', 4.0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:05+00:00', '{"openlibrary": {"ol_key": "/works/OL16184574W", "ol_cover_id": 9265707, "edition_count": 10, "languages": ["eng"], "subjects": ["Genetic Epigenesis", "Molecular Evolution", "Epigenomics", "Epigenesis", "Gene expression", "Genetik", "Genetics", "Evolution (Biology)", "Evolution (biologi)", "Science", "Evolution", "Genetic regulation"], "synopsis": "\"Epigenetics can potentially revolutionize our understanding of the structure and behavior of biological life on Earth. It explains why mapping an organism''s genetic code is not enough to determine how it develops or acts and shows how nurture combines with nature to engineer biological diversity. Surveying the twenty-year history of the field while also highlighting its latest findings and innovations, this volume provides a readily understandable introduction to the foundations of epigenetics. Nessa Carey, a leading epigenetics researcher, connects the field''s arguments to such diverse phenomena as how ants and queen bees control their colonies; why tortoiseshell cats are always female; why some plants need cold weather before they can flower; and how our bodies age and develop disease. Reaching beyond biology, epigenetics now informs work on drug addiction, the long-term effects of famine, and the physical and psychological consequences of childhood trauma. Carey concludes with a discussion of the future directions for this research and its ability to improve human health and well-being.\"--Amazon.com.", "publication_year": 2011, "page_count": 330, "isbn13": "9781848313477", "ratings_average": 4.0, "ratings_count": 1}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (61, 8055563, 9, '["eng"]', 4.15, 13, 'Q30893129', 'https://en.wikipedia.org/wiki/Stuff_Matters', NULL, NULL, '["Physics World Book of the Year Award"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:08+00:00', '{"openlibrary": {"ol_key": "/works/OL17778974W", "ol_cover_id": 8055563, "edition_count": 9, "languages": ["eng"], "subjects": ["Materials", "Material culture", "Materials science", "Popular works", "SCIENCE / Applied Sciences", "SCIENCE / Chemistry / Inorganic", "HISTORY / Modern / General", "nyt:science=2014-07-13", "New York Times bestseller", "New York Times reviewed", "Science des matériaux", "Ouvrages de vulgarisation"], "synopsis": "\"Why is glass see-through? What makes elastic stretchy? Why does a paperclip bend? Why does any material look and behave the way it does?With clarity and humor, world-leading materials scientist Mark Miodownik answers all the questions you''ve ever had about your pens, spoons, and razor blades, while also introducing a whole world full of materials you''ve never even heard of: the diamond five times the size of Earth; concrete cloth that can be molded into any shape; and graphene, the thinnest, strongest, stiffest material in existence--only a single atom thick.Stuff Matters tells enthralling stories that explain the science and history of materials. From the teacup to the jet engine, the silicon chip to the paper clip, the plastic in our appliances to the elastic in our underpants, Miodownik reveals the miracles of engineering that permeate our lives. As engaging as it is incisive, Stuff Matters will make you see the materials that surround you with new eyes\"--", "publication_year": 2013, "page_count": 272, "isbn13": "9780544236042", "ratings_average": 4.15, "ratings_count": 13}, "wikidata": {"wikidata_id": "Q30893129", "awards": ["Physics World Book of the Year Award"], "series": null, "goodreads_id": null, "wikipedia_title": "Stuff Matters", "wikipedia_url": "https://en.wikipedia.org/wiki/Stuff_Matters"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (62, 7898682, 25, '["srp", "eng", "por", "pol"]', 4.4, 35, 'Q53017202', 'https://en.wikipedia.org/wiki/Norse_Mythology_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:11+00:00', '{"openlibrary": {"ol_key": "/works/OL17619634W", "ol_cover_id": 7898682, "edition_count": 25, "languages": ["srp", "eng", "por", "pol"], "subjects": ["Norse Mythology", "FICTION / Literary", "FICTION / Fairy Tales, Folk Tales, Legends & Mythology", "Mythology, norse", "Fantasy", "nyt:combined-print-and-e-book-fiction=2017-02-26", "New York Times bestseller", "New York Times reviewed"], "synopsis": "Neil Gaiman has long been inspired by ancient mythology in creating the fantastical realms of his fiction. Now he turns his attention back to the source, presenting a bravura rendition of the great northern tales.\r\n\r\nIn Norse Mythology, Gaiman stays true to the myths in envisioning the major Norse pantheon: Odin, the highest of the high, wise, daring, and cunning; Thor, Odin’s son, incredibly strong yet not the wisest of gods; and Loki―son of a giant―blood brother to Odin and a trickster and unsurpassable manipulator.\r\n\r\nGaiman fashions these primeval stories into a novelistic arc that begins with the genesis of the legendary nine worlds and delves into the exploits of deities, dwarfs, and giants. Once, when Thor’s hammer is stolen, Thor must disguise himself as a woman―difficult with his beard and huge appetite―to steal it back. More poignant is the tale in which the blood of Kvasir―the most sagacious of gods―is turned into a mead that infuses drinkers with poetry. The work culminates in Ragnarok, the twilight of the gods and rebirth of a new time and people.\r\n\r\nThrough Gaiman’s deft and witty prose emerge these gods with their fiercely competitive natures, their susceptibility to being duped and to duping others, and their tendency to let passion ignite their actions, making these long-ago myths breathe pungent life again.", "publication_year": 2016, "page_count": 304, "isbn13": "9780393609097", "ratings_average": 4.4, "ratings_count": 35}, "wikidata": {"wikidata_id": "Q53017202", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Norse Mythology (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Norse_Mythology_%28book%29"}}');
