INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (66, 14846900, 28, '["spa", "eng", "ger", "chi"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:21+00:00', '{"openlibrary": {"ol_key": "/works/OL17357665W", "ol_cover_id": 14846900, "edition_count": 28, "languages": ["spa", "eng", "ger", "chi"], "subjects": ["Mountain people", "Family", "Social mobility", "Working class whites", "Case studies", "Economic conditions", "Social conditions", "Biography", "Arbeitssoziologie", "Sociology", "Umschulungswerkstätten für Siedler und Auswanderer", "Ausgrenzung"], "synopsis": "From a former marine and Yale Law School graduate, this book is a probing look at the struggles of America''s white working class through the author''s own story of growing up in a poor Rust Belt town. Hillbilly Elegy is a passionate and personal analysis of a culture in crisis - that of poor, white Americans. The disintegration of this group, a process that has been slowly occurring now for over forty years, has been reported with growing frequency and alarm, but has never before been written about as searingly from the inside.", "publication_year": null, "page_count": null, "isbn13": "9780062300546", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (67, 7355949, 17, '["eng", "fre"]', 3.92, 71, 'Q17001721', 'https://en.wikipedia.org/wiki/Ancillary_Justice', NULL, 'Imperial Radch', '["Hugo Award for Best Novel", "Locus Award for Best First Novel", "Arthur C. Clarke Award", "BSFA Award for Best Novel", "Seiun Award for Best Translated Long Work", "Nebula Award for Best Novel", "Bob Morane award for best foreign novel"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:25+00:00', '{"openlibrary": {"ol_key": "/works/OL17062644W", "ol_cover_id": 7355949, "edition_count": 17, "languages": ["eng", "fre"], "subjects": ["Science Fiction", "Quests (Expeditions)", "Ebook", "Space Opera", "Revenge", "Adult", "Adventure", "Fiction, science fiction, general", "award:nebula_award=novel", "Artificial intelligence", "Large type books", "Hugo Award Winner"], "synopsis": "On a remote, icy planet, the soldier known as Breq is drawing closer to completing her quest.\r\n\r\nOnce, she was the *Justice of Toren*--a colossal starship with an artificial intelligence linking thousands of soldiers in the service of the Radch, the empire that conquered the galaxy.\r\n\r\nNow, an act of treachery has ripped it all away, leaving her with one fragile human body, unanswered questions, and a burning desire for vengeance.\r\n\r\n\r\nSequels: Ancillary Sword; Ancillary Mercy.", "publication_year": 2013, "page_count": 409, "isbn13": "9780316246620", "ratings_average": 3.92, "ratings_count": 71}, "wikidata": {"wikidata_id": "Q17001721", "awards": ["Hugo Award for Best Novel", "Locus Award for Best First Novel", "Arthur C. Clarke Award", "BSFA Award for Best Novel", "Seiun Award for Best Translated Long Work", "Nebula Award for Best Novel", "Bob Morane award 