INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (70, 7422488, 1, '["eng"]', 4.0, 2, 'Q97627911', 'https://en.wikipedia.org/wiki/The_Rise_and_Fall_of_American_Growth', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '9780691147727', NULL, '2026-06-26T14:52:33+00:00', '{"openlibrary": {"ol_key": "/works/OL17343962W", "ol_cover_id": 7422488, "edition_count": 1, "languages": ["eng"], "subjects": ["Economic conditions", "Cost and standard of living", "Economic history", "United states, economic conditions, 1865-1918", "United states, economic conditions, 1918-1945", "United states, economic conditions, 1945-", "Lebensstandard", "Wohlstand", "Wohlfahrtsmessung"], "synopsis": "The trajectory and impetus of American growth from the end of the Civil War until now.", "publication_year": 2016, "page_count": 762, "isbn13": "9780691147727", "ratings_average": 4.0, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q97627911", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Rise and Fall of American Growth", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Rise_and_Fall_of_American_Growth"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (71, 8463846, 34, '["heb", "spa", "eng", "pol"]', 4.07, 167, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:37+00:00', '{"openlibrary": {"ol_key": "/works/OL17184556W", "ol_cover_id": 8463846, "edition_count": 34, "languages": ["heb", "spa", "eng", "pol"], "subjects": ["SpaceX (Firm)", "PayPal (Firm)", "Businesspeople", "Biography", "Tesla Motors", "Businesspeople, biography", "Technological innovations, economic aspects", "Aerospace industries", "Automobiles, electric", "Inventors", "nyt:combined-print-and-e-book-nonfiction=2015-06-07", "New York Times bestseller"], "synopsis": "In the spirit of Steve Jobs and Moneyball, Elon Musk is both an illuminating and authorized look at the extraordinary life of one of Silicon Valley''s most exciting, unpredictable, and ambitious entrepreneurs -- a real-life Tony Stark -- and a fascinating exploration of the renewal of American invention and its new \"makers.\" Elon Musk spotlights the technology and vision of Elon Musk, the renowned entrepreneur and innovator behind SpaceX, Tesla, and SolarCity, who sold one of his Internet companies, PayPal, for $1.5 billion. Ashlee Vance captures the full spectacle and arc of the genius''s life and work, from his tumultuous upbringing in South Africa and flight to the United States to his dramatic technical innovations and entrepreneurial pursuits. Vance uses Musk''s story to explore one of the pressing questions of our age: can the nation of inventors and creators who led the modern world for a century still compete in an age of fierce global competition? He argues that Musk -- one of the most unusual and striking figures in American business history -- is a contemporary, visionary amalgam of legendary inventors and industrialists including Thomas Edison, Henry Ford, Howard Hughes, and Steve Jobs. More than any other entrepreneur today, Musk has dedicated his energies and his own vast fortune to inventing a future that is as rich and far-reaching as the visionaries of the golden age of science-fiction fantasy. Thorough and insightful, Elon Musk brings to life a technology industry that is rapidly and dramatically changing by examining the life of one of its most powerful and influential titans. - Publisher.", "publication_year": 2013, "page_count": 396, "isbn13": "9780753555620", "ratings_average": 4.07, "ratings_count": 167}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (72, 9142114, 17, '["eng"]', 4.12, 8, 'Q21203378', 'https://en.wikipedia.org/wiki/Superforecasting%3A_The_Art_and_Science_of_Prediction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:40+00:00', '{"openlibrary": {"ol_key": "/works/OL18233878W", "ol_cover_id": 9142114, "edition_count": 17, "languages": ["eng"], "subjects": ["Economic forecasting", "Forecasting", "decision making", "predictions", "reasoning", "analysis", "psychology", "SOCIAL SCIENCE / Future Studies", "BUSINESS & ECONOMICS / Forecasting", "PSYCHOLOGY / Cognitive Psychology", "BUSINESS & ECONOMICS", "SOCIAL SCIENCE"], "synopsis": "Everyone would benefit from seeing further into the future, whether buying stocks, crafting policy, launching a new product, or simply planning the week’s meals. Unfortunately, people tend to be terrible forecasters. As Wharton professor Philip Tetlock showed in a landmark 2005 study, even experts’ predictions are only slightly better than chance. However, an important and underreported conclusion of that study was that some experts do have real foresight, and Tetlock has spent the past decade trying to figure out why. What makes some people so good? And can this talent be taught?\r\n \r\nIn Superforecasting, Tetlock and coauthor Dan Gardner offer a masterwork on prediction, drawing on decades of research and the results of a massive, government-funded forecasting tournament. The Good Judgment Project involves tens of thousands of ordinary people—including a Brooklyn filmmaker, a retired pipe installer, and a former ballroom dancer—who set out to forecast global events. Some of the volunteers have turned out to be astonishingly good. They’ve beaten other benchmarks, competitors, and prediction markets. They’ve even beaten the collective judgment of intelligence analysts with access to classified information. They are \"superforecasters.\"\r\n \r\nIn this groundbreaking and accessible book, Tetlock and Gardner show us how we can learn from this elite group. Weaving together stories of forecasting successes (the raid on Osama bin Laden’s compound) and failures (the Bay of Pigs) and interviews with a range of high-level decision makers, from David Petraeus to Robert Rubin, they show that good forecasting doesn’t require powerful computers or arcane methods. It involves gathering evidence from a variety of sources, thinking probabilistically, working in teams, keeping score, and being willing to admit error and change course. Superforecasting offers the first demonstrably effective way to improve our ability to predict the future—whether in business, finance, politics, international affairs, or daily life—and is destined to become a modern classic.", "publication_year": 2015, "page_count": 338, "isbn13": "9780771070525", "ratings_average": 4.12, "ratings_count": 8}, "wikidata": {"wikidata_id": "Q21203378", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Superforecasting: The Art and Science of Prediction", "wikipedia_url": "https://en.wikipedia.org/wiki/Superforecasting%3A_The_Art_and_Science_of_Prediction"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (73, 8477368, 31, '["chi", "eng", "dan", "por", "spa", "dut", "fre"]', 4.45, 40, 'Q109499729', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:44+00:00', '{"openlibrary": {"ol_key": "/works/OL17079567W", "ol_cover_id": 8477368, "edition_count": 31, "languages": ["chi", "eng", "dan", "por", "spa", "dut", "fre"], "subjects": ["dying", "geriatrics", "medicine", "Activities of Daily Living", "Conduct of life", "Attitude to Death", "Critical care medicine", "Terminal care", "Diagnosis", "Attitude (Psychology)", "SOCIAL SCIENCE", "Elderly"], "synopsis": "Being Mortal: Medicine and What Matters in the End is a 2014 non-fiction book by American surgeon Atul Gawande. The book addresses end-of-life care, hospice care, and also contains Gawande''s reflections and personal stories. He suggests that medical care should focus on well-being rather than survival. Being Mortal has won awards, appeared on lists of best books, and been featured in a documentary.", "publication_year": 1899, "page_count": 283, "isbn13": "9781510015036", "ratings_average": 4.45, "ratings_count": 40}, "wikidata": {"wikidata_id": "Q109499729", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (74, 9293827, 14, '["eng", "kor"]', 3.57, 7, 'Q7776075', 'https://en.wikipedia.org/wiki/The_World_Until_Yesterday', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:47+00:00', '{"openlibrary": {"ol_key": "/works/OL16637581W", "ol_cover_id": 9293827, "edition_count": 14, "languages": ["eng", "kor"], "subjects": ["Social life and customs", "Social evolution", "Dani (New Guinean people)", "Cultural assimilation", "Social change", "Anthropology", "Social History", "Manners and customs", "nyt:combined-print-and-e-book-nonfiction=2013-01-20", "New York Times bestseller", "Papua new guinea, social life and customs", "nyt:paperback-nonfiction=2013-11-17"], "synopsis": "Overview: Most of us take for granted the features of our modern society, from air travel and telecommunications to literacy and obesity. Yet for nearly all of its six million years of existence, human society had none of these things. While the gulf that divides us from our primitive ancestors may seem unbridgeably wide, we can glimpse much of our former lifestyle in those largely traditional societies still or recently in existence. Societies like those of the New Guinea Highlanders remind us that it was only yesterday-in evolutionary time-when everything changed and that we moderns still possess bodies and social practices often better adapted to traditional than to modern conditions. The World Until Yesterday provides a mesmerizing firsthand picture of the human past as it had been for millions of years-a past that has mostly vanished-and considers what the differences between that past and our present mean for our lives today. This is Jared Diamond''s most personal book to date, as he draws extensively from his decades of field work in the Pacific islands, as well as evidence from Inuit, Amazonian Indians, Kalahari San people, and others. Diamond doesn''t romanticize traditional societies-after all, we are shocked by some of their practices-but he finds that their solutions to universal human problems such as child rearing, elder care, dispute resolution, risk, and physical fitness have much to teach us. A characteristically provocative, enlightening, and entertaining book, The World Until Yesterday will be essential and delightful reading.", "publication_year": 2012, "page_count": 552, "isbn13": "9781101606001", "ratings_average": 3.57, "ratings_count": 7}, "wikidata": {"wikidata_id": "Q7776075", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The World Until Yesterday", "wikipedia_url": "https://en.wikipedia.org/wiki/The_World_Until_Yesterday"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (75, 94285, 18, '["eng", "chi", "fre", "ger"]', 4.16, 25, 'Q2916374', 'https://en.wikipedia.org/wiki/Amusing_Ourselves_to_Death', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:49+00:00', '{"openlibrary": {"ol_key": "/works/OL137916W", "ol_cover_id": 94285, "edition_count": 18, "languages": ["eng", "chi", "fre", "ger"], "subjects": ["Mass media", "Influence", "Television broadcasting", "Social aspects", "Social aspects of Television broadcasting", "Performing Arts", "Sociology", "Culturele invloeden", "Televisie", "open_syllabus_project", "Médias", "Television"], "synopsis": "Amusing Ourselves to Death is a prophetic look at what happens when politics, journalism, education, and even religion become subject to the demands of  entertainment. It is also a blueprint for regaining control of our media, so that they can serve our highest goals.", "publication_year": 1985, "page_count": 195, "isbn13": "9780136006466", "ratings_average": 4.16, "ratings_count": 25}, "wikidata": {"wikidata_id": "Q2916374", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Amusing Ourselves to Death", "wikipedia_url": "https://en.wikipedia.org/wiki/Amusing_Ourselves_to_Death"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (76, 6752719, 25, '["rus", "por", "eng", "spa", "fre"]', 4.31, 71, 'Q848517', 'https://en.wikipedia.org/wiki/Roadside_Picnic', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:52+00:00', '{"openlibrary": {"ol_key": "/works/OL7967812W", "ol_cover_id": 6752719, "edition_count": 25, "languages": ["rus", "por", "eng", "spa", "fre"], "subjects": ["science fiction", "Russian science fiction", "alien visitation", "anomalies", "Russian fiction", "Fiction, science fiction, general"], "synopsis": "[Comment by Hari Kunru in The Guardian][1]:\r\n\r\n> Soviet-era Russian science fiction deserves a wider audience in English. The Strugatsky brothers collaborated on numerous novels and stories, the best known of which is this, partly because it was filmed by Andrei Tarkovsky as Stalker, in 1977. The novel takes place 10 years after a mysterious alien visitation, which seems to have no rational explanation. No one saw the visitors. Their presence caused disease and blindness in the areas where they landed. Now, in the six \"Zones\", the laws of physics (and, seemingly, of reality) are disturbed by anomalies, and littered with inexplicable, deadly wreckage. Only a few brave \"stalkers\" risk their lives to enter the zones to gather alien artefacts for sale. Some of these artefacts offer the promise of extraordinary powers. Unlike Tarkovsky''s film, which concentrates on the hallucinatory, vacated landscape of the zones, the novels portray a society adapting to an inexplicable, terrifying event, an eruption of the unknown. Though written in 1971 and published in English in 1977, the novel was heavily bowdlerised by Soviet censors, and an authoritative text wasn''t available in Russian until 2000. It''s a book with an extraordinary atmosphere – and a demonstration of how science fiction, by using a single bold central metaphor, can open up the possibilities of the novel.\r\n\r\nOriginal Title: Пикник на обочине\r\n\r\n\r\n  [1]: http://www.guardian.co.uk/books/2011/may/14/science-fiction-authors-choice", "publication_year": 1978, "page_count": 190, "isbn13": "9781473208735", "ratings_average": 4.31, "ratings_count": 71}, "wikidata": {"wikidata_id": "Q848517", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Roadside Picnic", "wikipedia_url": "https://en.wikipedia.org/wiki/Roadside_Picnic"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (77, 7313659, 18, '["spa", "eng"]', 3.95, 22, 'Q18389865', 'https://en.wikipedia.org/wiki/The_Innovators_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:54+00:00', '{"openlibrary": {"ol_key": "/works/OL17074268W", "ol_cover_id": 7313659, "edition_count": 18, "languages": ["spa", "eng"], "subjects": ["Biography", "Computer scientists", "Internet", "Computer science", "Bell Telephone Laboratories", "BIOGRAPHY & AUTOBIOGRAPHY", "Science & Technology", "BUSINESS & ECONOMICS", "Industries", "Computer Industry", "TECHNOLOGY & ENGINEERING", "TECHNOLOGY & ENGINEERING / History"], "synopsis": "Following his blockbuster biography of Steve Jobs, The Innovators is Walter Isaacson’s revealing story of the people who created the computer and the Internet. It is destined to be the standard history of the digital revolution and an indispensable guide to how innovation really happens.\r\n\r\nWhat were the talents that allowed certain inventors and entrepreneurs to turn their visionary ideas into disruptive realities? What led to their creative leaps? Why did some succeed and others fail?\r\n\r\nIn his masterly saga, Isaacson begins with Ada Lovelace, Lord Byron’s daughter, who pioneered computer programming in the 1840s. He explores the fascinating personalities that created our current digital revolution, such as Vannevar Bush, Alan Turing, John von Neumann, J.C.R. Licklider, Doug Engelbart, Robert Noyce, Bill Gates, Steve Wozniak, Steve Jobs, Tim Berners-Lee, and Larry Page. \r\n\r\nThis is the story of how their minds worked and what made them so inventive. It’s also a narrative of how their ability to collaborate and master the art of teamwork made them even more creative.\r\n\r\nFor an era that seeks to foster innovation, creativity, and teamwork, The Innovators shows how they happen.", "publication_year": 2014, "page_count": 583, "isbn13": "9781471138799", "ratings_average": 3.95, "ratings_count": 22}, "wikidata": {"wikidata_id": "Q18389865", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Innovators (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Innovators_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (78, 8063712, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:52:58+00:00', '{"openlibrary": {"ol_key": "/works/OL17785073W", "ol_cover_id": 8063712, "edition_count": 1, "languages": [], "subjects": ["Complexity (philosophy)", "Komplexität", "Komplexes System"], "synopsis": null, "publication_year": 2014, "page_count": 112, "isbn13": "9780199662548", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (79, 10791692, 22, '["dut", "fre", "jpn", "eng", "srp", "chi"]', 4.05, 19, 'Q16978519', 'https://en.wikipedia.org/wiki/No_Place_to_Hide_%28Greenwald_book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:02+00:00', '{"openlibrary": {"ol_key": "/works/OL16819228W", "ol_cover_id": 10791692, "edition_count": 22, "languages": ["dut", "fre", "jpn", "eng", "srp", "chi"], "subjects": ["Überwachung", "USA", "Politischer Skandal", "Datenerfassung", "Electronic surveillance", "Leaks (Disclosure of information)", "United States", "World Wide Web 2.0", "Privatsphäre", "USA National Security Agency", "United States. National Security Agency/Central Security Service", "Enttarnung"], "synopsis": "The story of one of the greatest national security leaks in US history. In June 2013, reporter and political commentator Glenn Greenwald published a series of reports in the Guardian which rocked the world. The reports revealed shocking truths about the extent to which the National Security Agency had been gathering information about US citizens and intercepting communication worldwide, and were based on documents leaked by former National Security Agency employee Edward Snowden to Greenwald. Including new revelations from documents entrusted to Greenwald by Snowden.", "publication_year": 2013, "page_count": 296, "isbn13": "9780241146705", "ratings_average": 4.05, "ratings_count": 19}, "wikidata": {"wikidata_id": "Q16978519", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "No Place to Hide (Greenwald book)", "wikipedia_url": "https://en.wikipedia.org/wiki/No_Place_to_Hide_%28Greenwald_book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (80, 9339865, 5, '["eng"]', 4.0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:05+00:00', '{"openlibrary": {"ol_key": "/works/OL20001821W", "ol_cover_id": 9339865, "edition_count": 5, "languages": ["eng"], "subjects": ["Electronic commerce", "Currency question", "Electronic funds transfers", "Bitcoin", "BUSINESS & ECONOMICS / E-Commerce / Internet Marketing"], "synopsis": "\"Bitcoin became a buzzword overnight. A cyber-enigma with an enthusiastic following, it pops up in headlines and fuels endless media debate. You can apparently use it to buy anything from coffee to cars, yet few people seem to truly understand what it is. This raises the question: Why should anyone care about bitcoin? In The Age of Cryptocurrency, Wall Street journalists Paul Vigna and Michael J. Casey deliver the definitive answer to this question. Cybermoney is poised to launch a revolution, one that could reinvent traditional financial and social structures while bringing the world''s billions of \"unbanked\" individuals into a new global economy. Cryptocurrency holds the promise of a financial system without a middleman, one owned by the people who use it and one safeguarded from the devastation of a 2008-type crash. But bitcoin, the most famous of the cybermonies, carries a reputation for instability, wild fluctuation, and illicit business; some fear it has the power to eliminate jobs and to upend the concept of a nation-state. It implies, above all, monumental and wide-reaching change--for better and for worse. But it is here to stay, and you ignore it at your peril.Vigna and Casey demystify cryptocurrency--its origins, its function, and what you need to know to navigate a cyber-economy. The digital currency world will look very different from the paper currency world; The Age of Cryptocurrency will teach you how to be ready.\"--", "publication_year": 2015, "page_count": 363, "isbn13": "9781250073082", "ratings_average": 4.0, "ratings_count": 2}, "wikidata": {}}');
