INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (83, 8457814, 13, '["eng", "por"]', 4.5, 2, 'Q7165186', 'https://en.wikipedia.org/wiki/Far_from_the_Tree', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:12+00:00', '{"openlibrary": {"ol_key": "/works/OL16654793W", "ol_cover_id": 8457814, "edition_count": 13, "languages": ["eng", "por"], "subjects": ["homosexuality", "deafness", "dwarfism", "Down Syndrome", "autism", "scizophrenia", "disability", "prodigies", "rape", "crime", "transgender", "Identity (Psychology)"], "synopsis": "Solomon’s startling proposition in *Far from the Tree* is that being exceptional is at the core of the human condition—that difference is what unites us. He writes about families coping with deafness, dwarfism, Down''s syndrome, autism, schizophrenia, or multiple severe disabilities; with children who are prodigies, who are conceived in rape, who become criminals, and who are transgender. While each of these characteristics is potentially isolating, the experience of difference within families is universal, and Solomon documents triumphs of love over prejudice in every chapter.\r\n\r\nAll parenting turns on a crucial question: to what extent should parents accept their children for who they are, and to what extent they should help them become their best selves. Drawing on ten years of research and interviews with more than three-hundred families, Solomon mines the eloquence of ordinary people facing extreme challenges.\r\n\r\nElegantly reported by a spectacularly original and compassionate thinker, *Far from the Tree* explores how people who love each other must struggle to accept each other, a theme in every family’s life.", "publication_year": 2012, "page_count": 721, "isbn13": "9781481440905", "ratings_average": 4.5, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q7165186", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Far from the Tree", "wikipedia_url": "https://en.wikipedia.org/wiki/Far_from_the_Tree"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (84, 14420637, 11, '["dut", "por", "eng"]', 4.3, 30, 'Q111945826', 'https://en.wikipedia.org/wiki/Thinking_In_Systems%3A_A_Primer', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:16+00:00', '{"openlibrary": {"ol_key": "/works/OL3737036W", "ol_cover_id": 14420637, "edition_count": 11, "languages": ["dut", "por", "eng"], "subjects": ["critical thinking", "systems thinking", "systems dynamics", "complex systems", "policy", "Sustainable development", "Environmental education", "Economic development", "System analysis", "Simulation methods", "Population", "Social sciences"], "synopsis": "A clear, thoughtful, and wide-reaching exploration of complex systems, in theory and in practice. Meadows was a masterful and elegant writer and researcher, and an early voice in systems analysis at MIT and elsewhere. This book, completed from draft manuscript after Meadows'' death, is both accessible and deeply thought-provoking. She connects the dots between careful descriptions of systems analysis and systems insights, and the personal, social, societal, and political implications of systems thinking.", "publication_year": 2008, "page_count": 240, "isbn13": "9781136551406", "ratings_average": 4.3, "ratings_count": 30}, "wikidata": {"wikidata_id": "Q111945826", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Thinking In Systems: A Primer", "wikipedia_url": "https://en.wikipedia.org/wiki/Thinking_In_Systems%3A_A_Primer"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (85, 7264584, 15, '["eng"]', 4.19, 27, 'Q22908276', 'https://en.wikipedia.org/wiki/The_Everything_Store', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:18+00:00', '{"openlibrary": {"ol_key": "/works/OL16808249W", "ol_cover_id": 7264584, "edition_count": 15, "languages": ["eng"], "subjects": ["Amazon.com (Firm)", "Electronic commerce", "Internet bookstores", "Businessmen", "Booksellers and bookselling", "Biography", "Success in business", "Entrepreneurship", "Businesspeople, biography", "nyt:business-books=2013-11-10", "New York Times bestseller", "New York Times reviewed"], "synopsis": "This book is the definitive story of Amazon.com, one of the most successful companies in the world, and of its driven, brilliant founder, Jeff Bezos. Amazon.com started off delivering books through the mail. But its visionary founder, Jeff Bezos, wasn''t content with being a bookseller. He wanted Amazon to become the everything store, offering limitless selection and seductive convenience at disruptively low prices. To do so, he developed a corporate culture of relentless ambition and secrecy that''s never been cracked. Until now. Brad Stone enjoyed unprecedented access to current and former Amazon employees and Bezos family members, giving readers the first in-depth, fly-on-the-wall account of life at Amazon. Compared to tech''s other elite innovators -- Jobs, Gates, Zuckerberg -- Bezos is a private man. But he stands out for his restless pursuit of new markets, leading Amazon into risky new ventures like the Kindle and cloud computing, and transforming retail in the same way Henry Ford revolutionized manufacturing. The Everything Store will be the revealing, definitive biography of the company that placed one of the first and largest bets on the Internet and forever changed the way we shop and read. - Publisher.", "publication_year": 2013, "page_count": 416, "isbn13": "9780552167833", "ratings_average": 4.19, "ratings_count": 27}, "wikidata": {"wikidata_id": "Q22908276", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Everything Store", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Everything_Store"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (86, 9180157, 18, '["spa", "heb", "eng", "fre", "chi"]', 3.97, 37, 'Q4774726', 'https://en.wikipedia.org/wiki/Antifragile_%28book%29', NULL, 'Incerto', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:21+00:00', '{"openlibrary": {"ol_key": "/works/OL16726829W", "ol_cover_id": 9180157, "edition_count": 18, "languages": ["spa", "heb", "eng", "fre", "chi"], "subjects": ["Resilience (Personality trait)", "PSYCHOLOGY / General", "BUSINESS & ECONOMICS / General", "Long Now Manual for Civilization", "Social aspects", "Uncertainty (Information theory)", "Forecasting", "Complexity (Philosophy)", "Psychological Resilience", "Psychological Adaptation", "Uncertainty", "Adjustment (psychology)"], "synopsis": "\"The acclaimed author of the influential bestseller The Black Swan, Nicholas Nassim Taleb takes a next big step with a deceptively simple concept: the \"antifragile.\" Like the Greek hydra that grows two heads for each one it loses, people, systems, and institutions that are antifragile not only withstand shocks, they benefit from them. In a modern world dominated by chaos and uncertainty, Antifragile is a revolutionary vision from one of the most subversive and important thinkers of our time.  Praise for Nicholas Nassim Taleb     \"[This] is the lesson of Taleb. and also the lesson of our volatile times. There is more courage and heroism in defying the human impulse, in taking the purposeful and painful steps to prepare for the unimaginable.\"--Malcolm Gladwell, author of The Tipping Point     \"[Taleb writes] in a style that owes as much to Stephen Colbert as it does to Michel de Montaigne.\"--The Wall Street Journal     \"The most prophetic voice of all. [Taleb is] a genuinely significant philosopher. someone who is able to change the way we view the structure of the world through the strength, originality and veracity of his ideas alone.\"--GQ     \"Changed my view of how the world works.\"--Daniel Kahneman, Nobel laureate\"--\r\n\r\n\"Examples of Antifragility: When you stress your body by lifting a big weight, your body gets stronger. New York has the best restaurants in the world because particular restaurants are always going bust, making the aggregate stronger and stronger, or antifragile. Evolution is antifragile. Certain business and investment strategies are antifragile. Older things tend to be more antifragile than newer ones - because they''ve been exposed to more Black Swans\"--", "publication_year": 2012, "page_count": 639, "isbn13": "9781846141577", "ratings_average": 3.97, "ratings_count": 37}, "wikidata": {"wikidata_id": "Q4774726", "awards": [], "series": "Incerto", "goodreads_id": null, "wikipedia_title": "Antifragile (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Antifragile_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (87, 11447888, 74, '["pol", "heb", "bel", "eng", "ita", "fre", "chi", "spa", "kor", "ara", "por", "dan"]', 4.4, 331, 'Q17111624', 'https://en.wikipedia.org/wiki/The_Martian_%28Weir_novel%29', NULL, NULL, '["Ignotus Award for Best Foreign Novel", "Seiun Award for Best Translated Long Work"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:24+00:00', '{"openlibrary": {"ol_key": "/works/OL17091839W", "ol_cover_id": 11447888, "edition_count": 74, "languages": ["pol", "heb", "bel", "eng", "ita", "fre", "chi", "spa", "kor", "ara", "por", "dan"], "subjects": ["Science-Fiction", "Science Fiction & Fantasy", "Suspense & Thriller", "Science fiction", "Amerikanisches Englisch", "Astronauts", "Survival", "Survival skills", "Supervivencia", "Novela", "Astronautas", "Reading Level-Grade 7"], "synopsis": "The Martian is a 2011 science fiction novel written by Andy Weir. It was his debut novel under his own name. It was originally self-published in 2011; Crown Publishing purchased the rights and re-released it in 2014. The story follows an American astronaut, Mark Watney, as he becomes stranded alone on Mars in 2035 and must improvise in order to survive.", "publication_year": 2011, "page_count": 407, "isbn13": "9780804139021", "ratings_average": 4.4, "ratings_count": 331}, "wikidata": {"wikidata_id": "Q17111624", "awards": ["Ignotus Award for Best Foreign Novel", "Seiun Award for Best Translated Long Work"], "series": null, "goodreads_id": null, "wikipedia_title": "The Martian (Weir novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Martian_%28Weir_novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (88, 208092, 15, '["eng", "spa"]', 3.69, 13, 'Q4118932', 'https://en.wikipedia.org/wiki/A_History_of_God', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:27+00:00', '{"openlibrary": {"ol_key": "/works/OL3280815W", "ol_cover_id": 208092, "edition_count": 15, "languages": ["eng", "spa"], "subjects": ["Biblical teaching", "Comparative studies", "Dios", "Dios (Islamismo)", "Dios (Judaísmo)", "Doctrinas", "Doctrines", "Enseñanza bíblica", "Estudios comparados", "God", "God (Islam)", "God (Judaism)"], "synopsis": "As soon as they became recognizably human, men and women - in their hunger to understand their own presence on earth and the mysteries within and around them - began to worship gods. Karen Armstrong''s masterly and illuminating book explores the ways in which the idea and experience of God evolved among the monotheists - Jews, Christians and Muslims.\n\nWeaving a multicolored fabric of historical, philosophical, intellectual and social developments and insights, Armstrong shows how, at various times through the centuries, each of the monotheistic religions has held a subtly different concept of God. At the same time she draws our attention to the basic and profound similarities among them, making it clear that in all of them God has been and is experienced intensely, passionately and often - especially in the West - traumatically.\n\nSome monotheists have seen darkness, desolation and terror, where others have seen light and transfiguration; the reasons for these inherent differences are examined, and the people behind them are brought to life.\n\nWe look first at the gradual move away from the pagan gods to the full-fledged monotheism of the Jews during the exile in Babylon. Next considered is the development of parallel, yet different, perceptions and beliefs among Christians and Muslims.\n\nThe book then moves \"generationally\" through time to examine the God of the philosophers and mystics in all three traditions, the God of the Reformation, the God of the Enlightenment and finally the nineteenth- and twentieth-century challenges of skeptics and atheists, as well as the fiercely reductive faith of the fundamentalists of our own day.\n\nArmstrong suggests that any particular idea of God must - if it is to survive - work for the people who develop it, and that ideas of God change when they cease to be effective. She argues that the concept of a personal God who behaves like a larger version of ourselves was suited to mankind at a certain stage but no longer works for an increasing number of people.\n\nUnderstanding the ever-changing ideas of God in the past and their relevance and usefulness in their time, she says, is a way to begin the search for a new concept for the twenty-first century. Her book shows that such a development is virtually inevitable, in spite of the despair of our increasingly \"Godless\" world, because it is a natural aspect of our humanity to seek a symbol for the ineffable reality that is universally perceived.", "publication_year": 1993, "page_count": 478, "isbn13": "9780099273677", "ratings_average": 3.69, "ratings_count": 13}, "wikidata": {"wikidata_id": "Q4118932", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "A History of God", "wikipedia_url": "https://en.wikipedia.org/wiki/A_History_of_God"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (89, 7079753, 11, '["eng"]', 4.12, 93, 'Q7271846', 'https://en.wikipedia.org/wiki/Quiet%3A_The_Power_of_Introverts_in_a_World_That_Can%27t_Stop_Talking', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:31+00:00', '{"openlibrary": {"ol_key": "/works/OL16484595W", "ol_cover_id": 7079753, "edition_count": 11, "languages": ["eng"], "subjects": ["Extraversion", "Introverts", "Interpersonal relations", "Introversion", "New York Times bestseller", "nyt:combined_print_nonfiction=2012-03-03", "Reading Level-Grade 11", "Reading Level-Grade 12", "Self-actualization (psychology)", "Temperament", "Popular Works", "Psychological Introversion"], "synopsis": "Passionately argued, impressively researched, and filled with indelible stories of real people, Quiet shows how dramatically we undervalue introverts, and how much we lose in doing so. Taking the reader on a journey from Dale Carnegie''s birthplace to Harvard Business School, from a Tony Robbins seminar to an evangelical megachurch, Susan Cain charts the rise of the Extrovert Ideal in the twentieth century and explores its far-reaching effects. She talks to Asian-American students who feel alienated from the brash, backslapping atmosphere of American schools. She questions the dominant values of American business culture, where forced collaboration can stand in the way of innovation, and where the leadership potential of introverts is often overlooked. And she draws on cutting-edge research in psychology and neuroscience to reveal the surprising differences between extroverts and introverts. Perhaps most inspiring, she introduces us to successful introverts–from a witty, high-octane public speaker who recharges in solitude after his talks, to a record-breaking salesman who quietly taps into the power of questions. Finally, she offers invaluable advice on everything from how to better negotiate differences in introvert-extrovert relationships to how to empower an introverted child to when it makes sense to be a \"pretend extrovert.\" This extraordinary book has the power to permanently change how we see introverts and, equally important, how introverts see themselves. - Publisher.", "publication_year": 2012, "page_count": 360, "isbn13": "9780606320825", "ratings_average": 4.12, "ratings_count": 93}, "wikidata": {"wikidata_id": "Q7271846", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Quiet: The Power of Introverts in a World That Can''t Stop Talking", "wikipedia_url": "https://en.wikipedia.org/wiki/Quiet%3A_The_Power_of_Introverts_in_a_World_That_Can%27t_Stop_Talking"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (90, 8088422, 3, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:35+00:00', '{"openlibrary": {"ol_key": "/works/OL17803533W", "ol_cover_id": 8088422, "edition_count": 3, "languages": ["eng"], "subjects": ["Renewable energy sources", "Environmental engineering", "Research", "Popular works", "Forecasting", "Sustainable engineering"], "synopsis": null, "publication_year": 2011, "page_count": null, "isbn13": "9780306819773", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (91, 11320203, 29, '["eng", "spa", "por", "ger", "jpn", "fre", "pol", "chi"]', 4.08, 12, 'Q4202130', 'https://en.wikipedia.org/wiki/The_Emperor_of_All_Maladies', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:37+00:00', '{"openlibrary": {"ol_key": "/works/OL15540668W", "ol_cover_id": 11320203, "edition_count": 29, "languages": ["eng", "spa", "por", "ger", "jpn", "fre", "pol", "chi"], "subjects": ["medical history", "social sciences", "civilization", "oncology", "Cancer", "nyt:paperback_nonfiction=2011-08-27", "research", "New York Times bestseller", "medicine", "Leukemia", "Antineoplastic Agents", "drug therapy"], "synopsis": "The Emperor of All Maladies: A Biography of Cancer is a book written by Siddhartha Mukherjee, an Indian-born American physician and oncologist. Published on 16 November 2010 by Scribner, it won the 2011 Pulitzer Prize for General Non-Fiction.", "publication_year": 2010, "page_count": 582, "isbn13": "9780007367481", "ratings_average": 4.08, "ratings_count": 12}, "wikidata": {"wikidata_id": "Q4202130", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Emperor of All Maladies", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Emperor_of_All_Maladies"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (92, 7166857, 13, '["eng"]', 4.06, 18, 'Q4880827', 'https://en.wikipedia.org/wiki/Behind_the_Beautiful_Forevers', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:40+00:00', '{"openlibrary": {"ol_key": "/works/OL16262891W", "ol_cover_id": 7166857, "edition_count": 13, "languages": ["eng"], "subjects": ["Urban poor", "New York Times bestseller", "Creative nonfiction", "nyt:hardcover_political_books=2012-02-25", "Poor", "Slums", "Economic conditions", "Social conditions", "Poverty", "Social classes", "Fattiga", "Armut"], "synopsis": "The dramatic and sometimes heartbreaking story of families striving toward a better life in one of the twenty-first century''s great, unequal cities. In this fast-paced book, based on three years of uncompromising reporting, a bewildering age of global change and inequality is made human. Annawadi is a makeshift settlement in the shadow of luxury hotels near the Mumbai airport, and as India starts to prosper, Annawadians are electric with hope. Abdul, a reflective and enterprising Muslim teenager, sees fortune in the recyclable garbage of richer people. Asha, a woman of formidable wit and deep scars from a rural childhood, has identified an alternate route to the middle class: political corruption. And even the poorest Annawadians, like Kalu, a fifteen-year-old scrap-metal thief, believe themselves inching closer to good times. But then, as the tenderest individual hopes intersect with the greatest global truths, the true contours of a competitive age are revealed.", "publication_year": 2011, "page_count": 256, "isbn13": "9780679643951", "ratings_average": 4.06, "ratings_count": 18}, "wikidata": {"wikidata_id": "Q4880827", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Behind the Beautiful Forevers", "wikipedia_url": "https://en.wikipedia.org/wiki/Behind_the_Beautiful_Forevers"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (93, 8160378, 5, '["eng"]', 4.0, 5, 'Q48816976', 'https://en.wikipedia.org/wiki/This_Machine_Kills_Secrets', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:43+00:00', '{"openlibrary": {"ol_key": "/works/OL16499532W", "ol_cover_id": 8160378, "edition_count": 5, "languages": ["eng"], "subjects": ["Computer hackers", "Whistleblowing", "Official secrets", "Computer crimes", "Secrecy", "Political activity", "World Wide Web", "Hackers", "Whistle blowing", "Informationsfreiheit", "Assange, julian, 1971-", "Wikileaks (organization)"], "synopsis": "Who Are The Cypherpunks?\r\n \r\nThis is the unauthorized telling of the revolutionary cryptography story behind the motion picture The Fifth Estate in theatres this October, and We Steal Secrets: The Story of Wikileaks, a documentary out now.\r\n \r\nWikiLeaks brought to light a new form of whistleblowing, using powerful cryptographic code to hide leakers’ identities while they spill the private data of government agencies and corporations. But that technology has been evolving for decades in the hands of hackers and radical activists, from the libertarian enclaves of Northern California to Berlin to the Balkans. And the secret-killing machine continues to evolve beyond WikiLeaks, as a movement of hacktivists aims to obliterate the world’s institutional secrecy.\r\n\r\nForbes journalist Andy Greenberg has traced its shadowy history from the cryptography revolution of the 1970s to Wikileaks founding hacker Julian Assange, Anonymous, and beyond.\r\n\r\nThis is the story of the code and the characters—idealists, anarchists, extremists—who are transforming the next generation’s notion of what activism can be.\r\n\r\nWith unrivaled access to such major players as Julian Assange, Daniel Domscheit-Berg, and WikiLeaks’ shadowy engineer known as the Architect, never before interviewed, Greenberg unveils the world of politically-motivated hackers—who they are and how they operate.", "publication_year": 2012, "page_count": 384, "isbn13": "9780142180495", "ratings_average": 4.0, "ratings_count": 5}, "wikidata": {"wikidata_id": "Q48816976", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "This Machine Kills Secrets", "wikipedia_url": "https://en.wikipedia.org/wiki/This_Machine_Kills_Secrets"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (94, 7916605, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:47+00:00', '{"openlibrary": {"ol_key": "/works/OL17643839W", "ol_cover_id": 7916605, "edition_count": 1, "languages": ["eng"], "subjects": ["Politics and government", "Foreign relations", "Political culture", "Communism", "Korea (north), politics and government", "Korea, foreign relations"], "synopsis": "\"In The Real North Korea, Lankov substitutes cold, clear analysis for the overheated rhetoric surrounding this opaque state. After providing an accessible history of the nation, he turns his focus to what North Korea is, what its leadership thinks, and how its people cope with living in such an oppressive and impoverished place. He argues that North Korea is not irrational, and nothing shows this better than its continuing survival against all odds. A living political fossil, it clings to existence in the face of limited resources and a zombie economy, manipulating great powers despite its weakness. Its leaders are not ideological zealots or madmen, but perhaps the best practitioners of Machiavellian politics that can be found in the modern world. Even though they preside over a failed state, they have successfully used diplomacy - including nuclear threats - to extract support from other nations. But while the people in charge have been ruthless and successful in holding on to power, Lankov contends that this cannot continue forever. The old system is slowly falling apart, and in the long run the regime is unsustainable - with or without reform. Indeed, reforms, if attempted, will most likely trigger a dramatic implosion of the regime. They will not prolong its existence.\"--Book jacket.", "publication_year": 2013, "page_count": 288, "isbn13": "9780199964291", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (95, 9266506, 8, '["eng", "spa"]', 4.4, 10, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:49+00:00', '{"openlibrary": {"ol_key": "/works/OL16681334W", "ol_cover_id": 9266506, "edition_count": 8, "languages": ["eng", "spa"], "subjects": ["Mathematics", "Mathematics, popular works", "Popular works", "MATHEMATICS / General", "award:euler_book_prize"], "synopsis": "Many people take math in high school and promptly forget much of it. But math plays a part in all of our lives all of the time, whether we know it or not. In The Joy of x, Steven Strogatz expands on his hit New York Times series to explain the big ideas of math gently and clearly, with wit, insight, and brilliant illustrations.\r\n\r\nWhether he is illuminating how often you should flip your mattress to get the maximum lifespan from it, explaining just how Google searches the internet, or determining how many people you should date before settling down, Strogatz shows how math connects to every aspect of life. Discussing pop culture, medicine, law, philosophy, art, and business, Strogatz is the math teacher you wish you’d had. Whether you aced integral calculus or aren’t sure what an integer is, you’ll find profound wisdom and persistent delight in The Joy of x.", "publication_year": 2012, "page_count": 336, "isbn13": "9781848878433", "ratings_average": 4.4, "ratings_count": 10}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (96, 9475786, 3, '["eng"]', 4.0, 18, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:51+00:00', '{"openlibrary": {"ol_key": "/works/OL16184230W", "ol_cover_id": 9475786, "edition_count": 3, "languages": ["eng"], "subjects": ["Will", "Self-control", "SELF-HELP", "Self-Management", "Time Management", "PSYCHOLOGY", "Applied Psychology", "Motivation", "Volition", "Erfolg", "Selbstkontrolle", "Volonté"], "synopsis": "The first book to explain the new science of self-control and how it can be harnessed to improve our health, happiness, and productivity.\r\n\r\nAfter years of watching her students struggling with their choices, health psychologist Kelly McGonigal, Ph.D., realized that much of what people believe about willpower is actually sabotaging their success. Committed to sharing what the scientific community already knew about self-control, McGonigal created a course called \"The Science of Willpower\" for Stanford University''s Continuing Studies Program. The course was an instant hit and spawned the hugely successful Psychology Today blog with the same name.\r\n\r\nInformed by the latest research and combining cutting-edge insights from psychology, economics, neuroscience, and medicine, McGonigal''s book explains exactly what willpower is, how it works, and why it matters. Readers will learn:\r\n\r\nWillpower is a mind-body response, not a virtue. It is a biological function that can be improved through mindfulness, exercise, nutrition, and sleep. People who have better control of their attention, emotions, and actions are healthier, happier, have more satisfying relationships, and make more money. Willpower is not an unlimited resource. Too much self-control can actually be bad for your health. Temptation and stress hijack the brain''s systems of self-control, and that the brain can be trained for greater willpower.\r\n\r\nIn the groundbreaking tradition of Getting Things Done, The Willpower Instinct combines life-changing prescriptive advice and complementary exercises to help readers with goals ranging from a healthier life to more patient parenting, from greater productivity at work to finally finishing the basement.", "publication_year": 2011, "page_count": 288, "isbn13": "9781583335086", "ratings_average": 4.0, "ratings_count": 18}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (97, 7256893, 10, '["spa", "tur", "eng"]', 3.9, 48, 'Q17154021', 'https://en.wikipedia.org/wiki/The_Signal_and_the_Noise', NULL, 'The New York Times Best Seller list', '["Phi Beta Kappa Award in Science"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:54+00:00', '{"openlibrary": {"ol_key": "/works/OL16700318W", "ol_cover_id": 7256893, "edition_count": 10, "languages": ["spa", "tur", "eng"], "subjects": ["Bayesian statistical decision theory", "Theory of Knowledge", "Forecasting", "Methodology", "Knowledge, theory of", "nyt:combined-print-and-e-book-nonfiction=2012-10-14", "New York Times bestseller", "Economics", "POLITICAL SCIENCE", "Bayes-Entscheidungstheorie", "Prognose", "Prévision"], "synopsis": "Nate Silver built an innovative system for predicting baseball performance, predicted the 2008 election within a hair’s breadth, and became a national sensation as a blogger—all by the time he was thirty. The New York Times now publishes FiveThirtyEight.com, where Silver is one of the nation’s most influential political forecasters.\r\n\r\nDrawing on his own groundbreaking work, Silver examines the world of prediction, investigating how we can distinguish a true signal from a universe of noisy data. Most predictions fail, often at great cost to society, because most of us have a poor understanding of probability and uncertainty. Both experts and laypeople mistake more confident predictions for more accurate ones. But overconfidence is often the reason for failure. If our appreciation of uncertainty improves, our predictions can get better too. This is the “prediction paradox”: The more humility we have about our ability to make predictions, the more successful we can be in planning for the future.\r\n\r\nIn keeping with his own aim to seek truth from data, Silver visits the most successful forecasters in a range of areas, from hurricanes to baseball, from the poker table to the stock market, from Capitol Hill to the NBA. He explains and evaluates how these forecasters think and what bonds they share. What lies behind their success? Are they good—or just lucky? What patterns have they unraveled? And are their forecasts really right? He explores unanticipated commonalities and exposes unexpected juxtapositions. And sometimes, it is not so much how good a prediction is in an absolute sense that matters but how good it is relative to the competition. In other cases, prediction is still a very rudimentary—and dangerous—science.\r\n\r\nSilver observes that the most accurate forecasters tend to have a superior command of probability, and they tend to be both humble and hardworking. They distinguish the predictable from the unpredictable, and they notice a thousand little details that lead them closer to the truth. Because of their appreciation of probability, they can distinguish the signal from the noise.\r\n\r\nWith everything from the health of the global economy to our ability to fight terrorism dependent on the quality of our predictions, Nate Silver’s insights are an essential read.", "publication_year": 2012, "page_count": 552, "isbn13": "9780606368056", "ratings_average": 3.9, "ratings_count": 48}, "wikidata": {"wikidata_id": "Q17154021", "awards": ["Phi Beta Kappa Award in Science"], "series": "The New York Times Best Seller list", "goodreads_id": null, "wikipedia_title": "The Signal and the Noise", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Signal_and_the_Noise"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (98, 982148, 22, '["eng", "fre", "kor"]', 3.71, 17, 'Q2719299', 'https://en.wikipedia.org/wiki/To_Say_Nothing_of_the_Dog', NULL, 'Oxford time-traveling historians', '["Hugo Award for Best Novel", "Locus Award for Best Science Fiction Novel", "Kurd Lasswitz Award for Best Foreign Work", "Bob Morane award for best foreign novel"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:53:58+00:00', '{"openlibrary": {"ol_key": "/works/OL14858392W", "ol_cover_id": 982148, "edition_count": 22, "languages": ["eng", "fre", "kor"], "subjects": ["Hugo Award Winner", "award:hugo_award=1999", "award:hugo_award=novel", "Time travel", "Fiction, science fiction, general", "Fiction, historical, general", "England, fiction", "Fantasy", "Science Fiction", "Fiction, historical", "Large type books", "American Fantasy fiction"], "synopsis": "Connie Willis'' entertaining comedy inspired by Jerome K. Jerome''s [Three Men in a Boat (to say nothing of the dog)][1]. \r\n\r\n[Robert A. Heinlein][2] mentioned the earlier work in [Have Spacesuit will Travel][3] as Kip''s father''s favorite.\r\n\r\n\r\n  [1]: https://openlibrary.org/works/OL1793164W/Three_Men_in_a_Boat_(to_say_nothing_of_the_dog)\r\n  [2]: https://openlibrary.org/authors/OL28641A/Robert_A._Heinlein\r\n  [3]: https://openlibrary.org/works/OL59727W/Have_Space_Suit_Will_Travel", "publication_year": 1997, "page_count": 512, "isbn13": "9781399617192", "ratings_average": 3.71, "ratings_count": 17}, "wikidata": {"wikidata_id": "Q2719299", "awards": ["Hugo Award for Best Novel", "Locus Award for Best Science Fiction Novel", "Kurd Lasswitz Award for Best Foreign Work", "Bob Morane award for best foreign novel"], "series": "Oxford time-traveling historians", "goodreads_id": null, "wikipedia_title": "To Say Nothing of the Dog", "wikipedia_url": "https://en.wikipedia.org/wiki/To_Say_Nothing_of_the_Dog"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (99, 7263283, 1, '["eng"]', 4.0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:00+00:00', '{"openlibrary": {"ol_key": "/works/OL16626501W", "ol_cover_id": 7263283, "edition_count": 1, "languages": ["eng"], "subjects": ["Interpersonal relations", "Sociology", "Social stability", "Social aspects", "Trust", "Social interaction", "Truthfulness and falsehood", "Gesellschaft", "Vertrauen", "Wirtschaft"], "synopsis": "In today''s hyper-connected society, understanding the mechanisms of trust is crucial. Issues of trust are critical to solving problems as diverse as corporate responsibility, global warming, and the political system. In this insightful and entertaining book, Schneier weaves together ideas from across the social and biological sciences to explain how society induces trust. He shows the unique role of trust in facilitating and stabilizing human society. He discusses why and how trust has evolved, why it works the way it does, and the ways the information society is changing everything. - Publisher.", "publication_year": 2012, "page_count": 366, "isbn13": "9781118143308", "ratings_average": 4.0, "ratings_count": 3}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (100, 6712222, 7, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:05+00:00', '{"openlibrary": {"ol_key": "/works/OL15686817W", "ol_cover_id": 6712222, "edition_count": 7, "languages": ["eng"], "subjects": ["Peer pressure", "Social groups", "Social change", "New York Times reviewed"], "synopsis": "This book identifies a brewing social revolution that is changing the way people live, based on harnessing the positive force of peer pressure, and shows how peer pressure has reduced teen smoking in the United States, made villages in India healthier and more prosperous, helped minority students get top grades in college calculus, and even led to the fall of Slobodan Milosevic.", "publication_year": 2011, "page_count": 402, "isbn13": "9781848313002", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (101, 12320115, 3, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:06+00:00', '{"openlibrary": {"ol_key": "/works/OL16299424W", "ol_cover_id": 12320115, "edition_count": 3, "languages": ["eng"], "subjects": ["Gays", "Homosexuality", "Trials, litigation", "Texas", "Criminal provisions", "Law and legislation", "Trials (Sodomy)", "Legal status, laws", "NEW LIST 20120331", "Trials", "Trials, united states", "Homosexuality, law and legislation"], "synopsis": "No one could have predicted that the night of September 17, 1998, would be anything but routine in Houston, Texas. Even the call to police that a black man was \"going crazy with a gun\" was hardly unusual in this urban setting. Nobody could have imagined that the arrest of two men for a minor criminal offense would reverberate in American constitutional law, exposing a deep malignity in our judicial system and challenging the traditional conception of what makes a family. Indeed, when Harris County sheriff’s deputies entered the second-floor apartment, there was no gun. Instead, they reported that they had walked in on John Lawrence and Tyron Garner having sex in Lawrence’s bedroom.\r\n\r\nSo begins Dale Carpenter’s \"gripping and brilliantly researched\" Flagrant Conduct, a work nine years in the making that transforms our understanding of what we thought we knew about Lawrence v. Texas, the landmark Supreme Court decision of 2003 that invalidated America’s sodomy laws. Drawing on dozens of interviews, Carpenter has taken on the \"gargantuan\" task of extracting the truth about the case, analyzing the claims of virtually every person involved.\r\n\r\nCarpenter first introduces us to the interracial defendants themselves, who were hardly prepared \"for the strike of lightning\" that would upend their lives, and then to the Harris County arresting officers, including a sheriff’s deputy who claimed he had \"looked eye to eye\" in the faces of the men as they allegedly fornicated. Carpenter skillfully navigates Houston’s complex gay world of the late 1990s, where a group of activists and court officers, some of them closeted themselves, refused to bury what initially seemed to be a minor arrest.\r\n\r\nThe author charts not only the careful legal strategy that Lambda Legal attorneys adopted to make the case compatible to a conservative Supreme Court but also the miscalculations of the Houston prosecutors who assumed that the nation’s extant sodomy laws would be upheld. Masterfully reenacting the arguments that riveted spectators and Justices alike in 2003, Flagrant Conduct then reaches a point where legal history becomes literature, animating a Supreme Court decision as few writers have done.\r\n\r\nIn situating Lawrence v. Texas within the larger framework of America’s four-century persecution of gay men and lesbians, Flagrant Conduct compellingly demonstrates that gay history is an integral part of our national civil rights story.", "publication_year": 2012, "page_count": 384, "isbn13": "9780393081961", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (102, 10221348, 72, '["heb", "ukr", "eng", "spa", "ger", "und"]', 3.89, 81, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:10+00:00', '{"openlibrary": {"ol_key": "/works/OL2626638W", "ol_cover_id": 10221348, "edition_count": 72, "languages": ["heb", "ukr", "eng", "spa", "ger", "und"], "subjects": ["Hugo Award Winner", "award:hugo_award=1961", "award:hugo_award=novel", "American Science fiction", "apocalypse", "nuclear war", "civilization", "science fiction", "church versus state", "Long Now Manual for Civilization", "Monks", "Monasticism and religious orders"], "synopsis": "Highly unusual After the Holocaust novel.  In the far future, 20th century texts are preserved in a monastery, as \"sacred  books\".  The monks preserve for centuries what little science there is, and have saved the science texts and blueprints from destruction many times, also making beautifully illuminated copies. As the story opens to a world run on a basically fuedal lines, science is again becoming fashionable, as a hobby of rich men, at perhaps 18th or early 19th century level of comprehesion. A local lord, interested in science, comes to the monastery. What happens after that is an exquisitely told tale, stunning and extremely moving, totally different from any other After the Holocaust story", "publication_year": 1959, "page_count": 320, "isbn13": "9780553121803", "ratings_average": 3.89, "ratings_count": 81}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (103, 13698291, 3, '["eng"]', NULL, NULL, 'Q7752879', 'https://en.wikipedia.org/wiki/The_Mystery_of_Banking', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:13+00:00', '{"openlibrary": {"ol_key": "/works/OL34894655W", "ol_cover_id": 13698291, "edition_count": 3, "languages": ["eng"], "subjects": ["Money", "Banks and banking"], "synopsis": null, "publication_year": 1983, "page_count": 286, "isbn13": "9781388173838", "ratings_average": null, "ratings_count": null}, "wikidata": {"wikidata_id": "Q7752879", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Mystery of Banking", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Mystery_of_Banking"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (104, 284322, 30, '["eng", "ger", "spa", "por", "fre", "dut", "ita", "dan"]', 3.96, 55, 'Q2384854', 'https://en.wikipedia.org/wiki/Count_Zero', NULL, 'Sprawl trilogy', '["20th Century''s Greatest Hits: 100 English-Language Books of Fiction"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:16+00:00', '{"openlibrary": {"ol_key": "/works/OL27256W", "ol_cover_id": 284322, "edition_count": 30, "languages": ["eng", "ger", "spa", "por", "fre", "dut", "ita", "dan"], "subjects": ["Long Now Manual for Civilization", "Fiction, mystery & detective, general", "American literature", "Fiction, science fiction, general", "Sprawl Trilogy", "Virtual reality", "Cyberspace", "Matrix (Imaginary place)", "genre:cyberpunk"], "synopsis": "Turner, corporate mercenary, wakes in a reconstructed body, a beautiful woman by his side. Then Hosaka Corporation reactivates him for a mission more dangerous than the one he''s recovering from: Maas-Neotek''s chief of R&D is defecting. Turner is the one assigned to get him out intact, along with the biochip he''s perfected. But this proves to be of supreme interest to certain other parties--some of whom aren''t remotely human.\r\n\r\nBobby Newmark is entirely human: a rustbelt data-hustler totally unprepared for what comes his way when the defection triggers war in cyberspace. With voodoo on the Net and a price on his head, Newmark thinks he''s only trying to get out alive.\r\n\r\nThe second novel of William Gibson''s Sprawl trilogy, *Count Zero* is a stylish, streetsmart, frighteningly probable parable of the future and sequel to Neuromancer.", "publication_year": 1986, "page_count": 312, "isbn13": "9781473217409", "ratings_average": 3.96, "ratings_count": 55}, "wikidata": {"wikidata_id": "Q2384854", "awards": ["20th Century''s Greatest Hits: 100 English-Language Books of Fiction"], "series": "Sprawl trilogy", "goodreads_id": null, "wikipedia_title": "Count Zero", "wikipedia_url": "https://en.wikipedia.org/wiki/Count_Zero"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (105, 13290711, 35, '["eng", "dut", "ger", "kor", "chi", "pol", "tur"]', 4.1, 231, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:21+00:00', '{"openlibrary": {"ol_key": "/works/OL15992072W", "ol_cover_id": 13290711, "edition_count": 35, "languages": ["eng", "dut", "ger", "kor", "chi", "pol", "tur"], "subjects": ["Intuition", "Thought and thinking", "Reasoning", "Decision making", "New York Times bestseller", "Long Now Manual for Civilization", "Thinking", "Kognition", "77.32 intelligence, creativity", "New York Times reviewed", "Reason", "Cognition"], "synopsis": "In his mega bestseller, Thinking, Fast and Slow, Daniel Kahneman, world-famous psychologist and winner of the Nobel Prize in Economics, takes us on a groundbreaking tour of the mind and explains the two systems that drive the way we think.\r\n\r\nSystem 1 is fast, intuitive, and emotional; System 2 is slower, more deliberative, and more logical. The impact of overconfidence on corporate strategies, the difficulties of predicting what will make us happy in the future, the profound effect of cognitive biases on everything from playing the stock market to planning our next vacation―each of these can be understood only by knowing how the two systems shape our judgments and decisions.\r\n\r\nEngaging the reader in a lively conversation about how we think, Kahneman reveals where we can and cannot trust our intuitions and how we can tap into the benefits of slow thinking. He offers practical and enlightening insights into how choices are made in both our business and our personal lives―and how we can use different techniques to guard against the mental glitches that often get us into trouble. Topping bestseller lists for almost ten years, Thinking, Fast and Slow is a contemporary classic, an essential book that has changed the lives of millions of readers.", "publication_year": 2011, "page_count": 528, "isbn13": "9781535535830", "ratings_average": 4.1, "ratings_count": 231}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (106, 7323639, 1, '["eng"]', 4.5, 2, 'Q131436467', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:23+00:00', '{"openlibrary": {"ol_key": "/works/OL16163232W", "ol_cover_id": 7323639, "edition_count": 1, "languages": ["eng"], "subjects": ["Human beings", "Turing test", "Philosophical anthropology", "PHILOSOPHY", "Humanism", "Movements"], "synopsis": "\"The Most Human Human\" is a provocative exploration of the ways in which computers are reshaping our ideas of what it means to be human. Its starting point is the annual Turing Test, which pits artificial intelligence programs against people to determine if computers can \"think.\"", "publication_year": 2011, "page_count": 320, "isbn13": "9780385533065", "ratings_average": 4.5, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q131436467", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (107, 7004628, 7, '["eng"]', 5.0, 2, 'Q7314374', 'https://en.wikipedia.org/wiki/Republic%2C_Lost', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:26+00:00', '{"openlibrary": {"ol_key": "/works/OL16202595W", "ol_cover_id": 7004628, "edition_count": 7, "languages": ["eng"], "subjects": ["Politics and government", "Lobbying", "Corrupt practices", "United States", "Political corruption", "United States. Congress", "Ethics", "Campaign funds", "Korruption", "USA", "Kongress", "USA Congress"], "synopsis": "In an era when special interests funnel huge amounts of money into our government—driven by shifts in campaign-finance rules and brought to new levels by the Supreme Court in Citizens United v. Federal Election Commission—trust in our government has reached an all-time low. More than ever before, Americans believe that money buys results in Congress, and that business interests wield control over our legislature.\r\n\r\n \r\n\r\nWith heartfelt urgency and a keen desire for righting wrongs, Harvard law professor Lawrence Lessig takes a clear-eyed look at how we arrived at this crisis: how fundamentally good people, with good intentions, have allowed our democracy to be co-opted by outside interests, and how this exploitation has become entrenched in the system. Rejecting simple labels and reductive logic—and instead using examples that resonate as powerfully on the Right as on the Left—Lessig seeks out the root causes of our situation. He plumbs the issues of campaign financing and corporate lobbying, revealing the human faces and follies that have allowed corruption to take such a foothold in our system. He puts the issues in terms that nonwonks can understand, using real-world analogies and real human stories. And ultimately he calls for widespread mobilization and a new Constitutional Convention, presenting achievable solutions for regaining control of our corrupted—but redeemable—representational system. In this way, Lessig plots a roadmap for returning our republic to its intended greatness.\r\n\r\nWhile America may be divided, Lessig vividly champions the idea that we can succeed if we accept that corruption is our common enemy and that we must find a way to fight against it. In REPUBLIC, LOST, he not only makes this need palpable and clear—he gives us the practical and intellectual tools to do something about it. \r\n\r\n*Source:* [Twelve Books][1]\r\n\r\n\r\n  [1]: http://twelvebooks.com/books/republic_lost.asp", "publication_year": 2011, "page_count": 384, "isbn13": "9781306756686", "ratings_average": 5.0, "ratings_count": 2}, "wikidata": {"wikidata_id": "Q7314374", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Republic, Lost", "wikipedia_url": "https://en.wikipedia.org/wiki/Republic%2C_Lost"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (108, 210914, 17, '["eng", "ger"]', 3.6, 10, 'Q2246747', 'https://en.wikipedia.org/wiki/Darwin%27s_Radio', NULL, NULL, '["Nebula Award for Best Novel"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:30+00:00', '{"openlibrary": {"ol_key": "/works/OL16508W", "ol_cover_id": 210914, "edition_count": 17, "languages": ["eng", "ger"], "subjects": ["Women molecular biologists", "DNA viruses", "Science Fiction", "Human evolution", "Evolution", "Viruses", "Evolution (Biology)", "Fiction, thrillers, general", "Fiction, medical", "award:nebula_award=novel", "Fiction, general", "Fiction, science fiction, general"], "synopsis": "\"Virus hunter\" Christopher Dicken is a man on a mission, following a trail of rumors, government cover-ups, and dead bodies around the globe in search of a mysterious disease that strikes only pregnant women and invariably results in miscarriage. But when Dicken finds what he''s looking for, the answer proves to be stranger--and far deadlier--than he ever could have imagined. Something that has slept in human DNA for millions of years is waking up.Molecular biologist Kaye Lang has spent her career tracing ancient retroviruses in the human genome. She believes these microscopic fossils can come to life again. But when Dicken''s discovery becomes public, Lang''s theory suddenly turns to chilling fact. As the outbreak of this terrifying disease threatens to become a deadly epidemic, Dicken and Lang must race against time to assemble the pieces of a puzzle only they are equipped to solve--an evolutionary puzzle that will determine the future of the human race . . . if a future exists at all.", "publication_year": 1999, "page_count": 440, "isbn13": "9780345464927", "ratings_average": 3.6, "ratings_count": 10}, "wikidata": {"wikidata_id": "Q2246747", "awards": ["Nebula Award for Best Novel"], "series": null, "goodreads_id": null, "wikipedia_title": "Darwin''s Radio", "wikipedia_url": "https://en.wikipedia.org/wiki/Darwin%27s_Radio"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (109, 133936, 41, '["eng", "ger", "ara", "spa", "dut", "tur", "kor", "fre", "pol"]', 4.37, 73, 'Q212789', 'https://en.wikipedia.org/wiki/The_Selfish_Gene', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:32+00:00', '{"openlibrary": {"ol_key": "/works/OL1966488W", "ol_cover_id": 133936, "edition_count": 41, "languages": ["eng", "ger", "ara", "spa", "dut", "tur", "kor", "fre", "pol"], "subjects": ["Evolution (Biology)", "Genetics", "Sociobiology", "Behavior genetics", "Genetica", "Etologia Animal", "Genetics.\u001e 0", "Long Now Manual for Civilization", "Natural selection", "Sociobiologie", "Évolution (biologie)", "Memen"], "synopsis": "As influential today as when it was first published, The Selfish Gene has become a classic exposition of evolutionary thought. Professor Dawkins articulates a gene''s eye view of evolution - a view giving centre stage to these persistent units of information, and in which organisms can be seen as vehicles for their replication. This imaginative, powerful, and stylistically brilliant work not only brought the insights of Neo-Darwinism to a wide audience, but galvanized the biology\r\ncommunity, generating much debate and stimulating whole new areas of research. Forty years later, its insights remain as relevant today as on the day it was published.\r\n\r\nThis 40th anniversary edition includes a new epilogue from the author discussing the continuing relevance of these ideas in evolutionary biology today, as well as the original prefaces and foreword, and extracts from early reviews.\r\n\r\nOxford Landmark Science books are ''must-read'' classics of modern science writing which have crystallized big ideas, and shaped the way we think.", "publication_year": 1976, "page_count": 352, "isbn13": "9780195690668", "ratings_average": 4.37, "ratings_count": 73}, "wikidata": {"wikidata_id": "Q212789", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Selfish Gene", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Selfish_Gene"}}');
