INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (112, 1047334, 47, '["eng", "tur", "ita", "fre", "jpn", "und", "chi", "rus", "spa"]', 3.85, 71, 'Q951587', 'https://en.wikipedia.org/wiki/Never_Let_Me_Go_%28novel%29', NULL, NULL, '["Corine Literature Prize"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:40+00:00', '{"openlibrary": {"ol_key": "/works/OL59038W", "ol_cover_id": 1047334, "edition_count": 47, "languages": ["eng", "tur", "ita", "fre", "jpn", "und", "chi", "rus", "spa"], "subjects": ["Organ donors", "Cloning", "Donation of organs, tissues", "Women", "New York Times bestseller", "nyt:trade_fiction_paperback=2010-09-05", "Human cloning", "Science fiction", "Fiction, psychological", "Fiction, science fiction, general", "England, fiction", "Large type books"], "synopsis": "Ishiguro explores what it means to have a soul and how art distinguishes man from other life forms. But above all, *Never Let Me Go* is a study of friendship and the bonds we form which make or break while we come of age.", "publication_year": 2005, "page_count": 288, "isbn13": "9780571328475", "ratings_average": 3.85, "ratings_count": 71}, "wikidata": {"wikidata_id": "Q951587", "awards": ["Corine Literature Prize"], "series": null, "goodreads_id": null, "wikipedia_title": "Never Let Me Go (novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Never_Let_Me_Go_%28novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (113, 8675730, 6, '["eng"]', 3.4, 5, 'Q120142613', 'https://en.wikipedia.org/wiki/Triumph_of_the_City', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:44+00:00', '{"openlibrary": {"ol_key": "/works/OL19873317W", "ol_cover_id": 8675730, "edition_count": 6, "languages": ["eng"], "subjects": ["Long Now Manual for Civilization", "Urban economics", "Urbanisation", "Cities and towns", "Urbanization", "Stedelijke economie", "Forensisme", "Villes", "Urban sociology", "Stadtentwicklung", "Stadtökonomie", "Stadtsoziologie"], "synopsis": "**A pioneering urban economist offers fascinating, even inspiring proof that the city is humanity''s greatest invention and our best hope for the future.**\r\n\r\nAmerica is an urban nation. More than two thirds of us live on the 3 percent of land that contains our cities. Yet cities get a bad rap: they''re dirty, poor, unhealthy, crime ridden, expensive, environmentally unfriendly... Or are they?\r\n\r\nAs Edward Glaeser proves in this myth-shattering book, cities are actually the healthiest, greenest, and richest (in cultural and economic terms) places to live. New Yorkers, for instance, live longer than other Americans; heart disease and cancer rates are lower in Gotham than in the nation as a whole. More than half of America''s income is earned in twenty-two metropolitan areas. And city dwellers use, on average, 40 percent less energy than suburbanites.\r\n\r\nGlaeser travels through history and around the globe to reveal the hidden workings of cities and how they bring out the best in humankind. Even the worst cities-Kinshasa, Kolkata, Lagos- confer surprising benefits on the people who flock to them, including better health and more jobs than the rural areas that surround them. Glaeser visits Bangalore and Silicon Valley, whose strangely similar histories prove how essential education is to urban success and how new technology actually encourages people to gather together physically. He discovers why Detroit is dying while other old industrial cities-Chicago, Boston, New York-thrive. He investigates why a new house costs 350 percent more in Los Angeles than in Houston, even though building costs are only 25 percent higher in L.A. He pinpoints the single factor that most influences urban growth-January temperatures-and explains how certain chilly cities manage to defy that link. He explains how West Coast environmentalists have harmed the environment, and how struggling cities from Youngstown to New Orleans can \"shrink to greatness.\" And he exposes the dangerous anti-urban political bias that is harming both cities and the entire country.\r\n\r\nUsing intrepid reportage, keen analysis, and eloquent argument, Glaeser makes an impassioned case for the city''s import and splendor. He reminds us forcefully why we should nurture our cities or suffer consequences that will hurt us all, no matter where we live.\r\n\r\n(*Source: Penguin Press blurb*)", "publication_year": 2011, "page_count": 404, "isbn13": "9780330458078", "ratings_average": 3.4, "ratings_count": 5}, "wikidata": {"wikidata_id": "Q120142613", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Triumph of the City", "wikipedia_url": "https://en.wikipedia.org/wiki/Triumph_of_the_City"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (114, 6727108, 8, '["eng", "ger"]', 3.6, 5, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:48+00:00', '{"openlibrary": {"ol_key": "/works/OL15118227W", "ol_cover_id": 6727108, "edition_count": 8, "languages": ["eng", "ger"], "subjects": ["Telecommunication", "Information technology", "Long Now Manual for Civilization", "Telecommunication -- History", "Histoire", "Telecommunicatie", "Informationswirtschaft", "Informatiemaatschappij", "Massmedia", "Mass media", "Internet", "Monopol"], "synopsis": "In this age of an open internet, it is easy to forget that every American information industry, beginning with the telephone, has eventually been taken captive by some ruthless monopoly or cartel. With all our media now traveling a single network, an unprecedented potential is building for centralized control over what Americans see and hear. Could history repeat itself with the next industrial consolidation? Could the internet- the entire flow of American information- come to be ruled by one corporate leviathan in possession of \"the master switch\"? That is the big question that the author presents in this pathbreaking book. As Wu''s sweeping history shows, each of the new media of the twentieth century- radio, telephone, television, and film- was born free and open. Each invited unrestricted use and enterprising experiment until some would-be mogul battled his way to total domination. Explaining how invention begets industry and industry begets empire- a progress often blessed by government, typically with stifling consequences for free expression and technical innovation alike- Wu identifies a time-honored pattern in the maneuvers of today''s great information powers: Apple, Goggle, and an eerily resurgent AT & T.A battle royal looms for the internet''s future, and with almost every aspect of our lives now dependent on that network, this is one war we dare not tune out. Part industrial expose, part meditation of what freedom requires in the information age, this book is a stirring illumination of a drama that has played out over decades in the shadows of our national life and now culminates with terrifying implications for our future. -- from Book Jacket.", "publication_year": 2010, "page_count": 377, "isbn13": "9780307269935", "ratings_average": 3.6, "ratings_count": 5}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (115, 7005914, 34, '["ger", "eng", "spa", "fre", "rum"]', 3.79, 14, 'Q5302883', 'https://en.wikipedia.org/wiki/Down_Under_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:50+00:00', '{"openlibrary": {"ol_key": "/works/OL74115W", "ol_cover_id": 7005914, "edition_count": 34, "languages": ["ger", "eng", "spa", "fre", "rum"], "subjects": ["Social life and customs", "Description and travel", "Humour", "Journeys", "Travel", "Civilization", "Australia", "Bill Bryson", "Description", "Large type books", "Australia, social life and customs", "Australia, description and travel"], "synopsis": "*In a Sunburned Country* is the 2000 travelogue book about Australia written by best-selling travel writer Bill Bryson. The title is taken from the famous Australian poem, \"My Country\".  In other countries, including Britain, the book was titled *Down Under*.\r\n\r\nIn this book, Bill Bryson describes his travels by railway and car throughout Australia, his conversations with people in all walks of life about the history, geography, unusual plants and animals of the country, and his wry impressions of the life, culture and amenities (or lack thereof) in each locality.  \r\n\r\nIn a style similar to his book *A Walk in the Woods*, Bryson''s research enabled him to include many stories about Australia''s 19th-century explorers and settlers who suffered extreme deprivations, as well as details about its natural resources, culture, and economy. His writings are intertwined with recurring humorous themes, notably, in the chapter Crossing Australia he makes constant reference to drinking of urine to survive, as was done by many 19th century explorers.", "publication_year": 2000, "page_count": 348, "isbn13": "9781409095644", "ratings_average": 3.79, "ratings_count": 14}, "wikidata": {"wikidata_id": "Q5302883", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Down Under (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Down_Under_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (116, 581334, 14, '["ger", "eng", "spa"]', 3.5, 4, 'Q2386750', 'https://en.wikipedia.org/wiki/Hegemony_or_Survival', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:54+00:00', '{"openlibrary": {"ol_key": "/works/OL71680W", "ol_cover_id": 581334, "edition_count": 14, "languages": ["ger", "eng", "spa"], "subjects": ["Imperialism", "War on Terrorism, 2001-2009", "State-sponsored terrorism", "Unilateral acts (International law)", "Ballistic missile defense system", "Military policy", "War on Terrorism, 2001-", "Intervention (International law)", "Foreign relations", "UNILATERAL ACTS OF STATES", "UNITED STATES", "Diplomatic relations"], "synopsis": "From the world''s foremost intellectual activist, here is an irrefutable analysis of America''s pursuit of total domination and the catastrophic consequences that are sure to follow. The United States is in the process of staking out not just the globe, but the last unarmed spot in our neighbourhood - the skies - as a militarized sphere of influence. Our earth and its skies are, for the Bush administration, the final frontiers of imperial control. In Hegemony or Survival, Noam Chomsky explains how we came to this moment, what kind of peril we find ourselves in, and why our rulers are willing to jeopardize the future of our species. In our era, Chomsky argues, empire is a recipe for an earthly wasteland.", "publication_year": 2003, "page_count": 316, "isbn13": "9780241142509", "ratings_average": 3.5, "ratings_count": 4}, "wikidata": {"wikidata_id": "Q2386750", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Hegemony or Survival", "wikipedia_url": "https://en.wikipedia.org/wiki/Hegemony_or_Survival"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (117, 5071195, 46, '["eng", "ger"]', 4.13, 15, 'Q2234406', 'https://en.wikipedia.org/wiki/A_Distant_Mirror', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:54:56+00:00', '{"openlibrary": {"ol_key": "/works/OL3378547W", "ol_cover_id": 5071195, "edition_count": 46, "languages": ["eng", "ger"], "subjects": ["Nobleza", "Noblesse", "Biographies", "Histoire", "France", "Middle Ages", "Biography", "Ambassadors", "Soldiers", "Manners and customs", "Biografía", "Nobility"], "synopsis": "Amazon.com Review\r\n\r\nIn this sweeping historical narrative, Barbara Tuchman writes of the cataclysmic 14th century, when the energies of medieval Europe were devoted to fighting internecine wars and warding off the plague. Some medieval thinkers viewed these disasters as divine punishment for mortal wrongs; others, more practically, viewed them as opportunities to accumulate wealth and power. One of the latter, whose life informs much of Tuchman''s book, was the French nobleman Enguerrand de Coucy, who enjoyed the opulence and elegance of the courtly tradition while ruthlessly exploiting the peasants under his thrall. Tuchman looks into such events as the Hundred Years War, the collapse of the medieval church, and the rise of various heresies, pogroms, and other events that caused medieval Europeans to wonder what they had done to deserve such horrors.", "publication_year": 1600, "page_count": 691, "isbn13": "9781439558577", "ratings_average": 4.13, "ratings_count": 15}, "wikidata": {"wikidata_id": "Q2234406", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "A Distant Mirror", "wikipedia_url": "https://en.wikipedia.org/wiki/A_Distant_Mirror"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (118, 6868550, 2, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:01+00:00', '{"openlibrary": {"ol_key": "/works/OL16018523W", "ol_cover_id": 6868550, "edition_count": 2, "languages": ["eng"], "subjects": ["Cytology", "Cell interaction", "Molecular biology", "Computational biology", "Cell Biology", "Cell Physiological Phenomena"], "synopsis": "\"How does a single-cell creature, such as an amoeba, lead such a sophisticated life? How does it hunt living prey, respond to lights, sounds, and smells, and display complex sequences of movements without the benefit of a nervous system? This book offers a startling and original answer. The author taps the findings of the new discipline of systems biology to show that the internal chemistry of living cells is a form of computation. Cells are built out of molecular circuits that perform logical operations, as electronic devices do, but with unique properties. Bray argues that the computational juice of cells provides the basis of all the distinctive properties of living systems: it allows organisms to embody in their internal structure an image of the world, and this accounts for their adaptability, responsiveness, and intelligence.\"--Book jacket.", "publication_year": 2009, "page_count": 267, "isbn13": "9780300141733", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (119, 9286949, 14, '["eng", "chi", "kor"]', 3.8, 10, 'Q7691655', 'https://en.wikipedia.org/wiki/Team_of_Rivals', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:04+00:00', '{"openlibrary": {"ol_key": "/works/OL1856010W", "ol_cover_id": 9286949, "edition_count": 14, "languages": ["eng", "chi", "kor"], "subjects": ["Union Army", "Thirteenth Amendment", "assassination of Abraham Lincoln", "secretary of war", "1864 presidential election", "Emancipation Proclamation", "secretary of state", "secretary of treasury", "United States Attorney General", "American Civil War", "Lincoln-Douglas debates", "Democratic Party"], "synopsis": "Team of Rivals: The Political Genius of Abraham Lincoln is a 2005 book by Pulitzer Prize-winning American historian Doris Kearns Goodwin, published by Simon & Schuster. The book is a biographical portrait of U.S. President Abraham Lincoln and some of the men who served with him in his cabinet from 1861 to 1865. Three of his Cabinet members had previously run against Lincoln in the 1860 election: Attorney General Edward Bates, Secretary of the Treasury Salmon P. Chase and Secretary of State William H. Seward. The book focuses on Lincoln''s mostly successful attempts to reconcile conflicting personalities and political factions on the path to abolition and victory in the American Civil War.\r\n\r\nGoodwin''s sixth book, Team of Rivals was well received by critics and won the 2006 Lincoln Prize and the inaugural Book Prize for American History of the New-York Historical Society. US President Barack Obama cited it as one of his favorite books and was said to have used it as a model for constructing his own cabinet, although he later wrote this was not the reason he chose Hillary Clinton as his Secretary of State. In 2012, a Steven Spielberg film based on the book was released to critical acclaim.", "publication_year": 2003, "page_count": 916, "isbn13": "9780141043722", "ratings_average": 3.8, "ratings_count": 10}, "wikidata": {"wikidata_id": "Q7691655", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Team of Rivals", "wikipedia_url": "https://en.wikipedia.org/wiki/Team_of_Rivals"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (120, 182324, 5, '["eng"]', 4.0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:08+00:00', '{"openlibrary": {"ol_key": "/works/OL5725219W", "ol_cover_id": 182324, "edition_count": 5, "languages": ["eng"], "subjects": ["Science Fiction", "Space Travel in Fiction", "Fiction, romance, fantasy", "Fiction, science fiction, general", "Amnesia", "Extraterrestrial beings"], "synopsis": "\"The Golden Age takes place 10,000 years in the future in our solar system, an interplanetary utopian society filled with immortal humans. Within the frame of a traditional tale - the one rebel who is unhappy in utopia - Wright spins an elaborate plot web filled with suspense and passion.\" \"Phaethon, of Radamanthus House, is attending a glorious party at his family mansion to celebrate the thousand-year anniversary of the High Transcendence. There he meets first an old man who accuses him of being an impostor and then a being from Neptune who claims to be an old friend. The Neptunian tells him that essential parts of his memory were removed and stored by the very government that Phaethon believes to be wholly honorable. It shakes his faith. He is an exile from himself.\" And so Phaethon embarks upon a quest across the transformed solar system - Jupiter is now a second sun, Mars and Venus terraformed, humanity immortal - among humans, intelligent machines, and bizarre lifeforms that are partly both, to recover his memory, and to learn what crime he planned that warranted such preemptive punishment. His quest is to regain his true identity.", "publication_year": 2002, "page_count": 320, "isbn13": "9780812579840", "ratings_average": 4.0, "ratings_count": 4}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (121, 554640, 6, '["eng"]', 4.17, 18, 'Q3503996', 'https://en.wikipedia.org/wiki/Don%27t_Make_Me_Think', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:11+00:00', '{"openlibrary": {"ol_key": "/works/OL8578577W", "ol_cover_id": 554640, "edition_count": 6, "languages": ["eng"], "subjects": ["Web sites", "Web site development", "Design", "Evaluation", "Publishing", "Internet", "Data Display", "Writing", "User-Computer Interface", "WORLD WIDE WEB", "Sites Web", "INTERNETS"], "synopsis": "Yesterday''s Web looked far different from today''s Web, and tomorrow''s Web will look more different still. Amidst all of this change, however, one aspect of Web use remains the same: The sites that offer the best, easiest, most intuitive experience are the ones people visit again and again. To ensure that your sites provide that experience, this guide from usability guru Krug distills his years of on-the-job experience into a practical primer on the do''s and don''ts of good Web design. The second edition of this classic adds three new chapters that explain why people really leave Web sites, how to make sites usable and accessible, and the art of surviving executive design whims, plus a new preface and updated recommended reading.--From publisher description", "publication_year": 2000, "page_count": 201, "isbn13": "9780321965516", "ratings_average": 4.17, "ratings_count": 18}, "wikidata": {"wikidata_id": "Q3503996", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Don''t Make Me Think", "wikipedia_url": "https://en.wikipedia.org/wiki/Don%27t_Make_Me_Think"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (122, 3350262, 16, '["eng", "spa"]', 4.14, 7, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:13+00:00', '{"openlibrary": {"ol_key": "/works/OL1079340W", "ol_cover_id": 3350262, "edition_count": 16, "languages": ["eng", "spa"], "subjects": ["Condiciones económicas", "Microcrédit", "Banques", "Histoire", "Conditions sociales", "Conditions économiques", "Pauvreté", "Développement économique et social", "Crédit bancaire", "Microfinance", "Banques populaires", "Débiteur et créancier"], "synopsis": "The winner of the Nobel Peace Prize outlines his vision for a new business model that combines the power of free markets with the quest for a more humane world--and he tells the inspiring stories of companies that are doing this work today. In the last two decades, free markets have swept the globe, bringing with them enormous potential for positive change. But traditional capitalism cannot solve problems like inequality and poverty, because it is hampered by a narrow view of human nature in which people are one-dimensional beings concerned only with profit. In fact, human beings have many other drives and passions, including the spiritual, the social, and the altruistic. Welcome to the world of social business, where the creative vision of the entrepreneur is applied to today''s most serious problems: feeding the poor, housing the homeless, healing the sick, and protecting the planet.--From publisher description.", "publication_year": 1999, "page_count": 301, "isbn13": "9781586484934", "ratings_average": 4.14, "ratings_count": 7}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (123, 431011, 28, '["fre", "eng"]', 3.88, 68, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:17+00:00', '{"openlibrary": {"ol_key": "/works/OL3902892W", "ol_cover_id": 431011, "edition_count": 28, "languages": ["fre", "eng"], "subjects": ["Compliance", "Influence (Psychology)", "Persuasion (Psychology)", "Self-Improvement", "Persuasion (Psychologie)", "Influence (Psychologie)", "Sociale beïnvloeding", "Overreding", "Complaisance", "Communication", "Psychological aspects", "Beeinflussung"], "synopsis": "Influence, the classic book on persuasion, explains the psychology of why people say \"yes\"—and how to apply these understandings. Dr. Robert Cialdini is the seminal expert in the rapidly expanding field of influence and persuasion. His thirty-five years of rigorous, evidence-based research along with a three-year program of study on what moves people to change behavior has resulted in this highly acclaimed book.\r\n\r\nYou''ll learn the six universal principles, how to use them to become a skilled persuader—and how to defend yourself against them. Perfect for people in all walks of life, the principles of Influence will move you toward profound personal change and act as a driving force for your success.\r\n\r\nSome images that appeared in the print edition of this book are unavailable in the electronic edition due to rights reasons.", "publication_year": 1983, "page_count": 287, "isbn13": "9780320087318", "ratings_average": 3.88, "ratings_count": 68}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (124, 9491369, 2, '["eng"]', 2.5, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:22+00:00', '{"openlibrary": {"ol_key": "/works/OL6431320W", "ol_cover_id": 9491369, "edition_count": 2, "languages": ["eng"], "subjects": ["Mind and body", "Play", "Psychological aspects", "Psychological aspects of Play", "Psychology", "Self-Improvement", "Social aspects", "Social aspects of Play", "Spiel", "Psychologie", "Play and Playthings", "Play, psychological aspects"], "synopsis": "From a leading expert, a groundbreaking book on the science of play, and its essential role in fueling our intelligence and happiness throughout our lives.We’ve all seen the happiness in the face of a child while playing in the school yard. Or the blissful abandon of a golden retriever racing with glee across a lawn. This is the joy of play. By definition, play is purposeless and all-consuming. And, most important, it’s fun.As we become adults, taking time to play feels like a guilty pleasure—a distraction from “real” work and life. But as Dr. Stuart Brown illustrates, play is anything but trivial. It is a biological drive as integral to our health as sleep or nutrition. In fact, our ability to play throughout life is the single most important factor in determining our success and happiness.Dr. Brown has spent his career studying animal behavior and conducting more than six thousand “play histories” of humans from all walks of life—from serial murderers to Nobel Prize winners. Backed by the latest research, Play explains why play is essential to our social skills, adaptability, intelligence, creativity, ability to problem solve, and more. Play is hardwired into our brains—it is the mechanism by which we become resilient, smart, and adaptable people.Beyond play’s role in our personal fulfillment, its benefits have profound implications for child development and the way we parent, education and social policy, business innovation, productivity, and even the future of our society. From new research suggesting the direct role of three-dimensional-object play in shaping our brains to animal studies showing the startling effects of the lack of play, Brown provides a sweeping look at the latest breakthroughs in our understanding of the importance of this behavior. A fascinating blend of cutting-edge neuroscience, biology, psychology, social science, and inspiring human stories of the transformative power of play, this book proves why play just might be the most important work we can ever do.", "publication_year": 2009, "page_count": 229, "isbn13": "9781583333334", "ratings_average": 2.5, "ratings_count": 2}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (125, 3845086, 4, '["eng"]', 4.5, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:27+00:00', '{"openlibrary": {"ol_key": "/works/OL506563W", "ol_cover_id": 3845086, "edition_count": 4, "languages": ["eng"], "subjects": ["Creative ability", "Creative thinking", "Psychology", "Creativity", "Bf408 .c77 1996", "Bf 408 c958 1997", "153.3/5"], "synopsis": "Creativity is about capturing those moments that make life worth living. The author''s objective is to offer an understanding of what leads to these moments, be it the excitement of the artist at the easel or the scientist in the lab, so that knowledge can be used to enrich people''s lives. Drawing on 100 interviews with exceptional people, from biologists and physicists to politicians and business leaders, poets and artists, as well as his 30 years of research on the subject, Csikszentmihalyi uses his famous theory to explore the creative process. He discusses such ideas as why creative individuals are often seen as selfish and arrogant, and why the tortured genius is largely a myth. Most important, he clearly explains why creativity needs to be cultivated and is necessary for the future of our country, if not the world.", "publication_year": 1996, "page_count": 464, "isbn13": "9780060928209", "ratings_average": 4.5, "ratings_count": 2}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (126, 7243923, 4, '["eng"]', 5.0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:29+00:00', '{"openlibrary": {"ol_key": "/works/OL16797804W", "ol_cover_id": 7243923, "edition_count": 4, "languages": ["eng"], "subjects": ["Energy Policy", "Environment", "Energy consumption", "Sustainable development", "Energy conservation", "Environmental aspects", "Energy industries", "Environmental policy", "Renewable energy sources", "Nachhaltigkeit", "Energies renouvelables", "Développement durable"], "synopsis": "Provides an overview of the sustainable energy crisis that is threatening the world''s natural resources, explaining how energy consumption is estimated and how those numbers have been skewed by various factors and discussing alternate forms of energy that can and should be used.", "publication_year": 2009, "page_count": 384, "isbn13": "9781906860011", "ratings_average": 5.0, "ratings_count": 4}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (127, 7254516, 4, '["eng"]', 4.43, 7, 'Q1820616', 'https://en.wikipedia.org/wiki/The_China_Study', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:32+00:00', '{"openlibrary": {"ol_key": "/works/OL15176142W", "ol_cover_id": 7254516, "edition_count": 4, "languages": ["eng"], "subjects": ["Health & Fitness", "Nutrition", "Nutritionally induced diseases", "diet in disease", "Methods", "Maladies d''origine nutritionnelle", "Food Habits", "Disease", "Diet", "Etiology", "Preventive Medicine", "Adverse effects"], "synopsis": "Referred to as the \"Grand Prix of epidemiology\" by The New York Times, this study examines more than 350 variables of health and nutrition with surveys from 6,500 adults in more than 2,500 counties across China and Taiwan, and conclusively demonstrates the link between nutrition and heart disease, diabetes, and cancer. While revealing that proper nutrition can have a dramatic effect on reducing and reversing these ailments as well as curbing obesity, this text calls into question the practices of many of the current dietary programs, such as the Atkins diet, that are widely popular in the West. The politics of nutrition and the impact of special interest groups in the creation and dissemination of public information are also discussed.", "publication_year": 2004, "page_count": 417, "isbn13": "9781932100389", "ratings_average": 4.43, "ratings_count": 7}, "wikidata": {"wikidata_id": "Q1820616", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The China Study", "wikipedia_url": "https://en.wikipedia.org/wiki/The_China_Study"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (128, 8126239, 1, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:35+00:00', '{"openlibrary": {"ol_key": "/works/OL11903988W", "ol_cover_id": 8126239, "edition_count": 1, "languages": ["eng"], "subjects": ["Social psychology", "Social perception", "Social interaction", "Organizational behavior", "Business networks", "Communication", "Interpersonal Relations", "Réseau informatique", "Société (milieu humain)", "Comportement organisationnel", "Entreprise", "Internet"], "synopsis": "\"How can you know when someone is bluffing? Paying attention? Genuinely interested? The answer, writes Sandy Pentland in Honest Signals, is that subtle patterns in how we interact with other people reveal our attitudes toward them. These unconscious social signals are not just a back channel or a complement to our conscious language; they form a separate communication network. Biologically based \"honest signaling,\" evolved from ancient primate signaling mechanisms, offers an unmatched window into our intentions, goals, and values. If we understand this ancient channel of communication, Pentland claims, we can accurately predict the outcomes of situations ranging from job interviews to first dates.\" \"Pentland, an MIT professor, has used a specially designed digital sensor worn like an ID badge - a \"sociometer\"--To monitor and analyze the back-and-forth patterns of signaling among groups of people. He and his researchers found that this second channel of communication, revolving not around words but around social relations, profoundly Influences major decisions in our lives - even though we are largely unaware of it. Pentland presents the scientific background necessary for understanding this form of communication, applies it to examples of group behavior in real organizations, and shows how by \"reading\" our social networks we can become more successful at pitching an idea, getting a job, or closing a deal. Using this \"network intelligence\" theory of social signaling, Pentland describes how we can harness the intelligence of our social network to become better managers, workers, and communicators.\"--", "publication_year": 2008, "page_count": 184, "isbn13": "9780262162562", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (129, 369478, 11, '["eng"]', 3.62, 21, 'Q2603313', 'https://en.wikipedia.org/wiki/Doomsday_Book_%28novel%29', NULL, 'Oxford time-traveling historians', '["NPR Top 100 Science Fiction and Fantasy Books", "Hugo Award for Best Novel", "Locus Award for Best Science Fiction Novel", "Ignotus Award for Best Foreign Novel", "Kurd Lasswitz Award for Best Foreign Work", "Nebula Award for Best Novel"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:38+00:00', '{"openlibrary": {"ol_key": "/works/OL14858406W", "ol_cover_id": 369478, "edition_count": 11, "languages": ["eng"], "subjects": ["Black Death", "Fantasy", "Hugo Award Winner", "Middle Ages", "Time travel", "award:hugo_award=1993", "award:hugo_award=novel", "Science fiction", "award:nebula_award=novel", "Fiction, science fiction, general", "New York Times reviewed"], "synopsis": "Somewhere in the future, ordinary history students must travel back in time as part of their university degree. An award-winning best-seller in the United States, this is the first of Connie Willis'' brilliant Oxford trilogy.Kivrin knows everything about the Middle Ages - she''s read all the books. She knows it''s dangerous: cutthroats in the woods, witch hunts, cholera, and millions dying in the plague. For a young historian, it''s fascinating.When Kivrin''s tutors in Oxford''s history lab finally agree to send her on an on-site study trip, she jumps at the chance to observe medieval life first-hand. But a crisis that strangely links the past and future leaves her stranded in the most deadly and terrifying era in human history, face to face with the heart-rending reality behind the statistics. And while she fights for her own life, Kivrin finds she has become an unlikely angel of hope in this dark time.Five years in the writing, Doomsday Book is a storytelling triumph. Connie Willis draws upon her understanding of the universalities of human nature to explore the timeless issues of evil, suffering and the indomitable will of the human spirit.", "publication_year": 1992, "page_count": 559, "isbn13": "9780739487136", "ratings_average": 3.62, "ratings_count": 21}, "wikidata": {"wikidata_id": "Q2603313", "awards": ["NPR Top 100 Science Fiction and Fantasy Books", "Hugo Award for Best Novel", "Locus Award for Best Science Fiction Novel", "Ignotus Award for Best Foreign Novel", "Kurd Lasswitz Award for Best Foreign Work", "Nebula Award for Best Novel"], "series": "Oxford time-traveling historians", "goodreads_id": null, "wikipedia_title": "Doomsday Book (novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Doomsday_Book_%28novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (130, 35299, 7, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:41+00:00', '{"openlibrary": {"ol_key": "/works/OL274903W", "ol_cover_id": 35299, "edition_count": 7, "languages": ["eng"], "subjects": ["Medical", "Business", "Medical care", "Cost effectiveness", "Medical economics", "Fees and Charges", "Cost-Benefit Analysis", "Health Care Costs", "Coût-efficacité", "Soins médicaux", "Économie de la santé", "Popular Works"], "synopsis": "Why is medical care in the United States so expensive? For decades, Americans have taken it as a matter of faith that we spend more because we have the best health care system in the world. But as costs levitate, that argument becomes more difficult to make. Today, we spend twice as much as Japan on health care — yet few would argue that our health care system is twice as good.Instead, startling new evidence suggests that one out of every three of our health care dollars is squandered on unnecessary or redundant tests; unproven, sometimes unwanted procedures; and overpriced drugs and devices that, too often, are no better than the less expensive products they have replaced.How did this happen? In Money-Driven Medicine, Maggie Mahar takes the reader behind the scenes of a $2 trillion industry to witness how billions of dollars are wasted in a Hobbesian marketplace that pits the industry''s players against each other. In remarkably candid interviews, doctors, hospital administrators, patients, health care economists, corporate executives, and Wall Street analysts describe a war of \"all against all\" that can turn physicians, hospitals, insurers, drugmakers, and device makers into blood rivals. Rather than collaborating, doctors and hospitals compete. Rather than sharing knowledge, drugmakers and device makers divide value. Rather than thinking about long-term collective goals, the imperatives of an impatient marketplace force health care providers to focus on short-term fiscal imperatives. And so investments in untested bleeding-edge medical technologies crowd out investments in information technology that might, in the long run, not only reduce errors but contain costs.In theory, free market competition should tame health care inflation. In fact, Mahar demonstrates, when it comes to medicine, the traditional laws of supply and demand do not apply. Normally, when supply expands, prices fall. But in the health care industry, as the number and variety of drugs, devices, and treatments multiplies, demand rises to absorb the excess, and prices climb. Meanwhile, the perverse incentives of a fee-for-service system reward health care providers for doing more, not less.In this superbly written book, Mahar shows why doctors must take responsibility for the future of our health care industry. Today, she observes, \"physicians have been stripped of their standing as professionals: Insurers address them as vendors (Dear Health Care Provider''), drugmakers and device makers see them as customers (someone you might take to lunch or a strip club), while . . . consumers (aka patients) are encouraged to see their doctors as overpaid retailers. . . . Before patients can reclaim their rightful place as the center—and indeed as the raison d''etre—of our health care system,\" Mahar suggests, \"we must once again empower doctors . . . to practice patient-centered medicine—based not on corporate imperatives, doctors'' druthers, or even patients'' demands,\" but on the best scientific research available.", "publication_year": 2006, "page_count": 480, "isbn13": "9780061873829", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (131, 242895, 5, '["eng"]', 4.25, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:45+00:00', '{"openlibrary": {"ol_key": "/works/OL119176W", "ol_cover_id": 242895, "edition_count": 5, "languages": ["eng"], "subjects": ["Current Events", "Political aspects", "Political questions and judicial power", "United States. Supreme Court", "United States", "Conservatism", "Judicial review", "Politics", "Law", "Political aspects of Law", "Politique et pouvoir judiciaire", "Contrôle juridictionnel des lois"], "synopsis": "Bestselling author Jeffrey Toobin takes you into the chambers of the most important--and secret--legal body in our country, the Supreme Court, and reveals the complex dynamic among the nine people who decide the law of the land.Just in time for the 2008 presidential election--where the future of the Court will be at stake--Toobin reveals an institution at a moment of transition, when decades of conservative disgust with the Court have finally produced a conservative majority, with major changes in store on such issues as abortion, civil rights, presidential power, and church-state relations.Based on exclusive interviews with justices themselves, The Nine tells the story of the Court through personalities--from Anthony Kennedy''s overwhelming sense of self-importance to Clarence Thomas''s well-tended grievances against his critics to David Souter''s odd nineteenth-century lifestyle. There is also, for the first time, the full behind-the-scenes story of Bush v. Gore--and Sandra Day O''Connor''s fateful breach with George W. Bush, the president she helped place in office. The Nine is the book bestselling author Jeffrey Toobin was born to write. A CNN senior legal analyst and New Yorker staff writer, no one is more superbly qualified to profile the nine justices.", "publication_year": 2007, "page_count": 384, "isbn13": "9780385516402", "ratings_average": 4.25, "ratings_count": 4}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (132, 8172445, 24, '["heb", "ger", "dut", "eng", "spa"]', 4.22, 18, 'Q7748388', 'https://en.wikipedia.org/wiki/The_Looming_Tower', NULL, NULL, '["Pulitzer Prize for General Nonfiction"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:48+00:00', '{"openlibrary": {"ol_key": "/works/OL193645W", "ol_cover_id": 8172445, "edition_count": 24, "languages": ["heb", "ger", "dut", "eng", "spa"], "subjects": ["Current Events", "September 11 Terrorist Attacks, 2001", "Qaida (Organization)", "Intelligence service", "Government policy", "Terrorism", "Large type books", "HISTORY / Modern / 20th Century", "POLITICAL SCIENCE / Intelligence & Espionage", "POLITICAL SCIENCE / Terrorism", "New York Times reviewed", "Intelligence service, united states"], "synopsis": "National Book Award FinalistA Time, Newsweek, Washington Post, Chicago Tribune, and New York Times Book Review Best Book of the YearA gripping narrative that spans five decades, The Looming Tower explains in unprecedented detail the growth of Islamic fundamentalism, the rise of al-Qaeda, and the intelligence failures that culminated in the attacks on the World Trade Center. Lawrence Wright re-creates firsthand the transformation of Osama bin Laden and Ayman al-Zawahiri from incompetent and idealistic soldiers in Afghanistan to leaders of the most successful terrorist group in history. He follows FBI counterterrorism chief John O''Neill as he uncovers the emerging danger from al-Qaeda in the 1990s and struggles to track this new threat. Packed with new information and a deep historical perspective, The Looming Tower is the definitive history of the long road to September 11.From the Trade Paperback edition.", "publication_year": 2006, "page_count": 550, "isbn13": "9780141029351", "ratings_average": 4.22, "ratings_count": 18}, "wikidata": {"wikidata_id": "Q7748388", "awards": ["Pulitzer Prize for General Nonfiction"], "series": null, "goodreads_id": null, "wikipedia_title": "The Looming Tower", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Looming_Tower"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (133, 6605927, 4, '["eng"]', 3.67, 9, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:53+00:00', '{"openlibrary": {"ol_key": "/works/OL6209302W", "ol_cover_id": 6605927, "edition_count": 4, "languages": ["eng"], "subjects": ["Automobile driving", "Psychological aspects of Automobile driving", "Traffic congestion", "Psychological aspects", "Sociology", "Transportation", "Conduite automobile", "Migrations alternantes", "Technique de la Circulation", "Verkehrspsychologie", "Circulation routière", "Traffic safety"], "synopsis": "A New York Times Notable BookOne of the Best Books of the YearThe Washington Post  - The Cleveland Plain-Dealer  - Rocky Mountain NewsIn this brilliant, lively, and eye-opening investigation, Tom Vanderbilt examines the perceptual limits and cognitive underpinnings that make us worse drivers than we think we are. He demonstrates why plans to protect pedestrians from cars often lead to more accidents. He uncovers who is more likely to honk at whom, and why. He explains why traffic jams form, outlines the unintended consequences of our quest for safety, and even identifies the most common mistake drivers make in parking lots. Traffic is about more than driving: it''s about human nature. It will change the way we see ourselves and the world around us, and it may even make us better drivers.From the Trade Paperback edition.", "publication_year": 2008, "page_count": 409, "isbn13": "9780307264787", "ratings_average": 3.67, "ratings_count": 9}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (134, 6402116, 17, '["eng"]', 3.74, 23, 'Q2004267', 'https://en.wikipedia.org/wiki/Nudge_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:55:57+00:00', '{"openlibrary": {"ol_key": "/works/OL3936258W", "ol_cover_id": 6402116, "edition_count": 17, "languages": ["eng"], "subjects": ["Business", "Choice (Psychology)", "Consumer behavior", "Decision making", "Economic aspects", "Economic aspects of Choice (Psychology)", "Economics", "Psychological aspects", "Psychological aspects of Decision making", "Psychological aspects of Economics", "autonomy", "decisions"], "synopsis": "Thaler and Sunstein develop libertarian paternalism as a middle path between command-and-control and strict-neutrality choice architectures.  Libertarian paternalism protects humans against their damaging psychological traits (inertia, bounded rationality, undue influence) by exploiting those habits to nudge people into making better choices.", "publication_year": 2008, "page_count": 312, "isbn13": "9780141040011", "ratings_average": 3.74, "ratings_count": 23}, "wikidata": {"wikidata_id": "Q2004267", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Nudge (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/Nudge_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (135, 1860706, 23, '["eng", "chi"]', 4.11, 9, 'Q4764731', 'https://en.wikipedia.org/wiki/Animal%2C_Vegetable%2C_Miracle', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:00+00:00', '{"openlibrary": {"ol_key": "/works/OL1846871W", "ol_cover_id": 1860706, "edition_count": 23, "languages": ["eng", "chi"], "subjects": ["Gardening", "Anecdotes", "Food habits", "Biography & Autobiography", "Country life", "Farm life", "Agriculture", "Alimentation", "Vie quotidienne", "Sud", "Document", "Farm life, united states"], "synopsis": "Bestselling author Barbara Kingsolver returns with her first nonfiction narrative that will open your eyes in a hundred new ways to an old truth: You are what you eat.\"As the U.S. population made an unprecedented mad dash for the Sun Belt, one carload of us paddled against the tide, heading for the Promised Land where water falls from the sky and green stuff grows all around. We were about to begin the adventure of realigning our lives with our food chain.\"Naturally, our first stop was to buy junk food and fossil fuel. . . .\"Hang on for the ride: With characteristic poetry and pluck, Barbara Kingsolver and her family sweep readers along on their journey away from the industrial-food pipeline to a rural life in which they vow to buy only food raised in their own neighborhood, grow it themselves, or learn to live without it. Their good-humored search yields surprising discoveries about turkey sex life and overly zealous zucchini plants, en route to a food culture that''s better for the neighborhood and also better on the table. Part memoir, part journalistic investigation, Animal, Vegetable, Miracle makes a passionate case for putting the kitchen back at the center of family life and diversified farms at the center of the American diet.\"This is the story of a year in which we made every attempt to feed ourselves animals and vegetables whose provenance we really knew . . . and of how our family was changed by our first year of deliberately eating food produced from the same place where we worked, went to school, loved our neighbors, drank the water, and breathed the air.\"", "publication_year": 2007, "page_count": 384, "isbn13": "9780062020062", "ratings_average": 4.11, "ratings_count": 9}, "wikidata": {"wikidata_id": "Q4764731", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Animal, Vegetable, Miracle", "wikipedia_url": "https://en.wikipedia.org/wiki/Animal%2C_Vegetable%2C_Miracle"}}');
