INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (138, 1153727, 7, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:09+00:00', '{"openlibrary": {"ol_key": "/works/OL9281256W", "ol_cover_id": 1153727, "edition_count": 7, "languages": ["eng"], "subjects": ["Video games", "Cheating at video games", "Video games industry", "Corrupt practices", "Moral and ethical aspects"], "synopsis": "\"In Cheating, Mia Consalvo investigates how players choose to play games and what happens when they can''t always play the way they''d like. She explores a broad range of player behavior, including cheating (alone and in groups); examines the varying ways that players and industry define cheating; describes how the game industry itself has helped systematize cheating; and studies online cheating in context in an online ethnography of Final Fantasy XI.\"--Jacket.", "publication_year": 2007, "page_count": 240, "isbn13": "9780262251211", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
