INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (140, 6981028, 22, '["aze", "spa", "eng", "ger", "chi"]', 4.38, 8, 'Q611356', 'https://en.wikipedia.org/wiki/The_World_Without_Us', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:15+00:00', '{"openlibrary": {"ol_key": "/works/OL2746364W", "ol_cover_id": 6981028, "edition_count": 22, "languages": ["aze", "spa", "eng", "ger", "chi"], "subjects": ["Human-plant relationships", "Efecto del ser humano sobre", "Nature", "Effect of human beings on", "Ecología", "Environmental degradation", "Aarde (planeet)", "Relaciones entre seres humanos y animales", "Naturaleza", "Mensheid", "Cultura material", "Het fictieve"], "synopsis": "The World Without Us, an intriguing peek inside the impact homo sapiens have on the world around us and what will be left when we cease to exist. Alan Weisman intelligently intertwines the affect we have on the Earth and its ecosystems and the way we have damaged it, the things nature can''t undo. A tremendous report on the ways we have killed the flora and fauna and how we will ultimately exterminate ourselves, bringing all that is left of human civilization with us. ~ Written by an 11 year old", "publication_year": 2007, "page_count": 348, "isbn13": "9781429917216", "ratings_average": 4.38, "ratings_count": 8}, "wikidata": {"wikidata_id": "Q611356", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The World Without Us", "wikipedia_url": "https://en.wikipedia.org/wiki/The_World_Without_Us"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (141, 4814439, 3, '["eng"]', 4.0, 7, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:17+00:00', '{"openlibrary": {"ol_key": "/works/OL2824008W", "ol_cover_id": 4814439, "edition_count": 3, "languages": ["eng"], "subjects": ["Visual communication", "Statistics", "Nonverbal Communication", "Visual Perception", "Communication (human)", "Communication visuelle", "Information", "Gebrauchsgrafik", "Illustration", "Semiotik", "Visualisierung", "Visuelle Kommunikation"], "synopsis": "Science and art have in common intense seeing, the wide-eyed observing that generates visual information. \r\nBeautiful Evidence is about how seeing turns into showing, how data and evidence turn into explanation. The book identifies excellent and effective methods for showing nearly every kind of information, suggests many new designs (including sparklines), and provides analytical tools for assessing the credibility of evidence presentations (which are seen from both sides: how to produce and how to consume presentations). \r\n\r\nFor alert consumers of presentations, there are chapters on diagnosing evidence corruption and PowerPoint pitches. Beautiful Evidence concludes with two chapters that leave the world of pixel and paper flatland representations - and move onto seeing and thinking in space land, the real-land of three-space and time.\r\n\r\nEdward Rolf Tufte (born 1942 in Kansas City, Missouri to Virginia and Edward E. Tufte), a professor emeritus of statistics, graphic design, and political economy at Yale University has been described by The New York Times as \"the Leonardo da Vinci of Data\". He is an expert in the presentation of informational graphics such as charts and diagrams, and is a fellow of the American Statistical Association. Tufte has held fellowships from the Guggenheim Foundation and the Center for Advanced Studies in Behavioral Sciences.\r\n\r\nTufte currently resides in Cheshire, Connecticut. He periodically travels around the United States to offer one-day workshops on data presentation and information graphics.  http://www.edwardtufte.com", "publication_year": 2006, "page_count": 213, "isbn13": "9781930824164", "ratings_average": 4.0, "ratings_count": 7}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (142, 9261340, 43, '["chi", "ita", "eng", "fre", "heb", "por", "tur", "spa", "ger", "jpn", "srp", "ara"]', 3.74, 23, 'Q1954977', 'https://en.wikipedia.org/wiki/Musicophilia', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:19+00:00', '{"openlibrary": {"ol_key": "/works/OL277255W", "ol_cover_id": 9261340, "edition_count": 43, "languages": ["chi", "ita", "eng", "fre", "heb", "por", "tur", "spa", "ger", "jpn", "srp", "ara"], "subjects": ["psychology", "Alzheimer’s disese", "amnesia", "Parkinson’s disease", "amusia", "Williams syndrome", "Musicophilia", "the brain", "the human experience", "medical", "neurology", "psychiatry"], "synopsis": "Music can move us to the heights or depths of emotion. It can persuade us to buy something, or remind us of our first date. It can lift us out of depression when nothing else can. It can get us dancing to its beat. But the power of music goes much, much further. Indeed, music occupies more areas of our brain than language does–humans are a musical species.\r\n\r\nOliver Sacks’s compassionate, compelling tales of people struggling to adapt to different neurological conditions have fundamentally changed the way we think of our own brains, and of the human experience. In Musicophilia, he examines the powers of music through the individual experiences of patients, musicians, and everyday people–from a man who is struck by lightning and suddenly inspired to become a pianist at the age of forty-two, to an entire group of children with Williams syndrome who are hypermusical from birth; from people with “amusia,” to whom a symphony sounds like the clattering of pots and pans, to a man whose memory spans only seven seconds–for everything but music.\r\n\r\nOur exquisite sensitivity to music can sometimes go wrong: Sacks explores how catchy tunes can subject us to hours of mental replay, and how a surprising number of people acquire nonstop musical hallucinations that assault them night and day. Yet far more frequently, music goes right: Sacks describes how music can animate people with Parkinson’s disease who cannot otherwise move, give words to stroke patients who cannot otherwise speak, and calm and organize people whose memories are ravaged by Alzheimer’s or amnesia.\r\n\r\nMusic is irresistible, haunting, and unforgettable, and in Musicophilia, Oliver Sacks tells us why.\r\n\r\n([source][1])\r\n\r\n\r\n  [1]: https://www.oliversacks.com/books-by-oliver-sacks/musicophilia/", "publication_year": 2007, "page_count": 425, "isbn13": "9781035068371", "ratings_average": 3.74, "ratings_count": 23}, "wikidata": {"wikidata_id": "Q1954977", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Musicophilia", "wikipedia_url": "https://en.wikipedia.org/wiki/Musicophilia"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (143, 2549298, 10, '["eng"]', 3.71, 7, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:23+00:00', '{"openlibrary": {"ol_key": "/works/OL4988033W", "ol_cover_id": 2549298, "edition_count": 10, "languages": ["eng"], "subjects": ["Containerization", "International economic integration", "International economic relations", "McLean, Malcolm Purcell,", "Containervervoer", "Businesspeople, biography", "North carolina, biography"], "synopsis": "In April 1956, a refitted oil tanker carried fifty-eight shipping containers from Newark to Houston. From that modest beginning, container shipping developed into a huge industry that made the boom in global trade possible. The Box tells the dramatic story of the container''s creation, the decade of struggle before it was widely adopted, and the sweeping economic consequences of the sharp fall in transportation costs that containerization brought about. Drawing on previously neglected sources, economist Marc Levinson shows how the container transformed economic geography, devastating traditional ports such as New York and London and fueling the growth of previously obscure ones, such as Oakland. By making shipping so cheap that industry could locate factories far from its customers, the container paved the way for Asia to become the world''s workshop and brought consumers a previously unimaginable variety of low-cost products from around the globe.--From publisher description.", "publication_year": 2006, "page_count": 395, "isbn13": "9780691170817", "ratings_average": 3.71, "ratings_count": 7}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (144, 8622062, 4, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:27+00:00', '{"openlibrary": {"ol_key": "/works/OL19396663W", "ol_cover_id": 8622062, "edition_count": 4, "languages": ["eng"], "subjects": ["Software engineering", "Computer programming"], "synopsis": "How do the experts solve difficult problems in software development? In this unique and insightful book, leading computer scientists offer case studies that reveal how they found unusual, carefully designed solutions to high-profile projects. You will be able to look over the shoulder of major coding and design experts to see problems through their eyes.\r\n\r\nThis is not simply another design patterns book, or another software engineering treatise on the right and wrong way to do things. The authors think aloud as they work through their project''s architecture, the tradeoffs made in its construction, and when it was important to break rules. Beautiful Code is an opportunity for master coders to tell their story. All author royalties will be donated to Amnesty International.", "publication_year": null, "page_count": null, "isbn13": "9780596515980", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (145, 7774899, 34, '["por", "ger", "eng", "fre", "spa"]', 4.48, 233, 'Q128444', 'https://en.wikipedia.org/wiki/Watchmen', NULL, NULL, '["NPR Top 100 Science Fiction and Fantasy Books", "Eisner Award for Best Limited Series"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:30+00:00', '{"openlibrary": {"ol_key": "/works/OL2897798W", "ol_cover_id": 7774899, "edition_count": 34, "languages": ["por", "ger", "eng", "fre", "spa"], "subjects": ["Watchmen (Comic strip)", "Graphic novels", "Comic books, strips", "New York Times bestseller", "nyt:paperback_graphic_books=2009-03-15", "Comics & graphic novels, science fiction", "Superheroes", "Crimes against", "Comics & graphic novels, superheroes", "Good and evil", "Bandes dessinées", "Comicroman"], "synopsis": "\"This book examines each of the series'' twelve issues in unprecedented detail, moving page by page and panel by panel to reveal the hidden foundations of this milestone in modern storytelling. Edited with notes by Leslie S. Klinger, this new edition draws upon critical and scholastic commentary, in-depth interviews with Dave Gibbons, and previously unseen original source material. Klinger provides the reader with a unique and comprehensive view of Watchmen as both a singular artistic achievement and a transformative event in the history of comics as a medium. Set in a world in which history has been forever altered by the existence of superheroes, Alan Moore and Dave Gibbons'' monumental graphic novel Watchmen is one of the most influential comic book series of all time. Following two generations of masked crime-fighters from the end of World War II to the height of the Cold War, this compelling tale unfolds from a simple murder mystery into an epic saga of power, corruption and the ultimate meaning of humanity. More than 30 years after it was first published, Moore and Gibbons'' masterpiece continues to inspire and entertain readers around the world. Named one of Time magazine''s 100 best English-language novels of the 20th century, Watchmen has won countless critical accolades and honors, including the Eisner Award and the Hugo Award\"--", "publication_year": 1987, "page_count": 424, "isbn13": "9780606357425", "ratings_average": 4.48, "ratings_count": 233}, "wikidata": {"wikidata_id": "Q128444", "awards": ["NPR Top 100 Science Fiction and Fantasy Books", "Eisner Award for Best Limited Series"], "series": null, "goodreads_id": null, "wikipedia_title": "Watchmen", "wikipedia_url": "https://en.wikipedia.org/wiki/Watchmen"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (146, 10679940, 19, '["fre", "ger", "eng", "spa"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:34+00:00', '{"openlibrary": {"ol_key": "/works/OL276032W", "ol_cover_id": 10679940, "edition_count": 19, "languages": ["fre", "ger", "eng", "spa"], "subjects": ["Illustrations", "Technique", "Cartooning", "Comics", "Comic Books", "Art", "Historietas", "Cartoon", "Manga", "Story", "Sequential", "Sequential art"], "synopsis": "Praised throughout the cartoon industry by such luminaries as Art Spiegelman, Matt Groening, and Will Eisner, Scott McCloud''s Understanding Comics is a seminal examination of comics art: its rich history, surprising technical components, and major cultural significance. Explore the secret world between the panels, through the lines, and within the hidden symbols of a powerful but misunderstood art form.", "publication_year": null, "page_count": null, "isbn13": "9781563897597", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (147, 6915361, 11, '["chi", "eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:39+00:00', '{"openlibrary": {"ol_key": "/works/OL3510570W", "ol_cover_id": 6915361, "edition_count": 11, "languages": ["chi", "eng"], "subjects": ["Computer programming management", "Addresses, essays, lectures", "Software engineering", "Electronic digital computers", "Programming", "Computer programming", "MULTICS", "Technologie logiciel", "Gestion projet", "Programmation (Informatique)", "Gestion", "Système exploitation 360"], "synopsis": "Classic text on the human side of software engineering, containing essays on the management of software teams, projections about how computer languages and tools will evolve, and philosophical speculation. Unlike most other books about computing, Brooks'' work has been remarkably enduring, remaining in print for at least four decades. The book is most famous for its statement of Brooks'' Law: \"adding manpower to a late software project makes it later\".", "publication_year": null, "page_count": null, "isbn13": "9780201835953", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (148, 11419815, 5, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:42+00:00', '{"openlibrary": {"ol_key": "/works/OL21562807W", "ol_cover_id": 11419815, "edition_count": 5, "languages": ["eng"], "subjects": ["Religious life, buddhism", "Happiness", "Buddhism"], "synopsis": "\"In his ... book, Buddhist monk Matthieu Ricard shows that happiness is not just an emotion, but a skill that can be developed. Free of jargon, Happiness contains simple exercises that will train the mind to recognize and pursue happiness by concentrating on the fundamental things in life, and in doing so change the way we view the world\"-- Back cover.", "publication_year": 2007, "page_count": 291, "isbn13": "9780316376532", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (149, 894367, 22, '["eng", "chi", "fre", "dut", "spa"]', 4.0, 10, 'Q16962717', 'https://en.wikipedia.org/wiki/The_Long_Tail_%28book%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:45+00:00', '{"openlibrary": {"ol_key": "/works/OL4091759W", "ol_cover_id": 894367, "edition_count": 22, "languages": ["eng", "chi", "fre", "dut", "spa"], "subjects": ["Commerce électronique", "Nachfrage", "Electronic commerce", "Marketing", "Angebot", "Innovations technologiques", "Wirtschaftstheorie", "Demande de consommation", "Internet", "Marktforschung", "Telemarketing", "Market segmentation"], "synopsis": "The New York Times bestseller that introduced the business world to a future that’s already here—now in a new edition with a new chapter about Long Tail Marketing and a new epilogue.Winner of the Gerald Loeb Award for Best Business Book of the YearIn the most important business book since The Tipping Point, Chris Anderson shows how the future of commerce and culture isn’t in hits, the high-volume head of a traditional demand curve, but in what used to be regarded as misses—the endlessly long tail of that same curve.", "publication_year": 2006, "page_count": 238, "isbn13": "9781401302375", "ratings_average": 4.0, "ratings_count": 10}, "wikidata": {"wikidata_id": "Q16962717", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Long Tail (book)", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Long_Tail_%28book%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (150, 198120, 69, '["por", "eng", "spa", "pol", "fre", "heb", "chi", "cat", "ita"]', 3.88, 170, 'Q1140295', 'https://en.wikipedia.org/wiki/The_Road', NULL, NULL, '["Ignotus Award for Best Foreign Novel", "NPR Top 100 Science Fiction and Fantasy Books", "Pulitzer Prize for Fiction", "James Tait Black Memorial Prize", "Believer Book Award", "Oprah''s Book Club", "Tähtivaeltaja Award"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:50+00:00', '{"openlibrary": {"ol_key": "/works/OL40873W", "ol_cover_id": 198120, "edition_count": 69, "languages": ["por", "eng", "spa", "pol", "fre", "heb", "chi", "cat", "ita"], "subjects": ["Dystopia", "Adventure", "post-apocalyptic fiction", "extinction event", "Fathers and sons", "Survival skills", "Regression (Civilization)", "Voyages and travels", "literary fiction", "Robinsonades", "Apocalyptic fiction", "Novels"], "synopsis": "Cormac McCarthy''s tenth novel, The Road, is his most harrowing yet deeply personal work. Some unnamed catastrophe has scourged the world to a burnt-out cinder, inhabited by the last remnants of mankind and a very few surviving dogs and fungi. The sky is perpetually shrouded by dust and toxic particulates; the seasons are merely varied intensities of cold and dampness. Bands of cannibals roam the roads and inhabit what few dwellings remain intact in the woods.\r\n\r\nThrough this nightmarish residue of America a haggard father and his young son attempt to flee the oncoming Appalachian winter and head towards the southern coast along carefully chosen back roads. Mummified corpses are their only benign companions, sitting in doorways and automobiles, variously impaled or displayed on pikes and tables and in cake bells, or they rise in frozen poses of horror and agony out of congealed asphalt. The boy and his father hope to avoid the marauders, reach a milder climate, and perhaps locate some remnants of civilization still worthy of that name. They possess only what they can scavenge to eat, and the rags they wear and the heat of their own bodies are all the shelter they have. A pistol with only a few bullets is their only defense besides flight. Before them the father pushes a shopping cart filled with blankets, cans of food and a few other assets, like jars of lamp oil or gasoline siphoned from the tanks of abandoned vehicles—the cart is equipped with a bicycle mirror so that they will not be surprised from behind.\r\n\r\nThrough encounters with other survivors brutal, desperate or pathetic, the father and son are both hardened and sustained by their will, their hard-won survivalist savvy, and most of all by their love for each other. They struggle over mountains, navigate perilous roads and forests reduced to ash and cinders, endure killing cold and freezing rainfall. Passing through charred ghost towns and ransacking abandoned markets for meager provisions, the pair battle to remain hopeful. They seek the most rudimentary sort of salvation. However, in The Road, such redemption as might be permitted by their circumstances depends on the boy’s ability to sustain his own instincts for compassion and empathy in opposition to his father’s insistence upon their mutual self-interest and survival at all physical and moral costs.\r\n\r\nThe Road was the winner of the 2006 Pulitzer Prize for Literature.\r\n([source][1])\r\n\r\n\r\n  [1]: https://www.cormacmccarthy.com/works/the-road/", "publication_year": 2006, "page_count": 287, "isbn13": "9780330447539", "ratings_average": 3.88, "ratings_count": 170}, "wikidata": {"wikidata_id": "Q1140295", "awards": ["Ignotus Award for Best Foreign Novel", "NPR Top 100 Science Fiction and Fantasy Books", "Pulitzer Prize for Fiction", "James Tait Black Memorial Prize", "Believer Book Award", "Oprah''s Book Club", "Tähtivaeltaja Award"], "series": null, "goodreads_id": null, "wikipedia_title": "The Road", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Road"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (151, 8596706, 1, '["eng"]', 4.18, 45, 'Q3222320', 'https://en.wikipedia.org/wiki/The_Omnivore%27s_Dilemma', NULL, NULL, NULL, NULL, NULL, NULL, 450, NULL, NULL, '2026-06-26T14:56:54+00:00', '{"openlibrary": {"ol_key": "/works/OL28339036W", "ol_cover_id": 8596706, "edition_count": 1, "languages": ["eng"], "subjects": ["hunting", "foodies", "feral pigs", "wild mushrooms", "abalone", "salads", "leaf vegetables", "sourdough", "wild yeast", "cherries", "Whole Foods Market", "omnivores"], "synopsis": null, "publication_year": 2006, "page_count": 450, "isbn13": "9781504044844", "ratings_average": 4.18, "ratings_count": 45}, "wikidata": {"wikidata_id": "Q3222320", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Omnivore''s Dilemma", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Omnivore%27s_Dilemma"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (152, 6803663, 12, '["eng"]', 3.92, 12, 'Q2509382', 'https://en.wikipedia.org/wiki/Stumbling_on_Happiness', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:57+00:00', '{"openlibrary": {"ol_key": "/works/OL15840192W", "ol_cover_id": 6803663, "edition_count": 12, "languages": ["eng"], "subjects": ["Happiness", "Psychology", "Self realization", "Self-Improvement", "New York Times reviewed", "Imagination", "Interpersonal relations", "Bonheur", "Geluk", "Contentment", "Forecasting", "Psychological aspects"], "synopsis": "A smart and funny book by a prominent Harvard psychologist, which uses groundbreaking research and (often hilarious) anecdotes to show us why we''re so lousy at predicting what will make us happy -- and what we can do about it.Most of us spend our lives steering ourselves toward the best of all possible futures, only to find that tomorrow rarely turns out as we had expected. Why? As Harvard psychologist Daniel Gilbert explains, when people try to imagine what the future will hold, they make some basic and consistent mistakes. Just as memory plays tricks on us when we try to look backward in time, so does imagination play tricks when we try to look forward. Using cutting-edge research, much of it original, Gilbert shakes, cajoles, persuades, tricks and jokes us into accepting the fact that happiness is not really what or where we thought it was. Among the unexpected questions he poses: Why are conjoined twins no less happy than the general population? When you go out to eat, is it better to order your favourite dish every time, or to try something new? If Ingrid Bergman hadn''t gotten on the plane at the end of Casablanca, would she and Bogey have been better off?Smart, witty, accessible and laugh-out-loud funny, Stumbling on Happiness brilliantly describes all that science has to tell us about the uniquely human ability to envision the future, and how likely we are to enjoy it when we get there.From the Hardcover edition.", "publication_year": 2006, "page_count": 310, "isbn13": "9780676978582", "ratings_average": 3.92, "ratings_count": 12}, "wikidata": {"wikidata_id": "Q2509382", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Stumbling on Happiness", "wikipedia_url": "https://en.wikipedia.org/wiki/Stumbling_on_Happiness"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (153, 390818, 6, '["eng"]', 4.0, 11, 'Q5533147', 'https://en.wikipedia.org/wiki/Genghis_Khan_and_the_Making_of_the_Modern_World', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:56:59+00:00', '{"openlibrary": {"ol_key": "/works/OL8162628W", "ol_cover_id": 390818, "edition_count": 6, "languages": ["eng"], "subjects": ["Biography & Autobiography", "Mongols", "Kings and rulers", "Biography", "nyt:combined-print-and-e-book-nonfiction=2014-10-12", "New York Times bestseller", "Long Now Manual for Civilization"], "synopsis": "The name Genghis Khan often conjures the image of a relentless, bloodthirsty barbarian on horseback leading a ruthless band of nomadic warriors in the looting of the civilized world. But the surprising truth is that Genghis Khan was a visionary leader whose conquests joined backward Europe with the flourishing cultures of Asia to trigger a global awakening, an unprecedented explosion of technologies, trade, and ideas. In Genghis Khan and the Making of the Modern World, Jack Weatherford, the only Western scholar ever to be allowed into the Mongols'' \"Great Taboo\"--Genghis Khan''s homeland and forbidden burial site--tracks the astonishing story of Genghis Khan and his descendants, and their conquest and transformation of the world.  Fighting his way to power on the remote steppes of Mongolia, Genghis Khan developed revolutionary military strategies and weaponry that emphasized rapid attack and siege warfare, which he then brilliantly used to overwhelm opposing armies in Asia, break the back of the Islamic world, and render the armored knights of Europe obsolete. Under Genghis Khan, the Mongol army never numbered more than 100,000 warriors, yet it subjugated more lands and people in twenty-five years than the Romans conquered in four hundred. With an empire that stretched from Siberia to India, from Vietnam to Hungary, and from Korea to the Balkans, the Mongols dramatically redrew the map of the globe, connecting disparate kingdoms into a new world order.  But contrary to popular wisdom, Weatherford reveals that the Mongols were not just masters of conquest, but possessed a genius for progressive and benevolent rule. On every level and from any perspective, the scale and scope of Genghis Khan''s accomplishments challenge the limits of imagination. Genghis Khan was an innovative leader, the first ruler in many conquered countries to put the power of law above his own power, encourage religious freedom, create public schools, grant diplomatic immunity, abolish torture, and institute free trade. The trade routes he created became lucrative pathways for commerce, but also for ideas, technologies, and expertise that transformed the way people lived. The Mongols introduced the first international paper currency and postal system and developed and spread revolutionary technologies like printing, the cannon, compass, and abacus. They took local foods and products like lemons, carrots, noodles, tea, rugs, playing cards, and pants and turned them into staples of life around the world. The Mongols were the architects of a new way of life at a pivotal time in history.  In Genghis Khan and the Making of the Modern World, Jack Weatherford resurrects the true history of Genghis Khan, from the story of his relentless rise through Mongol tribal culture to the waging of his devastatingly successful wars and the explosion of civilization that the Mongol Empire unleashed. This dazzling work of revisionist history doesn''t just paint an unprecedented portrait of a great leader and his legacy, but challenges us to reconsider how the modern world was made.From the Hardcover edition.", "publication_year": 2004, "page_count": 352, "isbn13": "9781491513705", "ratings_average": 4.0, "ratings_count": 11}, "wikidata": {"wikidata_id": "Q5533147", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Genghis Khan and the Making of the Modern World", "wikipedia_url": "https://en.wikipedia.org/wiki/Genghis_Khan_and_the_Making_of_the_Modern_World"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (154, 426348, 6, '["eng"]', 4.67, 3, 'Q4845526', 'https://en.wikipedia.org/wiki/Bowling_Alone', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:01+00:00', '{"openlibrary": {"ol_key": "/works/OL4291077W", "ol_cover_id": 426348, "edition_count": 6, "languages": ["eng"], "subjects": ["Social conditions", "Social change", "Isolation <Soziologie>", "Conditions sociales", "Histoire", "Changement social", "Mudança social (história;século 20)", "Sozialer Wandel", "Participation sociale", "Estrutura social (século 20)", "Community life", "Social isolation"], "synopsis": "\"Updated to include a new chapter about the influence of social media and the Internet—the 20th anniversary edition of Bowling Alone remains a seminal work of social analysis, and its examination of what happened to our sense of community remains more relevant than ever in today’s fractured America. Twenty years, ago, Robert Putnam made a seemingly simple observation: once we bowled in leagues, usually after work; but no longer. This seemingly small phenomenon symbolized a significant social change that became the basis of the acclaimed bestseller, Bowling Alone, which The Washington Post called “a very important book” and Putnam, “the de Tocqueville of our generation.” Bowling Alone surveyed in detail Americans’ changing behavior over the decades, showing how we had become increasingly disconnected from family, friends, neighbors, and social structures, whether it’s with the PTA, church, clubs, political parties, or bowling leagues. In the revised edition of his classic work, Putnam shows how our shrinking access to the “social capital” that is the reward of communal activity and community sharing still poses a serious threat to our civic and personal health, and how these consequences have a new resonance for our divided country today. He includes critical new material on the pervasive influence of social media and the internet, which has introduced previously unthinkable opportunities for social connection—as well as unprecedented levels of alienation and isolation. At the time of its publication, Putnam’s then-groundbreaking work showed how social bonds are the most powerful predictor of life satisfaction, and how the loss of social capital is felt in critical ways, acting as a strong predictor of crime rates and other measures of neighborhood quality of life, and affecting our health in other ways. While the ways in which we connect, or become disconnected, have changed over the decades, his central argument remains as powerful and urgent as ever: mending our frayed social capital is key to preserving the very fabric of our society\"--Simon & Schuster.", "publication_year": 2000, "page_count": 544, "isbn13": "9781982130848", "ratings_average": 4.67, "ratings_count": 3}, "wikidata": {"wikidata_id": "Q4845526", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Bowling Alone", "wikipedia_url": "https://en.wikipedia.org/wiki/Bowling_Alone"}}');
