INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (159, 866090, 3, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:17+00:00', '{"openlibrary": {"ol_key": "/works/OL8982019W", "ol_cover_id": 866090, "edition_count": 3, "languages": ["eng"], "subjects": ["Internet industry", "Internet", "Entwicklung", "Recherche sur Internet", "Google (Firme)", "Information society", "Industrie", "Business", "Google (Firm)", "Computer Technology", "World Wide Web", "Biographies"], "synopsis": "How Google and Its Rivals Rewrote the Rules of Business and Transformed Our Culture• The Wall Street Journal and BusinessWeek Bestseller• Finalist for the Goldman Sachs/FT Business Book of the Year AwardWhat does the world want? According to John Battelle, a company that answers that question—in all its shades of meaning—can unlock the most intractable riddles of business and arguably of human culture itself. And for the past few years, that''s exactly what Google has been doing.But The Search offers much more than the inside story of Google''s triumph. It''s a big- picture book about the past, present, and future of search technology and the enormous impact it''s starting to have on marketing, media, pop culture, dating, job hunting, international law, civil liberties, and just about every other sphere of human interest.", "publication_year": 2005, "page_count": 324, "isbn13": "9781429514811", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (160, 440085, 1, '["eng"]', NULL, NULL, 'Q7727217', 'https://en.wikipedia.org/wiki/The_Complexity_of_Cooperation', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '9780691015675', NULL, '2026-06-26T14:57:19+00:00', '{"openlibrary": {"ol_key": "/works/OL2620281W", "ol_cover_id": 440085, "edition_count": 1, "languages": ["eng"], "subjects": ["Computational complexity", "Social systems", "Adaptability (Psychology)", "Conflict management", "Competition", "Adjustment (Psychology)", "Computer simulation", "Cooperativeness"], "synopsis": null, "publication_year": 1997, "page_count": 232, "isbn13": "9780691015675", "ratings_average": null, "ratings_count": null}, "wikidata": {"wikidata_id": "Q7727217", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Complexity of Cooperation", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Complexity_of_Cooperation"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (161, 11172914, 63, '["eng", "spa", "por"]', 3.88, 184, 'Q1211497', 'https://en.wikipedia.org/wiki/Freakonomics', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:22+00:00', '{"openlibrary": {"ol_key": "/works/OL278022W", "ol_cover_id": 11172914, "edition_count": 63, "languages": ["eng", "spa", "por"], "subjects": ["Economics", "Economics -- Psychological aspects", "Economics -- Sociological aspects", "Finance", "Sociology", "nyt:paperback_business_books=2012-02-25", "New York Times bestseller", "Popular Culture", "business & economics", "social science", "economics theory", "psychology"], "synopsis": "*A Rogue Economist Explores the Hidden Side of Everything*\r\n\r\nWhich is more dangerous, a gun or a swimming pool? What do schoolteachers and sumo wrestlers have in common? Why do drug dealers still live with their moms? How much do parents really matter? How did the legalization of abortion affect the rate of violent crime?\r\n\r\nThese may not sound like typical questions for an economist to ask. But Steven D. Levitt is not a typical economist. He is a much-heralded scholar who studies the riddles of everyday life—from cheating and crime to sports and child-rearing—and whose conclusions turn the conventional wisdom on its head.\r\n\r\nFreakonomics is a ground-breaking collaboration between Levitt and Stephen J. Dubner, an award-winning author and journalist. They usually begin with a mountain of data and a simple, unasked question. Some of these questions concern life-and-death issues; others have an admittedly freakish quality. Thus the new field of study contained in this book: Freakonomics.\r\n\r\nThrough forceful storytelling and wry insight, Levitt and Dubner show that economics is, at root, the study of incentives—how people get what they want, or need, especially when other people want or need the same thing. In Freakonomics, they explore the hidden side of … well, everything. The inner workings of a crack gang. The truth about real-estate agents. The myths of campaign finance. The telltale marks of a cheating schoolteacher. The secrets of the Ku Klux Klan.\r\n\r\nWhat unites all these stories is a belief that the modern world, despite a great deal of complexity and downright deceit, is not impenetrable, is not unknowable, and—if the right questions are asked—is even more intriguing than we think. All it takes is a new way of looking at things.\r\n\r\nFreakonomics establishes this unconventional premise: If morality represents how we would like the world to work, then economics represents how it actually does work. It is true that readers of this book will be armed with enough riddles and stories to last a thousand cocktail parties. ButFreakonomics can provide more than that. It will literally redefine the way we view the modern world.\r\n\r\nFirst published in the U.S. in 2005, Freakonomics went on to sell more than 4 million copies around the world, in 35 languages. It also inspired a follow-up book, SuperFreakonomics; a high-profile documentary film; a radio program, and an award-winning blog, which has been called “the most readable economics blog in the universe.”\r\n\r\n([source][1])\r\n\r\n\r\n  [1]: http://freakonomics.com/books/", "publication_year": 2005, "page_count": 320, "isbn13": "9781554686360", "ratings_average": 3.88, "ratings_count": 184}, "wikidata": {"wikidata_id": "Q1211497", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Freakonomics", "wikipedia_url": "https://en.wikipedia.org/wiki/Freakonomics"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (162, 8349176, 43, '["heb", "spa", "eng", "fre", "por", "ger", "ita"]', 3.93, 43, 'Q1758811', 'https://en.wikipedia.org/wiki/The_Plot_Against_America', NULL, NULL, '["Society of American Historians Prize for Historical Fiction", "Sidewise Award for Alternate History"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:25+00:00', '{"openlibrary": {"ol_key": "/works/OL74664W", "ol_cover_id": 8349176, "edition_count": 43, "languages": ["heb", "spa", "eng", "fre", "por", "ger", "ita"], "subjects": ["American Historical Fiction", "Roth, Philip - Prose & Criticism", "Fiction - General", "Spanish: Adult Fiction", "Historical - General", "Political", "Elección", "Alternative histories (Fiction)", "Jews", "Presidentes", "Political fiction", "Presidents"], "synopsis": "The Plot Against America is a novel by Philip Roth published in 2004. It is an alternative history in which Franklin D. Roosevelt is defeated in the presidential election of 1940 by Charles Lindbergh. The novel follows the fortunes of the Roth family during the Lindbergh presidency, as antisemitism becomes more accepted in American life and Jewish-American families like the Roths are persecuted on various levels. The narrator and central character in the novel is the young Philip, and the care with which his confusion and terror are rendered makes the novel as much about the mysteries of growing up as about American politics. Roth based his novel on the isolationist ideas espoused by Lindbergh in real life as a spokesman for the America First Committee, and on his own experiences growing up in Newark, New Jersey. The novel received praise for the realism of its world and its treatment of topics such as antisemitism, trauma, and the perception of history. The novel depicts the Weequahic section of Newark which includes Weequahic High School from which Roth graduated.\r\n\r\nIn 2005, the novel won the James Fenimore Cooper Prize for Best Historical Fiction given by the Society of American Historians. It won the Sidewise Award for Alternate History, was a finalist for the John W. Campbell Memorial Award, and came in 11th for the 2005 Locus Awards.", "publication_year": 2004, "page_count": 400, "isbn13": "9781784703097", "ratings_average": 3.93, "ratings_count": 43}, "wikidata": {"wikidata_id": "Q1758811", "awards": ["Society of American Historians Prize for Historical Fiction", "Sidewise Award for Alternate History"], "series": null, "goodreads_id": null, "wikipedia_title": "The Plot Against America", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Plot_Against_America"}}');
