INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (166, 227791, 6, '["eng"]', 4.0, 3, 'Q138561847', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:34+00:00', '{"openlibrary": {"ol_key": "/works/OL108869W", "ol_cover_id": 227791, "edition_count": 6, "languages": ["eng"], "subjects": ["Poetry (poetic works by one author)", "New York Times reviewed", "Poetry"], "synopsis": "Offers a collection of witty, emotional, and direct poems by the popular and critically acclaimed poet, including selections from his four previous collections and new works such as \"Man Listening to a Disc,\" about headphones.", "publication_year": 2001, "page_count": 171, "isbn13": "9781588360953", "ratings_average": 4.0, "ratings_count": 3}, "wikidata": {"wikidata_id": "Q138561847", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": null, "wikipedia_url": null}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (167, 20382, 11, '["eng"]', 3.82, 11, 'Q7756070', 'https://en.wikipedia.org/wiki/The_Paradox_of_Choice', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:37+00:00', '{"openlibrary": {"ol_key": "/works/OL272375W", "ol_cover_id": 20382, "edition_count": 11, "languages": ["eng"], "subjects": ["Psychology", "Sociology", "Choice (psychology)", "Decision making", "Choice Behavior", "Wahlmöglichkeit", "Overvloed", "Entscheidungsfindung", "Keuzegedrag", "Entscheidung"], "synopsis": "In the spirit of [Alvin Toffler](/authors/OL433058A)’s [*Future Shock*](/works/OL2869043W), a social critique of our obsession with choice, and how it contributes to anxiety, dissatisfaction and regret. This paperback includes a new P.S. section with author interviews, insights, features, suggested readings, and more.Whether we’re buying a pair of jeans, ordering a cup of coffee, selecting a long-distance carrier, applying to college, choosing a doctor, or setting up a 401(k), everyday decisions--both big and small--have become increasingly complex due to the overwhelming abundance of choice with which we are presented.We assume that more choice means better options and greater satisfaction. But beware of excessive choice: choice overload can make you question the decisions you make before you even make them, it can set you up for unrealistically high expectations, and it can make you blame yourself for any and all failures. In the long run, this can lead to decision-making paralysis, anxiety, and perpetual stress. And, in a culture that tells us that there is no excuse for falling short of perfection when your options are limitless, too much choice can lead to clinical depression.In The Paradox of Choice, Barry Schwartz explains at what point choice--the hallmark of individual freedom and self-determination that we so cherish--becomes detrimental to our psychological and emotional well-being. In accessible, engaging, and anecdotal prose, Schwartz shows how the dramatic explosion in choice--from the mundane to the profound challenges of balancing career, family, and individual needs--has paradoxically become a problem instead of a solution. Schwartz also shows how our obsession with choice encourages us to seek that which makes us feel worse.By synthesizing current research in the social sciences, Schwartz makes the counterintuitive case that eliminating choices can greatly reduce the stress, anxiety, and busyness of our lives. He offers eleven practical steps on how to limit choices to a manageable number, have the discipline to focus on the important ones and ignore the rest, and ultimately derive greater satisfaction from the choices you have to make.", "publication_year": 2004, "page_count": 269, "isbn13": "9780061461545", "ratings_average": 3.82, "ratings_count": 11}, "wikidata": {"wikidata_id": "Q7756070", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Paradox of Choice", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Paradox_of_Choice"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (168, 37122, 32, '["spa", "tur", "dut", "ger", "ita", "rus", "eng", "jpn", "fre", "chi"]', 3.0, 4, 'Q708490', 'https://en.wikipedia.org/wiki/When_We_Were_Orphans', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:40+00:00', '{"openlibrary": {"ol_key": "/works/OL59042W", "ol_cover_id": 37122, "edition_count": 32, "languages": ["spa", "tur", "dut", "ger", "ita", "rus", "eng", "jpn", "fre", "chi"], "subjects": ["Private investigators", "Missing persons", "Death", "British", "Parents", "Psychological fiction", "Psychology", "Orphans", "Detective and mystery stories", "Detectives", "Psychological aspects", "Social life and customs"], "synopsis": "''You seldom read a novel that so convinces you it is extending the possibilities of fiction.'' Sunday TimesEngland, 1930s. Christopher Banks has become the country''s most celebrated detective, his cases the talk of London society. Yet one unsolved crime has always haunted him: the mysterious disappearance of his parents, in old Shanghai, when he was a small boy. Moving between London and Shanghai of the inter-war years, When We Were Orphans is a remarkable story of memory, intrigue and the need to return.", "publication_year": 2000, "page_count": 348, "isbn13": "9780571225408", "ratings_average": 3.0, "ratings_count": 4}, "wikidata": {"wikidata_id": "Q708490", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "When We Were Orphans", "wikipedia_url": "https://en.wikipedia.org/wiki/When_We_Were_Orphans"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (169, 213263, 10, '["eng"]', 3.83, 6, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:44+00:00', '{"openlibrary": {"ol_key": "/works/OL8036447W", "ol_cover_id": 213263, "edition_count": 10, "languages": ["eng"], "subjects": ["Sociology", "Common good", "Business", "Group decision making", "Consensus (Social sciences)", "Large type books", "New York Times reviewed", "Group Processes", "Consensus", "Decision Making", "Problem Solving", "Gemeinwohl"], "synopsis": "In this fascinating book, New Yorker business columnist James Surowiecki explores a deceptively simple idea: Large groups of people are smarter than an elite few, no matter how brilliant — better at solving problems, fostering innovation, coming to wise decisions, even predicting the future. \r\n\r\nSurowiecki ranges across fields as diverse as popular culture, psychology, ant biology, behavioral economics, artificial intelligence, military history, and politics to show how this simple idea offers important lessons for how we live our lives, select our leaders, run our companies, and think about our world.\r\n\r\nThe story is told of the first observations of this effect, through to anecdotes of the effect in modern economics and psychology. The book not heavy on statistics, and has prompted much research since its publication.\r\n\r\nThe title is an allusion to the famous phrase, the \"madness of crowds\".", "publication_year": 2004, "page_count": 328, "isbn13": "9780385721707", "ratings_average": 3.83, "ratings_count": 6}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (170, 30543, 20, '["eng", "spa"]', 3.67, 3, 'Q23306083', 'https://en.wikipedia.org/wiki/Over_the_Edge_of_the_World', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:47+00:00', '{"openlibrary": {"ol_key": "/works/OL2655768W", "ol_cover_id": 30543, "edition_count": 20, "languages": ["eng", "spa"], "subjects": ["Primera circunnavegación", "Expedición Magallanes-Elcano", "Biografías", "1520-1529", "Travel", "Jordomsejlinger", "Voyages around the world", "Opdagelsesrejser", "Explorers", "Biography", "1510-1519", "New York Times reviewed"], "synopsis": null, "publication_year": 2003, "page_count": 480, "isbn13": "9780062890481", "ratings_average": 3.67, "ratings_count": 3}, "wikidata": {"wikidata_id": "Q23306083", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Over the Edge of the World", "wikipedia_url": "https://en.wikipedia.org/wiki/Over_the_Edge_of_the_World"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (171, 417905, 11, '["eng"]', 4.0, 11, 'Q1971599', 'https://en.wikipedia.org/wiki/Pompeii_%28novel%29', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:51+00:00', '{"openlibrary": {"ol_key": "/works/OL4297223W", "ol_cover_id": 417905, "edition_count": 11, "languages": ["eng"], "subjects": ["Pompeji", "Italien", "Vulkaner", "1-99", "Naturkatastrofer"], "synopsis": "Historical fiction about the eruption of Mount Vesuvius in 79 AD from the perspective of Marcus Attilius, an *aquarius* (hydraulic engineer) responsible for Aqua Augusta, the regional aqueduct.", "publication_year": 2003, "page_count": 351, "isbn13": "9780345475671", "ratings_average": 4.0, "ratings_count": 11}, "wikidata": {"wikidata_id": "Q1971599", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "Pompeii (novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Pompeii_%28novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (172, 8347528, 18, '["eng", "ger"]', 4.0, 31, 'Q4398917', 'https://en.wikipedia.org/wiki/Quicksilver_%28Stephenson_novel%29', NULL, 'The Baroque Cycle', '["Arthur C. Clarke Award"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:56+00:00', '{"openlibrary": {"ol_key": "/works/OL38495W", "ol_cover_id": 8347528, "edition_count": 18, "languages": ["eng", "ger"], "subjects": ["Scientists", "Adventure stories", "Alchemists", "Puritans", "Adventure and adventurers", "Historical Fiction", "Rogues and vagabonds", "adventure fiction", "Fiction, historical", "Scientists, fiction", "Fiction, historical, general", "Fiction, technological"], "synopsis": "Volume One of The Baroque Cycle \r\n(Not to be confused with [Quicksilver: The Baroque Cycle #1](https://openlibrary.org/works/OL18199543W/Quicksilver))\r\n\r\nQuicksilver is a massive, exuberant and wildly ambitious historical novel that''s also Neal Stephenson''s eagerly awaited prequel to Cryptonomicon--his pyrotechnic reworking of the 20th century, from World War II codebreaking and disinformation to the latest issues of Internet data privacy.\r\n\r\nQuicksilver, \"Volume One of the Baroque Cycle\", backtracks to another time of high intellectual ferment: the late 17th century, with the natural philosophers of England''s newly formed Royal Society questioning the universe and dissecting everything that moves. One founding member, the Rev John Wilkins, really did write science fiction and a book on cryptography--but this isn''t history as we know it, for here his code book is called not Mercury but Cryptonomicon. And although the key political schemers of Charles II''s government still have initials spelling the word CABAL, their names are all different...\r\n\r\nWhile towering geniuses like Newton and Leibniz decode nature itself, bizarre adventures (merely beginning with the Great Plague and Great Fire) happen to the fictional Royal Society member Daniel Waterhouse, who knows everyone but isn''t quite bright enough for cutting-edge science. Two generations of Daniel''s family appear in Cryptonomicon, as does a descendant of the Shaftoes who here are soldiers and vagabonds. Other links include the island realm of Qwghlm with its impossible language and the mysterious, seemingly ageless alchemist Enoch Root.\r\n\r\nAs the reign of Charles II gives way to that of James II and then William of Orange, Stephenson traces the complex lines of finance and power that form the 17th-century Internet. Gold and silver, lead and (repeatedly) mercury or quicksilver flow in glittering patterns between centres of marketing and intrigue in England, Germany, France and Holland. Paper flows as well: stocks, shares, scams and letters holding layers of concealed code messages. Binary code? Yes, even that had already been invented and described by Francis Bacon.\r\n\r\nQuicksilver is crammed with unexpected incidents, fascinating digressions and deep-laid plots. Who''d believe that Eliza, a Qwghlmian slave girl liberated from a Turkish harem by mad Jack Shaftoe (King of the Vagabonds) could become a major player in European finance and politics? Still less believable, but all too historically authentic, are the appalling medical procedures of the time--about which we learn a lot. There are frequent passages of high comedy, like the lengthy description of a foppish earl''s costume which memorably explains that someone seemed to have been painted in glue before \"shaking and rolling him in a bin containing thousands of black silk doilies\".\r\n\r\nThis is a huge, exhausting read, full of rewards and quirky insights that no other author could have created. Fantastic or farcical episodes sometimes clash strangely with the deep cruelty and suffering of 17th-century realism. Recommended, though not to the faint-hearted.\r\n\r\n\r\n----------\r\n\r\n\r\nBook One: [Quicksilver](https://openlibrary.org/works/OL18199543W/Quicksilver)\r\nBook Two: [King of the Vagabonds](https://openlibrary.org/works/OL38479W/King_of_the_Vagabonds)\r\nBook Three: [Odalisque](https://openlibrary.org/works/OL38481W/Odalisque)", "publication_year": 2003, "page_count": 936, "isbn13": "9780099410683", "ratings_average": 4.0, "ratings_count": 31}, "wikidata": {"wikidata_id": "Q4398917", "awards": ["Arthur C. Clarke Award"], "series": "The Baroque Cycle", "goodreads_id": null, "wikipedia_title": "Quicksilver (Stephenson novel)", "wikipedia_url": "https://en.wikipedia.org/wiki/Quicksilver_%28Stephenson_novel%29"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (173, 100207, 24, '["heb", "spa", "eng"]', 4.25, 8, 'Q2453618', 'https://en.wikipedia.org/wiki/The_Blank_Slate', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:57:58+00:00', '{"openlibrary": {"ol_key": "/works/OL477826W", "ol_cover_id": 100207, "edition_count": 24, "languages": ["heb", "spa", "eng"], "subjects": ["Developmental psychology", "Nature and nurture", "Sociology", "Long Now Manual for Civilization", "Hérédité et milieu", "Psychobiologie", "Être humain", "Inné et acquis", "Erfelijkheid en omgeving", "Sociale evolutie", "Anthropologie philosophique", "Menselijke natuur"], "synopsis": "In The Blank Slate, Steven Pinker, one of the world''s leading experts on language and the mind, explores the idea of human nature and its moral, emotional, and political colorings. With characteristic wit, lucidity, and insight, Pinker argues that the dogma that the mind has no innate traits-a doctrine held by many intellectuals during the past century-denies our common humanity and our individual preferences, replaces objective analyses of social problems with feel-good slogans, and distorts our understanding of politics, violence, parenting, and the arts. Injecting calm and rationality into debates that are notorious for ax-grinding and mud-slinging, Pinker shows the importance of an honest acknowledgment of human nature based on science and common sense.", "publication_year": 2002, "page_count": 528, "isbn13": "9780713992564", "ratings_average": 4.25, "ratings_count": 8}, "wikidata": {"wikidata_id": "Q2453618", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Blank Slate", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Blank_Slate"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (174, 579416, 4, '["eng"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:58:00+00:00', '{"openlibrary": {"ol_key": "/works/OL1856237W", "ol_cover_id": 579416, "edition_count": 4, "languages": ["eng"], "subjects": ["Computer crimes", "LambdaMOO", "Virtual reality", "World Wide Web", "Criminaliteit", "Internet", "New York Times reviewed", "Fiction, thrillers, technological"], "synopsis": null, "publication_year": 1998, "page_count": 336, "isbn13": "9781841150574", "ratings_average": null, "ratings_count": null}, "wikidata": {}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (175, 223137, 31, '["may", "eng", "chi", "spa"]', 3.0, 3, 'Q1041237', 'https://en.wikipedia.org/wiki/The_Lexus_and_the_Olive_Tree', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:58:03+00:00', '{"openlibrary": {"ol_key": "/works/OL3740414W", "ol_cover_id": 223137, "edition_count": 31, "languages": ["may", "eng", "chi", "spa"], "subjects": ["ASPECTOS ECONOMICOS", "Aspectos sociales", "Capitalism", "Capitalismo", "Comunicación intercultural", "Economic aspects", "Economic aspects of Technological innovations", "Economía internacional", "Foreign economic relations", "Free trade", "Globalización", "Globalization"], "synopsis": "As the Foreign Affairs columnist for The New York Times, Thomas L. Friedman has traveled to the four corners of the globe, interviewing people from all walks of contemporary life - Brazilian peasants in the Amazon rain forest, new entrepreneurs in Indonesia, Islamic students in Teheran, and the financial wizards on Wall Street and in Silicon Valley.\r\n\r\nNow Friedman has drawn on his years on the road to produce an engrossing and original look at the new international system that, more than anything else, is shaping world affairs today: globalization.\r\n\r\nHis argument can be summarized quite simply. Globalization is not just a phenomenon and not just a passing trend. It is the international system that replaced the Cold War system. Globalization is the integration of capital, technology, and information across national borders, in a way that is creating a single global market and, to some degree, a global village.\r\n\r\nWith vivid stories and a set of original terms and concepts, Friedman shows us how to see this new system. He dramatizes the conflict of \"the Lexus and the olive tree\" - the tension between the globalization system and ancient forces of culture, geography, tradition, and community. He also details the powerful backlash that globalization produces among those who feel brutalized by it, and he spells out what we all need to do to keep this system in balance.", "publication_year": 1999, "page_count": 467, "isbn13": "9780965885942", "ratings_average": 3.0, "ratings_count": 3}, "wikidata": {"wikidata_id": "Q1041237", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Lexus and the Olive Tree", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Lexus_and_the_Olive_Tree"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (176, 541027, 25, '["chi", "spa", "eng"]', 3.95, 61, 'Q283445', 'https://en.wikipedia.org/wiki/The_Devil_in_the_White_City', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:58:05+00:00', '{"openlibrary": {"ol_key": "/works/OL20262W", "ol_cover_id": 541027, "edition_count": 25, "languages": ["chi", "spa", "eng"], "subjects": ["Social life and customs", "Murder", "Serial murders", "Architects", "New York Times bestseller", "Case studies", "Serial murderers", "World''s Columbian Exposition (1893 : Chicago, Ill.)", "Biography", "World''s Columbian Exposition (1893 : Chicago, Ill.) (NOBLE)39295", "World''s Columbian Exposition (1893 : Chicago, Ill)", "Murder, illinois"], "synopsis": "From back cover: Bringing Chicago circa 1893 to vivid life, Erik Larson''s spell-binding bestseller intertwines the true tale of two men - the brilliant architect behind the legendary 1893 World''s Fair, striving to secure America''s place in the world; and the cunning serial killer who used the fair to lure his victims to their death. Combining meticulous research with nail-biting storytelling, Erik Larson has crafted a narrative with all the wonder of newly discovered history and the thrills of the best fiction.", "publication_year": 2003, "page_count": 496, "isbn13": "9780553813531", "ratings_average": 3.95, "ratings_count": 61}, "wikidata": {"wikidata_id": "Q283445", "awards": [], "series": null, "goodreads_id": null, "wikipedia_title": "The Devil in the White City", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Devil_in_the_White_City"}}');
INSERT INTO club_book_enrichment (book_id, ol_cover_id, edition_count, languages_json, ratings_average, ratings_count, wikidata_id, wikipedia_url, goodreads_id, series, awards_json, ol_key, synopsis, publication_year, page_count, isbn13, subjects_json, enriched_at, enrichment_json) VALUES (177, 8758252, 19, '["eng"]', 4.19, 27, 'Q56277009', 'https://en.wikipedia.org/wiki/The_Overstory', NULL, NULL, '["Pulitzer Prize for Fiction"]', NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-26T14:58:08+00:00', '{"openlibrary": {"ol_key": "/works/OL19074847W", "ol_cover_id": 8758252, "edition_count": 19, "languages": ["eng"], "subjects": ["trees", "forest", "conservation", "environment", "activism", "Forest conservation", "Forests and forestry", "American fiction (fictional works by one author)", "Fiction, political", "nyt:hardcover-fiction=2018-05-06", "New York Times bestseller", "New York Times reviewed"], "synopsis": "*The Overstory* unfolds in concentric rings of interlocking fable that range from antebellum New York to the late-twentieth-century Timber Wars of the Pacific Northwest and beyond. An Air Force loadmaster in the Vietnam War is shot out of the sky, then saved by falling into a banyan. An artist inherits a hundred years of photographic portraits, all of the same doomed American chestnut. A hard-partying undergraduate in the late 1980s electrocutes herself, dies, and is sent back into life by creatures of air and light. A hearing- and speech-impaired scientist discovers that trees are communicating with one another. These and five other strangers, each summoned in different ways by trees, are brought together in a last stand to save the continent''s few remaining acres of virgin forest.\r\n\r\nThere is a world alongside ours—vast, slow, interconnected, resourceful, magnificently inventive, and almost invisible to us. This is the story of a handful of people who learn how to see that world and who are drawn up into its unfolding catastrophe.", "publication_year": 2018, "page_count": 531, "isbn13": "978-0393356687", "ratings_average": 4.19, "ratings_count": 27}, "wikidata": {"wikidata_id": "Q56277009", "awards": ["Pulitzer Prize for Fiction"], "series": null, "goodreads_id": null, "wikipedia_title": "The Overstory", "wikipedia_url": "https://en.wikipedia.org/wiki/The_Overstory"}}');
