INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (11, NULL, 1961, 2020, 'United States', '/authors/OL1395062A', 'Q1174579', 'https://en.wikipedia.org/wiki/David_Graeber', 'http://www.reddit.com/r/IAmA/comments/17fi6l/i_am_david_graeber_an_anthropologist_activist/', '["Fragments of an Anarchist Anthropology", "Debt", "Toward an Anthropological Theory of Value", "The Utopia of Rules", "Direct Action", "The Democracy Project"]', 'Open Library', '2026-06-26T14:58:37+00:00', '{"openlibrary": {"bio": "**David Rolfe Graeber** (/ˈɡreɪbər/; February 12, 1961 – September 2, 2020) was an American anthropologist, anarchist activist and author known for his books *Debt: The First 5000 Years* (2011), *The Utopia of Rules* (2015) and *Bullshit Jobs: A Theory* (2018). He was a professor of anthropology at the London School of Economics.\r\n\r\nAs an assistant professor and associate professor of anthropology at Yale from 1998–2007 he specialised in theories of value and social theory. The university''s decision not to rehire him when he would otherwise have become eligible for tenure sparked an academic controversy, and a petition with more than 4,500 signatures. He went on to become, from 2007–13, Reader in Social Anthropology at Goldsmiths, University of London. ([Source](https://en.wikipedia.org/wiki/David_Graeber))", "birth_year": 1961, "death_year": 2020, "website": "http://www.reddit.com/r/IAmA/comments/17fi6l/i_am_david_graeber_an_anthropologist_activist/", "wikidata_id": "Q1174579", "ol_photo_id": 8030191}, "wikidata": {"wikidata_id": "Q1174579", "birth_year": 1961, "death_year": 2020, "nationality": "United States", "notable_works": ["Fragments of an Anarchist Anthropology", "Debt", "Toward an Anthropological Theory of Value", "The Utopia of Rules", "Direct Action", "The Democracy Project"], "awards": ["Fulbright Scholarship", "Bread and Roses Award"], "website": "https://davidgraeber.org", "goodreads_id": "29101", "image_filename": "David Graeber 2015-03-07 (16741093492) (cropped).jpg", "wikipedia_title": "David Graeber", "wikipedia_url": "https://en.wikipedia.org/wiki/David_Graeber"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/e/e0/David_Graeber_Fire_Island_headshot_cropped.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/David_Graeber"}}');
