INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (21, NULL, 1976, NULL, 'United States', '/authors/OL6511583A', 'Q22087892', 'https://en.wikipedia.org/wiki/Patrick_Radden_Keefe', 'https://www.patrickraddenkeefe.com/', '["Say Nothing"]', 'Open Library', '2026-06-26T14:59:06+00:00', '{"openlibrary": {"bio": "Patrick Radden Keefe is an award-winning staff writer at The New Yorker magazine and the author of the New York Times bestseller Say Nothing: A True Story of Murder and Memory in Northern Ireland, as well as two other books: The Snakehead: An Epic Tale of the Chinatown Underworld and the American Dream, and Chatter: Dispatches from the Secret World of Global Eavesdropping. He started contributing to The New Yorker in 2006 and has written articles about the chef and TV host Anthony Bourdain, the hunt for the drug lord Chapo Guzman, the tragic personal history of the mass shooter Amy Bishop, and the role that the Sackler family and their company Purdue Pharma played in sparking the opioid crisis. He received the National Magazine Award for Feature Writing in 2014, and was a finalist for the National Magazine Award for Reporting in 2015 and 2016. Say Nothing received the Orwell Prize for Political Writing in 2019 and was named one of Literary Hub’s “20 Best Nonfiction Books of the Decade.”\r\n\r\nPatrick grew up in Dorchester, Massachusetts and went to college at Columbia. He received masters degrees from Cambridge University and the London School of Economics, and a JD from Yale Law School. In addition to The New Yorker, his work has appeared in The New York Review of Books, The New York Times Magazine, Slate, and other publications. He is the recipient of fellowships from the Guggenheim Foundation, the Rockefeller Foundation, the New America Foundation, the Woodrow Wilson International Center for Scholars, and the Cullman Center for Scholars and Writers at the New York Public Library.  \r\n\r\nPhotograph by Philip Montgomery\r\n([source](https://www.patrickraddenkeefe.com/bio-new))", "birth_year": 1976, "death_year": null, "website": "https://www.patrickraddenkeefe.com/", "wikidata_id": null, "ol_photo_id": 9242451}, "wikidata": {"wikidata_id": "Q22087892", "birth_year": 1976, "death_year": null, "nationality": "United States", "notable_works": ["Say Nothing"], "awards": ["Guggenheim Fellowship", "Baillie Gifford Prize", "National Book Critics Circle Award in Nonfiction"], "website": "https://www.patrickraddenkeefe.com", "goodreads_id": "197852", "image_filename": "Patrick Radden Keefe.jpg", "wikipedia_title": "Patrick Radden Keefe", "wikipedia_url": "https://en.wikipedia.org/wiki/Patrick_Radden_Keefe"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/Patrick_Radden_Keefe.jpg/330px-Patrick_Radden_Keefe.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Patrick_Radden_Keefe"}}');
