INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (23, NULL, 1961, NULL, 'United States', '/authors/OL3553076A', 'Q6077806', 'https://en.wikipedia.org/wiki/Isabel_Wilkerson', 'https://www.isabelwilkerson.com/', '["The Warmth of Other Suns"]', 'Wikimedia Commons', '2026-06-26T14:59:13+00:00', '{"openlibrary": {"bio": null, "birth_year": null, "death_year": null, "website": null, "wikidata_id": "Q6077806", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q6077806", "birth_year": 1961, "death_year": null, "nationality": "United States", "notable_works": ["The Warmth of Other Suns"], "awards": ["Guggenheim Fellowship", "George Polk Award", "National Humanities Medal", "Pulitzer Prize for Feature Writing", "Anisfield-Wolf Book Awards", "Chicago Tribune Heartland Prize", "Journalist of the Year", "Carl Sandburg Literary Award", "National Book Critics Circle Award in Nonfiction", "The Hillman Prize for Book Journalism"], "website": "https://www.isabelwilkerson.com/", "goodreads_id": "3567958", "image_filename": "Isabel wilkerson 2010.jpg", "wikipedia_title": "Isabel Wilkerson", "wikipedia_url": "https://en.wikipedia.org/wiki/Isabel_Wilkerson"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/e/e5/Isabel_wilkerson_2010.jpg/330px-Isabel_wilkerson_2010.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Isabel_Wilkerson"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (24, NULL, 1979, NULL, 'United States', '/authors/OL3392352A', 'Q22096471', 'https://en.wikipedia.org/wiki/Matthew_Desmond', 'https://scholar.princeton.edu/matthewdesmond/', NULL, 'Open Library', '2026-06-26T14:59:16+00:00', '{"openlibrary": {"bio": "Matthew Desmond is Maurice P. During Professor of Sociology and Principal Investigator of The Eviction Lab. After receiving his Ph.D. in 2010 from the University of Wisconsin at Madison, he joined the Harvard Society of Fellows as a Junior Fellow. His primary teaching and research interests include urban sociology, poverty, race and ethnicity, organizations and work, social theory, and ethnography.  \r\n\r\nDesmond is the author of four books: On the Fireline: Living and Dying with WIldland Firefighters (2007), Race in America (with Mustafa Emirbayer, 2015), The Racial Order (with Mustafa Emirbayer, 2015), and Evicted: Poverty and Profit in the American City (2016).  He also is the editor of the inaugural issue of RSF: The Russell Sage Foundation Journal of the Social Sciences, Volumes 1 & 2: Severe Deprivation in America (2015). \r\n\r\nDesmond has written essays on educational inequality, dangerous work, political ideology, race and social theory, and the inner-city housing market.  Recently, he has published on the prevalence and consequences of eviction and the low-income rental market, network-based survival strategies among the urban poor, and the consequences of new crime control policies on inner-city women in the American Journal of Sociology, American Sociological Review, Social Forces, and Demography.\r\n\r\nIn 2015, Desmond was awarded a MacArthur “Genius” grant.\r\n\r\n([source][1])\r\n\r\n\r\n  [1]: https://scholar.princeton.edu/matthewdesmond/", "birth_year": null, "death_year": null, "website": "https://scholar.princeton.edu/matthewdesmond/", "wikidata_id": "Q22096471", "ol_photo_id": 8363279}, "wikidata": {"wikidata_id": "Q22096471", "birth_year": 1979, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["MacArthur Fellows Program", "Chicago Tribune Heartland Prize", "PEN/John Kenneth Galbraith Award", "Silver Gavel Award", "Pulitzer Prize for General Nonfiction", "National Book Critics Circle Award in Nonfiction", "The Hillman Prize for Book Journalism"], "website": "https://sociology.princeton.edu/people/matthew-desmond", "goodreads_id": "915500", "image_filename": "Matthew Desmond at 2017 National Book Festival.jpg", "wikipedia_title": "Matthew Desmond", "wikipedia_url": "https://en.wikipedia.org/wiki/Matthew_Desmond"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/a/a9/Matthew_Desmond_at_2023_National_Book_Festival_%2853123258729%29_%28cropped%29.jpg/330px-Matthew_Desmond_at_2023_National_Book_Festival_%2853123258729%29_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Matthew_Desmond"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (25, NULL, 1943, NULL, 'Trinidad and Tobago', '/authors/OL33112A', 'Q370921', 'https://en.wikipedia.org/wiki/Steven_Pressfield', 'http://www.stevenpressfield.com/', '["The Legend of Bagger Vance", "Gates of Fire", "The War of Art"]', 'Open Library', '2026-06-26T14:59:18+00:00', '{"openlibrary": {"bio": "I was born in Port of Spain, Trinidad, in 1943 to a Navy father and mother.\r\n\r\nI graduated from Duke University in 1965.\r\n\r\nIn January of 1966, when I was on the bus leaving Parris Island as a freshly-minted Marine, I looked back and thought there was at least one good thing about this departure. \"No matter what happens to me for the rest of my life, no one can ever send me back to this freakin'' place again.\"\r\n\r\nForty years later, to my surprise and gratification, I am far more closely bound to the young men of the Marine Corps and to all other dirt-eating, ground-pounding outfits than I could ever have imagined.\r\n\r\nGATES OF FIRE is one reason. Dog-eared paperbacks of this tale of the ancient Spartans have circulated throughout platoons of U.S. troops in Iraq and Afghanistan since the first days of the invasions. E-mails come in by hundreds. GATES OF FIRE is on the Commandant of the Marine Corps'' Reading list. It is taught at West Point and Annapolis and at the Marine Corps Basic School at Quantico. TIDES OF WAR is on the curriculum of the Naval War College.\r\n\r\nFrom 2nd Battalion/6th Marines, which calls itself \"the Spartans,\" to ODA 316 of the Special Forces, whose forearms are tattooed with the lambda of Lakedaemon, today''s young warriors find a bond to their ancient precursors in the historical narratives of these novels.\r\n\r\nMy struggles to earn a living as a writer (it took seventeen years to get the first paycheck) are detailed in my 2002 book, THE WAR OF ART.\r\n\r\nI have worked as an advertising copywriter, schoolteacher, tractor-trailer driver, bartender, oilfield roustabout and attendant in a mental hospital. I have picked fruit in Washington state and written screenplays in Tinseltown.\r\n\r\nWith the publication of THE LEGEND OF BAGGER VANCE in 1995, I became a writer of books once and for all.\r\n\r\nMy writing philosophy is, not surprisingly, a kind of warrior code — internal rather than external — in which the enemy is identified as those forms of self-sabotage that I have labeled \"Resistance\" with a capital R (in THE WAR OF ART) and the technique for combatting these foes can be described as \"turning pro.\"\r\n\r\nI believe in previous lives.\r\n\r\nI believe in the Muse.\r\n\r\nI believe that books and music exist before they are written and that they are propelled into material being by their own imperative to be born, via the offices of those willing servants of discipline, imagination and inspiration, whom we call artists. My conception of the artist''s role is a combination of reverence for the unknowable nature of \"where it all comes from\" and a no-nonsense, blue-collar demystification of the process by which this mystery is approached. In other words, a paradox.\r\n\r\nThere''s a recurring character in my books named Telamon, a mercenary of ancient days. Telamon doesn''t say much. He rarely gets hurt or wounded. And he never seems to age. His view of the profession of arms is a lot like my conception of art and the artist:\r\n\r\n\"It is one thing to study war, and another to live the warrior''s life.\"", "birth_year": 1943, "death_year": null, "website": null, "wikidata_id": "Q370921", "ol_photo_id": 13259023}, "wikidata": {"wikidata_id": "Q370921", "birth_year": 1943, "death_year": null, "nationality": "Trinidad and Tobago", "notable_works": ["The Legend of Bagger Vance", "Gates of Fire", "The War of Art"], "awards": [], "website": "http://www.stevenpressfield.com/", "goodreads_id": "867", "image_filename": "Author Steven Pressfield, June 2011.JPG", "wikipedia_title": "Steven Pressfield", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Pressfield"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/c/c1/Author_Steven_Pressfield%2C_June_2011.JPG/330px-Author_Steven_Pressfield%2C_June_2011.JPG", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Pressfield"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (26, NULL, 1954, NULL, 'United Kingdom', '/authors/OL28493A', 'Q272855', 'https://en.wikipedia.org/wiki/Kazuo_Ishiguro', 'https://www.fantasticfiction.com/i/kazuo-ishiguro/', '["An Artist of the Floating World", "The Remains of the Day", "When We Were Orphans", "Never Let Me Go", "Klara and the Sun", "A Pale View of Hills"]', 'Open Library', '2026-06-26T14:59:21+00:00', '{"openlibrary": {"bio": "Sir Kazuo Ishiguro OBE FRSA FRSL (/kæˈzuːoʊ ˌɪʃɪˈɡʊəroʊ, ˈkæzuoʊ -/ kaz-OO-oh ISH-ig-OOR-oh, KAZ-oo-oh -⁠; born 8 November 1954) is an English novelist, screenwriter, musician, and short-story writer. Ishiguro was born in Nagasaki, Japan, and moved to Britain in 1960 with his parents when he was five.\r\n\r\nHe is one of the most critically-acclaimed and praised contemporary fiction authors writing in English, being awarded the 2017 Nobel Prize in Literature. In its 2017 citation, the Swedish Academy described Ishiguro as a writer \"who, in novels of great emotional force, has uncovered the abyss beneath our illusory sense of connection with the world\". [source](https://en.wikipedia.org/wiki/Kazuo_Ishiguro)", "birth_year": 1954, "death_year": null, "website": "https://www.fantasticfiction.com/i/kazuo-ishiguro/", "wikidata_id": "Q272855", "ol_photo_id": 14853910}, "wikidata": {"wikidata_id": "Q272855", "birth_year": 1954, "death_year": null, "nationality": "United Kingdom", "notable_works": ["An Artist of the Floating World", "The Remains of the Day", "When We Were Orphans", "Never Let Me Go", "Klara and the Sun", "A Pale View of Hills"], "awards": ["Costa Book Awards", "Officer of the Order of the British Empire", "Booker Prize", "Helmerich Award", "Fellow of the Royal Society of Arts", "Nobel Prize in Literature", "Chevalier des Arts et des Lettres", "Fellow of the Royal Society of Literature", "Bodley Medal", "Knight Bachelor"], "website": null, "goodreads_id": "4280", "image_filename": "Kazuo Ishiguro by Kubik.JPG", "wikipedia_title": "Kazuo Ishiguro", "wikipedia_url": "https://en.wikipedia.org/wiki/Kazuo_Ishiguro"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/86/MKr377543_Kazuo_Ishiguro_%28A_Pale_View_of_Hills%2C_Cannes_2025%29.jpg/330px-MKr377543_Kazuo_Ishiguro_%28A_Pale_View_of_Hills%2C_Cannes_2025%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Kazuo_Ishiguro"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (27, NULL, 1929, 1986, NULL, '/authors/OL3563573A', 'Q112352123', NULL, 'https://en.wikipedia.org/wiki/David_W._Anthony', NULL, NULL, '2026-06-26T14:59:29+00:00', '{"openlibrary": {"bio": "David W. Anthony is an American anthropologist who is Professor Emeritus of Anthropology at Hartwick College. He specializes in Indo-European migrations, and is a proponent of the Kurgan hypothesis. Anthony is well known for his award-winning book The Horse, the Wheel, and Language (2007). -Wikipedia", "birth_year": null, "death_year": null, "website": "https://en.wikipedia.org/wiki/David_W._Anthony", "wikidata_id": null, "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q112352123", "birth_year": 1929, "death_year": 1986, "nationality": null, "notable_works": [], "awards": [], "website": null, "goodreads_id": null, "image_filename": null, "wikipedia_title": null, "wikipedia_url": null}, "wikipedia": {}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (28, NULL, 1962, NULL, 'United States', '/authors/OL6644297A', 'Q5112847', 'https://en.wikipedia.org/wiki/Christopher_McDougall', 'http://www.chrismcdougall.com', NULL, 'Open Library', '2026-06-26T14:59:32+00:00', '{"openlibrary": {"bio": "Trained as a foreign correspondent for the Associated Press, Christopher McDougall covered wars in Rwanda and Angola before writing his international bestseller, Born to Run. His fascination with the limits of human potential led him to create the Outside magazine web series, “Art of the Hero.”\r\n--chrismcdougall.com", "birth_year": 1962, "death_year": null, "website": "http://www.chrismcdougall.com", "wikidata_id": "Q5112847", "ol_photo_id": 8078118}, "wikidata": {"wikidata_id": "Q5112847", "birth_year": 1962, "death_year": null, "nationality": "United States", "notable_works": [], "awards": [], "website": "https://www.chrismcdougall.com/", "goodreads_id": "133538", "image_filename": null, "wikipedia_title": "Christopher McDougall", "wikipedia_url": "https://en.wikipedia.org/wiki/Christopher_McDougall"}, "wikipedia": {"thumbnail_url": null, "wikipedia_url": "https://en.wikipedia.org/wiki/Christopher_McDougall"}}');
