INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (30, NULL, 1948, 2024, 'Kingdom of the Netherlands', '/authors/OL2628905A', 'Q303350', 'https://en.wikipedia.org/wiki/Frans_de_Waal', NULL, '["The Age of Empathy"]', 'Wikimedia Commons', '2026-06-26T14:59:36+00:00', '{"openlibrary": {"bio": "Frans de Waal has been named one of Time magazine’s 100 Most Influential People. The author of Are We Smart Enough to Know How Smart Animals Are?, among many other works, he is the C. H. Candler Professor in Emory University’s Psychology Department and director of the Living Links Center at the Yerkes National Primate Research Center. He lives in Atlanta, Georgia.", "birth_year": 1948, "death_year": 2024, "website": null, "wikidata_id": "Q303350", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q303350", "birth_year": 1948, "death_year": 2024, "nationality": "Kingdom of the Netherlands", "notable_works": ["The Age of Empathy"], "awards": ["Pierre Bayle award", "Ig Nobel Prize", "Ariëns Kappers Medal", "Arthur W. Staats Lecture for Unifying Psychology", "Los Angeles Times Book Prize", "Knight of the Order of the Netherlands Lion", "honorary doctorate from University of Jean-Monnet-Saint-Étienne"], "website": null, "goodreads_id": null, "image_filename": "Frans de Waal.jpg", "wikipedia_title": "Frans de Waal", "wikipedia_url": "https://en.wikipedia.org/wiki/Frans_de_Waal"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/Frans_de_Waal.jpg/330px-Frans_de_Waal.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Frans_de_Waal"}}');
