INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (34, NULL, 1952, NULL, 'United States', '/authors/OL832299A', 'Q681012', 'https://en.wikipedia.org/wiki/Walter_Isaacson', 'https://www.youtube.com/watch?v=9BDmC5u_MLE', '["Einstein. His life, his universe", "The Code Breaker"]', 'Open Library', '2026-06-26T14:59:46+00:00', '{"openlibrary": {"bio": "Walter Isaacson, the CEO of the Aspen Institute, has been chairman of CNN and the managing editor of Time magazine. He is the author of Steve Jobs; Einstein: His Life and Universe; Benjamin Franklin: An American Life; and Kissinger: A Biography, and the coauthor of The Wise Men: Six Friends and the World They Made. He lives in Washington, DC.\r\n[(Source)][1]\r\n\r\n\r\n  [1]: http://authors.simonandschuster.com/Walter-Isaacson/697650", "birth_year": 1952, "death_year": null, "website": "https://www.youtube.com/watch?v=9BDmC5u_MLE", "wikidata_id": "Q681012", "ol_photo_id": 7321644}, "wikidata": {"wikidata_id": "Q681012", "birth_year": 1952, "death_year": null, "nationality": "United States", "notable_works": ["Einstein. His life, his universe", "The Code Breaker"], "awards": ["The Nichols-Chancellor''s Medal", "Benjamin Franklin Medal", "Jefferson Lecture", "Rhodes Scholarship", "Carl Sandburg Literary Award", "National Humanities Medal"], "website": null, "goodreads_id": "7111", "image_filename": "Walter Isaacson VF 2012 Shankbone 2.JPG", "wikipedia_title": "Walter Isaacson", "wikipedia_url": "https://en.wikipedia.org/wiki/Walter_Isaacson"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/7/78/Walter_Isaacson_VF_2012_Shankbone_2.JPG/330px-Walter_Isaacson_VF_2012_Shankbone_2.JPG", "wikipedia_url": "https://en.wikipedia.org/wiki/Walter_Isaacson"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (35, NULL, 1944, 2003, 'United States', '/authors/OL292449A', 'Q1697118', 'https://en.wikipedia.org/wiki/Ken_Grimwood', NULL, '["Replay"]', 'Wikipedia', '2026-06-26T14:59:48+00:00', '{"openlibrary": {"bio": null, "birth_year": null, "death_year": null, "website": null, "wikidata_id": "Q1697118", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q1697118", "birth_year": 1944, "death_year": 2003, "nationality": "United States", "notable_works": ["Replay"], "awards": ["World Fantasy Awards", "World Fantasy Award for Best Novel"], "website": null, "goodreads_id": null, "image_filename": null, "wikipedia_title": "Ken Grimwood", "wikipedia_url": "https://en.wikipedia.org/wiki/Ken_Grimwood"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/en/5/5f/Ken_Grimwood.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Ken_Grimwood"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (36, NULL, 1945, NULL, 'United States', '/authors/OL1590665A', 'Q6833550', 'https://en.wikipedia.org/wiki/Michael_Pillsbury', 'http://www.michaelpillsbury.net', NULL, 'Wikimedia Commons', '2026-06-26T14:59:51+00:00', '{"openlibrary": {"bio": "Born in California in 1945, Pillsbury was educated at Stanford University (B.A. in History with Honors in Social Thought) and Columbia University (M.A., Ph.D.). Major academic advisers to Pillsbury at Columbia were Zbigniew Brzezinski and Michel Oksenberg, who later played key roles in the Jimmy Carter administration on policy toward both China and Afghanistan. Pillsbury studied the art and practice of bureaucratic politics with Roger Hilsman, President John Kennedy''s intelligence director at the State Department and the author of Politics Of Policy Making In Defense and Foreign Affairs. At Stanford, Pillsbury''s academic mentor was Mark Mancall, author of two books on the influence of ancient traditions on Chinese foreign policy.\r\n\r\nIn 1969-1970 Pillsbury was the Assistant Political Affairs Officer at the United Nations. From 1971-72, he was a doctoral dissertation Fellow for the National Science Foundation in Taiwan, and in 1973-1977, Pillsbury was an analyst at the Social Science Department at RAND. In 1978, Pillsbury was a research fellow at the Center for Science and International Affairs at Harvard University.\r\n\r\nDuring the Reagan administration, Dr. Pillsbury was the Assistant Under Secretary of Defense for Policy Planning and responsible for implementation of the program of covert aid known as the Reagan Doctrine. In 1975-76, while an analyst at the RAND Corporation, Pillsbury published articles in Foreign Policy and International Security recommending that the United States establish intelligence and military ties with China. The proposal, publicly commended by Ronald Reagan, Henry Kissinger, and James Schlesinger, later became US policy during the Carter and Reagan administrations.\r\n\r\nPillsbury served on the staff of four US Senate Committees from 1978-1984 and 1986-1991. As a staff member, Pillsbury drafted the Senate Labor Committee version of the legislation that enacted the US Institute of Peace in 1984. He also assisted in drafting the legislation to create the National Endowment for Democracy and the annual requirement for a DOD report on Chinese military power.\r\n\r\nIn 1992, under President George H. W. Bush, Pillsbury was Special Assistant for Asian Affairs in the Office of the Secretary of Defense, reporting to Andrew W. Marshall, Director of Net Assessment. Michael Pillsbury is a member of the Council on Foreign Relations and the International Institute for Strategic Studies.", "birth_year": null, "death_year": null, "website": "http://www.michaelpillsbury.net", "wikidata_id": "Q6833550", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q6833550", "birth_year": 1945, "death_year": null, "nationality": "United States", "notable_works": [], "awards": [], "website": null, "goodreads_id": null, "image_filename": "Michael Pillsbury (49625554677).jpg", "wikipedia_title": "Michael Pillsbury", "wikipedia_url": "https://en.wikipedia.org/wiki/Michael_Pillsbury"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/81/Michael_Pillsbury_%2849625554677%29.jpg/330px-Michael_Pillsbury_%2849625554677%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Michael_Pillsbury"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (37, NULL, 1928, 2017, 'United States', '/authors/OL70357A', 'Q366575', 'https://en.wikipedia.org/wiki/Robert_M._Pirsig', NULL, '["Zen and the Art of Motorcycle Maintenance", "Lila: An Inquiry into Morals"]', 'Open Library', '2026-06-26T14:59:54+00:00', '{"openlibrary": {"bio": "Robert Maynard Pirsig (Minneapolis, Minesota; September 6, 1928-South Berwick, Maine; April 24, 2017) was an American writer and philosopher, and the author of the philosophical novels *Zen and the Art of Motorcycle Maintenance: An Inquiry into Values* (1974) and *Lila: An Inquiry into Morals (1991)*\r\n\r\n**Source**: Wikipedia.", "birth_year": 1928, "death_year": 2017, "website": null, "wikidata_id": "Q366575", "ol_photo_id": 7408309}, "wikidata": {"wikidata_id": "Q366575", "birth_year": 1928, "death_year": 2017, "nationality": "United States", "notable_works": ["Zen and the Art of Motorcycle Maintenance", "Lila: An Inquiry into Morals"], "awards": ["Guggenheim Fellowship"], "website": null, "goodreads_id": "401", "image_filename": "Pirsig2005.jpg", "wikipedia_title": "Robert M. Pirsig", "wikipedia_url": "https://en.wikipedia.org/wiki/Robert_M._Pirsig"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b8/Pirsig2005_%28cropped%29.jpg/330px-Pirsig2005_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Robert_M._Pirsig"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (38, NULL, 1986, NULL, 'United States', '/authors/OL7421324A', 'Q50345244', 'https://en.wikipedia.org/wiki/Tara_Westover', 'https://tarawestover.com/', '["Educated"]', 'Open Library', '2026-06-26T14:59:56+00:00', '{"openlibrary": {"bio": "Tara Westover (born September 27, 1986) is an American memoirist, essayist and historian. Her memoir *Educated* (2018) debuted at No. 1 on *The New York Times* bestseller list and was a finalist for a number of national awards, including the LA Times Book Prize, PEN America''s Jean Stein Book Award, and two awards from the National Book Critics Circle Award.", "birth_year": 1986, "death_year": null, "website": "https://tarawestover.com/", "wikidata_id": "Q50345244", "ol_photo_id": 14656754}, "wikidata": {"wikidata_id": "Q50345244", "birth_year": 1986, "death_year": null, "nationality": "United States", "notable_works": ["Educated"], "awards": ["National Humanities Medal"], "website": "https://tarawestover.com/", "goodreads_id": "16121977", "image_filename": "Tara Westover receives the National Humanities Medal on March 21, 2023, in the East Room of the White House - P20230321ES-0780 (cropped).jpg", "wikipedia_title": "Tara Westover", "wikipedia_url": "https://en.wikipedia.org/wiki/Tara_Westover"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/0/09/Tara_Westover_receives_the_National_Humanities_Medal_on_March_21%2C_2023%2C_in_the_East_Room_of_the_White_House_-_P20230321ES-0780_%28cropped%29.jpg/330px-Tara_Westover_receives_the_National_Humanities_Medal_on_March_21%2C_2023%2C_in_the_East_Room_of_the_White_House_-_P20230321ES-0780_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Tara_Westover"}}');
