INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (41, NULL, 1964, NULL, 'United States', '/authors/OL7396886A', 'Q56068', 'https://en.wikipedia.org/wiki/Jennifer_Doudna', 'https://en.wikipedia.org/wiki/Jennifer_Doudna', '["Jennifer Doudna: We can now edit our DNA. But let''s do it wisely"]', 'Open Library', '2026-06-26T15:00:04+00:00', '{"openlibrary": {"bio": "JENNIFER A. DOUDNA, Ph.D. is a professor in the Chemistry and the Molecular and Cell Biology Departments at the University of California, Berkeley, investigator with the Howard Hughes Medical Institute, and researcher in the Molecular Biophysics and Integrated Bioimaging Division at the Lawrence Berkeley National Laboratory. She is internationally recognized as a leading expert on RNA-protein biochemistry, CRISPR biology, and genome engineering. She lives in the Bay Area. --([Source][1])\r\n\r\n\r\n  [1]: https://www.amazon.com/Crack-Creation-Editing-Unthinkable-Evolution/dp/0544716949/", "birth_year": 1964, "death_year": null, "website": "https://en.wikipedia.org/wiki/Jennifer_Doudna", "wikidata_id": "Q56068", "ol_photo_id": 8048637}, "wikidata": {"wikidata_id": "Q56068", "birth_year": 1964, "death_year": null, "nationality": "United States", "notable_works": ["Jennifer Doudna: We can now edit our DNA. But let''s do it wisely"], "awards": ["Princess of Asturias Award for Technical and Scientific Research", "Breakthrough Prize in Life Sciences", "Dr. Paul Janssen Award for Biomedical Research", "Gruber Prize in Genetics", "Paul Ehrlich and Ludwig Darmstaedter Prize", "Dickson Prize in Medicine", "Canada Gairdner International Award", "Dr H.P. Heineken Prize for Biochemistry and Biophysics", "Massry Prize", "Tang Prize"], "website": null, "goodreads_id": null, "image_filename": "Professor Jennifer Doudna ForMemRS (cropped).jpg", "wikipedia_title": "Jennifer Doudna", "wikipedia_url": "https://en.wikipedia.org/wiki/Jennifer_Doudna"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/7/7e/Jennifer_Doudna_by_Christopher_Michel_in_2023_01.jpg/330px-Jennifer_Doudna_by_Christopher_Michel_in_2023_01.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Jennifer_Doudna"}}');
