INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (46, NULL, 1960, NULL, 'United Kingdom', '/authors/OL53305A', 'Q210059', 'https://en.wikipedia.org/wiki/Neil_Gaiman', 'https://neilgaiman.com', '["The Sandman", "American Gods", "Stardust", "Coraline", "The Graveyard Book", "Good Omens"]', 'Open Library', '2026-06-26T15:00:16+00:00', '{"openlibrary": {"bio": "Neil Richard MacKinnon Gaiman born Neil Richard Gaiman, 10 November 1960) is an English author of short fiction, novels, comic books, graphic novels, audio theatre, and films. His notable works include the comic book series The Sandman and novels Stardust, American Gods, Coraline, and The Graveyard Book. He has won numerous awards, including the Hugo, Nebula, and Bram Stoker awards, as well as the Newbery and Carnegie medals. He is the first author to win both the Newbery and the Carnegie medals for the same work, The Graveyard Book (2008). In 2013, The Ocean at the End of the Lane was voted Book of the Year in the British National Book Awards.", "birth_year": 1960, "death_year": null, "website": "https://neilgaiman.com", "wikidata_id": "Q210059", "ol_photo_id": 7277125}, "wikidata": {"wikidata_id": "Q210059", "birth_year": 1960, "death_year": null, "nationality": "United Kingdom", "notable_works": ["The Sandman", "American Gods", "Stardust", "Coraline", "The Graveyard Book", "Good Omens"], "awards": ["Grand Prix de l''Imaginaire for Best Foreign-Language Short Story", "Bram Stoker Award for Novel", "Hugo Award for Best Novel", "Nebula Award for Best Novel", "Locus Award for Best Fantasy Novel", "Nebula Award for Best Novella", "Locus Award for Best Short Story", "Hugo Award for Best Novella", "Hugo Award for Best Short Story", "Locus Award for Best Short Story"], "website": "https://neilgaiman.com", "goodreads_id": "1221698", "image_filename": "Kyle-cassidy-neil-gaiman-April-2013.jpg", "wikipedia_title": "Neil Gaiman", "wikipedia_url": "https://en.wikipedia.org/wiki/Neil_Gaiman"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/bc/Kyle-cassidy-neil-gaiman-April-2013.jpg/330px-Kyle-cassidy-neil-gaiman-April-2013.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Neil_Gaiman"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (47, NULL, 1903, 1950, 'United Kingdom', '/authors/OL118077A', 'Q3335', 'https://en.wikipedia.org/wiki/George_Orwell', 'https://love-books-review.com/reviews-by-author/george-orwell/', '["The Road to Wigan Pier", "Homage to Catalonia", "Animal Farm", "Nineteen Eighty-Four", "Burmese Days", "Coming Up for Air"]', 'Open Library', '2026-06-26T15:00:19+00:00', '{"openlibrary": {"bio": "George Orwell, originally born as Eric Arthur Blair, was an English novelist and journalist. His work is marked by keen intelligence and wit, a profound awareness of social injustice, an intense, revolutionary opposition to totalitarianism, a passion for clarity in language and a belief in democratic socialism. ([Source][1].)\r\n\r\n[1]:https://en.wikipedia.org/wiki/George_Orwell", "birth_year": 1903, "death_year": 1950, "website": "https://love-books-review.com/reviews-by-author/george-orwell/", "wikidata_id": "Q3335", "ol_photo_id": 9160343}, "wikidata": {"wikidata_id": "Q3335", "birth_year": 1903, "death_year": 1950, "nationality": "United Kingdom", "notable_works": ["The Road to Wigan Pier", "Homage to Catalonia", "Animal Farm", "Nineteen Eighty-Four", "Burmese Days", "Coming Up for Air"], "awards": ["Prometheus Award - Hall of Fame", "Hugo Award for Best Novella", "Retro Hugo Award for Best Novella"], "website": null, "goodreads_id": "3706", "image_filename": "George Orwell, c. 1940 (41928180381).jpg", "wikipedia_title": "George Orwell", "wikipedia_url": "https://en.wikipedia.org/wiki/George_Orwell"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/7/7e/George_Orwell_press_photo.jpg/330px-George_Orwell_press_photo.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/George_Orwell"}}');
