INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (57, NULL, 1965, NULL, 'United States', '/authors/OL1485501A', 'Q2751383', 'https://en.wikipedia.org/wiki/Atul_Gawande', 'http://atulgawande.com/', '["The Checklist Manifesto"]', 'Open Library', '2026-06-26T15:00:47+00:00', '{"openlibrary": {"bio": "Atul Gawande, MD, MPH, is a surgeon, writer, and public health researcher. For more than 20 years, he has practiced general and endocrine surgery at Brigham and Women’s Hospital. He is Professor in the Department of Health Policy and Management at the Harvard T.H. Chan School of Public Health and the Samuel O. Thier Professor of Surgery at Harvard Medical School. He is also Executive Director of Ariadne Labs, a joint center for health systems innovation, and Chairman of Lifebox, a nonprofit organization making surgery safer globally. ([source][1])\r\n\r\nPhoto Credit: By <a href=\"//commons.wikimedia.org/w/index.php?title=User:Amar_Karodkar&action=edit&redlink=1\" class=\"new\" title=\"User:Amar Karodkar (page does not exist)\">Amar Karodkar</a> - <span class=\"int-own-work\" lang=\"en\">Own work</span>, <a href=\"https://creativecommons.org/licenses/by-sa/4.0\" title=\"Creative Commons Attribution-Share Alike 4.0\">CC BY-SA 4.0</a>, <a href=\"https://commons.wikimedia.org/w/index.php?curid=64884113\">Link</a>\r\n\r\n\r\n  [1]: http://atulgawande.com/about/", "birth_year": null, "death_year": null, "website": null, "wikidata_id": "Q2751383", "ol_photo_id": 8178183}, "wikidata": {"wikidata_id": "Q2751383", "birth_year": 1965, "death_year": null, "nationality": "United States", "notable_works": ["The Checklist Manifesto"], "awards": ["MacArthur Fellows Program", "Rhodes Scholarship", "Henry Ingersoll Bowditch Award for Excellence in Public Health"], "website": "http://atulgawande.com/", "goodreads_id": "3078", "image_filename": "Atul Gawande, USAID Assistant Administrator.jpg", "wikipedia_title": "Atul Gawande", "wikipedia_url": "https://en.wikipedia.org/wiki/Atul_Gawande"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/a/ae/Atul_Gawande%2C_USAID_Assistant_Administrator.jpg/330px-Atul_Gawande%2C_USAID_Assistant_Administrator.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Atul_Gawande"}}');
