INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (71, 'Brad Stone is an American journalist and author. He is the editor of Bloomberg Businessweek since January 2024. He is the author of the books The Everything Store: Jeff Bezos and the Age of Amazon (2013), Amazon Unbound: Jeff Bezos and the Invention of a Global Empire (2021), The Upstarts: How Uber, Airbnb, and the Killer Companies of the New Silicon Valley are Changing the World, and Gearheads: the Turbulent Rise of Robotic Sports.', 1966, NULL, 'United States', '/authors/OL27476A', 'Q4954294', 'https://en.wikipedia.org/wiki/Brad_Stone_%28journalist%29', 'http://brad-stone.com', '["The Upstarts", "The Everything Store: Jeff Bezos and the Age of Amazon"]', 'Wikimedia Commons', '2026-06-26T15:01:38+00:00', '{"openlibrary": {"bio": null, "birth_year": 1966, "death_year": null, "website": null, "wikidata_id": null, "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q4954294", "birth_year": 1971, "death_year": null, "nationality": "United States", "notable_works": ["The Upstarts", "The Everything Store: Jeff Bezos and the Age of Amazon"], "awards": ["Financial Times and McKinsey Business Book of the Year Award"], "website": "http://brad-stone.com", "goodreads_id": "219908", "image_filename": "Brad stone 2013.jpg", "wikipedia_title": "Brad Stone (journalist)", "wikipedia_url": "https://en.wikipedia.org/wiki/Brad_Stone_%28journalist%29"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/Brad_stone_2013.jpg/330px-Brad_stone_2013.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Brad_Stone_(journalist)"}}');
