INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (73, NULL, 1972, NULL, 'United States', '/authors/OL7234434A', 'Q18590295', 'https://en.wikipedia.org/wiki/Andy_Weir', 'https://andyweirauthor.com', '["The Martian", "The Egg", "Cheshire Crossing", "Artemis", "Project Hail Mary"]', 'Open Library', '2026-06-26T15:01:44+00:00', '{"openlibrary": {"bio": "Andy Weir built a career as a software engineer until the success of his first published novel, THE MARTIAN, allowed him to live out his dream of writing fulltime. He is a lifelong space nerd and a devoted hobbyist of subjects such as relativistic physics, orbital mechanics, and the history of manned spaceflight. He also mixes a mean cocktail. He lives in California.", "birth_year": 1972, "death_year": null, "website": "https://andyweirauthor.com", "wikidata_id": "Q18590295", "ol_photo_id": 8137363}, "wikidata": {"wikidata_id": "Q18590295", "birth_year": 1972, "death_year": null, "nationality": "United States", "notable_works": ["The Martian", "The Egg", "Cheshire Crossing", "Artemis", "Project Hail Mary"], "awards": ["Astounding Award for Best New Writer", "Geffen Award", "Ignotus Award for Best Foreign Novel", "Seiun Award for Best Translated Long Work", "Seiun Award for Best Translated Long Work", "Dragon Award for Best Science Fiction Novel", "Dragon Award for Best Science Fiction Novel"], "website": "http://www.andyweirauthor.com", "goodreads_id": "6540057", "image_filename": "Andy Weir by Gage Skidmore.jpg", "wikipedia_title": "Andy Weir", "wikipedia_url": "https://en.wikipedia.org/wiki/Andy_Weir"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/84/Andy_Weir_by_Gage_Skidmore.jpg/330px-Andy_Weir_by_Gage_Skidmore.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Andy_Weir"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (74, NULL, 1944, NULL, 'United Kingdom', '/authors/OL535878A', 'Q256548', 'https://en.wikipedia.org/wiki/Karen_Armstrong', 'http://charterforcompassion.org/', NULL, 'Open Library', '2026-06-26T15:01:46+00:00', '{"openlibrary": {"bio": "Karen Armstrong is a British author and commentator known for her books on comparative religion. A former Roman Catholic religious sister, she went from a conservative to a more liberal and mystical Christian faith. - Wikipedia", "birth_year": 1944, "death_year": null, "website": null, "wikidata_id": "Q256548", "ol_photo_id": 7435411}, "wikidata": {"wikidata_id": "Q256548", "birth_year": 1944, "death_year": null, "nationality": "United Kingdom", "notable_works": [], "awards": ["Four Freedoms Award – Freedom of Worship", "TED Prize", "Dr. Leopold Lucas Prize", "Princess of Asturias Award for Social Sciences", "Fellow of the Royal Society of Literature", "Officer of the Order of the British Empire"], "website": "http://charterforcompassion.org/", "goodreads_id": "2637", "image_filename": "Karen Armstrong.jpg", "wikipedia_title": "Karen Armstrong", "wikipedia_url": "https://en.wikipedia.org/wiki/Karen_Armstrong"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/f/fc/Karen_Armstrong.jpg/330px-Karen_Armstrong.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Karen_Armstrong"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (75, NULL, 1968, NULL, 'United States', '/authors/OL7071534A', 'Q2036370', 'https://en.wikipedia.org/wiki/Susan_Cain', 'HTTPS://SUSANCAIN.NET', '["Quiet"]', 'Open Library', '2026-06-26T15:01:48+00:00', '{"openlibrary": {"bio": "SUSAN CAIN is the author of the award-winning New York Times bestseller QUIET: The Power of Introverts in A World That Can’t Stop Talking, which has been translated into thirty-six languages, has appeared on many “Best of” lists, and was named the #1 best book of the year by Fast Company magazine. Cain’s book was the subject of a TIME Magazine cover story, and her writing has appeared in the The New York Times, The Atlantic, The Wall Street Journal, and many other publications. Her record-smashing TED talk has been viewed almost 10 million times, and was named by Bill Gates one of his all-time favorite talks. Cain has also spoken at Microsoft, Google, the U.S. Treasury, the S.E.C., Harvard, Yale, West Point and the US Naval Academy. She received quite a few awards and recognitions, including Harvard Law School’s Celebration Award for Thought Leadership. \r\nSource: Goodreads.com", "birth_year": 1968, "death_year": null, "website": null, "wikidata_id": "Q2036370", "ol_photo_id": 7272784}, "wikidata": {"wikidata_id": "Q2036370", "birth_year": 1968, "death_year": null, "nationality": "United States", "notable_works": ["Quiet"], "awards": [], "website": "HTTPS://SUSANCAIN.NET", "goodreads_id": "4101935", "image_filename": "SusanCainPortrait 250px 20120305.jpg", "wikipedia_title": "Susan Cain", "wikipedia_url": "https://en.wikipedia.org/wiki/Susan_Cain"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/6/61/SusanCainPortrait_250px_20120305.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Susan_Cain"}}');
