INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (81, NULL, 1959, NULL, 'United States', '/authors/OL710984A', 'Q1384920', 'https://en.wikipedia.org/wiki/Steven_Strogatz', 'http://www.stevenstrogatz.com/', NULL, 'Open Library', '2026-06-26T15:02:04+00:00', '{"openlibrary": {"bio": "Steven Henry Strogatz is an American mathematician and the Jacob Gould Schurman Professor of Applied Mathematics at Cornell University. He is known for his work on nonlinear systems, including contributions to the study of synchronization in dynamical systems, for his research in a variety of areas of applied mathematics, including mathematical biology and complex network theory, and for his outreach work in the public communication of mathematics. *--Wikipedia*\r\n\r\n*Photo Attribution:* Strogatz, CC BY-SA 4.0 <https://creativecommons.org/licenses/by-sa/4.0>, via Wikimedia Commons", "birth_year": 1959, "death_year": null, "website": null, "wikidata_id": "Q1384920", "ol_photo_id": 13008221}, "wikidata": {"wikidata_id": "Q1384920", "birth_year": 1959, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Presidential Young Investigator Award", "Marshall Scholarship", "Fellow of the American Physical Society", "Fellow of the Society for Industrial and Applied Mathematics", "Fellow of the American Mathematical Society", "Fellow of the American Academy of Arts and Sciences", "George Pólya Prize"], "website": "http://www.stevenstrogatz.com/", "goodreads_id": "47779", "image_filename": "Steven Strogatz.jpg", "wikipedia_title": "Steven Strogatz", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Strogatz"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/Steven_Strogatz_in_2025.jpg/330px-Steven_Strogatz_in_2025.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Strogatz"}}');
