INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (89, NULL, 1954, NULL, 'United States', '/authors/OL24465A', 'Q1223298', 'https://en.wikipedia.org/wiki/Erik_Larson_%28author%29', 'http://eriklarsonbooks.com/', NULL, 'Open Library', '2026-06-26T15:02:24+00:00', '{"openlibrary": {"bio": "Erik Larson is the author of the international bestseller Isaac''s Storm won an Edgar Award for fact-crime writing. His latest book, In the Garden of Beasts: Love Terror and an American Family in Hitler''s Berlin, has been acquired for publication in 20 countries and optioned by Tom Hanks for a feature film.\r\n\r\nErik is a former features writer for The Wall Street Journal and Time. His magazine stories have appeared in The New Yorker, The Atlantic Monthly, Harper''s and other publications. Source: Goodreads.com", "birth_year": 1954, "death_year": null, "website": null, "wikidata_id": "Q1223298", "ol_photo_id": 7405144}, "wikidata": {"wikidata_id": "Q1223298", "birth_year": 1954, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Edgar Awards", "Carl Sandburg Literary Award"], "website": "http://eriklarsonbooks.com/", "goodreads_id": "5869", "image_filename": "Erik Larson 03B.jpg", "wikipedia_title": "Erik Larson (author)", "wikipedia_url": "https://en.wikipedia.org/wiki/Erik_Larson_%28author%29"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Erik_Larson_03B.jpg/330px-Erik_Larson_03B.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Erik_Larson_(author)"}}');
