INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (91, NULL, 1948, NULL, 'United States', '/authors/OL26283A', 'Q188987', 'https://en.wikipedia.org/wiki/William_Gibson', 'https://williamgibsonbooks.com/', '["Neuromancer"]', 'Open Library', '2026-06-26T15:02:30+00:00', '{"openlibrary": {"bio": "William Ford Gibson is an American-Canadian writer who has been called the \"noir prophet\" of the cyberpunk subgenre of science fiction. Gibson coined the term \"cyberspace\" in his short story \"Burning Chrome\" and later popularized the concept in his debut novel, *Neuromancer* (1984). In envisaging cyberspace, Gibson created an iconography for the information age before the ubiquity of the Internet in the 1990s. He is also credited with predicting the rise of reality television and with establishing the conceptual foundations for the rapid growth of virtual environments such as video games and the Web. ([Source][1])\r\n\r\nPhoto by [FredArmitage][2]\r\n\r\n\r\n  [1]: http://en.wikipedia.org/wiki/William_Gibson\r\n  [2]: http://www.flickr.com/photos/fredarmitage/1057613629/", "birth_year": 1948, "death_year": null, "website": "https://williamgibsonbooks.com/", "wikidata_id": "Q188987", "ol_photo_id": 14538063}, "wikidata": {"wikidata_id": "Q188987", "birth_year": 1948, "death_year": null, "nationality": "United States", "notable_works": ["Neuromancer"], "awards": ["Nebula Award for Best Novel", "Hugo Award for Best Novel", "Philip K. Dick Award", "Seiun Award for Best Translated Long Work", "Aurora Awards", "Aurora Awards", "Science Fiction Chronicle Award", "Ditmar Award", "Locus Poll Award", "Science Fiction and Fantasy Hall of Fame"], "website": "https://williamgibsonbooks.com/", "goodreads_id": "9226", "image_filename": "William Gibson 60th birthday portrait.jpg", "wikipedia_title": "William Gibson", "wikipedia_url": "https://en.wikipedia.org/wiki/William_Gibson"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/d/df/William_Gibson_60th_birthday_portrait_%283x4_cropped%29.jpg/330px-William_Gibson_60th_birthday_portrait_%283x4_cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/William_Gibson"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (92, NULL, 1934, 2024, 'Israel', '/authors/OL2066695A', 'Q233950', 'https://en.wikipedia.org/wiki/Daniel_Kahneman', 'https://kahneman.scholar.princeton.edu', NULL, 'Open Library', '2026-06-26T15:02:32+00:00', '{"openlibrary": {"bio": "Israeli-American psychologist and economist notable for his work on the psychology of judgment and decision-making, as well as behavioral economics.", "birth_year": 1934, "death_year": 2024, "website": null, "wikidata_id": "Q233950", "ol_photo_id": 7292667}, "wikidata": {"wikidata_id": "Q233950", "birth_year": 1934, "death_year": 2024, "nationality": "Israel", "notable_works": [], "awards": ["APA Award for Distinguished Scientific Contributions to Psychology", "William James Fellow Award", "Fellow of the Econometric Society", "Howard Crosby Warren Medal", "Prize in Economic Sciences in Memory of Alfred Nobel", "Clarivate Citation Laureates", "Grawemeyer Awards", "Honorary doctorate from the Julius Maximilians University of Würzburg", "Kampé de Fériet Award", "honorary doctor of Paris Descartes University"], "website": "https://kahneman.scholar.princeton.edu", "goodreads_id": "72401", "image_filename": "Daniel Kahneman (3283955327) (cropped).jpg", "wikipedia_title": "Daniel Kahneman", "wikipedia_url": "https://en.wikipedia.org/wiki/Daniel_Kahneman"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/4d/Daniel_Kahneman_%283283955327%29_%28cropped%29.jpg/330px-Daniel_Kahneman_%283283955327%29_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Daniel_Kahneman"}}');
