INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (94, NULL, 1961, NULL, 'United States', '/authors/OL1518080A', 'Q217790', 'https://en.wikipedia.org/wiki/Lawrence_Lessig', 'http://twitter.com/lessig', NULL, 'Open Library', '2026-06-26T15:02:37+00:00', '{"openlibrary": {"bio": "Lawrence \"Larry\" Lessig is an American academic and political activist. He is best known as a proponent of reduced legal restrictions on copyright, trademark, and radio frequency spectrum, particularly in technology applications.\r\n\r\nHe is a director of the Edmond J. Safra Foundation Center for Ethics at Harvard University and a professor of law at Harvard Law School. Prior to rejoining Harvard, he was a professor of law at Stanford Law School and founder of its Center for Internet and Society. Lessig is a founding board member of Creative Commons, a board member of the Software Freedom Law Center and a former board member of the Electronic Frontier Foundation.", "birth_year": 1961, "death_year": null, "website": "http://twitter.com/lessig", "wikidata_id": "Q217790", "ol_photo_id": 5723660}, "wikidata": {"wikidata_id": "Q217790", "birth_year": 1961, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Webby Lifetime Achievement Award", "FSF Award for the Advancement of Free Software", "Berlin Prize", "Scientific American 50", "honorary doctorate of Lund University"], "website": "https://lessig.org", "goodreads_id": "25159", "image_filename": "Lawrence Lessig May 2017.jpg", "wikipedia_title": "Lawrence Lessig", "wikipedia_url": "https://en.wikipedia.org/wiki/Lawrence_Lessig"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/d/d3/Lessig_in_2024.png/330px-Lessig_in_2024.png", "wikipedia_url": "https://en.wikipedia.org/wiki/Lawrence_Lessig"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (95, NULL, 1951, 2022, 'United States', '/authors/OL23206A', 'Q317491', 'https://en.wikipedia.org/wiki/Greg_Bear', 'https://gregbear.com', '["Blood Music"]', 'Open Library', '2026-06-26T15:02:39+00:00', '{"openlibrary": {"bio": "Gregory Dale Bear (born August 20, 1951) is an American writer and illustrator best known for science fiction. His work has covered themes of galactic conflict (Forge of God books), artificial universes (The Way series), consciousness and cultural practices (Queen of Angels), and accelerated evolution (Blood Music, Darwin''s Radio, and Darwin''s Children). His most recent work is the 2021 novel The Unfinished Land. Greg Bear has written over 50 books in total. Greg Bear was also one of the five co-founders of the San Diego Comic-Con. [source](https://en.wikipedia.org/wiki/Greg_Bear)", "birth_year": 1951, "death_year": 2022, "website": null, "wikidata_id": "Q317491", "ol_photo_id": 5971154}, "wikidata": {"wikidata_id": "Q317491", "birth_year": 1951, "death_year": 2022, "nationality": "United States", "notable_works": ["Blood Music"], "awards": ["Inkpot Award", "Nebula Award for Best Novella", "Nebula Award for Best Novelette", "Hugo Award for Best Novelette", "Nebula Award for Best Short Story", "Prix Tour-Apollo Award", "Hugo Award for Best Short Story", "Tähtivaeltaja Award", "Nebula Award for Best Novel", "Nebula Award for Best Novel"], "website": "https://gregbear.com", "goodreads_id": "16024", "image_filename": "Greg Bear.jpg", "wikipedia_title": "Greg Bear", "wikipedia_url": "https://en.wikipedia.org/wiki/Greg_Bear"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/6/6a/Greg-bear-by-kyle-cassidy-L1008770_%28cropped%29.jpg/330px-Greg-bear-by-kyle-cassidy-L1008770_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Greg_Bear"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (96, NULL, 1941, NULL, 'United Kingdom', '/authors/OL236174A', 'Q44461', 'https://en.wikipedia.org/wiki/Richard_Dawkins', 'https://www.richarddawkins.net', '["The Selfish Gene", "The Greatest Show on Earth: The Evidence for Evolution"]', 'Open Library', '2026-06-26T15:02:42+00:00', '{"openlibrary": {"bio": "Clinton Richard Dawkins, FRS, FRSL is a British ethologist, evolutionary biologist and popular science author. He was formerly Professor for Public Understanding of Science at Oxford and was a fellow of New College, Oxford.\r\n\r\nDawkins came to prominence with his 1976 book *The Selfish Gene*, which popularised the gene-centred view of evolution and introduced the term meme. In 1982, he made a widely cited contribution to evolutionary biology with the concept, presented in his book *The Extended Phenotype*, that the phenotypic effects of a gene are not necessarily limited to an organism''s body, but can stretch far into the environment, including the bodies of other organisms.\r\n\r\nDawkins is well known for his candid criticism of creationism and intelligent design. In his 1986 book *The Blind Watchmaker*, he argued against the watchmaker analogy, an argument for the existence of a supernatural creator based upon the complexity of living organisms. Instead, he described evolutionary processes as analogous to a blind watchmaker. He has since written several popular science books, and makes regular television and radio appearances, predominantly discussing these topics.\r\n\r\n([Source][1])\r\n\r\n\r\n  [1]: http://en.wikipedia.org/wiki/Richard_Dawkins", "birth_year": 1941, "death_year": null, "website": null, "wikidata_id": "Q44461", "ol_photo_id": 12847320}, "wikidata": {"wikidata_id": "Q44461", "birth_year": 1941, "death_year": null, "nationality": "United Kingdom", "notable_works": ["The Selfish Gene", "The Greatest Show on Earth: The Evidence for Evolution"], "awards": ["Fellow of the Royal Society", "Kistler Prize", "Michael Faraday Prize", "International Cosmos Prize", "Lewis Thomas Prize", "Shakespeare Prize", "Humanist of the Year", "Medal of Representation of the President of the Italian Republic", "Nierenberg Prize", "Silver Medal of the Zoological Society of London"], "website": "https://www.richarddawkins.net", "goodreads_id": "1194", "image_filename": "Richard Dawkins Cooper Union Shankbone.jpg", "wikipedia_title": "Richard Dawkins", "wikipedia_url": "https://en.wikipedia.org/wiki/Richard_Dawkins"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/82/Dinner_with_Richard_Dawkins_and_CFI..._like_a_candle_in_the_dark.jpg/330px-Dinner_with_Richard_Dawkins_and_CFI..._like_a_candle_in_the_dark.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Richard_Dawkins"}}');
