INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (98, NULL, 1967, NULL, 'United States', '/authors/OL562969A', 'Q1292350', 'https://en.wikipedia.org/wiki/Edward_Glaeser', 'http://en.wikipedia.org/wiki/Edward_L._Glaeser', NULL, 'Open Library', '2026-06-26T15:02:49+00:00', '{"openlibrary": {"bio": "Edward L. Glaeser is the Fred and Eleanor Glimp Professor of Economics at Harvard University. He studies the economics of cities, housing, segregation, obesity, crime, innovation and other subjects, and writes about many of these issues for Economix. He serves as the director of the Taubman Center for State and Local Government and the Rappaport Institute for Greater Boston. He is also a senior fellow at the Manhattan Institute. He received his Ph.D. from the University of Chicago in 1992.  (*Source: Penguin USA*)", "birth_year": 1967, "death_year": null, "website": "http://en.wikipedia.org/wiki/Edward_L._Glaeser", "wikidata_id": "Q1292350", "ol_photo_id": 6685853}, "wikidata": {"wikidata_id": "Q1292350", "birth_year": 1967, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Fellow of the Econometric Society", "Fellow of the American Academy of Arts and Sciences", "Clarivate Citation Laureates"], "website": null, "goodreads_id": null, "image_filename": "ASSA 2026 - Edward Glaeser 01 (cropped).jpg", "wikipedia_title": "Edward Glaeser", "wikipedia_url": "https://en.wikipedia.org/wiki/Edward_Glaeser"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/ASSA_2026_-_Edward_Glaeser_01_%28cropped%29.jpg/330px-ASSA_2026_-_Edward_Glaeser_01_%28cropped%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Edward_Glaeser"}}');
