INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (110, NULL, 1934, 2021, 'Hungary', '/authors/OL33636A', 'Q316147', 'https://en.wikipedia.org/wiki/Mihaly_Csikszentmihalyi', NULL, NULL, 'Open Library', '2026-06-26T15:03:23+00:00', '{"openlibrary": {"bio": "Hungarian psychologist Mihaly Csikszentmihalyi was the Distinguished Professor of Psychology and Management at Claremont Graduate University. He is noted for his work in the study of happiness and creativity, but is best known as the architect of the notion of flow, a highly focused mental state. \r\n\r\nMartin Seligman, former president of the American Psychological Association, described Csikszentmihalyi as the world''s leading researcher on positive psychology.\r\n\r\nCsikszentmihalyi once said: \"Repression is not the way to virtue. When people restrain themselves out of fear, their lives are by necessity diminished. Only through freely chosen discipline can life be enjoyed and still kept within the bounds of reason.\" (Wikipedia)", "birth_year": 1934, "death_year": 2021, "website": null, "wikidata_id": "Q316147", "ol_photo_id": 8109605}, "wikidata": {"wikidata_id": "Q316147", "birth_year": 1934, "death_year": 2021, "nationality": "Hungary", "notable_works": [], "awards": ["Széchenyi Prize", "James McKeen Cattell Fellow Award"], "website": null, "goodreads_id": "27446", "image_filename": "Mihaly Csikszentmihalyi.jpg", "wikipedia_title": "Mihaly Csikszentmihalyi", "wikipedia_url": "https://en.wikipedia.org/wiki/Mihaly_Csikszentmihalyi"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/c/c3/Mihaly_Csikszentmihalyi.jpg/330px-Mihaly_Csikszentmihalyi.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Mihaly_Csikszentmihalyi"}}');
