INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (125, NULL, 1947, NULL, 'United States', '/authors/OL402867A', 'Q720561', 'https://en.wikipedia.org/wiki/Alan_Weisman', NULL, NULL, 'Open Library', '2026-06-26T15:04:08+00:00', '{"openlibrary": {"bio": "Alan H. Weisman, an American author, professor, and journalist, was born in Minneapolis, Minnesota. He holds a bachelor''s degree in literature and a master''s degree in journalism from Northwestern University. From 2004 to 2013 he was Laureate Professor in Journalism and Latin American Studies at the University of Arizona. He has also taught writing and journalism at Prescott College and Williams College and has been a Fulbright Scholar in Colombia.\r\n\r\nHe has written several books and won numerous international awards for his work in journalism and literature. His reports from around the world have appeared in leading magazines, and in several anthologies. He is also a producer of radio documentaries for Homelands Productions, creating reports for National Public Radio and American Public Media.\r\n\r\nSource: Wikipedia", "birth_year": 1947, "death_year": null, "website": null, "wikidata_id": "Q720561", "ol_photo_id": 7401303}, "wikidata": {"wikidata_id": "Q720561", "birth_year": 1947, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Fulbright Scholarship"], "website": null, "goodreads_id": "79216", "image_filename": "Alan Weisman at Powell''s Books.jpg", "wikipedia_title": "Alan Weisman", "wikipedia_url": "https://en.wikipedia.org/wiki/Alan_Weisman"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/3/3d/Alan_Weisman_at_Powell%27s_Books.jpg/330px-Alan_Weisman_at_Powell%27s_Books.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Alan_Weisman"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (126, NULL, 1942, NULL, 'United States', '/authors/OL421269A', 'Q1293908', 'https://en.wikipedia.org/wiki/Edward_Tufte', 'http://www.edwardtufte.com/tufte/', NULL, 'Open Library', '2026-06-26T15:04:11+00:00', '{"openlibrary": {"bio": "An American statistician and professor emeritus of political science, statistics, and computer science.", "birth_year": 1942, "death_year": null, "website": "http://www.edwardtufte.com/tufte/", "wikidata_id": "Q1293908", "ol_photo_id": 7026307}, "wikidata": {"wikidata_id": "Q1293908", "birth_year": 1942, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Guggenheim Fellowship", "Fellow of the American Statistical Association", "AIGA Medal"], "website": "https://edwardtufte.com", "goodreads_id": "10775", "image_filename": "Edware Tufte giving a class.jpg", "wikipedia_title": "Edward Tufte", "wikipedia_url": "https://en.wikipedia.org/wiki/Edward_Tufte"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/46/Edward_Tufte_-_cropped.jpg/330px-Edward_Tufte_-_cropped.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Edward_Tufte"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (127, NULL, 1933, 2015, 'United Kingdom', '/authors/OL217344A', 'Q258662', 'https://en.wikipedia.org/wiki/Oliver_Sacks', 'https://www.oliversacks.com', '["The Man Who Mistook His Wife for a Hat", "Awakenings"]', 'Open Library', '2026-06-26T15:04:14+00:00', '{"openlibrary": {"bio": "Oliver Sacks, M.D. was a physician, a best-selling author, and a professor of neurology at the NYU School of Medicine. The New York Times has referred to him as “the poet laureate of medicine.”\r\n\r\nHe is best known for his collections of neurological case histories, including The Man who Mistook his Wife for a Hat, Musicophilia: Tales of Music and the Brain and An Anthropologist on Mars. Awakenings, his book about a group of patients who had survived the great encephalitis lethargica epidemic of the early twentieth century, inspired the 1990 Academy Award-nominated feature film starring Robert De Niro and Robin Williams.\r\n\r\nDr. Sacks was a frequent contributor to the New Yorker and the New York Review of Books.\r\n\r\n([source][1])\r\n\r\n\r\n  [1]: https://www.oliversacks.com/about-oliver-sacks/", "birth_year": 1933, "death_year": 2015, "website": "https://www.oliversacks.com", "wikidata_id": "Q258662", "ol_photo_id": 8186972}, "wikidata": {"wikidata_id": "Q258662", "birth_year": 1933, "death_year": 2015, "nationality": "United Kingdom", "notable_works": ["The Man Who Mistook His Wife for a Hat", "Awakenings"], "awards": ["Guggenheim Fellowship", "Commander of the Order of the British Empire", "George Polk Award", "Lewis Thomas Prize", "Hawthornden Prize", "Oskar Pfister Award", "Emperor Has No Clothes Award", "honorary doctorate from the Pontifical Catholic University of Peru", "Fellow of the American Association for the Advancement of Science", "Bodley Medal"], "website"