INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (130, 'Scott McCloud (born Scott McLeod on June 10, 1960)  is an American cartoonist and theorist on comics as a distinct literary and artistic non-linear medium. He is best known for his non-fiction books about comics: *Understanding Comics* (1993), *Reinventing Comics* (2000), and *Making Comics* (2006), all of which also use the medium of comics.
