INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (134, NULL, 1933, 2023, 'United States', '/authors/OL28104A', 'Q272610', 'https://en.wikipedia.org/wiki/Cormac_McCarthy', 'https://cormacmccarthybooks.com/', '["Suttree", "Blood Meridian", "All the Pretty Horses", "The Border Trilogy", "No Country for Old Men", "The Road"]', 'Open Library', '2026-06-26T15:04:32+00:00', '{"openlibrary": {"bio": "Cormac McCarthy (born Charles Joseph McCarthy Jr.) is an American writer who has written twelve novels, two plays, five screenplays, and three short stories, spanning the Western and postapocalyptic genres. He is known for his graphic depictions of violence and his unique writing style, recognizable by a sparse use of punctuation and attribution. McCarthy is widely regarded as one of the greatest contemporary American writers.", "birth_year": 1933, "death_year": 2023, "website": null, "wikidata_id": "Q272610", "ol_photo_id": 14333158}, "wikidata": {"wikidata_id": "Q272610", "birth_year": 1933, "death_year": 2023, "nationality": "United States", "notable_works": ["Suttree", "Blood Meridian", "All the Pretty Horses", "The Border Trilogy", "No Country for Old Men", "The Road"], "awards": ["National Book Award for Fiction", "Pulitzer Prize for Fiction", "Guggenheim Fellowship", "MacArthur Fellows Program", "James Tait Black Memorial Prize", "Lillian Smith Book Award", "Ignotus Award for Best Foreign Novel", "National Book Critics Circle Award for Fiction", "Believer Book Award", "Guggenheim Fellowship"], "website": "https://cormacmccarthybooks.com/", "goodreads_id": "4178", "image_filename": "Cormac McCarthy (Child of God author portrait - high-res).jpg", "wikipedia_title": "Cormac McCarthy", "wikipedia_url": "https://en.wikipedia.org/wiki/Cormac_McCarthy"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/7/7f/Cormac_McCarthy_%28Child_of_God_author_portrait_-_high-res%29.jpg/330px-Cormac_McCarthy_%28Child_of_God_author_portrait_-_high-res%29.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Cormac_McCarthy"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (135, NULL, 1955, NULL, 'United States', '/authors/OL539266A', 'Q1138996', 'https://en.wikipedia.org/wiki/Michael_Pollan', 'https://michaelpollan.com/', NULL, 'Open Library', '2026-06-26T15:04:34+00:00', '{"openlibrary": {"bio": "Michael Pollan is an American author, journalist, activist, and professor of journalism at the UC Berkeley Graduate School of Journalism. He writes about the places where nature and culture intersect: on our plates, in our farms and gardens, and in the built environment.", "birth_year": 1955, "death_year": null, "website": "https://michaelpollan.com/", "wikidata_id": "Q1138996", "ol_photo_id": 3366183}, "wikidata": {"wikidata_id": "Q1138996", "birth_year": 1955, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Orwell Award", "LennonOno Grant for Peace", "Nierenberg Prize", "Guggenheim Fellowship"], "website": "http://michaelpollan.com/", "goodreads_id": "2121", "image_filename": "Michael Pollan at Yale 1 cropped.jpg", "wikipedia_title": "Michael Pollan", "wikipedia_url": "https://en.wikipedia.org/wiki/Michael_Pollan"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/9/92/Michael_Pollan_in_2025.jpg/330px-Michael_Pollan_in_2025.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Michael_Pollan"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (136, 'Daniel Todd Gilbert is an American social psychologist and writer. He is the Edgar Pierce Professor of Psychology at Harvard University and is known for his research with Timothy Wilson of the University of Virginia on affective forecasting. He is the author of the international bestseller Stumbling on Happiness, which has been translated into more than 30 languages and won the 2007 Royal Society Prize for Science Books. He has also written essays for several newspapers and magazines, hosted a non-fiction television series on PBS, and given three popular TED talks.', 1957, NULL, 'United States', '/authors/OL1434193A', 'Q449564', 'https://en.wikipedia.org/wiki/Daniel_Gilbert_%28psychologist%29', 'http://www.danielgilbert.com/', '["Stumbling on Happiness"]', 'Wikimedia Commons', '2026-06-26T15:04:37+00:00', '{"openlibrary": {"bio": null, "birth_year": null, "death_year": null, "website": null, "wikidata_id": "Q449564", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q449564", "birth_year": 1957, "death_year": null, "nationality": "United States", "notable_works": ["Stumbling on Happiness"], "awards": ["Guggenheim Fellowship", "Royal Society Science Books Prize", "Fellow of the American Academy of Arts and Sciences", "William James Fellow Award", "Donald T. Campbell Award", "APA Distinguished Scientific Award for an Early Career Contribution to Psychology"], "website": "http://www.danielgilbert.com/", "goodreads_id": null, "image_filename": "Daniel Todd Gilbert.jpg", "wikipedia_title": "Daniel Gilbert (psychologist)", "wikipedia_url": "https://en.wikipedia.org/wiki/Daniel_Gilbert_%28psychologist%29"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/2/22/GILBERT_2020.jpg/330px-GILBERT_2020.jpg", "wikipedia_url": "ht