INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (144, 'Robert Marshall Axelrod is an American political scientist. He is Professor of Political Science and Public Policy at the University of Michigan where he has been since 1974. He is best known for his interdisciplinary work on the evolution of cooperation. His current research interests include complexity theory, international security, and cyber security. His research includes innovative approaches to explaining conflict of interest, the emergence of norms, how game theory is used to study cooperation, and cross-disciplinary studies on evolutionary processes.', 1943, NULL, 'United States', '/authors/OL381711A', 'Q583438', 'https://en.wikipedia.org/wiki/Robert_Axelrod_%28political_scientist%29', NULL, '["The Evolution of Cooperation", "Conflict of Interest: A Theory of Divergent Goals with Applications to Politics", "The Complexity of Cooperation", "Harnessing Complexity: Organizational Implications of a Scientific Frontier"]', 'Wikimedia Commons', '2026-06-26T15:04:55+00:00', '{"openlibrary": {"bio": null, "birth_year": null, "death_year": null, "website": null, "wikidata_id": "Q583438", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q583438", "birth_year": 1943, "death_year": null, "nationality": "United States", "notable_works": ["The Evolution of Cooperation", "Conflict of Interest: A Theory of Divergent Goals with Applications to Politics", "The Complexity of Cooperation", "Harnessing Complexity: Organizational Implications of a Scientific Frontier"], "awards": ["MacArthur Fellows Program", "Johan Skytte Prize in Political Science", "National Medal of Science", "Wilbur Cross Medal", "Jefferson Science Fellow", "Fellow of the American Academy of Arts and Sciences", "Charles E. Merriam Award for Outstanding Public Policy Research", "William and Katherine Estes Award"], "website": null, "goodreads_id": "151970", "image_filename": "Professor RobertMAxelrod.png", "wikipedia_title": "Robert Axelrod (political scientist)", "wikipedia_url": "https://en.wikipedia.org/wiki/Robert_Axelrod_%28political_scientist%29"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f1/Professor_RobertMAxelrod.png/330px-Professor_RobertMAxelrod.png", "wikipedia_url": "https://en.wikipedia.org/wiki/Robert_Axelrod_(political_scientist)"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (145, NULL, 1967, NULL, 'United States', '/authors/OL1453058A', 'Q730969', 'https://en.wikipedia.org/wiki/Steven_Levitt', NULL, '["Freakonomics"]', 'Open Library', '2026-06-26T15:04:58+00:00', '{"openlibrary": {"bio": "\"Steven David \"Steve\" Levitt is a prominent American economist best known for his work on crime, in particular on the link between legalized abortion and crime rates. Winner of the 2003 John Bates Clark Medal, he is currently the Alvin H. Baum Professor of Economics at the University of Chicago, director of the Becker Center on Chicago Price Theory at the University of Chicago Graduate School of Business, and co-editor of the Journal of Political Economy published by the University of Chicago Press.\" - Wikipedia", "birth_year": 1967, "death_year": null, "website": null, "wikidata_id": "Q730969", "ol_photo_id": 7402424}, "wikidata": {"wikidata_id": "Q730969", "birth_year": 1967, "death_year": null, "nationality": "United States", "notable_works": ["Freakonomics"], "awards": ["Sloan Fellowship", "John Bates Clark Medal", "Fellow of the Econometric Society", "Presidential Early Career Award for Scientists and Engineers"], "website": null, "goodreads_id": "798", "image_filename": "Steven Levitt, 2012.jpg", "wikipedia_title": "Steven Levitt", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Levitt"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/2/20/Steven_Levitt%2C_2012.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Levitt"}}');
