INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (147, NULL, 1933, 2018, 'United States', '/authors/OL2444787A', 'Q187019', 'https://en.wikipedia.org/wiki/Philip_Roth', 'http://en.wikipedia.org/wiki/Philip_Roth', NULL, 'Open Library', '2026-06-26T15:05:04+00:00', '{"openlibrary": {"bio": "Philip Milton Roth (March 19, 1933 – May 22, 2018) was an American novelist and short-story writer. Roth''s fiction—often set in his birthplace of Newark, New Jersey—is known for its intensely autobiographical character, for philosophically and formally blurring the distinction between reality and fiction, for its \"sensual, ingenious style\" and for its provocative explorations of Jewish and American identity. He first gained attention with the 1959 short story collection *Goodbye, Columbus,* which won the U.S. National Book Award for Fiction. Ten years later, he published the bestseller *Portnoy''s Complaint.* Nathan Zuckerman, Roth''s literary alter ego, narrates several of his books. A fictionalized Roth narrates some of his others, such as the alternate history *The Plot Against America.*", "birth_year": 1933, "death_year": 2018, "website": "http://en.wikipedia.org/wiki/Philip_Roth", "wikidata_id": "Q187019", "ol_photo_id": 6462349}, "wikidata": {"wikidata_id": "Q187019", "birth_year": 1933, "death_year": 2018, "nationality": "United States", "notable_works": [], "awards": ["Guggenheim Fellowship", "National Medal of Arts", "National Humanities Medal", "Franz Kafka Prize", "Princess of Asturias Literary Prize", "National Book Award for Fiction", "PEN/Faulkner Award for Fiction", "National Book Award for Fiction", "Pulitzer Prize for Fiction", "PEN/Faulkner Award for Fiction"], "website": null, "goodreads_id": "463", "image_filename": "Philip Roth - 1973.jpg", "wikipedia_title": "Philip Roth", "wikipedia_url": "https://en.wikipedia.org/wiki/Philip_Roth"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/7/77/Philip_Roth%2C_Author_2020732799_3x4.jpg/330px-Philip_Roth%2C_Author_2020732799_3x4.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Philip_Roth"}}');
