INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (151, 'Barry Schwartz is an American psychologist. Schwartz is the Dorwin Cartwright Emeritus Professor of Social Theory and Social Action at Swarthmore College and since 2016 has been visiting professor at the University of California, Berkeley. His work focuses on the intersection of psychology and economics. He frequently publishes editorials in The New York Times, applying his research in psychology to current events.', 1946, NULL, 'United States', '/authors/OL591196A', 'Q3500411', 'https://en.wikipedia.org/wiki/Barry_Schwartz_%28psychologist%29', NULL, '["The Paradox of Choice"]', 'Wikimedia Commons', '2026-06-26T15:05:16+00:00', '{"openlibrary": {"bio": null, "birth_year": 1946, "death_year": null, "website": null, "wikidata_id": "Q3500411", "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q3500411", "birth_year": 1946, "death_year": null, "nationality": "United States", "notable_works": ["The Paradox of Choice"], "awards": ["Athenaeum Literary Award", "Athenaeum Literary Award"], "website": null, "goodreads_id": "6957", "image_filename": "Barry Schwartz.jpg", "wikipedia_title": "Barry Schwartz (psychologist)", "wikipedia_url": "https://en.wikipedia.org/wiki/Barry_Schwartz_%28psychologist%29"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/44/Barry_Schwartz.jpg/330px-Barry_Schwartz.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Barry_Schwartz_(psychologist)"}}');
