INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (155, NULL, 1959, NULL, 'United States', '/authors/OL19430A', 'Q312853', 'https://en.wikipedia.org/wiki/Neal_Stephenson', 'https://nealstephenson.com', NULL, 'Open Library', '2026-06-26T15:05:29+00:00', '{"openlibrary": {"bio": "Neal Town Stephenson (born October 31, 1959) is an American writer and game designer known for his works of speculative fiction. His novels have been categorized as science fiction, historical fiction, cyberpunk, postcyberpunk, and baroque.\r\n\r\nStephenson''s work explores subjects such as mathematics, cryptography, linguistics, philosophy, currency, and the history of science. He also writes non-fiction articles about technology in publications such as *Wired*. He has also written novels with his uncle, George Jewsbury (\"J. Frederick George\"), under the collective pseudonym Stephen Bury.\r\n\r\nStephenson has worked part-time as an advisor for Blue Origin, a company (funded by Jeff Bezos) developing a manned sub-orbital launch system, and is also a cofounder of Subutai Corporation, whose first offering is the interactive fiction project *The Mongoliad*. He is currently Magic Leap''s Chief Futurist.\r\n\r\n**Source**: <a href=https://en.wikipedia.org/wiki/Neal_Stephenson\">Neal Stephenson</a> on Wikipedia (Wikipedia contributors, <a href=\"https://en.wikipedia.org/wiki/Wikipedia:Text_of_Creative_Commons_Attribution-ShareAlike_3.0_Unported_License\">CC BY-SA 2.0</a>)", "birth_year": 1959, "death_year": null, "website": "https://nealstephenson.com", "wikidata_id": "Q312853", "ol_photo_id": 14855803}, "wikidata": {"wikidata_id": "Q312853", "birth_year": 1959, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Prometheus Award - Hall of Fame", "Grand Prix de l''Imaginaire for Best Foreign Novel", "Hugo Award for Best Novel", "Locus Award for Best Science Fiction Novel", "Locus Award for Best Science Fiction Novel", "Arthur C. Clarke Award", "Locus Award for Best Science Fiction Novel", "Locus Award for Best Science Fiction Novel", "Ignotus Award for Best Foreign Novel", "Robert A. Heinlein Award"], "website": "http://www.nealstephenson.com/", "goodreads_id": "545", "image_filename": "Neal Stephenson 2008 crop.jpg", "wikipedia_title": "Neal Stephenson", "wikipedia_url": "https://en.wikipedia.org/wiki/Neal_Stephenson"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Neal_Stephenson_in_2019_A_021.jpg/330px-Neal_Stephenson_in_2019_A_021.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Neal_Stephenson"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (156, NULL, 1954, NULL, 'United States', '/authors/OL29930A', 'Q212730', 'https://en.wikipedia.org/wiki/Steven_Pinker', 'https://en.wikipedia.org/wiki/Steven_Pinker', '["The Language Instinct", "How the Mind Works", "The Blank Slate", "The Better Angels of Our Nature", "Enlightenment Now", "Words and Rules"]', 'Open Library', '2026-06-26T15:05:32+00:00', '{"openlibrary": {"bio": "Steven Arthur \"Steve\" Pinker is a Canadian-born American cognitive scientist, psychologist, linguist, and popular science author. He is Johnstone Family Professor in the Department of Psychology at Harvard University, and is known for his advocacy of evolutionary psychology and the computational theory of mind.", "birth_year": 1954, "death_year": null, "website": "https://en.wikipedia.org/wiki/Steven_Pinker", "wikidata_id": "Q212730", "ol_photo_id": 7374710}, "wikidata": {"wikidata_id": "Q212730", "birth_year": 1954, "death_year": null, "nationality": "United States", "notable_works": ["The Language Instinct", "How the Mind Works", "The Blank Slate", "The Better Angels of Our Nature", "Enlightenment Now", "Words and Rules"], "awards": ["APA Distinguished Scientific Award for an Early Career Contribution to Psychology", "Boyd McCandless Award", "Troland Research Awards", "Emperor Has No Clothes Award", "Walter P. Kistler Book Award", "Humanist of the Year", "Richard Dawkins Award", "William James Fellow Award", "Emperor Has No Clothes Award", "Carl Sagan Award for Public Understanding of Science"], "website": "http://stevenpinker.com/", "goodreads_id": "3915", "image_filename": "Steven Pinker in 2023 A 04 (cropped).jpg", "wikipedia_title": "Steven Pinker", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Pinker"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/a/a6/Steven_Pinker_in_2023.jpg/330px-Steven_Pinker_in_2023.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Steven_Pinker"}}');
