INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (161, NULL, 1817, 1862, 'United States', '/authors/OL19690A', 'Q131149', 'https://en.wikipedia.org/wiki/Henry_David_Thoreau', 'http://thoreau.library.ucsb.edu/', '["Walden", "Civil Disobedience"]', 'Open Library', '2026-06-26T15:05:51+00:00', '{"openlibrary": {"bio": "Henry David Thoreau (born David Henry Thoreau) was an American author, poet, naturalist, tax resister, development critic, surveyor, historian, philosopher, and leading transcendentalist. He is best known for his book Walden, a reflection upon simple living in natural surroundings, and his essay, Civil Disobedience, an argument for individual resistance to civil government in moral opposition to an unjust state.\r\n\r\nThoreau''s books, articles, essays, journals, and poetry total over 20 volumes. Among his lasting contributions were his writings on natural history and philosophy, where he anticipated the methods and findings of ecology and environmental history, two sources of modern day environmentalism. His literary style interweaves close natural observation, personal experience, pointed rhetoric, symbolic meanings, and historical lore; while displaying a poetic sensibility, philosophical austerity, and \"Yankee\" love of practical detail. He was also deeply interested in the idea of survival in the face of hostile elements, historical change, and natural decay; at the same time imploring one to abandon waste and illusion in order to discover life''s true essential needs.\r\n\r\n([Source][1])\r\n\r\n\r\n  [1]: https://en.wikipedia.org/wiki/Henry_David_Thoreau", "birth_year": 1817, "death_year": 1862, "website": "http://thoreau.library.ucsb.edu/", "wikidata_id": "Q131149", "ol_photo_id": 7273527}, "wikidata": {"wikidata_id": "Q131149", "birth_year": 1817, "death_year": 1862, "nationality": "United States", "notable_works": ["Walden", "Civil Disobedience"], "awards": ["Hall of Fame for Great Americans"], "website": null, "goodreads_id": "10264", "image_filename": "Benjamin D. Maxham - Henry David Thoreau - Restored - greyscale - straightened.jpg", "wikipedia_title": "Henry David Thoreau", "wikipedia_url": "https://en.wikipedia.org/wiki/Henry_David_Thoreau"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f0/Benjamin_D._Maxham_-_Henry_David_Thoreau_-_Restored.jpg/330px-Benjamin_D._Maxham_-_Henry_David_Thoreau_-_Restored.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Henry_David_Thoreau"}}');
INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (162, NULL, 1803, 1882, 'United States', '/authors/OL18405A', 'Q48226', 'https://en.wikipedia.org/wiki/Ralph_Waldo_Emerson', NULL, '["Concord Hymn", "The Humble-Bee", "Music", "Thine Eyes still shined", "Waldeinsamkeit", "Woodnotes I"]', 'Open Library', '2026-06-26T15:05:55+00:00', '{"openlibrary": {"bio": "Ralph Waldo Emerson was an American philosopher, essayist, and poet, best remembered for leading the Transcendentalist movement of the mid-19th century. His teachings directly influenced the growing New Thought movement of the mid-1800s. He was seen as a champion of individualism and a prescient critic of the countervailing pressures of society.\r\n\r\nEmerson gradually moved away from the religious and social beliefs of his contemporaries, formulating and expressing the philosophy of Transcendentalism in his 1836 essay, Nature. As a result of this ground-breaking work he gave a speech entitled The American Scholar in 1837, which Oliver Wendell Holmes, Sr. considered to be America''s \"Intellectual Declaration of Independence\". Considered one of the great orators of the time, Emerson''s enthusiasm and respect for his audience enraptured crowds. His support for abolitionism late in life created controversy, and at times he was subject to abuse from crowds while speaking on the topic. When asked to sum up his work, he said his central doctrine was \"the infinitude of the private man.\"\r\n\r\n([Source][1])\r\n\r\n\r\n  [1]: http://en.wikipedia.org/wiki/Ralph_Waldo_Emerson", "birth_year": 1803, "death_year": 1882, "website": null, "wikidata_id": "Q48226", "ol_photo_id": 6390493}, "wikidata": {"wikidata_id": "Q48226", "birth_year": 1803, "death_year": 1882, "nationality": "United States", "notable_works": ["Concord Hymn", "The Humble-Bee", "Music", "Thine Eyes still shined", "Waldeinsamkeit", "Woodnotes I"], "awards": ["Fellow of the American Academy of Arts and Sciences"], "website": null, "goodreads_id": "12080", "image_filename": "Ralph Waldo Emerson ca1857 retouched.jpg", "wikipedia_title": "Ralph Waldo Emerson", "wikipedia_url": "https://en.wikipedia.org/wiki/Ralph_Waldo_Emerson"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/4/4b/Ralph_Waldo_Emerson_by_Josiah_Johnson_Hawes_1857.jpg/330px-Ralph_Waldo_Emerson_by_Josiah_Johnson_Hawes_1857.jpg", "wikipedia_url": "https://en.wikipedia.org/wiki/Ralph_Waldo_Emerson"}}');
