INSERT INTO club_author_enrichment (author_id, bio, birth_year, death_year, nationality, ol_author_key, wikidata_id, wikipedia_url, website, notable_works_json, photo_credit, enriched_at, enrichment_json) VALUES (171, NULL, 1968, NULL, 'United States', '/authors/OL7147517A', 'Q743045', 'https://en.wikipedia.org/wiki/Matthew_Walker_%28American_actor%29', 'https://www.sleepdiplomat.com/', NULL, NULL, '2026-06-26T15:06:21+00:00', '{"openlibrary": {"bio": "Dr. Walker earned his degree in neuroscience from Nottingham University, UK, and his PhD in neurophysiology from the Medical Research Council, London, UK. He subsequently became a Professor of Psychiatry at Harvard Medical School, USA. \r\n\r\nCurrently, he is Professor of Neuroscience and Psychology at the University of California, Berkeley, USA. He is also the founder and director of the Center for Human Sleep Science. \r\n\r\nDr. Walker’s research examines the impact of sleep on human health and disease. He has received numerous funding awards from the National Science Foundation and the National Institutes of Health, and is a Kavli Fellow of the National Academy of Sciences. \r\n\r\nHis research examines the impact of sleep on human brain function in healthy and disease populations. To date, he has published over 100 scientific research studies. \r\n([source][1])\r\n\r\n\r\n  [1]: https://www.sleepdiplomat.com/professor", "birth_year": null, "death_year": null, "website": "https://www.sleepdiplomat.com/", "wikidata_id": null, "ol_photo_id": null}, "wikidata": {"wikidata_id": "Q743045", "birth_year": 1968, "death_year": null, "nationality": "United States", "notable_works": [], "awards": [], "website": null, "goodreads_id": null, "image_filename": null, "wikipedia_title": "Matthew Walker (American actor)", "wikipedia_url": "https://en.wikipedia.org/wiki/Matthew_Walker_%28American_actor%29"}, "wikipedia": {"thumbnail_url": null, "wikipedia_url": "https://en.wikipedia.org/wiki/Matthew_Walker_(American_actor)"}}');
