**Source**: [Scott McCloud](https://en.wikipedia.org/wiki/Scott_McCloud) on Wikipedia', 1960, NULL, 'United States', '/authors/OL49389A', 'Q454833', 'https://en.wikipedia.org/wiki/Scott_McCloud', 'http://www.scottmccloud.com', NULL, 'Open Library', '2026-06-26T15:04:22+00:00', '{"openlibrary": {"bio": "Scott McCloud (born Scott McLeod on June 10, 1960)  is an American cartoonist and theorist on comics as a distinct literary and artistic non-linear medium. He is best known for his non-fiction books about comics: *Understanding Comics* (1993), *Reinventing Comics* (2000), and *Making Comics* (2006), all of which also use the medium of comics.\r\n\r\nSee [TED talk](http://www.ted.com/talks/scott_mccloud_on_comics.html) from McCloud.\r\n\r\n**Source**: [Scott McCloud](https://en.wikipedia.org/wiki/Scott_McCloud) on Wikipedia", "birth_year": 1960, "death_year": null, "website": "http://www.scottmccloud.com", "wikidata_id": "Q454833", "ol_photo_id": 6390121}, "wikidata": {"wikidata_id": "Q454833", "birth_year": 1960, "death_year": null, "nationality": "United States", "notable_works": [], "awards": ["Yellow Kid Award", "Eisner Award for Best Comics-Related Book", "Inkpot Award", "Harvey Award for Best Writer", "Will Eisner Hall of Fame", "Adamson Awards"], "website": "http://www.scottmccloud.com", "goodreads_id": null, "image_filename": "Scott McCloud.Making Comics Tour.RISD.gk.JPG", "wikipedia_title": "Scott McCloud", "wikipedia_url": "https://en.wikipedia.org/wiki/Scott_McCloud"}, "wikipedia": {"thumbnail_url": "https://upload.wikimedia.org/wikipedia/commons/thumb/6/61/Scott_McCloud.Making_Comics_Tour.RISD.gk.JPG/330px-Scott_McCloud.Making_Comics_Tour.RISD.gk.JPG", "wikipedia_url": "https://en.wikipedia.org/wiki/Scott_McCloud"}}');
